/**
 * 浼佷笟绾ч敊璇竟鐣岀粍浠禱n *
 * 鎻愪緵澧炲己鐨勯敊璇崟鑾枫€佸垎绫汇€佷笂鎶ュ拰鎭㈠鑳藉姏
 */

import React, { Component, ErrorInfo, ReactNode } from "react";
import { View, StyleSheet, InteractionManager } from "react-native";
import {
  handleError,
  ErrorCategory,
  ErrorSeverity,
  RecoveryStrategy,
  StructuredError,
} from "../../utils/errorHandling";
import { ErrorFallback, ErrorFallbackProps } from "./ErrorFallback";

// ============================================================================
// 绫诲瀷瀹氫箟
// ============================================================================

/**
 * 閿欒杈圭晫缁勪欢灞炴€n */
export interface ErrorBoundaryProps {
  /** 瀛愮粍浠?*/
  children: ReactNode;
  /** 鑷畾涔夐敊璇睍绀虹粍浠?*/
  fallback?: ReactNode | ((props: ErrorFallbackProps) => ReactNode);
  /** 閿欒閲嶇疆鍥炶皟 */
  onReset?: () => void;
  /** 閿欒鍙戠敓鏃剁殑鍥炶皟 */
  onError?: (error: Error, errorInfo: ErrorInfo, structuredError: StructuredError) => void;
  /** 鏄惁鏄剧ず璇︾粏閿欒淇℃伅锛堜粎寮€鍙戠幆澧冿級 */
  showDetails?: boolean;
  /** 灞忓箷鍚嶇О锛岀敤浜庨敊璇拷韪?*/
  screenName?: string;
  /** 閿欒鍙戠敓鏃剁殑涓婁笅鏂?*/
  context?: Record<string, unknown>;
  /** 鏈€澶ч噸璇曟鏁?*/
  maxRetries?: number;
  /** 鏄惁鍚敤鑷姩鎭㈠ */
  autoRecover?: boolean;
  /** 鑷姩鎭㈠寤惰繜锛堟绉掞級 */
  autoRecoverDelay?: number;
  /** 鑷畾涔夐敊璇垎绫?*/
  errorCategory?: ErrorCategory;
  /** 鑷畾涔夐敊璇弗閲嶇骇鍒?*/
  errorSeverity?: ErrorSeverity;
  /** 鑷畾涔夋仮澶嶇瓥鐣?*/
  recoveryStrategy?: RecoveryStrategy;
}

/**
 * 閿欒杈圭晫鐘舵€乗n */
interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
  structuredError: StructuredError | null;
  retryCount: number;
  isRecovering: boolean;
}

// ============================================================================
// 閿欒杈圭晫缁勪欢
// ============================================================================

/**
 * 浼佷笟绾ч敊璇竟鐣岀粍浠禱n *
 * 鐗规€э細
 * - 鑷姩閿欒鍒嗙被鍜屼弗閲嶇骇鍒瘎浼癨n * - 闆嗘垚閿欒涓婃姤绯荤粺
 * - 鏀寔澶氱鎭㈠绛栫暐
 * - 閲嶈瘯鏈哄埗
 * - 鑷姩鎭㈠锛堝彲閫夛級
 */
export class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  private autoRecoverTimer?: ReturnType<typeof setTimeout>;
  private retryTimer?: ReturnType<typeof setTimeout>;

  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
      errorInfo: null,
      structuredError: null,
      retryCount: 0,
      isRecovering: false,
    };
  }

  static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo): void {
    const { screenName, context, onError, errorCategory, errorSeverity, recoveryStrategy } =
      this.props;

    // 澶勭悊閿欒锛岃幏鍙栫粨鏋勫寲閿欒淇℃伅
    const structuredError = handleError(error, {
      ...context,
      screenName,
      componentStack: errorInfo.componentStack,
    });

    // 濡傛灉鎻愪緵浜嗚嚜瀹氫箟鍒嗙被锛岃鐩栬嚜鍔ㄥ垎绫籠n    if (errorCategory) {
      structuredError.category = errorCategory;
    }

    // 濡傛灉鎻愪緵浜嗚嚜瀹氫箟涓ラ噸绾у埆锛岃鐩栬嚜鍔ㄨ瘎浼癨n    if (errorSeverity) {
      structuredError.severity = errorSeverity;
    }

    // 濡傛灉鎻愪緵浜嗚嚜瀹氫箟鎭㈠绛栫暐锛岃鐩栬嚜鍔ㄧ瓥鐣n    if (recoveryStrategy) {
      structuredError.recoveryStrategy = recoveryStrategy;
    }

    // 鏇存柊鐘舵€乗n    this.setState({
      errorInfo,
      structuredError,
    });

    // 璋冪敤鑷畾涔夐敊璇鐞哱n    onError?.(error, errorInfo, structuredError);

    // 濡傛灉鍚敤鑷姩鎭㈠锛屽惎鍔ㄨ嚜鍔ㄦ仮澶嶈鏃跺櫒
    if (this.props.autoRecover && structuredError.recoverable) {
      this.scheduleAutoRecover();
    }
  }

  componentWillUnmount(): void {
    this.clearTimers();
  }

  /**
   * 娓呴櫎鎵€鏈夎鏃跺櫒
   */
  private clearTimers(): void {
    if (this.autoRecoverTimer) {
      clearTimeout(this.autoRecoverTimer);
      this.autoRecoverTimer = undefined;
    }
    if (this.retryTimer) {
      clearTimeout(this.retryTimer);
      this.retryTimer = undefined;
    }
  }

  /**
   * 瀹夋帓鑷姩鎭㈠
   */
  private scheduleAutoRecover(): void {
    const { autoRecoverDelay = 3000 } = this.props;

    this.autoRecoverTimer = setTimeout(() => {
      this.handleReset();
    }, autoRecoverDelay);
  }

  /**
   * 澶勭悊閲嶇疆
   */
  private handleReset = (): void => {
    const { onReset, maxRetries = 3 } = this.props;
    const { retryCount, structuredError } = this.state;

    // 妫€鏌ユ槸鍚﹁秴杩囨渶澶ч噸璇曟鏁癨n    if (retryCount >= maxRetries) {
      console.warn(`[ErrorBoundary] 宸茶揪鍒版渶澶ч噸璇曟鏁?(${maxRetries})`);
      return;
    }

    // 妫€鏌ラ敊璇槸鍚﹀彲鎭㈠
    if (structuredError && !structuredError.recoverable) {
      console.warn("[ErrorBoundary] 閿欒涓嶅彲鎭㈠");
      return;
    }

    // 鏇存柊鐘舵€乗n    this.setState({
      hasError: false,
      error: null,
      errorInfo: null,
      structuredError: null,
      retryCount: retryCount + 1,
      isRecovering: false,
    });

    // 璋冪敤閲嶇疆鍥炶皟
    onReset?.();
  };

  /**
   * 澶勭悊閲嶈瘯
   */
  private handleRetry = (): void => {
    this.setState({ isRecovering: true });

    // 浣跨敤 InteractionManager 纭繚鍦ㄤ氦浜掑畬鎴愬悗閲嶈瘯
    void InteractionManager.runAfterInteractions(() => {
      this.handleReset();
    });
  };

  /**
   * 澶勭悊鍒锋柊
   */
  private handleRefresh = (): void => {
    this.handleRetry();
  };

  /**
   * 澶勭悊杩斿洖
   */
  private handleGoBack = (): void => {
    // 杩欓噷闇€瑕佸鑸敮鎸侊紝鐢卞閮ㄦ彁渚沑n    this.handleReset();
  };

  /**
   * 澶勭悊杩斿洖棣栭〉
   */
  private handleGoHome = (): void => {
    // 杩欓噷闇€瑕佸鑸敮鎸侊紝鐢卞閮ㄦ彁渚沑n    this.handleReset();
  };

  /**
   * 澶勭悊閲嶆柊鐧诲綍
   */
  private handleReLogin = (): void => {
    // 杩欓噷闇€瑕佹竻闄よ璇佺姸鎬佸苟璺宠浆鐧诲綍椤礬n    this.handleReset();
  };

  /**
   * 鑾峰彇鎭㈠澶勭悊鍑芥暟
   */
  private getRecoveryHandler = (strategy: RecoveryStrategy): (() => void) => {
    switch (strategy) {
      case RecoveryStrategy.RETRY:
        return this.handleRetry;
      case RecoveryStrategy.REFRESH:
        return this.handleRefresh;
      case RecoveryStrategy.GO_BACK:
        return this.handleGoBack;
      case RecoveryStrategy.GO_HOME:
        return this.handleGoHome;
      case RecoveryStrategy.RE_LOGIN:
        return this.handleReLogin;
      case RecoveryStrategy.IGNORE:
        return this.handleReset;
      case RecoveryStrategy.MANUAL:
        return this.handleReset;
      default:
        return this.handleRetry;
    }
  };

  render(): ReactNode {
    const { hasError, error, errorInfo, structuredError, retryCount, isRecovering } = this.state;
    const { children, fallback, showDetails = __DEV__, maxRetries = 3 } = this.props;

    if (!hasError) {
      return children;
    }

    // 濡傛灉鎻愪緵浜嗚嚜瀹氫箟 fallback
    if (fallback) {
      if (typeof fallback === "function") {
        return fallback({
          error: error!,
          errorInfo: errorInfo!,
          structuredError: structuredError!,
          onRetry: this.handleRetry,
          onReset: this.handleReset,
          retryCount,
          maxRetries,
          isRecovering,
        });
      }
      return fallback;
    }

    // 浣跨敤榛樿閿欒灞曠ず缁勪欢
    return (
      <View style={styles.container}>
        <ErrorFallback
          error={error!}
          errorInfo={errorInfo!}
          structuredError={structuredError!}
          onRetry={this.handleRetry}
          onReset={this.handleReset}
          onRecovery={this.getRecoveryHandler(
            structuredError?.recoveryStrategy || RecoveryStrategy.RETRY
          )}
          showDetails={showDetails}
          retryCount={retryCount}
          maxRetries={maxRetries}
          isRecovering={isRecovering}
        />
      </View>
    );
  }
}

// ============================================================================
// 鏍峰紡
// ============================================================================

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
});

export default ErrorBoundary;

/**
 * 閿欒灞曠ず UI 缁勪欢
 *
 * 鎻愪緵涓板瘜鐨勯敊璇睍绀虹晫闈紝鏀寔澶氱閿欒绫诲瀷鍜屾仮澶嶆搷浣淺n */

import React from "react";
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
  ActivityIndicator,
} from "react-native";
import { Ionicons } from "../../polyfills/expo-vector-icons";
import { Colors, BorderRadius, Spacing, Typography } from "../../theme";
import {
  StructuredError,
  ErrorCategory,
  ErrorSeverity,
  RecoveryStrategy,
} from "../../utils/errorHandling";
import type { ErrorInfo } from "react";

// ============================================================================
// 绫诲瀷瀹氫箟
// ============================================================================

/**
 * 閿欒灞曠ず缁勪欢灞炴€n */
export interface ErrorFallbackProps {
  /** 鍘熷閿欒瀵硅薄 */
  error: Error;
  /** 閿欒淇℃伅 */
  errorInfo: ErrorInfo;
  /** 缁撴瀯鍖栭敊璇俊鎭?*/
  structuredError: StructuredError;
  /** 閲嶈瘯鍥炶皟 */
  onRetry?: () => void;
  /** 閲嶇疆鍥炶皟 */
  onReset?: () => void;
  /** 鎭㈠鍥炶皟 */
  onRecovery?: () => void;
  /** 鏄惁鏄剧ず璇︾粏閿欒淇℃伅 */
  showDetails?: boolean;
  /** 褰撳墠閲嶈瘯娆℃暟 */
  retryCount?: number;
  /** 鏈€澶ч噸璇曟鏁?*/
  maxRetries?: number;
  /** 鏄惁姝ｅ湪鎭㈠ */
  isRecovering?: boolean;
}

// ============================================================================
// 閿欒鍥炬爣缁勪欢
// ============================================================================

/**
 * 鏍规嵁閿欒绫诲瀷鑾峰彇鍥炬爣
 */
const getErrorIcon = (category: ErrorCategory): keyof typeof Ionicons.glyphMap => {
  switch (category) {
    case ErrorCategory.NETWORK:
      return "cloud-offline-outline";
    case ErrorCategory.PERMISSION:
      return "lock-closed-outline";
    case ErrorCategory.RESOURCE:
      return "search-outline";
    case ErrorCategory.STORAGE:
      return "save-outline";
    case ErrorCategory.RENDER:
      return "bug-outline";
    case ErrorCategory.BUSINESS:
      return "warning-outline";
    case ErrorCategory.THIRD_PARTY:
      return "cube-outline";
    default:
      return "alert-circle-outline";
  }
};

/**
 * 鏍规嵁閿欒涓ラ噸绾у埆鑾峰彇棰滆壊
 */
const getSeverityColor = (severity: ErrorSeverity): string => {
  switch (severity) {
    case ErrorSeverity.LOW:
      return Colors.warning[500];
    case ErrorSeverity.MEDIUM:
      return Colors.warning[600];
    case ErrorSeverity.HIGH:
      return Colors.error[500];
    case ErrorSeverity.CRITICAL:
      return Colors.error[600];
    default:
      return Colors.error[500];
  }
};

// ============================================================================
// 鎭㈠鎸夐挳缁勪欢
// ============================================================================

interface RecoveryButtonProps {
  strategy: RecoveryStrategy;
  onPress: () => void;
  disabled?: boolean;
  loading?: boolean;
}

const RecoveryButton: React.FC<RecoveryButtonProps> = ({
  strategy,
  onPress,
  disabled,
  loading,
}) => {
  const getButtonConfig = () => {
    switch (strategy) {
      case RecoveryStrategy.RETRY:
        return {
          icon: "refresh-outline" as const,
          label: "閲嶈瘯",
        };
      case RecoveryStrategy.REFRESH:
        return {
          icon: "refresh-outline" as const,
          label: "鍒锋柊椤甸潰",
        };
      case RecoveryStrategy.GO_BACK:
        return {
          icon: "arrow-back-outline" as const,
          label: "杩斿洖涓婁竴椤礬

home-outline" as const,
          label: "杩斿洖棣栭〉",
        };
      case RecoveryStrategy.RE_LOGIN:
        return {
          icon: "log-in-outline" as const,
          label: "閲嶆柊鐧诲綍",
        };
      case RecoveryStrategy.IGNORE:
        return {
          icon: "close-outline" as const,
          label: "蹇界暐",
        };
      case RecoveryStrategy.MANUAL:
        return {
          icon: "hand-left-outline" as const,
          label: "鎵嬪姩澶勭悊",
        };
      default:
        return {
          icon: "refresh-outline" as const,
          label: "閲嶈瘯",
        };
    }
  };

  const config = getButtonConfig();

  return (
    <TouchableOpacity
      style={[styles.button, disabled && styles.buttonDisabled]}
      onPress={onPress}
      disabled={disabled || loading}
      activeOpacity={0.7}
    >
      {loading ? (
        <ActivityIndicator size="small" color={Colors.neutral.white} />
      ) : (
        <>
          <Ionicons name={config.icon} size={20} color={Colors.neutral.white} />
          <Text style={styles.buttonText}>{config.label}</Text>
        </>
      )}
    </TouchableOpacity>
  );
};

// ============================================================================
// 閿欒灞曠ず缁勪欢
// ============================================================================

/**
 * 閿欒灞曠ず缁勪欢
 */
export const ErrorFallback: React.FC<ErrorFallbackProps> = ({
  error,
  errorInfo,
  structuredError,
  onRetry,
  onReset,
  onRecovery,
  showDetails = __DEV__,
  retryCount = 0,
  maxRetries = 3,
  isRecovering = false,
}) => {
  const severityColor = getSeverityColor(structuredError.severity);
  const iconName = getErrorIcon(structuredError.category);

  return (
    <View style={styles.container}>
      {/* 閿欒鍥炬爣 */}
      <View style={[styles.iconCircle, { backgroundColor: `${severityColor}15` }]}>
        <Ionicons name={iconName} size={48} color={severityColor} />
      </View>

      {/* 閿欒鏍囬 */}
      <Text style={styles.title}>鍑洪敊浜?/Text>

      {/* 鐢ㄦ埛鍙嬪ソ鐨勯敊璇秷鎭?*/}
      <Text style={styles.message}>{structuredError.userMessage}</Text>

      {/* 閿欒鍒嗙被鏍囩 */}
      <View style={styles.tagsContainer}>
        <View style={[styles.tag, { backgroundColor: `${severityColor}15` }]}>
          <Text style={[styles.tagText, { color: severityColor }]}>{structuredError.category}</Text>
        </View>
        <View style={[styles.tag, { backgroundColor: `${Colors.neutral[500]}15` }]}>
          <Text style={[styles.tagText, { color: Colors.neutral[600] }]}>
            {structuredError.severity}
          </Text>
        </View>
        {structuredError.code && (
          <View style={[styles.tag, { backgroundColor: `${Colors.primary[500]}15` }]}>
            <Text style={[styles.tagText, { color: Colors.primary[600] }]}>
              {structuredError.code}
            </Text>
          </View>
        )}
      </View>

      {/* 閲嶈瘯娆℃暟鎻愮ず */}
      {retryCount > 0 && (
        <Text style={styles.retryHint}>
          宸查噸璇?{retryCount}/{maxRetries} 娆n        </Text>
      )}

      {/* 寮€鍙戠幆澧冩樉绀鸿缁嗛敊璇俊鎭?*/}
      {showDetails && (
        <ScrollView style={styles.errorDetails} nestedScrollEnabled>
          <Text style={styles.errorTitle}>閿欒璇︽儏锛?/Text>
          <Text style={styles.errorText}>{error.message}</Text>

          {errorInfo.componentStack && (
            <>
              <Text style={styles.errorTitle}>缁勪欢鍫嗘爤锛?/Text>
              <Text style={styles.errorStack}>{errorInfo.componentStack}</Text>
            </>
          )}

          {structuredError.context && (
            <>
              <Text style={styles.errorTitle}>涓婁笅鏂囷細</Text>
              <Text style={styles.errorStack}>
                {JSON.stringify(structuredError.context, null, 2)}
              </Text>
            </>
          )}
        </ScrollView>
      )}

      {/* 鎿嶄綔鎸夐挳 */}
      <View style={styles.buttonsContainer}>
        {structuredError.recoverable && onRecovery && (
          <RecoveryButton
            strategy={structuredError.recoveryStrategy}
            onPress={onRecovery}
            disabled={retryCount >= maxRetries}
            loading={isRecovering}
          />
        )}

        {onReset && !structuredError.recoverable && (
          <TouchableOpacity
            style={[styles.button, styles.buttonSecondary]}
            onPress={onReset}
            activeOpacity={0.7}
          >
            <Ionicons name="refresh-outline" size={20} color={Colors.primary[500]} />
            <Text style={[styles.buttonText, styles.buttonTextSecondary]}>閲嶇疆</Text>
          </TouchableOpacity>
        )}
      </View>

      {/* 涓嶅彲鎭㈠鎻愮ず */}
      {!structuredError.recoverable && (
        <Text style={styles.unrecoverableHint}>姝ら敊璇棤娉曡嚜鍔ㄦ仮澶嶏紝璇疯仈绯诲鏈嶆垨閲嶅惎搴旂敤</Text>
      )}
    </View>
  );
};

// ============================================================================
// 鏍峰紡
// ============================================================================

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: "center",
    alignItems: "center",
    padding: Spacing[6],
    backgroundColor: Colors.neutral[50],
  },
  iconCircle: {
    width: 96,
    height: 96,
    borderRadius: 48,
    justifyContent: "center",
    alignItems: "center",
    marginBottom: Spacing[5],
  },
  title: {
    ...Typography.styles.h2,
    color: Colors.neutral[800],
    marginBottom: Spacing[2],
  },
  message: {
    ...Typography.body,
    color: Colors.neutral[500],
    textAlign: "center",
    lineHeight: 22,
    marginBottom: Spacing[4],
    maxWidth: 300,
  },
  tagsContainer: {
    flexDirection: "row",
    flexWrap: "wrap",
    gap: Spacing[2],
    marginBottom: Spacing[4],
  },
  tag: {
    paddingHorizontal: Spacing[3],
    paddingVertical: Spacing[1],
    borderRadius: BorderRadius.full,
  },
  tagText: {
    ...Typography.caption,
    fontWeight: "600",
  },
  retryHint: {
    ...Typography.caption,
    color: Colors.neutral[500],
    marginBottom: Spacing[4],
  },
  errorDetails: {
    maxHeight: 200,
    width: "100%",
    backgroundColor: Colors.neutral[100],
    borderRadius: BorderRadius.md,
    padding: Spacing[3],
    marginBottom: Spacing[5],
  },
  errorTitle: {
    ...Typography.caption,
    fontWeight: "600",
    color: Colors.neutral[700],
    marginTop: Spacing[2],
    marginBottom: Spacing[1],
  },
  errorText: {
    ...Typography.caption,
    color: Colors.error[600],
    fontFamily: "monospace",
  },
  errorStack: {
    ...Typography.caption,
    fontSize: 10,
    color: Colors.neutral[600],
    fontFamily: "monospace",
    lineHeight: 16,
  },
  buttonsContainer: {
    flexDirection: "row",
