import React, { useEffect, useRef, useState, useCallback } from "react";
import {
  View,
  Text,
  StyleSheet,
  Dimensions,
  TextInput,
  Pressable,
  ScrollView,
  Platform,
  ActivityIndicator,
  ActionSheetIOS,
} from "react-native";
import { LinearGradient } from "@/src/polyfills/expo-linear-gradient";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  withTiming,
  withDelay,
  interpolate,
  runOnJS,
} from "react-native-reanimated";
import AnimatedReanimated from "react-native-reanimated";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { DesignTokens } from "../../theme/tokens/design-tokens";
import { CompanionState } from "./AICompanionBall";
import {
  AiStylistAction,
  AiStylistActionType,
  AiStylistResolution,
} from "../../services/api/ai-stylist.api";
import { PreferenceSelector } from "./PreferenceSelector";
import { OutfitCard } from "./OutfitCard";
import { AnalysisProgress } from "./AnalysisProgress";

const { width: _SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get("window");
const AnimatedView = AnimatedReanimated.createAnimatedComponent(View);

export interface ChatMessage {
  id: string;
  role: "user" | "assistant";
  content: string;
  timestamp: Date;
  isLoading?: boolean;
  actionType?: AiStylistActionType;
  actionData?: AiStylistAction;
  outfitResult?: AiStylistResolution;
  progress?: AiStylistProgress;
}

export interface AiStylistProgress {
  stage: string;
  title: string;
  detail: string;
  etaSeconds?: number;
  canLeaveAndResume: boolean;
  isWaiting: boolean;
}

export interface AICompanionChatProps {
  visible: boolean;
  messages: ChatMessage[];
  state: CompanionState;
  onSendMessage: (message: string) => void;
  onClose: () => void;
  title?: string;
  placeholder?: string;
  currentAction?: AiStylistAction | null;
  onUploadPhoto?: (source?: "camera" | "library") => void;
  onSelectPreference?: (field: string, values: string[]) => void;
  onGenerateOutfit?: () => void;
  onStartVoice?: () => void;
  onStopVoice?: () => void;
  isVoiceAvailable?: boolean;
}

export const AICompanionChat: React.FC<AICompanionChatProps> = ({
  visible,
  messages,
  state,
  onSendMessage,
  onClose,
  title = "AI 閫犲瀷甯圽

杈撳叆浣犵殑闂...",
  currentAction,
  onUploadPhoto,
  onSelectPreference,
  onGenerateOutfit,
  onStartVoice,
  onStopVoice,
  isVoiceAvailable = false,
}) => {
  const insets = useSafeAreaInsets();
  const scrollViewRef = useRef<ScrollView>(null);
  const [inputText, setInputText] = useState("");
  const [showPhotoOptions, setShowPhotoOptions] = useState(false);

  const panelTranslateY = useSharedValue(SCREEN_HEIGHT);
  const panelOpacity = useSharedValue(0);
  const headerOpacity = useSharedValue(0);
  const inputOpacity = useSharedValue(0);

  useEffect(() => {
    if (visible) {
      panelOpacity.value = withTiming(1, { duration: 200 });
      panelTranslateY.value = withSpring(0, { damping: 20, stiffness: 100 });
      headerOpacity.value = withDelay(100, withTiming(1, { duration: 200 }));
      inputOpacity.value = withDelay(200, withTiming(1, { duration: 200 }));
    } else {
      panelOpacity.value = withTiming(0, { duration: 150 });
      panelTranslateY.value = withTiming(SCREEN_HEIGHT, { duration: 200 });
      headerOpacity.value = withTiming(0, { duration: 100 });
      inputOpacity.value = withTiming(0, { duration: 100 });
    }
  }, [visible]);

  useEffect(() => {
    if (messages.length > 0) {
      setTimeout(() => {
        scrollViewRef.current?.scrollToEnd({ animated: true });
      }, 100);
    }
  }, [messages]);

  const panelStyle = useAnimatedStyle(() => ({
    opacity: panelOpacity.value,
    transform: [{ translateY: panelTranslateY.value }],
  }));

  const headerStyle = useAnimatedStyle(() => ({
    opacity: headerOpacity.value,
  }));

  const inputStyle = useAnimatedStyle(() => ({
    opacity: inputOpacity.value,
  }));

  const handleSend = useCallback(() => {
    if (inputText.trim()) {
      onSendMessage(inputText.trim());
      setInputText("");
    }
  }, [inputText, onSendMessage]);

  const handlePhotoPress = useCallback(() => {
    if (Platform.OS === "ios") {
      ActionSheetIOS.showActionSheetWithOptions(
        {
          options: ["鍙栨秷", "鎷嶇収", "浠庣浉鍐岄€夋嫨"],
          cancelButtonIndex: 0,
        },
        (buttonIndex) => {
          if (buttonIndex === 1) {
            onUploadPhoto?.("camera");
          } else if (buttonIndex === 2) {
            onUploadPhoto?.("library");
          }
        }
      );
    } else {
      setShowPhotoOptions(true);
    }
  }, [onUploadPhoto]);

  const handleVoicePress = useCallback(() => {
    if (state === "listening") {
      onStopVoice?.();
    } else {
      onStartVoice?.();
    }
  }, [state, onStartVoice, onStopVoice]);

  const getStateIndicator = () => {
    switch (state) {
      case "listening":
        return (
          <View style={styles.stateIndicator}>
            <View style={[styles.stateDot, { backgroundColor: "#7B8FA2" }]} />
            <Text style={styles.stateText}>姝ｅ湪鑱嗗惉...</Text>
          </View>
        );
      case "thinking":
        return (
          <View style={styles.stateIndicator}>
            <ActivityIndicator size="small" color="#D9A441" />
            <Text style={styles.stateText}>鎬濊€冧腑...</Text>
          </View>
        );
      case "responding":
        return (
          <View style={styles.stateIndicator}>
            <View style={[styles.stateDot, { backgroundColor: "#5B8A72" }]} />
            <Text style={styles.stateText}>鍥炲涓?..</Text>
          </View>
        );
      default:
        return null;
    }
  };

  const renderMessageContent = (message: ChatMessage) => {
    if (message.isLoading) {
      return (
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="small" color={DesignTokens.colors.brand.sage} />
          <Text style={styles.loadingText}>AI 姝ｅ湪鎬濊€?..</Text>
        </View>
      );
    }

    if (message.progress?.isWaiting) {
      return <AnalysisProgress progress={message.progress} />;
    }

    if (message.outfitResult) {
      return (
        <View>
          <Text style={[styles.messageText, styles.assistantMessageText]}>{message.content}</Text>
          <OutfitCard result={message.outfitResult} />
        </View>
      );
    }

    return (
      <Text
        style={[
          styles.messageText,
          message.role === "user" ? styles.userMessageText : styles.assistantMessageText,
        ]}
      >
        {message.content}
      </Text>
    );
  };

  const renderActionUI = () => {
    if (!currentAction) {
      return null;
    }

    switch (currentAction.type) {
      case "show_preference_buttons":
        return (
          <PreferenceSelector action={currentAction} onSelect={onSelectPreference || (() => {})} />
        );

      case "request_photo_upload":
        return (
          <View style={styles.photoPrompt}>
            <Text style={styles.photoPromptText}>璇蜂笂浼犱竴寮犵収鐗?/Text>
            <View style={styles.photoButtons}>
              <Pressable style={styles.photoButton} onPress={() => onUploadPhoto?.("camera")}>
                <LinearGradient
                  colors={[DesignTokens.colors.brand.sage, DesignTokens.colors.brand.camel]}
                  style={styles.photoButtonGradient}
                >
                  <Ionicons name="camera" size={24} color="#FFFFFF" />
                  <Text style={styles.photoButtonText}>鎷嶇収</Text>
                </LinearGradient>
              </Pressable>
              <Pressable style={styles.photoButton} onPress={() => onUploadPhoto?.("library")}>
                <LinearGradient colors={["#7B8FA2", "#96A6B5"]} style={styles.photoButtonGradient}>
                  <Ionicons name="images" size={24} color="#FFFFFF" />
                  <Text style={styles.photoButtonText}>鐩稿唽</Text>
                </LinearGradient>
              </Pressable>
            </View>
            {currentAction.canSkip && (
              <Pressable style={styles.skipPhotoButton}>
                <Text style={styles.skipPhotoText}>鏆傛椂璺宠繃</Text>
              </Pressable>
            )}
          </View>
        );

      case "generate_outfit":
        return (
          <View style={styles.generatePrompt}>
            <Text style={styles.generatePromptText}>
              鎴戝凡缁忎簡瑙ｄ綘鐨勯渶姹備簡锛屾槸鍚︾幇鍦ㄧ敓鎴愮┛鎼柟妗堬紵
            </Text>
            <Pressable style={styles.generateButton} onPress={onGenerateOutfit}>
              <LinearGradient
                colors={[DesignTokens.colors.brand.terracotta, DesignTokens.colors.brand.camel]}
                style={styles.generateButtonGradient}
              >
                <Ionicons name="sparkles" size={18} color="#FFFFFF" />
                <Text style={styles.generateButtonText}>鐢熸垚绌挎惌鏂规</Text>
              </LinearGradient>
            </Pressable>
          </View>
        );

      default:
        return null;
    }
  };

  const lastMessage = messages[messages.length - 1];
  const showActionUI =
    lastMessage?.role === "assistant" &&
    lastMessage.actionType &&
    !lastMessage.isLoading &&
    !lastMessage.outfitResult;

  return (
    <AnimatedView style={[styles.container, panelStyle]}>
      <LinearGradient colors={["#FFFFFF", "#FAFAF8"]} style={styles.gradient}>
        <AnimatedView style={[styles.header, headerStyle]}>
          <View style={styles.headerLeft}>
            <Pressable onPress={onClose} style={styles.closeButton}>
              <Ionicons name="close" size={20} color={DesignTokens.colors.neutral[600]} />
            </Pressable>
          </View>
          <View style={styles.headerCenter}>
            <Text style={styles.title}>{title}</Text>
            {getStateIndicator()}
          </View>
          <View style={styles.headerRight} />
        </AnimatedView>

        <ScrollView
          ref={scrollViewRef}
          style={styles.messagesContainer}
          contentContainerStyle={styles.messagesContent}
          showsVerticalScrollIndicator={false}
        >
          {messages.length === 0 && (
            <View style={styles.emptyState}>
              <LinearGradient
                colors={[DesignTokens.colors.brand.sage, DesignTokens.colors.brand.camel]}
                style={styles.emptyIcon}
              >
                <Text style={styles.emptyIconText}>AI</Text>
              </LinearGradient>
              <Text style={styles.emptyTitle}>浣犲ソ锛佹垜鏄?AI 閫犲瀷甯?/Text>
              <Text style={styles.emptySubtitle}>鎴戝彲浠ュ府浣犲垎鏋愯韩鏉愩€佹帹鑽愮┛鎼€佽В绛旀椂灏氶棶棰?/Text>
              <View style={styles.suggestions}>
                <Pressable
                  style={styles.suggestionChip}
                  onPress={() => onSendMessage("浠婂ぉ绌夸粈涔堬紵")}
                >
                  <Text style={styles.suggestionText}>浠婂ぉ绌夸粈涔堬紵</Text>
                </Pressable>
                <Pressable
                  style={styles.suggestionChip}
                  onPress={() => onSendMessage("甯垜鍒嗘瀽韬潗")}
                >
                  <Text style={styles.suggestionText}>甯垜鍒嗘瀽韬潗</Text>
                </Pressable>
                <Pressable
                  style={styles.suggestionChip}
                  onPress={() => onSendMessage("绾︿細绌挎惌寤鸿")}
                >
                  <Text style={styles.suggestionText}>绾︿細绌挎惌寤鸿</Text>
                </Pressable>
              </View>
            </View>
          )}

          {messages.map((message) => (
            <View
              key={message.id}
              style={[
                styles.messageWrapper,
                message.role === "user"
                  ? styles.userMessageWrapper
                  : styles.assistantMessageWrapper,
              ]}
            >
              {message.role === "assistant" &&
                !message.isLoading &&
                !message.progress &&
                !message.outfitResult && (
                  <LinearGradient
                    colors={[DesignTokens.colors.brand.sage, DesignTokens.colors.brand.camel]}
                    style={styles.assistantAvatar}
                  >
                    <Text style={styles.assistantAvatarText}>AI</Text>
                  </LinearGradient>
                )}
              <View
                style={[
                  styles.messageBubble,
                  message.role === "user" ? styles.userBubble : styles.assistantBubble,
                  (message.isLoading || message.progress || message.outfitResult) &&
                    styles.wideBubble,
                ]}
              >
                {renderMessageContent(message)}
              </View>
            </View>
          ))}

          {showActionUI && renderActionUI()}
        </ScrollView>

        <AnimatedView
          style={[styles.inputContainer, inputStyle, { paddingBottom: insets.bottom + 16 }]}
        >
          <View style={styles.inputWrapper}>
            {onUploadPhoto && (
              <Pressable style={styles.attachButton} onPress={handlePhotoPress}>
                <Ionicons
                  name="camera-outline"
                  size={22}
                  color={DesignTokens.colors.neutral[500]}
                />
              </Pressable>
            )}

            <TextInput
              style={styles.textInput}
              value={inputText}
              onChangeText={setInputText}
              placeholder={placeholder}
              placeholderTextColor={DesignTokens.colors.neutral[400]}
              multiline
              maxLength={500}
              editable={state !== "thinking"}
            />

            {isVoiceAvailable && onStartVoice && (
              <Pressable
                style={[styles.voiceButton, state === "listening" && styles.voiceButtonActive]}
                onPress={handleVoicePress}
              >
                <Ionicons
                  name={state === "listening" ? "mic" : "mic-outline"}
                  size={22}
                  color={
                    state === "listening"
                      ? DesignTokens.colors.brand.terracotta
                      : DesignTokens.colors.neutral[500]
                  }
                />
              </Pressable>
            )}

            <Pressable
              style={[styles.sendButton, !inputText.trim() && styles.sendButtonDisabled]}
              onPress={handleSend}
              disabled={!inputText.trim() || state === "thinking"}
            >
              <LinearGradient
                colors={
                  inputText.trim() && state !== "thinking"
                    ? [DesignTokens.colors.brand.terracotta, DesignTokens.colors.brand.camel]
                    : [DesignTokens.colors.neutral[300], DesignTokens.colors.neutral[400]]
                }
                style={styles.sendButtonGradient}
              >
                <Ionicons name="send" size={18} color="#FFFFFF" />
              </LinearGradient>
            </Pressable>
          </View>
        </AnimatedView>
      </LinearGradient>

      {showPhotoOptions && Platform.OS === "android" && (
        <View style={styles.photoOptionsOverlay}>
          <Pressable
            style={styles.photoOptionsBackdrop}
            onPress={() => setShowPhotoOptions(false)}
          />
          <View style={styles.photoOptionsSheet}>
            <Pressable
              style={styles.photoOptionItem}
              onPress={() => {
                setShowPhotoOptions(false);
                onUploadPhoto?.("camera");
              }}
            >
              <Ionicons name="camera" size={24} color={DesignTokens.colors.neutral[700]} />
              <Text style={styles.photoOptionText}>鎷嶇収</Text>
            </Pressable>
            <Pressable
              style={styles.photoOptionItem}
              onPress={() => {
                setShowPhotoOptions(false);
                onUploadPhoto?.("library");
              }}
            >
              <Ionicons name="images" size={24} color={DesignTokens.colors.neutral[700]} />
              <Text style={styles.photoOptionText}>浠庣浉鍐岄€夋嫨</Text>
            </Pressable>
            <Pressable
              style={[styles.photoOptionItem, styles.photoOptionCancel]}
              onPress={() => setShowPhotoOptions(false)}
            >
              <Text style={styles.photoOptionCancelText}>鍙栨秷</Text>
            </Pressable>
          </View>
        </View>
      )}
    </AnimatedView>
  );
};

const styles = StyleSheet.create({
  container: {
    position: "absolute",
    top: 0,
