export interface QuickAction {
  id: string;
  icon: string;
  label: string;
  description?: string;
  onPress: () => void;
  gradient?: [string, string];
}

interface ActionItemProps {
  action: QuickAction;
  index: number;
  visible: boolean;
  onPress: (action: QuickAction) => void;
}

const ActionItemComponent: React.FC<ActionItemProps> = ({ action, index, visible, onPress }) => {
  const opacity = useSharedValue(0);
  const scale = useSharedValue(0.8);

  useEffect(() => {
    if (visible) {
      opacity.value = withDelay(100 + index * 50, withTiming(1, { duration: 200 }));
      scale.value = withDelay(100 + index * 50, withSpring(1, { damping: 12, stiffness: 200 }));
    } else {
      opacity.value = withTiming(0, { duration: 100 });
      scale.value = withTiming(0.8, { duration: 100 });
    }
  }, [visible]);

  const actionStyle = useAnimatedStyle(() => ({
    opacity: opacity.value,
    transform: [{ scale: scale.value }],
  }));

  const renderIcon = () => {
    const iconColor = "#FFFFFF";
    switch (action.id) {
      case "stylist":
        return <Icons.stylist color={iconColor} />;
      case "photo":
        return <Icons.photo color={iconColor} />;
      case "recommend":
        return <Icons.recommend color={iconColor} />;
      case "wardrobe":
        return <Icons.wardrobe color={iconColor} />;
      default:
        return <Text style={styles.actionIconText}>{action.icon}</Text>;
    }
  };

  return (
    <AnimatedView style={actionStyle}>
      <Pressable style={styles.actionItem} onPress={() => onPress(action)}>
        <LinearGradient
          colors={
            action.gradient || [
              DesignTokens.colors.brand.terracotta,
              DesignTokens.colors.brand.camel,
            ]
          }
          style={styles.actionIcon}
        >
          {renderIcon()}
        </LinearGradient>
        <View style={styles.actionContent}>
          <Text style={styles.actionLabel}>{action.label}</Text>
          {action.description && <Text style={styles.actionDescription}>{action.description}</Text>}
        </View>
        <Text style={styles.actionArrow}>鈫?/Text>
      </Pressable>
    </AnimatedView>
  );
};

export interface AICompanionMenuProps {
  visible: boolean;
  position: { x: number; y: number };
  ballSize: number;
  onClose: () => void;
  actions?: QuickAction[];
}

const DEFAULT_ACTIONS: QuickAction[] = [
  {
    id: "stylist",
    icon: "stylist",
    label: "AI 閫犲瀷甯圽

#7B8FA2", "#96A6B5"],
    onPress: () => {},
  },
  {
    id: "recommend",
    icon: "recommend",
    label: "鏅鸿兘鎺ㄨ崘",
    description: "涓€у寲鎺ㄨ崘",
    gradient: ["#5B8A72", "#7BA896"],
    onPress: () => {},
  },
  {
    id: "wardrobe",
    icon: "wardrobe",
    label: "鎴戠殑琛ｆ┍",
    description: "绠＄悊浣犵殑琛ｇ墿",
    gradient: ["#D9A441", "#E8B86D"],
    onPress: () => {},
  },
];

export const AICompanionMenu: React.FC<AICompanionMenuProps> = ({
  visible,
  position,
  ballSize,
  onClose,
  actions = DEFAULT_ACTIONS,
}) => {
  const insets = useSafeAreaInsets();

  const backdropOpacity = useSharedValue(0);
  const menuScale = useSharedValue(0);
  const menuOpacity = useSharedValue(0);

  useEffect(() => {
    if (visible) {
      backdropOpacity.value = withTiming(0.3, { duration: 200 });
      menuOpacity.value = withTiming(1, { duration: 200 });
      menuScale.value = withSpring(1, { damping: 15, stiffness: 150 });
    } else {
      backdropOpacity.value = withTiming(0, { duration: 150 });
      menuOpacity.value = withTiming(0, { duration: 150 });
      menuScale.value = withTiming(0.8, { duration: 150 });
    }
  }, [visible]);

  const backdropStyle = useAnimatedStyle(() => ({
    opacity: backdropOpacity.value,
  }));

  const menuStyle = useAnimatedStyle(() => ({
    opacity: menuOpacity.value,
    transform: [{ scale: menuScale.value }],
  }));

  const handleActionPress = useCallback(
    (action: QuickAction) => {
      onClose();
      action.onPress();
    },
    [onClose]
  );

  if (!visible) {
    return null;
  }

  const isLeftSide = position.x < SCREEN_WIDTH / 2;
  const menuWidth = SCREEN_WIDTH - 40;
  const menuHeight = Math.min(400, actions.length * 80 + 60);

  let menuTop = position.y - menuHeight / 2;
  menuTop = Math.max(
    insets.top + 20,
    Math.min(SCREEN_HEIGHT - insets.bottom - menuHeight - 100, menuTop)
  );

  const menuLeft = isLeftSide ? position.x + ballSize + 16 : position.x - menuWidth - 16;

  return (
    <>
      <AnimatedPressable style={[styles.backdrop, backdropStyle]} onPress={onClose} />

      <AnimatedView
        style={[
          styles.menuContainer,
          {
            top: menuTop,
            left: menuLeft,
            width: menuWidth,
          },
          menuStyle,
        ]}
      >
        <LinearGradient colors={["#FFFFFF", "#FAFAF8"]} style={styles.menuGradient}>
          <View style={styles.menuHeader}>
            <Text style={styles.menuTitle}>AI 鍔╂墜</Text>
            <Text style={styles.menuSubtitle}>閫夋嫨浣犻渶瑕佺殑鏈嶅姟</Text>
          </View>

          <ScrollView showsVerticalScrollIndicator={false} style={styles.actionsList}>
            {actions.map((action, index) => (
              <ActionItemComponent
                key={action.id}
                action={action}
                index={index}
                visible={visible}
                onPress={handleActionPress}
              />
            ))}
          </ScrollView>

          <View style={styles.menuFooter}>
            <Pressable style={styles.closeButton} onPress={onClose}>
              <Text style={styles.closeButtonText}>鍏抽棴</Text>
            </Pressable>
          </View>
        </LinearGradient>
      </AnimatedView>
    </>
  );
};

const styles = StyleSheet.create({
  backdrop: {
    ...StyleSheet.absoluteFillObject,
    backgroundColor: "#000",
    zIndex: 9998,
  },
  menuContainer: {
    position: "absolute",
    borderRadius: 20,
    shadowColor: "#000",
    shadowOffset: { width: 0, height: 10 },
    shadowOpacity: 0.15,
    shadowRadius: 30,
    elevation: 10,
    zIndex: 9999,
    overflow: "hidden",
  },
  menuGradient: {
    flex: 1,
    padding: 16,
  },
  menuHeader: {
    marginBottom: 16,
    paddingBottom: 12,
    borderBottomWidth: 1,
    borderBottomColor: DesignTokens.colors.neutral[200],
  },
  menuTitle: {
    fontSize: 20,
    fontWeight: "700",
    color: DesignTokens.colors.neutral[900],
    marginBottom: 4,
  },
  menuSubtitle: {
    fontSize: 14,
    color: DesignTokens.colors.neutral[500],
  },
  actionsList: {
    flex: 1,
  },
  actionItem: {
    flexDirection: "row",
    alignItems: "center",
    paddingVertical: 12,
    paddingHorizontal: 12,
    borderRadius: 12,
    backgroundColor: DesignTokens.colors.neutral[50],
    marginBottom: 8,
  },
  actionIcon: {
    width: 48,
    height: 48,
    borderRadius: 12,
    alignItems: "center",
    justifyContent: "center",
  },
  actionIconText: {
    fontSize: 24,
  },
  actionContent: {
    flex: 1,
    marginLeft: 12,
  },
  actionLabel: {
    fontSize: 16,
    fontWeight: "600",
    color: DesignTokens.colors.neutral[900],
    marginBottom: 2,
  },
  actionDescription: {
    fontSize: 13,
    color: DesignTokens.colors.neutral[500],
  },
  actionArrow: {
