import React, { createContext, useContext, useState, useCallback, useRef, useEffect } from "react";
import { AppState, AppStateStatus } from "react-native";
import AsyncStorage from "@react-native-async-storage/async-storage";
import * as ImagePicker from "expo-image-picker";
import { navigateTab } from "../../navigation/navigationService";
import { AICompanionBall, CompanionState } from "./AICompanionBall";
import { AICompanionMenu, QuickAction } from "./AICompanionMenu";
import { AICompanionChat, ChatMessage } from "./AICompanionChat";
import {
  aiStylistApi,
  AiStylistSessionResponse,
  AiStylistAction,
  AiStylistActionType,
  AiStylistSessionState,
  AiStylistSlots,
  AiStylistResolution,
  AiStylistProgress,
  AiStylistOutfitPlan,
} from "../../services/api/ai-stylist.api";
import {
  useSpeechRecognition,
  SpeechRecognitionResult,
} from "../../services/speech/speechRecognition";

const POSITION_STORAGE_KEY = "@xuno_companion_position";
const SESSION_STORAGE_KEY = "@xuno_stylist_session";

export interface ExtendedChatMessage extends ChatMessage {
  actionType?: AiStylistActionType;
  actionData?: AiStylistAction;
  outfitResult?: AiStylistResolution;
  progress?: AiStylistProgress;
}

interface AICompanionContextValue {
  isVisible: boolean;
  state: CompanionState;
  messages: ExtendedChatMessage[];
  sessionState: AiStylistSessionState | null;
  slots: AiStylistSlots | null;
  showCompanion: () => void;
  hideCompanion: () => void;
  setState: (state: CompanionState) => void;
  sendMessage: (content: string) => Promise<void>;
  openChat: () => void;
  closeChat: () => void;
  showMenu: () => void;
  hideMenu: () => void;
  startVoiceInput: () => void;
  stopVoiceInput: () => void;
  isVoiceAvailable: boolean;
  uploadPhoto: (source?: "camera" | "library") => Promise<void>;
  selectPreference: (field: string, values: string[]) => Promise<void>;
  generateOutfit: () => Promise<void>;
  resetSession: () => void;
}

const AICompanionContext = createContext<AICompanionContextValue | undefined>(undefined);

export const useAICompanion = () => {
  const context = useContext(AICompanionContext);
  if (!context) {
    throw new Error("useAICompanion must be used within AICompanionProvider");
  }
  return context;
};

export interface AICompanionProviderProps {
  children: React.ReactNode;
  actions?: QuickAction[];
  enableChat?: boolean;
  autoShowHint?: boolean;
  enableVoiceInput?: boolean;
  onVoiceResult?: (text: string) => void;
  currentRouteName?: string;
}

const POLL_INTERVAL = 3000;
const MAX_POLL_ATTEMPTS = 60;

export const AICompanionProvider: React.FC<AICompanionProviderProps> = ({
  children,
  actions,
  enableChat = true,
  autoShowHint = true,
  enableVoiceInput = true,
  onVoiceResult,
  currentRouteName,
}) => {
  const [isVisible, setIsVisible] = useState(true);
  const [state, setState] = useState<CompanionState>("idle");
  const [position, setPosition] = useState<{ x: number; y: number } | undefined>();
  const [menuVisible, setMenuVisible] = useState(false);
  const [chatVisible, setChatVisible] = useState(false);
  const [messages, setMessages] = useState<ExtendedChatMessage[]>([]);
  const [sessionId, setSessionId] = useState<string | null>(null);
  const [showHint, setShowHint] = useState(autoShowHint);
  const [_isVoiceMode, setIsVoiceMode] = useState(false);
  const [sessionState, setSessionState] = useState<AiStylistSessionState | null>(null);
  const [slots, setSlots] = useState<AiStylistSlots | null>(null);
  const [currentAction, setCurrentAction] = useState<AiStylistAction | null>(null);
  const [_outfitResult, setOutfitResult] = useState<AiStylistResolution | null>(null);
  const suppressedRoutes = new Set(["VirtualTryOn", "Checkout", "AiStylist"]);
  const shouldSuspendFloatingUI =
    currentRouteName !== undefined && suppressedRoutes.has(currentRouteName);

  const appStateRef = useRef<AppStateStatus>(AppState.currentState);
  const hintTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const pollIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const pollAttemptsRef = useRef<number>(0);

  const {
    status: _voiceStatus,
    result: _voiceResult,
    isAvailable: isVoiceAvailable,
    startListening,
    stopListening,
    cancel: _cancelVoice,
    requestPermissions: requestVoicePermissions,
  } = useSpeechRecognition({
    language: "zh-CN",
    timeout: 30000,
    onResult: (result: SpeechRecognitionResult) => {
      setIsVoiceMode(false);
      setState("thinking");

      if (onVoiceResult) {
        onVoiceResult(result.text);
      }

      if (enableChat && result.text) {
        void sendMessage(result.text);
      }
    },
    onError: (error) => {
      console.error("Voice recognition error:", error);
      setIsVoiceMode(false);
      setState("idle");
    },
    onStatusChange: (status) => {
      if (status === "listening") {
        setState("listening");
        setIsVoiceMode(true);
      } else if (status === "processing") {
        setState("thinking");
      }
    },
  });

  useEffect(() => {
    void loadPosition();
    void loadSession();

    const subscription = AppState.addEventListener("change", handleAppStateChange);

    return () => {
      subscription.remove();
      if (hintTimeoutRef.current) {
        clearTimeout(hintTimeoutRef.current);
      }
      if (pollIntervalRef.current) {
        clearInterval(pollIntervalRef.current);
      }
    };
  }, []);

  useEffect(() => {
    if (autoShowHint && state === "idle" && !chatVisible && !menuVisible) {
      hintTimeoutRef.current = setTimeout(() => {
        setShowHint(true);
      }, 3000);
    } else {
      setShowHint(false);
    }

    return () => {
      if (hintTimeoutRef.current) {
        clearTimeout(hintTimeoutRef.current);
      }
    };
  }, [state, chatVisible, menuVisible, autoShowHint]);

  useEffect(() => {
    if (shouldSuspendFloatingUI) {
      setShowHint(false);
      setMenuVisible(false);
      setChatVisible(false);
      if (state !== "idle") {
        setState("idle");
      }
    }
  }, [shouldSuspendFloatingUI, state]);

  const loadPosition = async () => {
    try {
      const savedPosition = await AsyncStorage.getItem(POSITION_STORAGE_KEY);
      if (savedPosition) {
        setPosition(JSON.parse(savedPosition));
      }
    } catch (error) {
      console.warn("Failed to load companion position:", error);
    }
  };

  const savePosition = async (x: number, y: number) => {
    try {
      await AsyncStorage.setItem(POSITION_STORAGE_KEY, JSON.stringify({ x, y }));
    } catch (error) {
      console.warn("Failed to save companion position:", error);
    }
  };

  const loadSession = async () => {
    try {
      const savedSession = await AsyncStorage.getItem(SESSION_STORAGE_KEY);
      if (savedSession) {
        const { sessionId: savedId, expiresAt } = JSON.parse(savedSession);
        if (new Date(expiresAt) > new Date()) {
          setSessionId(savedId);
          const response = await aiStylistApi.getSessionStatus(savedId);
          if (response.data?.sessionState) {
            setSessionState(response.data.sessionState);
            setSlots(response.data.sessionState.slots);
          }
        }
      }
    } catch (error) {
      console.warn("Failed to load session:", error);
    }
  };

  const saveSession = async (id: string, expiresAt?: string) => {
    try {
      await AsyncStorage.setItem(
        SESSION_STORAGE_KEY,
        JSON.stringify({
          sessionId: id,
          expiresAt: expiresAt || new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
        })
      );
    } catch (error) {
      console.warn("Failed to save session:", error);
    }
  };

  const clearSession = async () => {
    try {
      await AsyncStorage.removeItem(SESSION_STORAGE_KEY);
    } catch (error) {
      console.warn("Failed to clear session:", error);
    }
  };

  const handleAppStateChange = (nextAppState: AppStateStatus) => {
    if (appStateRef.current.match(/inactive|background/) && nextAppState === "active") {
      setShowHint(autoShowHint);
    }
    appStateRef.current = nextAppState;
  };

  const handleBallPress = useCallback(() => {
    setShowHint(false);
    if (enableChat) {
      setChatVisible(true);
    } else {
      setMenuVisible(true);
    }
  }, [enableChat]);

  const handleBallLongPress = useCallback(() => {
    setShowHint(false);
    setMenuVisible(true);
  }, []);

  const handleDragEnd = useCallback((x: number, y: number) => {
    setPosition({ x, y });
    void savePosition(x, y);
  }, []);

  const showCompanion = useCallback(() => {
    setIsVisible(true);
  }, []);

  const hideCompanion = useCallback(() => {
    setIsVisible(false);
    setMenuVisible(false);
    setChatVisible(false);
  }, []);

  const openChat = useCallback(() => {
    setShowHint(false);
    setChatVisible(true);
  }, []);

  const closeChat = useCallback(() => {
    setChatVisible(false);
    setState("idle");
  }, []);

  const showMenu = useCallback(() => {
    setShowHint(false);
    setMenuVisible(true);
  }, []);

  const hideMenu = useCallback(() => {
    setMenuVisible(false);
  }, []);

  const processResponse = useCallback((response: AiStylistSessionResponse) => {
    if (response.sessionState) {
      setSessionState(response.sessionState);
      setSlots(response.sessionState.slots);
    }

    if (response.nextAction) {
      setCurrentAction(response.nextAction);
    }

    if (response.result) {
      setOutfitResult(response.result);
    }

    if (response.progress) {
      startPollingIfNeeded(response.progress);
    }

    return response;
  }, []);

  const _buildAssistantMessage = useCallback(
    (response: AiStylistSessionResponse): ExtendedChatMessage => ({
      id: `assistant-${Date.now()}`,
      role: "assistant",
      content: response.assistantMessage || response.message || "濂界殑锛屾垜鏉ュ府浣犲垎鏋愩€俓

source:
Polling error:", error);
          }
        }, POLL_INTERVAL);
      }
    },
    [sessionId, processResponse]
  );

  const sendMessage = useCallback(
    async (content: string) => {
      const userMessage: ExtendedChatMessage = {
        id: `user-${Date.now()}`,
        role: "user",
        content,
        timestamp: new Date(),
      };

      setMessages((prev) => [...prev, userMessage]);
      setState("thinking");

      const loadingMessage: ExtendedChatMessage = {
        id: `loading-${Date.now()}`,
        role: "assistant",
        content: "",
        timestamp: new Date(),
        isLoading: true,
      };

      setMessages((prev) => [...prev, loadingMessage]);

      try {
        let currentSessionId = sessionId;
        let responseData: AiStylistSessionResponse | undefined;

        if (!currentSessionId) {
          const createResponse = await aiStylistApi.createSession({
            entry: content,
            goal: "global_ai_companion",
            context: {
              source: "ai_companion_ball",
              channel: "overlay_chat",
            },
          });

          if (!createResponse.success || !createResponse.data) {
            throw new Error(createResponse.error?.message || "Failed to create session");
          }

          responseData = createResponse.data;

          if (responseData.sessionId) {
            currentSessionId = responseData.sessionId;
            setSessionId(currentSessionId);
            void saveSession(currentSessionId, responseData.sessionExpiresAt);
          } else {
            throw new Error("Failed to create session");
          }
        } else {
          const response = await aiStylistApi.sendMessage(currentSessionId, content);
          if (!response.success || !response.data) {
            throw new Error(response.error?.message || "Failed to send message");
          }
          responseData = response.data;
        }

        processResponse(responseData);
        const response = { data: responseData! };

        const assistantMessage: ExtendedChatMessage = {
          id: `assistant-${Date.now()}`,
          role: "assistant",
          content:
            response.data?.assistantMessage || response.data?.message || "濂界殑锛屾垜鏉ュ府浣犲垎鏋愩€俓

responding");

        setTimeout(() => {
          setState("idle");
        }, 1000);
      } catch (error) {
        console.log("AI companion sendMessage failed:", error);

        const errorMessage: ExtendedChatMessage = {
          id: `error-${Date.now()}`,
          role: "assistant",
          content: "鎶辨瓑锛屾垜閬囧埌浜嗕竴浜涢棶棰橈紝璇风◢鍚庡啀璇曘€俓

idle");
      }
    },
    [sessionId, processResponse]
  );

  const uploadPhoto = useCallback(
    async (source: "camera" | "library" = "library") => {
      if (!sessionId) {
        const userMessage: ExtendedChatMessage = {
          id: `user-${Date.now()}`,
          role: "user",
          content: "鎴戞兂涓婁紶鐓х墖杩涜鍒嗘瀽",
          timestamp: new Date(),
        };
        setMessages((prev) => [...prev, userMessage]);

        try {
          const createResponse = await aiStylistApi.createSession();
          if (createResponse.data?.sessionId) {
            const newSessionId = createResponse.data.sessionId;
            setSessionId(newSessionId);
            void saveSession(newSessionId);
          }
        } catch (error) {
          console.error("Failed to create session for photo upload:", error);
          return;
        }
      }

      try {
        let result: ImagePicker.ImagePickerResult;

        if (source === "camera") {
          const { status } = await ImagePicker.requestCameraPermissionsAsync();
          if (status !== "granted") {
            const errorMessage: ExtendedChatMessage = {
              id: `error-${Date.now()}`,
              role: "assistant",
              content: "闇€瑕佺浉鏈烘潈闄愭墠鑳芥媿鐓

granted") {
            const errorMessage: ExtendedChatMessage = {
              id: `error-${Date.now()}`,
              role: "assistant",
              content: "闇€瑕佺浉鍐屾潈闄愭墠鑳介€夋嫨鐓х墖",
              timestamp: new Date(),
            };
            setMessages((prev) => [...prev, errorMessage]);
            return;
          }
          result = await ImagePicker.launchImageLibraryAsync({
            mediaTypes: ImagePicker.MediaTypeOptions.Images,
            allowsEditing: true,
            aspect: [3, 4],
            quality: 0.8,
          });
        }

        if (!result.canceled && result.assets && result.assets[0]) {
          const asset = result.assets[0];

          const userMessage: ExtendedChatMessage = {
            id: `user-${Date.now()}`,
            role: "user",
            content: "馃摲 [宸蹭笂浼犵収鐗嘳",
            timestamp: new Date(),
          };
          setMessages((prev) => [...prev, userMessage]);

          setState("thinking");

          const photoType = currentAction?.photoType || "full_body";
          const response = await aiStylistApi.uploadPhoto(sessionId!, asset.uri, photoType);
          if (response.data) {
            processResponse(response.data);
          }

          const assistantMessage: ExtendedChatMessage = {
            id: `assistant-${Date.now()}`,
            role: "assistant",
            content: response.data?.assistantMessage || "鐓х墖宸蹭笂浼狅紝姝ｅ湪鍒嗘瀽涓?..",
            timestamp: new Date(),
            progress: response.data?.progress,
          };

          setMessages((prev) => [...prev, assistantMessage]);

          if (response.data?.progress?.isWaiting) {
            startPollingIfNeeded(response.data.progress);
          }
        }
      } catch (error) {
        console.error("Failed to upload photo:", error);
        const errorMessage: ExtendedChatMessage = {
          id: `error-${Date.now()}`,
          role: "assistant",
          content: "鐓х墖涓婁紶澶辫触锛岃閲嶈瘯",
          timestamp: new Date(),
        };
        setMessages((prev) => [...prev, errorMessage]);
        setState("idle");
      }
    },
    [sessionId, currentAction, processResponse, startPollingIfNeeded]
  );

  const selectPreference = useCallback(
    async (field: string, values: string[]) => {
      if (!sessionId) {
        return;
      }

      const userMessage: ExtendedChatMessage = {
        id: `user-${Date.now()}`,
        role: "user",
        content: `閫夋嫨浜? ${values.join(", ")}`,
        timestamp: new Date(),
      };
      setMessages((prev) => [...prev, userMessage]);

      setState("thinking");

      try {
        const messageContent = `${field}: ${values.join(", ")}`;
        const response = await aiStylistApi.sendMessage(sessionId, messageContent);
        if (response.data) {
          processResponse(response.data);
        }

        const assistantMessage: ExtendedChatMessage = {
          id: `assistant-${Date.now()}`,
          role: "assistant",
          content: response.data?.assistantMessage || "濂界殑锛屽凡璁板綍浣犵殑鍋忓ソ銆俓

responding");

        setTimeout(() => {
          setState("idle");
        }, 1000);
      } catch (error) {
        console.error("Failed to select preference:", error);
        setState("idle");
      }
    },
    [sessionId, processResponse]
  );

  const generateOutfit = useCallback(async () => {
    if (!sessionId) {
      return;
    }

    setState("thinking");

    const loadingMessage: ExtendedChatMessage = {
      id: `loading-${Date.now()}`,
      role: "assistant",
      content: "",
      timestamp: new Date(),
      isLoading: true,
    };
    setMessages((prev) => [...prev, loadingMessage]);

    try {
      const response = await aiStylistApi.resolveSession(sessionId);
      if (response.data) {
        processResponse(response.data);
      }

      const assistantMessage: ExtendedChatMessage = {
        id: `assistant-${Date.now()}`,
        role: "assistant",
        content: response.data?.assistantMessage || "杩欐槸涓轰綘鍑嗗鐨勭┛鎼柟妗堬紒",
        timestamp: new Date(),
        outfitResult: response.data?.result,
        actionType: "show_outfit_cards",
      };

      setMessages((prev) => prev.filter((m) => !m.isLoading).concat(assistantMessage));
      setState("responding");

      setTimeout(() => {
        setState("idle");
      }, 1000);
    } catch (error) {
      console.error("Failed to generate outfit:", error);
      const errorMessage: ExtendedChatMessage = {
        id: `error-${Date.now()}`,
        role: "assistant",
        content: "鐢熸垚绌挎惌鏂规澶辫触锛岃閲嶈瘯",
        timestamp: new Date(),
      };
      setMessages((prev) => prev.filter((m) => !m.isLoading).concat(errorMessage));
      setState("idle");
    }
  }, [sessionId, processResponse]);

  const resetSession = useCallback(async () => {
    setSessionId(null);
    setSessionState(null);
    setSlots(null);
    setCurrentAction(null);
    setOutfitResult(null);
    setMessages([]);
    await clearSession();
  }, []);

  const defaultActions: QuickAction[] = [
    {
      id: "stylist",
      icon: "stylist",
      label: "AI 閫犲瀷甯圽

鑾峰彇绌挎惌寤鸿",
      onPress: () => {
        setMenuVisible(false);
        setChatVisible(true);
      },
    },
    {
      id: "photo",
      icon: "photo",
      label: "鎷嶇収鍒嗘瀽",
      description: "鍒嗘瀽韬潗鍜岃偆鑹瞈

Profile", "Wardrobe");
      },
    },
    {
      id: "recommend",
      icon: "recommend",
      label: "鏅鸿兘鎺ㄨ崘",
      description: "涓€у寲鎺ㄨ崘",
      onPress: () => {
        setMenuVisible(false);
        navigateTab("Home", "RecommendationDetail");
      },
    },
    {
      id: "wardrobe",
      icon: "wardrobe",
      label: "鎴戠殑琛ｆ┍",
      description: "绠＄悊浣犵殑琛ｇ墿",
      onPress: () => {
        setMenuVisible(false);
        navigateTab("Profile", "Wardrobe");
      },
    },
  ];

  const startVoiceInput = useCallback(async () => {
    if (!enableVoiceInput || !isVoiceAvailable) {
      console.warn("Voice input is not available");
      return;
    }

    try {
      const hasPermission = await requestVoicePermissions();
      if (!hasPermission) {
        console.warn("Voice permission denied");
        return;
      }

      setShowHint(false);
      await startListening();
    } catch (error) {
      console.error("Failed to start voice input:", error);
    }
  }, [enableVoiceInput, isVoiceAvailable, requestVoicePermissions, startListening]);

  const stopVoiceInput = useCallback(() => {
    void stopListening();
    setIsVoiceMode(false);
  }, [stopListening]);

  const contextValue: AICompanionContextValue = {
    isVisible,
    state,
    messages,
    sessionState,
    slots,
    showCompanion,
    hideCompanion,
    setState,
    sendMessage,
    openChat,
    closeChat,
    showMenu,
    hideMenu,
    startVoiceInput,
    stopVoiceInput,
    isVoiceAvailable: enableVoiceInput && isVoiceAvailable,
    uploadPhoto,
    selectPreference,
    generateOutfit,
    resetSession,
  };

  return (
    <AICompanionContext.Provider value={contextValue}>
      {children}

      {isVisible && !shouldSuspendFloatingUI && (
        <>
          <AICompanionBall
            state={state}
            onPress={handleBallPress}
            onLongPress={handleBallLongPress}
            onDragEnd={handleDragEnd}
            position={position}
            showHint={showHint}
          />

          <AICompanionMenu
            visible={menuVisible}
            position={position || { x: 0, y: 0 }}
            ballSize={64}
            onClose={hideMenu}
            actions={actions || defaultActions}
          />

          {enableChat && (
            <AICompanionChat
              visible={chatVisible}
              messages={messages}
              state={state}
              onSendMessage={sendMessage}
              onClose={closeChat}
              currentAction={currentAction}
              onUploadPhoto={uploadPhoto}
              onSelectPreference={selectPreference}
              onGenerateOutfit={generateOutfit}
              onStartVoice={startVoiceInput}
              onStopVoice={stopVoiceInput}
              isVoiceAvailable={enableVoiceInput && isVoiceAvailable}
            />
          )}
        </>
      )}
    </AICompanionContext.Provider>
  );
};

