import React, { useEffect } from "react";
import { View, Text, StyleSheet } from "react-native";
import { LinearGradient } from "@/src/polyfills/expo-linear-gradient";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import {
  useSharedValue,
  useAnimatedStyle,
  withRepeat,
  withTiming,
  withSequence,
  withDelay,
  interpolate,
  Easing as ReanimatedEasing,
} from "react-native-reanimated";
import AnimatedReanimated from "react-native-reanimated";
import { DesignTokens } from "../../theme/tokens/design-tokens";
import { AiStylistProgress } from "../../services/api/ai-stylist.api";

const AnimatedView = AnimatedReanimated.createAnimatedComponent(View);

export interface AnalysisProgressProps {
  progress: AiStylistProgress;
}

const PROGRESS_STAGES = [
  { key: "uploading", label: "涓婁紶涓璡

checkmark-circle-outline" },
];

interface AnimatedDotProps {
  dotValue: ReturnType<typeof useSharedValue<number>>;
}

const AnimatedDot: React.FC<AnimatedDotProps> = ({ dotValue }) => {
  const style = useAnimatedStyle(() => ({
    opacity: dotValue.value,
    transform: [{ scale: interpolate(dotValue.value, [0, 1], [1, 1.3]) }],
  }));
  return <AnimatedView style={[styles.dot, style]} />;
};

export const AnalysisProgress: React.FC<AnalysisProgressProps> = ({ progress }) => {
  const pulseValue = useSharedValue(0);
  const dotValues = [useSharedValue(0), useSharedValue(0), useSharedValue(0)];
  const progressValue = useSharedValue(0);

  useEffect(() => {
    pulseValue.value = withRepeat(
      withSequence(
        withTiming(1, {
          duration: 1000,
          easing: ReanimatedEasing.inOut(ReanimatedEasing.ease),
        }),
        withTiming(0, {
          duration: 1000,
          easing: ReanimatedEasing.inOut(ReanimatedEasing.ease),
        })
      ),
      -1,
      true
    );

    dotValues.forEach((dot, index) => {
      dot.value = withDelay(
        index * 200,
        withRepeat(
          withSequence(withTiming(1, { duration: 400 }), withTiming(0, { duration: 400 })),
          -1,
          true
        )
      );
    });

    const etaMatch = progress.etaSeconds ? Math.max(0, 1 - progress.etaSeconds / 60) : 0.5;
    progressValue.value = withTiming(etaMatch, { duration: 500 });
  }, [progress.etaSeconds]);

  const pulseStyle = useAnimatedStyle(() => ({
    opacity: interpolate(pulseValue.value, [0, 1], [0.3, 0.8]),
    transform: [{ scale: interpolate(pulseValue.value, [0, 1], [1, 1.1]) }],
  }));

  const progressStyle = useAnimatedStyle(() => ({
    width: `${progressValue.value * 100}%`,
  }));

  const formatEta = (seconds?: number) => {
    if (!seconds) {
      return null;
    }
    if (seconds < 60) {
      return `绾?${seconds} 绉抈;
    }
    const minutes = Math.ceil(seconds / 60);
    return `绾?${minutes} 鍒嗛挓`;
  };

  const getCurrentStageIndex = () => {
    const stageMap: Record<string, number> = {
      uploading: 0,
      analyzing: 1,
      processing: 2,
      finalizing: 3,
    };
    return stageMap[progress.stage] ?? 1;
  };

  const currentStageIndex = getCurrentStageIndex();

  return (
    <View style={styles.container}>
      <View style={styles.iconContainer}>
        <AnimatedView style={[styles.iconGlow, pulseStyle]}>
          <LinearGradient
            colors={[DesignTokens.colors.brand.sage, DesignTokens.colors.brand.camel]}
            style={styles.iconGradient}
          >
            <Ionicons name="analytics" size={28} color="#FFFFFF" />
          </LinearGradient>
        </AnimatedView>
      </View>

      <View style={styles.content}>
        <Text style={styles.title}>{progress.title}</Text>
        <Text style={styles.detail}>{progress.detail}</Text>

        <View style={styles.progressContainer}>
          <View style={styles.progressTrack}>
            <AnimatedView style={[styles.progressFill, progressStyle]} />
          </View>
          {progress.etaSeconds && (
            <Text style={styles.etaText}>{formatEta(progress.etaSeconds)}</Text>
          )}
        </View>

        <View style={styles.stagesContainer}>
          {PROGRESS_STAGES.map((stage, index) => {
            const isActive = index === currentStageIndex;
            const isCompleted = index < currentStageIndex;

            return (
              <View key={stage.key} style={styles.stageItem}>
                <View
                  style={[
                    styles.stageDot,
                    isActive && styles.stageDotActive,
                    isCompleted && styles.stageDotCompleted,
                  ]}
                >
                  {isCompleted ? (
                    <Ionicons name="checkmark" size={12} color="#FFFFFF" />
                  ) : (
                    <Ionicons
                      name={stage.icon}
                      size={12}
                      color={
                        isActive ? DesignTokens.colors.brand.sage : DesignTokens.colors.neutral[400]
                      }
                    />
                  )}
                </View>
                <Text
                  style={[
                    styles.stageLabel,
                    isActive && styles.stageLabelActive,
                    isCompleted && styles.stageLabelCompleted,
                  ]}
                >
                  {stage.label}
                </Text>
                {index < PROGRESS_STAGES.length - 1 && (
                  <View style={[styles.stageLine, isCompleted && styles.stageLineCompleted]} />
                )}
              </View>
            );
          })}
        </View>

        {progress.canLeaveAndResume && (
          <View style={styles.hintContainer}>
            <Ionicons
              name="information-circle-outline"
              size={16}
              color={DesignTokens.colors.neutral[500]}
            />
            <Text style={styles.hintText}>浣犲彲浠ョ寮€锛岀◢鍚庡洖鏉ユ煡鐪嬬粨鏋?/Text>
          </View>
        )}

        <View style={styles.loadingDots}>
          {dotValues.map((dotValue, index) => (
            <AnimatedDot key={index} dotValue={dotValue} />
          ))}
        </View>
      </View>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    backgroundColor: DesignTokens.colors.neutral[50],
    borderRadius: 16,
    padding: 16,
    marginVertical: 8,
    borderWidth: 1,
    borderColor: DesignTokens.colors.neutral[200],
    flexDirection: "row",
  },
  iconContainer: {
    marginRight: 16,
  },
  iconGlow: {
    width: 56,
    height: 56,
    borderRadius: 28,
    alignItems: "center",
    justifyContent: "center",
  },
  iconGradient: {
    width: 56,
    height: 56,
    borderRadius: 28,
    alignItems: "center",
    justifyContent: "center",
  },
  content: {
    flex: 1,
  },
  title: {
    fontSize: 16,
    fontWeight: "600",
    color: DesignTokens.colors.neutral[900],
    marginBottom: 4,
  },
  detail: {
    fontSize: 13,
    color: DesignTokens.colors.neutral[500],
    marginBottom: 12,
    lineHeight: 18,
  },
  progressContainer: {
    marginBottom: 16,
  },
  progressTrack: {
    height: 6,
    backgroundColor: DesignTokens.colors.neutral[200],
    borderRadius: 3,
    overflow: "hidden",
  },
  progressFill: {
    height: "100%",
    backgroundColor: DesignTokens.colors.brand.sage,
    borderRadius: 3,
  },
  etaText: {
    fontSize: 12,
    color: DesignTokens.colors.neutral[500],
    marginTop: 6,
    textAlign: "right",
  },
  stagesContainer: {
    flexDirection: "row",
    justifyContent: "space-between",
    marginBottom: 16,
  },
  stageItem: {
    alignItems: "center",
    flex: 1,
  },
  stageDot: {
    width: 24,
    height: 24,
    borderRadius: 12,
    backgroundColor: DesignTokens.colors.neutral[200],
    alignItems: "center",
    justifyContent: "center",
    marginBottom: 4,
  },
  stageDotActive: {
    backgroundColor: DesignTokens.colors.brand.sage + "30",
    borderWidth: 2,
    borderColor: DesignTokens.colors.brand.sage,
  },
  stageDotCompleted: {
    backgroundColor: DesignTokens.colors.brand.sage,
  },
  stageLabel: {
    fontSize: 10,
    color: DesignTokens.colors.neutral[400],
    textAlign: "center",
  },
  stageLabelActive: {
    color: DesignTokens.colors.brand.sage,
    fontWeight: "600",
  },
  stageLabelCompleted: {
    color: DesignTokens.colors.brand.sage,
  },
  stageLine: {
    position: "absolute",
    top: 12,
    left: "60%",
    right: "-40%",
    height: 2,
    backgroundColor: DesignTokens.colors.neutral[200],
    zIndex: -1,
  },
  stageLineCompleted: {
    backgroundColor: DesignTokens.colors.brand.sage,
  },
  hintContainer: {
    flexDirection: "row",
    alignItems: "center",
    backgroundColor: DesignTokens.colors.neutral[100],
    paddingHorizontal: 12,
    paddingVertical: 8,
    borderRadius: 8,
    marginBottom: 12,
  },
  hintText: {
    fontSize: 12,
    color: DesignTokens.colors.neutral[500],
    marginLeft: 6,
  },
  loadingDots: {
    flexDirection: "row",
    justifyContent: "center",
    gap: 6,
  },
  dot: {
    width: 8,
    height: 8,
    borderRadius: 4,
    backgroundColor: DesignTokens.colors.brand.sage,
  },
});

import React, { useEffect, useCallback, useState } from "react";
import { View, Text, StyleSheet, Dimensions, Platform, StatusBar } from "react-native";
import { LinearGradient } from "@/src/polyfills/expo-linear-gradient";
import {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  withTiming,
  withRepeat,
  withSequence,
  withDelay,
  interpolate,
  Easing,
  runOnJS,
  cancelAnimation,
  useDerivedValue,
} from "react-native-reanimated";
import AnimatedReanimated from "react-native-reanimated";
import { Gesture, GestureDetector } from "react-native-gesture-handler";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { DesignTokens } from "../../theme/tokens/design-tokens";

const { width: SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get("window");
const AnimatedView = AnimatedReanimated.createAnimatedComponent(View);
const AnimatedLinearGradient = AnimatedReanimated.createAnimatedComponent(LinearGradient);

export type CompanionState = "idle" | "listening" | "thinking" | "responding" | "collapsed";

export interface EnhancedAICompanionBallProps {
  state?: CompanionState;
  onPress?: () => void;
  onLongPress?: () => void;
  onDragEnd?: (x: number, y: number) => void;
  position?: { x: number; y: number };
  size?: number;
  showHint?: boolean;
  hintMessage?: string;
  enableVoiceInput?: boolean;
  onVoiceStart?: () => void;
  onVoiceEnd?: () => void;
  onVoiceResult?: (text: string) => void;
  enableParticleEffect?: boolean;
  enableColorFlow?: boolean;
}

const STATE_CONFIG = {
  idle: {
    gradient: [DesignTokens.colors.brand.sage, DesignTokens.colors.brand.camel] as [string, string],
    gradientFlow: [
      DesignTokens.colors.brand.sage,
      DesignTokens.colors.brand.camel,
      DesignTokens.colors.brand.terracottaLight,
      DesignTokens.colors.brand.sage,
    ] as [string, string, string, string],
    innerGradient: ["rgba(255,255,255,0.3)", "rgba(255,255,255,0.05)"] as [string, string],
    glowColor: DesignTokens.colors.brand.sage,
    particleColor: DesignTokens.colors.brand.sage,
    animation: "breathe",
  },
  listening: {
    gradient: ["#7B8FA2", "#96A6B5"] as [string, string],
    gradientFlow: ["#7B8FA2", "#96A6B5", "#B8C5D1", "#7B8FA2"] as [string, string, string, string],
    innerGradient: ["rgba(255,255,255,0.35)", "rgba(255,255,255,0.08)"] as [string, string],
    glowColor: "#7B8FA2",
    particleColor: "#96A6B5",
    animation: "pulse",
  },
  thinking: {
    gradient: ["#D9A441", "#E8B86D"] as [string, string],
    gradientFlow: ["#D9A441", "#E8B86D", "#F5D89A", "#D9A441"] as [string, string, string, string],
    innerGradient: ["rgba(255,255,255,0.4)", "rgba(255,255,255,0.1)"] as [string, string],
    glowColor: "#D9A441",
    particleColor: "#E8B86D",
    animation: "pulse",
  },
  responding: {
    gradient: ["#5B8A72", "#7BA896"] as [string, string],
    gradientFlow: ["#5B8A72", "#7BA896", "#9DC4B5", "#5B8A72"] as [string, string, string, string],
    innerGradient: ["rgba(255,255,255,0.32)", "rgba(255,255,255,0.06)"] as [string, string],
    glowColor: "#5B8A72",
    particleColor: "#7BA896",
    animation: "glow",
  },
  collapsed: {
    gradient: [DesignTokens.colors.brand.terracotta, DesignTokens.colors.brand.camel] as [
      string,
      string
    ],
    gradientFlow: [
      DesignTokens.colors.brand.terracotta,
      DesignTokens.colors.brand.camel,
      DesignTokens.colors.brand.terracottaLight,
      DesignTokens.colors.brand.terracotta,
    ] as [string, string, string, string],
    innerGradient: ["rgba(255,255,255,0.25)", "rgba(255,255,255,0.03)"] as [string, string],
    glowColor: DesignTokens.colors.brand.terracotta,
    particleColor: DesignTokens.colors.brand.camel,
    animation: "none",
  },
};

interface ParticleProps {
  index: number;
  color: string;
  ballSize: number;
  isActive: boolean;
}

const Particle: React.FC<ParticleProps> = ({ index, color, ballSize, isActive }) => {
  const angle = useSharedValue(index * 72 * (Math.PI / 180));
  const radius = useSharedValue(ballSize * 0.6);
  const opacity = useSharedValue(0);
  const scale = useSharedValue(0.5);
  const floatOffset = useSharedValue(0);

  useEffect(() => {
    if (isActive) {
      angle.value = withRepeat(
        withTiming(angle.value + Math.PI * 2, {
          duration: 8000 + index * 1000,
          easing: Easing.linear,
        }),
        -1,
        false
      );

      radius.value = withRepeat(
        withSequence(
          withTiming(ballSize * 0.8, {
            duration: 2000 + index * 500,
            easing: Easing.inOut(Easing.ease),
          }),
          withTiming(ballSize * 0.5, {
            duration: 2000 + index * 500,
            easing: Easing.inOut(Easing.ease),
          })
        ),
        -1,
        true
      );

      opacity.value = withRepeat(
        withSequence(
          withTiming(0.8, {
            duration: 1500 + index * 300,
            easing: Easing.ease,
          }),
          withTiming(0.3, {
            duration: 1500 + index * 300,
            easing: Easing.ease,
          })
        ),
        -1,
        true
      );

      scale.value = withRepeat(
        withSequence(
          withTiming(1, { duration: 1800 + index * 400, easing: Easing.ease }),
          withTiming(0.6, {
            duration: 1800 + index * 400,
            easing: Easing.ease,
          })
        ),
        -1,
        true
      );

      floatOffset.value = withRepeat(
        withSequence(
          withTiming(5, {
            duration: 1000 + index * 200,
            easing: Easing.inOut(Easing.ease),
          }),
          withTiming(-5, {
            duration: 1000 + index * 200,
            easing: Easing.inOut(Easing.ease),
          })
        ),
        -1,
        true
      );
    } else {
      cancelAnimation(angle);
      cancelAnimation(radius);
      cancelAnimation(opacity);
      cancelAnimation(scale);
      cancelAnimation(floatOffset);
      opacity.value = withTiming(0, { duration: 300 });
    }
  }, [isActive, ballSize, index]);

  const animatedStyle = useAnimatedStyle(() => {
    const x = Math.cos(angle.value) * radius.value;
    const y = Math.sin(angle.value) * radius.value;

    return {
      transform: [{ translateX: x }, { translateY: y + floatOffset.value }, { scale: scale.value }],
      opacity: opacity.value,
    };
  });

  return (
    <AnimatedView
      style={[
        styles.particle,
        {
          width: 6,
          height: 6,
          borderRadius: 3,
          backgroundColor: color,
        },
        animatedStyle,
      ]}
    />
  );
};

export const EnhancedAICompanionBall: React.FC<EnhancedAICompanionBallProps> = ({
  state = "idle",
  onPress,
  onLongPress,
  onDragEnd,
  position,
  size = 64,
  showHint = false,
  hintMessage = "鏈変粈涔堝彲浠ュ府浣犵殑锛焅

idle") {
      breatheValue.value = withRepeat(
        withSequence(
          withTiming(1, { duration: 2000, easing: Easing.inOut(Easing.ease) }),
          withTiming(0, { duration: 2000, easing: Easing.inOut(Easing.ease) })
        ),
        -1,
        true
      );
      pulseValue.value = 0;
      glowValue.value = 0;
      innerGlowValue.value = withRepeat(
        withSequence(
          withTiming(1, { duration: 3000, easing: Easing.inOut(Easing.ease) }),
          withTiming(0, { duration: 3000, easing: Easing.inOut(Easing.ease) })
        ),
        -1,
        true
      );

      if (enableColorFlow) {
        colorFlowAngle.value = withRepeat(
          withTiming(360, { duration: 12000, easing: Easing.linear }),
          -1,
          false
        );
      }

      shimmerValue.value = withRepeat(
        withSequence(
          withTiming(1, { duration: 2500, easing: Easing.inOut(Easing.ease) }),
          withTiming(0, { duration: 2500, easing: Easing.inOut(Easing.ease) })
        ),
        -1,
        true
      );
    } else if (state === "listening" || state === "thinking") {
      cancelAnimation(breatheValue);
      cancelAnimation(innerGlowValue);
      pulseValue.value = withRepeat(
        withSequence(
          withTiming(1, { duration: 600, easing: Easing.inOut(Easing.ease) }),
          withTiming(0.7, { duration: 600, easing: Easing.inOut(Easing.ease) })
        ),
        -1,
        true
      );
      innerGlowValue.value = withRepeat(
        withSequence(
          withTiming(1, { duration: 400, easing: Easing.inOut(Easing.ease) }),
          withTiming(0.5, { duration: 400, easing: Easing.inOut(Easing.ease) })
        ),
        -1,
        true
      );

      if (enableColorFlow) {
        colorFlowAngle.value = withRepeat(
          withTiming(360, { duration: 6000, easing: Easing.linear }),
          -1,
          false
        );
      }

      shimmerValue.value = withRepeat(
        withSequence(
          withTiming(1, { duration: 800, easing: Easing.inOut(Easing.ease) }),
          withTiming(0, { duration: 800, easing: Easing.inOut(Easing.ease) })
        ),
        -1,
        true
      );
    } else if (state === "responding") {
      cancelAnimation(breatheValue);
      cancelAnimation(pulseValue);
      cancelAnimation(innerGlowValue);
      glowValue.value = withRepeat(
        withSequence(withTiming(1, { duration: 800 }), withTiming(0.5, { duration: 800 })),
        -1,
        true
      );
      innerGlowValue.value = 0.8;

      if (enableColorFlow) {
        colorFlowAngle.value = withRepeat(
          withTiming(360, { duration: 8000, easing: Easing.linear }),
          -1,
          false
        );
      }

      shimmerValue.value = withRepeat(
        withSequence(
          withTiming(1, { duration: 1000, easing: Easing.inOut(Easing.ease) }),
          withTiming(0.3, {
            duration: 1000,
            easing: Easing.inOut(Easing.ease),
          })
        ),
        -1,
        true
      );
    } else {
      cancelAnimation(breatheValue);
      cancelAnimation(pulseValue);
      cancelAnimation(glowValue);
      cancelAnimation(innerGlowValue);
      cancelAnimation(colorFlowAngle);
      cancelAnimation(shimmerValue);
    }
  }, [state, enableColorFlow]);

  useEffect(() => {
    if (showHint && state === "idle") {
      hintOpacity.value = withDelay(500, withTiming(1, { duration: 300 }));
      hintTranslateX.value = withDelay(500, withSpring(0, { damping: 15, stiffness: 150 }));
    } else {
      hintOpacity.value = withTiming(0, { duration: 200 });
      hintTranslateX.value = withTiming(20, { duration: 200 });
    }
  }, [showHint, state]);

  const triggerRipple = useCallback(() => {
    rippleValue.value = 0;
    setRippleKey((prev) => prev + 1);
    rippleValue.value = withSequence(
      withTiming(1, { duration: 600, easing: Easing.out(Easing.ease) }),
      withTiming(0, { duration: 0 })
    );
  }, []);

  const panGesture = Gesture.Pan()
    .onStart(() => {
      runOnJS(setIsDragging)(true);
      scale.value = withSpring(1.1, { damping: 15, stiffness: 200 });
    })
    .onUpdate((event) => {
      translateX.value = event.translationX + (position?.x ?? defaultX);
      translateY.value = event.translationY + (position?.y ?? defaultY);
    })
    .onEnd((event) => {
      runOnJS(setIsDragging)(false);
      scale.value = withSpring(1, { damping: 15, stiffness: 200 });

      let finalX = event.translationX + (position?.x ?? defaultX);
      let finalY = event.translationY + (position?.y ?? defaultY);

      const margin = 16;
      const minX = margin;
      const maxX = SCREEN_WIDTH - size - margin;
      const minY = (Platform.OS === "ios" ? insets.top : StatusBar.currentHeight || 24) + margin;
      const maxY = SCREEN_HEIGHT - insets.bottom - size - 80;

      finalX = Math.max(minX, Math.min(maxX, finalX));
      finalY = Math.max(minY, Math.min(maxY, finalY));

      const leftDistance = finalX - minX;
      const rightDistance = maxX - finalX;

      if (leftDistance < rightDistance) {
        finalX = minX;
      } else {
        finalX = maxX;
      }

      translateX.value = withSpring(finalX, { damping: 15, stiffness: 150 });
      translateY.value = withSpring(finalY, { damping: 15, stiffness: 150 });

      if (onDragEnd) {
        runOnJS(onDragEnd)(finalX, finalY);
      }
    });

  const tapGesture = Gesture.Tap().onEnd(() => {
    if (!isDragging && onPress) {
      scale.value = withSequence(
        withSpring(0.9, { damping: 15, stiffness: 300 }),
        withSpring(1, { damping: 15, stiffness: 150 })
      );
      runOnJS(triggerRipple)();
      runOnJS(onPress)();
    }
  });

  const longPressGesture = Gesture.LongPress()
    .minDuration(500)
    .onStart(() => {
      if (onLongPress) {
        scale.value = withSpring(1.2, { damping: 15, stiffness: 150 });
        runOnJS(onLongPress)();
      }
    })
    .onEnd(() => {
      scale.value = withSpring(1, { damping: 15, stiffness: 150 });
    });

  const composedGesture = Gesture.Race(panGesture, longPressGesture, tapGesture);

  const ballAnimatedStyle = useAnimatedStyle(() => {
    let animatedScale = scale.value;

    if (state === "idle") {
      animatedScale *= interpolate(breatheValue.value, [0, 1], [1, 1.05]);
    } else if (state === "listening" || state === "thinking") {
      animatedScale *= interpolate(pulseValue.value, [0, 1], [0.95, 1.1]);
    }

    const glowOpacity =
      glowValue.value > 0
        ? interpolate(glowValue.value, [0, 1], [0.2, 0.6])
        : interpolate(breatheValue.value, [0, 1], [0.15, 0.4]);

    return {
      transform: [
        { translateX: translateX.value },
        { translateY: translateY.value },
        { scale: animatedScale },
      ],
      shadowColor: config.glowColor,
      shadowOffset: { width: 0, height: 0 },
      shadowOpacity: glowOpacity,
      shadowRadius: interpolate(breatheValue.value, [0, 1], [20, 40]),
      elevation: 8,
    };
  });

  const hintAnimatedStyle = useAnimatedStyle(() => ({
    opacity: hintOpacity.value,
    transform: [{ translateX: hintTranslateX.value }],
  }));

  const innerGlowAnimatedStyle = useAnimatedStyle(() => ({
    opacity: interpolate(innerGlowValue.value, [0, 1], [0.4, 0.9]),
    transform: [{ scale: interpolate(innerGlowValue.value, [0, 1], [0.82, 0.96]) }],
  }));

  const shimmerAnimatedStyle = useAnimatedStyle(() => ({
    opacity: shimmerValue.value * 0.5,
    transform: [{ translateX: interpolate(shimmerValue.value, [0, 1], [-size, size]) }],
  }));

  const rippleAnimatedStyle = useAnimatedStyle(() => ({
    opacity: interpolate(rippleValue.value, [0, 1], [0.6, 0]),
    transform: [{ scale: interpolate(rippleValue.value, [0, 1], [0.8, 1.5]) }],
  }));

  const _gradientAngle = useDerivedValue(() => {
    return colorFlowAngle.value;
  });

  return (
    <GestureDetector gesture={composedGesture}>
      <AnimatedView style={[styles.container, ballAnimatedStyle]}>
        {showHint && state === "idle" && (
          <AnimatedView style={[styles.hintContainer, { right: size + 12 }, hintAnimatedStyle]}>
            <View style={styles.hintBubble}>
              <Text style={styles.hintText}>{hintMessage}</Text>
            </View>
            <View style={[styles.hintArrow, { right: -6 }]} />
          </AnimatedView>
        )}

        <View style={[styles.ballContainer, { width: size, height: size }]}>
          {enableParticleEffect && state !== "collapsed" && (
            <View style={[styles.particleContainer, { width: size, height: size }]}>
              {Array.from({ length: particleCount }).map((_, index) => (
                <Particle
                  key={index}
                  index={index}
                  color={config.particleColor}
                  ballSize={size}
                  isActive={true}
                />
              ))}
            </View>
          )}

          <LinearGradient
            colors={enableColorFlow ? config.gradientFlow : config.gradient}
            start={{ x: 0, y: 0 }}
            end={{ x: 1, y: 1 }}
            style={[styles.ball, { width: size, height: size, borderRadius: size / 2 }]}
          >
            <AnimatedView style={[styles.innerGlow, innerGlowAnimatedStyle]}>
              <LinearGradient
                colors={config.innerGradient}
                start={{ x: 0.2, y: 0.2 }}
                end={{ x: 0.9, y: 0.9 }}
                style={[styles.innerGlowGradient, { borderRadius: size / 2 - 6 }]}
              />
            </AnimatedView>

            <View style={styles.highlight} />

            <AnimatedView style={[styles.shimmer, shimmerAnimatedStyle]}>
              <View style={[styles.shimmerLine, { height: size }]} />
            </AnimatedView>
          </LinearGradient>

          <AnimatedView
            key={rippleKey}
            style={[
              styles.ripple,
              {
                width: size,
                height: size,
                borderRadius: size / 2,
                borderColor: config.glowColor,
              },
              rippleAnimatedStyle,
            ]}
          />
        </View>
      </AnimatedView>
    </GestureDetector>
  );
};

const styles = StyleSheet.create({
  container: {
    position: "absolute",
    zIndex: 9999,
  },
  ballContainer: {
    position: "relative",
    alignItems: "center",
    justifyContent: "center",
  },
  particleContainer: {
    position: "absolute",
    alignItems: "center",
    justifyContent: "center",
    zIndex: -1,
  },
  particle: {
    position: "absolute",
    shadowColor: "#fff",
    shadowOffset: { width: 0, height: 0 },
    shadowOpacity: 0.5,
    shadowRadius: 4,
  },
  ball: {
    alignItems: "center",
    justifyContent: "center",
    borderWidth: 1.5,
    borderColor: "rgba(255, 255, 255, 0.4)",
  },
  innerGlow: {
    position: "absolute",
    top: 6,
    left: 6,
    right: 6,
    bottom: 6,
  },
  innerGlowGradient: {
    flex: 1,
  },
  highlight: {
    position: "absolute",
    top: 10,
    left: 14,
    width: 18,
    height: 9,
    borderRadius: 9,
    backgroundColor: "rgba(255, 255, 255, 0.5)",
    transform: [{ rotate: "-30deg" }],
  },
  shimmer: {
    position: "absolute",
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    overflow: "hidden",
  },
  shimmerLine: {
    width: 30,
    backgroundColor: "rgba(255, 255, 255, 0.3)",
    transform: [{ skewX: "-20deg" }],
  },
  ripple: {
    position: "absolute",
    borderWidth: 2,
  },
  hintContainer: {
    position: "absolute",
    top: "50%",
    transform: [{ translateY: -20 }],
    flexDirection: "row",
    alignItems: "center",
  },
  hintBubble: {
    backgroundColor: DesignTokens.colors.neutral[800],
    paddingHorizontal: 14,
    paddingVertical: 10,
    borderRadius: 14,
    shadowColor: "#000",
    shadowOffset: { width: 0, height: 3 },
    shadowOpacity: 0.18,
    shadowRadius: 10,
    elevation: 5,
  },
  hintText: {
    fontSize: 14,
    color: "#FFFFFF",
    fontWeight: "500",
    letterSpacing: 0.3,
  },
  hintArrow: {
    position: "absolute",
    width: 12,
    height: 12,
    backgroundColor: DesignTokens.colors.neutral[800],
    transform: [{ rotate: "45deg" }],
  },
});

