import React, { useState, useEffect } from "react";
import { View, Text, StyleSheet, Pressable, ScrollView } from "react-native";
import { LinearGradient } from "@/src/polyfills/expo-linear-gradient";
import {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  withTiming,
  withDelay,
  interpolate,
} from "react-native-reanimated";
import AnimatedReanimated from "react-native-reanimated";
import { DesignTokens } from "../../theme/tokens/design-tokens";
import { AiStylistAction } from "../../services/api/ai-stylist.api";

const AnimatedView = AnimatedReanimated.createAnimatedComponent(View);
const AnimatedPressable = AnimatedReanimated.createAnimatedComponent(Pressable);

export interface PreferenceOption {
  label: string;
  value: string;
  icon?: string;
}

export interface PreferenceSelectorProps {
  action: AiStylistAction;
  onSelect: (field: string, values: string[]) => void;
  onSkip?: () => void;
}

const PREFERENCE_CONFIG: Record<
  string,
  { title: string; multiSelect: boolean; options: PreferenceOption[] }
> = {
  preferredStyles: {
    title: "浣犲枩娆㈢殑椋庢牸",
    multiSelect: true,
    options: [
      { label: "鏋佺畝", value: "鏋佺畝", icon: "鉁╘

馃憯" },
      { label: "鏃ョ郴", value: "鏃ョ郴", icon: "馃帉" },
    ],
  },
  styleAvoidances: {
    title: "浣犳兂閬垮厤鐨勯鏍糪

杩囦簬鑺卞摠", value: "杩囦簬鑺卞摠" },
      { label: "杩囦簬姝ｅ紡", value: "杩囦簬姝ｅ紡" },
      { label: "杩囦簬浼戦棽", value: "杩囦簬浼戦棽" },
      { label: "杩囦簬鏆撮湶", value: "杩囦簬鏆撮湶" },
      { label: "杩囦簬淇濆畧", value: "杩囦簬淇濆畧" },
    ],
  },
  fitGoals: {
    title: "浣犳兂杈惧埌鐨勬晥鏋淺

馃帹" },
    ],
  },
  preferredColors: {
    title: "浣犲枩娆㈢殑棰滆壊",
    multiSelect: true,
    options: [
      { label: "榛慭

鏍″洯", value: "campus", icon: "馃摎" },
    ],
  },
  weather: {
    title: "澶╂皵鎬庝箞鏍凤紵",
    multiSelect: false,
    options: [
      { label: "鐐庣儹", value: "hot", icon: "鈽€锔廫

瀵掑喎", value: "cold", icon: "鉂勶笍" },
    ],
  },
};

export const PreferenceSelector: React.FC<PreferenceSelectorProps> = ({
  action,
  onSelect,
  onSkip,
}) => {
  const [selectedValues, setSelectedValues] = useState<string[]>([]);
  const containerOpacity = useSharedValue(0);
  const containerTranslateY = useSharedValue(20);

  const field = action.field || "preferredStyles";
  const config = PREFERENCE_CONFIG[field] || PREFERENCE_CONFIG.preferredStyles;
  const rawOptions = action.options || config.options;
  const options: PreferenceOption[] = rawOptions.map((opt) =>
    typeof opt === "string" ? { label: opt, value: opt } : opt
  );

  useEffect(() => {
    containerOpacity.value = withTiming(1, { duration: 300 });
    containerTranslateY.value = withSpring(0, { damping: 15, stiffness: 150 });
  }, []);

  const toggleOption = (value: string) => {
    if (config.multiSelect) {
      setSelectedValues((prev) =>
        prev.includes(value) ? prev.filter((v) => v !== value) : [...prev, value]
      );
    } else {
      setSelectedValues([value]);
      setTimeout(() => {
        onSelect(field, [value]);
      }, 300);
    }
  };

  const handleConfirm = () => {
    if (selectedValues.length > 0) {
      onSelect(field, selectedValues);
    }
  };

  const containerStyle = useAnimatedStyle(() => ({
    opacity: containerOpacity.value,
    transform: [{ translateY: containerTranslateY.value }],
  }));

  return (
    <AnimatedView style={[styles.container, containerStyle]}>
      <View style={styles.header}>
        <Text style={styles.title}>{config.title}</Text>
        {config.multiSelect && (
          <Text style={styles.subtitle}>鍙閫?({selectedValues.length} 宸查€?</Text>
        )}
      </View>

      <ScrollView
        horizontal
        showsHorizontalScrollIndicator={false}
        contentContainerStyle={styles.optionsContainer}
      >
        {options.map((option, index) => {
          const isSelected = selectedValues.includes(option.value);
          return (
            <OptionChip
              key={option.value}
              option={option}
              isSelected={isSelected}
              index={index}
              onPress={() => toggleOption(option.value)}
            />
          );
        })}
      </ScrollView>

      {config.multiSelect && (
        <View style={styles.footer}>
          {action.canSkip && (
            <Pressable style={styles.skipButton} onPress={onSkip}>
              <Text style={styles.skipText}>璺宠繃</Text>
            </Pressable>
          )}
          <Pressable
            style={[
              styles.confirmButton,
              selectedValues.length === 0 && styles.confirmButtonDisabled,
            ]}
            onPress={handleConfirm}
            disabled={selectedValues.length === 0}
          >
            <LinearGradient
              colors={
                selectedValues.length > 0
                  ? [DesignTokens.colors.brand.terracotta, DesignTokens.colors.brand.camel]
                  : [DesignTokens.colors.neutral[300], DesignTokens.colors.neutral[400]]
              }
              style={styles.confirmGradient}
            >
              <Text style={styles.confirmText}>纭閫夋嫨</Text>
            </LinearGradient>
          </Pressable>
        </View>
      )}
    </AnimatedView>
  );
};

interface OptionChipProps {
  option: PreferenceOption;
  isSelected: boolean;
  index: number;
  onPress: () => void;
}

const OptionChip: React.FC<OptionChipProps> = ({ option, isSelected, index, onPress }) => {
  const scale = useSharedValue(0.8);
  const opacity = useSharedValue(0);

  useEffect(() => {
    scale.value = withDelay(index * 50, withSpring(1, { damping: 12, stiffness: 200 }));
    opacity.value = withDelay(index * 50, withTiming(1, { duration: 200 }));
  }, []);

  const chipStyle = useAnimatedStyle(() => ({
    transform: [{ scale: scale.value }],
    opacity: opacity.value,
  }));

  return (
    <AnimatedPressable
      style={[styles.chip, isSelected && styles.chipSelected, chipStyle]}
      onPress={onPress}
    >
      {option.icon && <Text style={styles.chipIcon}>{option.icon}</Text>}
      <Text style={[styles.chipText, isSelected && styles.chipTextSelected]}>{option.label}</Text>
      {isSelected && (
        <View style={styles.checkmark}>
          <Text style={styles.checkmarkText}>鉁?/Text>
        </View>
      )}
    </AnimatedPressable>
  );
};

const styles = StyleSheet.create({
  container: {
    backgroundColor: DesignTokens.colors.neutral[50],
    borderRadius: 16,
    padding: 16,
    marginVertical: 8,
    borderWidth: 1,
    borderColor: DesignTokens.colors.neutral[200],
  },
  header: {
    marginBottom: 12,
  },
  title: {
    fontSize: 16,
    fontWeight: "600",
    color: DesignTokens.colors.neutral[900],
    marginBottom: 4,
  },
  subtitle: {
    fontSize: 13,
    color: DesignTokens.colors.neutral[500],
  },
  optionsContainer: {
    paddingVertical: 4,
    gap: 8,
  },
  chip: {
    flexDirection: "row",
    alignItems: "center",
    paddingHorizontal: 16,
    paddingVertical: 10,
    borderRadius: 20,
    backgroundColor: DesignTokens.colors.neutral[100],
    borderWidth: 1.5,
    borderColor: DesignTokens.colors.neutral[200],
    marginRight: 8,
  },
  chipSelected: {
    backgroundColor: DesignTokens.colors.brand.sage + "20",
    borderColor: DesignTokens.colors.brand.sage,
  },
  chipIcon: {
    fontSize: 16,
    marginRight: 6,
  },
  chipText: {
    fontSize: 14,
    fontWeight: "500",
    color: DesignTokens.colors.neutral[700],
  },
  chipTextSelected: {
    color: DesignTokens.colors.brand.sage,
    fontWeight: "600",
  },
  checkmark: {
    width: 18,
    height: 18,
    borderRadius: 9,
    backgroundColor: DesignTokens.colors.brand.sage,
    alignItems: "center",
    justifyContent: "center",
    marginLeft: 6,
  },
  checkmarkText: {
    fontSize: 12,
