  },
  footer: {
    flexDirection: "row",
    justifyContent: "flex-end",
    alignItems: "center",
    marginTop: 16,
    gap: 12,
  },
  skipButton: {
    paddingHorizontal: 16,
    paddingVertical: 10,
  },
  skipText: {
    fontSize: 14,
    color: DesignTokens.colors.neutral[500],
    fontWeight: "500",
  },
  confirmButton: {
    borderRadius: 20,
    overflow: "hidden",
  },
  confirmButtonDisabled: {
    opacity: 0.6,
