import React, { useState, useCallback, useRef, useEffect, memo } from "react";
import {
  View,
  StyleSheet,
  Animated,
  ViewStyle,
  TextStyle,
  TouchableOpacity,
  Text,
  Dimensions,
  ImageStyle,
  StyleProp,
} from "react-native";
import FastImage, { FastImageProps } from "react-native-fast-image";
import { Colors, Spacing, BorderRadius, Typography, Shadows } from "../../theme";

const { width: SCREEN_WIDTH } = Dimensions.get("window");

/**
 * 鍥剧墖鍔犺浇鐘舵€乗n */
type ImageLoadStatus = "loading" | "loaded" | "error";

/**
 * 楠ㄦ灦灞忓崰浣嶇缁勪欢
 */
const SkeletonPlaceholder: React.FC<{
  width: number | string;
  height: number | string;
  borderRadius: number;
  animationSpeed: number;
  style?: ViewStyle;
}> = ({ width, height, borderRadius, animationSpeed, style }) => {
  const animatedValue = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    const animation = Animated.loop(
      Animated.sequence([
        Animated.timing(animatedValue, {
          toValue: 1,
          duration: animationSpeed,
          useNativeDriver: true,
        }),
        Animated.timing(animatedValue, {
          toValue: 0,
          duration: animationSpeed,
          useNativeDriver: true,
        }),
      ])
    );
    animation.start();
    return () => animation.stop();
  }, [animatedValue, animationSpeed]);

  const opacity = animatedValue.interpolate({
    inputRange: [0, 1],
    outputRange: [1, 0.3],
  });

  return (
    <Animated.View
      style={[
        {
          width: width as any,
          height: height as any,
          borderRadius,
          backgroundColor: Colors.neutral[200],
          opacity,
        },
        style,
      ]}
    />
  );
};

/**
 * 閿欒鍗犱綅绗︾粍浠?- 浣跨敤 React.memo 浼樺寲
 */
const ErrorPlaceholder = memo(function ErrorPlaceholder({
  width,
  height,
  borderRadius,
  onRetry,
  enableRetry,
  retryCount,
  maxRetryCount,
  style,
}: {
  width: number | string;
  height: number | string;
  borderRadius: number;
  onRetry?: () => void;
  enableRetry: boolean;
  retryCount: number;
  maxRetryCount: number;
  style?: ViewStyle;
}) {
  const canRetry = enableRetry && retryCount < maxRetryCount;

  return (
    <View
      style={[
        styles.errorContainer,
        {
          width: width as any,
          height: height as any,
          borderRadius,
        },
        style,
      ]}
    >
      <Text style={styles.errorIcon}>馃柤锔?/Text>
      <Text style={styles.errorText}>鍔犺浇澶辫触</Text>
      {canRetry && (
        <TouchableOpacity style={styles.retryButton} onPress={onRetry} activeOpacity={0.7}>
          <Text style={styles.retryText}>鐐瑰嚮閲嶈瘯</Text>
        </TouchableOpacity>
      )}
      {retryCount > 0 && (
        <Text style={styles.retryCountText}>
          宸查噸璇?{retryCount}/{maxRetryCount} 娆n        </Text>
      )}
    </View>
  );
});

/**
 * ImageWithPlaceholder 缁勪欢灞炴€n */
export interface ImageWithPlaceholderProps
  extends Omit<FastImageProps, "onLoad" | "onError" | "style"> {
  /** 鍥剧墖婧?*/
  source: { uri: string; priority?: string } | number;
  /** 瀹瑰櫒鏍峰紡 */
  containerStyle?: ViewStyle;
  /** 鍥剧墖鏍峰紡 */
  style?: StyleProp<ImageStyle>;
  /** 鍗犱綅绗︽牱寮?*/
  placeholderStyle?: ViewStyle;
  /** 閿欒鍗犱綅绗︽牱寮?*/
  errorStyle?: ViewStyle;
  /** 鏄惁鏄剧ず鍔犺浇鍔ㄧ敾 */
  showLoadingAnimation?: boolean;
  /** 鍔犺浇鍔ㄧ敾閫熷害 (ms) */
  animationSpeed?: number;
  /** 鏄惁鍚敤閲嶈瘯鍔熻兘 */
  enableRetry?: boolean;
  /** 鏈€澶ч噸璇曟鏁?*/
  maxRetryCount?: number;
  /** 鑷畾涔夊姞杞藉崰浣嶇 */
  customPlaceholder?: React.ReactNode;
  /** 鑷畾涔夐敊璇崰浣嶇 */
  customError?: React.ReactNode;
  /** 鍔犺浇瀹屾垚鍥炶皟 */
  onLoad?: () => void;
  /** 鍔犺浇閿欒鍥炶皟 */
  onError?: (error: Error) => void;
  /** 閲嶈瘯鍥炶皟 */
  onRetry?: () => void;
  /** 鍥剧墖缂╂斁妯″紡 */
  resizeMode?: "contain" | "cover" | "stretch" | "center";
  /** 鏄惁涓哄渾褰㈠浘鐗?(鐢ㄤ簬澶村儚绛? */
  isCircular?: boolean;
  /** 鍦嗚澶у皬 */
  borderRadius?: number;
  /** 娴嬭瘯 ID */
  testID?: string;
}

/**
 * 楂樿川閲忓浘鐗囧姞杞界粍浠?- 浣跨敤 React.memo 浼樺寲
 *
 * 鐗规€?
 * - 鍔犺浇鍗犱綅绗?(楠ㄦ灦灞忓姩鐢绘晥鏋?
 * - 閿欒鐘舵€佹樉绀篭n * - 鑷姩閲嶈瘯鍔熻兘
 * - 骞虫粦杩囨浮鍔ㄧ敾
 * - 鏀寔鍦嗗舰鍥剧墖
 * - 瀹屽叏绫诲瀷瀹夊叏
 *
 * @example
 * ```tsx
 * // 鍩虹鐢ㄦ硶
 * <ImageWithPlaceholder
 *   source={{ uri: 'https://example.com/image.jpg' }}
 *   style={{ width: 200, height: 200 }}
 * />
 *
 * // 鍦嗗舰澶村儚
 * <ImageWithPlaceholder
 *   source={{ uri: avatarUrl }}
 *   style={{ width: 80, height: 80 }}
 *   isCircular
 * />
 *
 * // 甯﹂噸璇曞姛鑳絓n * <ImageWithPlaceholder
 *   source={{ uri: imageUrl }}
 *   style={{ width: 300, height: 200 }}
 *   enableRetry
 *   maxRetryCount={3}
 *   onRetry={() => console.log('Retrying...')}
 * />
 * ```
 */
export const ImageWithPlaceholder = memo(function ImageWithPlaceholder({
  source,
  containerStyle,
  style,
  placeholderStyle,
  errorStyle,
  showLoadingAnimation = true,
  animationSpeed = 1200,
  enableRetry = true,
  maxRetryCount = 3,
  customPlaceholder,
  customError,
  onLoad,
  onError,
  onRetry,
  resizeMode = "cover",
  isCircular = false,
  borderRadius: customBorderRadius,
  testID,
  ...props
}: ImageWithPlaceholderProps) {
  const [status, setStatus] = useState<ImageLoadStatus>("loading");
  const [retryCount, setRetryCount] = useState(0);
  const [imageKey, setImageKey] = useState(0);

  const fadeAnim = useRef(new Animated.Value(0)).current;
  const placeholderOpacity = useRef(new Animated.Value(1)).current;

  // 璁＄畻鍥剧墖灏哄
  const imageStyle = StyleSheet.flatten(style) || {};
  const imageWidth = (imageStyle.width as number) || SCREEN_WIDTH;
  const imageHeight = (imageStyle.height as number) || 200;
  const borderRadius = customBorderRadius ?? (isCircular ? imageWidth / 2 : BorderRadius.lg);

  /**
   * 澶勭悊鍔犺浇鎴愬姛
   */
  const handleLoad = useCallback(() => {
    setStatus("loaded");
    onLoad?.();

    // 娣″叆鍥剧墖
    Animated.parallel([
      Animated.timing(fadeAnim, {
        toValue: 1,
        duration: 300,
        useNativeDriver: true,
      }),
      Animated.timing(placeholderOpacity, {
        toValue: 0,
        duration: 300,
        useNativeDriver: true,
      }),
    ]).start();
  }, [fadeAnim, placeholderOpacity, onLoad]);

  /**
   * 澶勭悊鍔犺浇閿欒
   */
  const handleError = useCallback(() => {
    setStatus("error");
    const error = new Error("Image failed to load");
    onError?.(error);
  }, [onError]);

  /**
   * 澶勭悊閲嶈瘯
   */
  const handleRetry = useCallback(() => {
    if (retryCount >= maxRetryCount) {
      return;
    }

    setRetryCount((prev) => prev + 1);
    setStatus("loading");
    setImageKey((prev) => prev + 1);
    fadeAnim.setValue(0);
    placeholderOpacity.setValue(1);
    onRetry?.();
  }, [retryCount, maxRetryCount, fadeAnim, placeholderOpacity, onRetry]);

  /**
   * 娓叉煋鍗犱綅绗n   */
  const renderPlaceholder = () => {
    if (status === "loaded") {
      return null;
    }

    if (status === "error") {
      return customError ? (
        <View style={[styles.placeholderWrapper, { borderRadius }]}>{customError}</View>
      ) : (
        <ErrorPlaceholder
          width={imageWidth}
          height={imageHeight}
          borderRadius={borderRadius}
          onRetry={handleRetry}
          enableRetry={enableRetry}
          retryCount={retryCount}
          maxRetryCount={maxRetryCount}
          style={errorStyle}
        />
      );
    }

    return customPlaceholder ? (
      <View style={[styles.placeholderWrapper, { borderRadius }]}>{customPlaceholder}</View>
    ) : showLoadingAnimation ? (
      <SkeletonPlaceholder
        width={imageWidth}
        height={imageHeight}
        borderRadius={borderRadius}
        animationSpeed={animationSpeed}
        style={placeholderStyle}
      />
    ) : (
      <View
        style={[
          styles.staticPlaceholder,
          {
            width: imageWidth,
            height: imageHeight,
            borderRadius,
          },
          placeholderStyle,
        ]}
      />
    );
  };

  return (
    <View style={[styles.container, containerStyle]} testID={testID}>
      {/* 鍗犱綅绗?*/}
      <Animated.View style={[styles.placeholderContainer, { opacity: placeholderOpacity }]}>
        {renderPlaceholder()}
      </Animated.View>

      {/* 鍥剧墖 */}
      {status !== "error" && (
        <Animated.View style={[styles.imageContainer, { opacity: fadeAnim }]}>
          <FastImage
            key={imageKey}
            source={source}
            style={[
              styles.image,
              {
                width: imageWidth,
                height: imageHeight,
                borderRadius,
              },
              style,
            ]}
            resizeMode={resizeMode}
            onLoad={handleLoad}
