interface Collection {
  id: string;
  name: string;
  icon: string;
  itemCount: number;
}

interface BookmarkSheetProps {
  visible: boolean;
  postId: string;
  onClose: () => void;
  onBookmarked?: (collectionId: string) => void;
}

export const BookmarkSheet: React.FC<BookmarkSheetProps> = ({
  visible,
  postId,
  onClose,
  onBookmarked,
}) => {
  const [collections, setCollections] = useState<Collection[]>([]);
  const [loading, setLoading] = useState(false);
  const [showNewCollection, setShowNewCollection] = useState(false);
  const [newCollectionName, setNewCollectionName] = useState("");
  const [creating, setCreating] = useState(false);

  const fetchCollections = useCallback(async () => {
    try {
      setLoading(true);
      const response = await communityApi.getCollections?.();
      if (response && response.success && response.data) {
        const items = Array.isArray(response.data) ? response.data : [];
        setCollections(
          items.map(
            (item: { id?: string; name?: string; icon?: string; _count?: { items?: number } }) => ({
              id: item.id ?? "",
              name: item.name ?? "",
              icon: item.icon ?? "folder",
              itemCount: item._count?.items ?? 0,
            })
          )
        );
      }
    } catch {
      // Silently fail
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (visible) {
      void fetchCollections();
      setShowNewCollection(false);
      setNewCollectionName("");
    }
  }, [visible, fetchCollections]);

  const handleBookmark = useCallback(
    async (collectionId: string) => {
      try {
        const response = await communityApi.bookmarkPost(postId, { collectionId });
        if (response.success) {
          const collectionName = collections.find((c) => c.id === collectionId)?.name ?? "鍒嗙被";
          Alert.alert("鎴愬姛", `宸叉敹钘忓埌銆?{collectionName}銆峘);
          onBookmarked?.(collectionId);
          onClose();
        } else {
          Alert.alert("鎻愮ず", response.error?.message ?? "鏀惰棌澶辫触");
        }
      } catch {
        Alert.alert("鎻愮ず", "鏀惰棌澶辫触锛岃閲嶈瘯");
      }
    },
    [postId, collections, onBookmarked, onClose]
  );

  const handleCreateCollection = useCallback(async () => {
    if (!newCollectionName.trim()) {
      return;
    }
    try {
      setCreating(true);
      const response = await communityApi.createCollection?.({ name: newCollectionName.trim() });
      if (response && response.success && response.data) {
        const newCol: Collection = {
          id: (response.data as { id?: string }).id ?? "",
          name: newCollectionName.trim(),
          icon: "folder",
          itemCount: 0,
        };
        setCollections((prev) => [...prev, newCol]);
        setNewCollectionName("");
        setShowNewCollection(false);
      }
    } catch {
      Alert.alert("鎻愮ず", "鍒涘缓鍒嗙被澶辫触");
    } finally {
      setCreating(false);
    }
  }, [newCollectionName]);

  if (!visible) {
    return null;
  }

  return (
    <Modal visible={visible} transparent animationType="slide" onRequestClose={onClose}>
      <View style={styles.overlay}>
        <TouchableOpacity style={styles.backdrop} onPress={onClose} />
        <View style={styles.sheet}>
          <View style={styles.handle} />
          <Text style={styles.title}>鏀惰棌鍒扮伒鎰熻。姗?/Text>

          {loading ? (
            <ActivityIndicator size="small" color={theme.colors.primary} style={styles.loader} />
          ) : (
            <ScrollView style={styles.list} showsVerticalScrollIndicator={false}>
              {collections.map((col) => (
                <TouchableOpacity
                  key={col.id}
                  style={styles.collectionItem}
                  onPress={() => handleBookmark(col.id)}
                >
                  <View style={styles.collectionIcon}>
                    <Ionicons name={col.icon as "folder"} size={20} color={theme.colors.primary} />
                  </View>
                  <View style={styles.collectionInfo}>
                    <Text style={styles.collectionName}>{col.name}</Text>
                    <Text style={styles.collectionCount}>{col.itemCount} 涓唴瀹?/Text>
                  </View>
                  <Ionicons name="chevron-forward" size={18} color={theme.colors.textTertiary} />
                </TouchableOpacity>
              ))}
            </ScrollView>
          )}

          {showNewCollection ? (
            <View style={styles.newCollectionRow}>
              <TextInput
                style={styles.newCollectionInput}
                placeholder="杈撳叆鍒嗙被鍚嶇О"
                placeholderTextColor={theme.colors.textTertiary}
                value={newCollectionName}
                onChangeText={setNewCollectionName}
                autoFocus
                maxLength={20}
              />
              <TouchableOpacity
                style={[styles.createBtn, creating && styles.createBtnDisabled]}
                onPress={handleCreateCollection}
                disabled={creating}
              >
                <Text style={styles.createBtnText}>鍒涘缓</Text>
              </TouchableOpacity>
            </View>
          ) : (
            <TouchableOpacity style={styles.newBtn} onPress={() => setShowNewCollection(true)}>
              <Ionicons name="add" size={18} color={theme.colors.primary} />
              <Text style={styles.newBtnText}>鏂板缓鍒嗙被</Text>
            </TouchableOpacity>
          )}
        </View>
      </View>
    </Modal>
  );
};

