import React, { useState } from "react";
import { View, Text, StyleSheet, TouchableOpacity, ScrollView } from "react-native";
import { Feather } from "@/src/polyfills/expo-vector-icons";
import { ClothingCategory, CATEGORY_LABELS } from "../../types/clothing";

interface FilterOption {
  label: string;
  value: string;
  count?: number;
}

interface FilterSectionProps {
  title: string;
  options: FilterOption[];
  selected: string[];
  onSelect: (value: string) => void;
  multiSelect?: boolean;
}

function FilterSection({
  title,
  options,
  selected,
  onSelect,
  multiSelect = true,
}: FilterSectionProps) {
  return (
    <View style={styles.section}>
      <Text style={styles.sectionTitle}>{title}</Text>
      <View style={styles.options}>
        {options.map((option) => {
          const isSelected = selected.includes(option.value);
          return (
            <TouchableOpacity
              key={option.value}
              style={[styles.option, isSelected && styles.optionSelected]}
              onPress={() => onSelect(option.value)}
            >
              <Text style={[styles.optionText, isSelected && styles.optionTextSelected]}>
                {option.label}
              </Text>
              {option.count !== undefined && (
                <Text style={[styles.count, isSelected && styles.countSelected]}>
                  ({option.count})
                </Text>
              )}
            </TouchableOpacity>
          );
        })}
      </View>
    </View>
  );
}

interface FilterPanelProps {
  visible: boolean;
  onClose: () => void;
  onApply: (filters: FilterState) => void;
  onReset: () => void;
  categories: { value: ClothingCategory; count: number }[];
  seasons: { value: string; count: number }[];
  occasions: { value: string; count: number }[];
  initialFilters?: FilterState;
}

export interface FilterState {
  categories: ClothingCategory[];
  seasons: string[];
  occasions: string[];
  priceRange?: [number, number];
  isFavorite?: boolean;
}

export function FilterPanel({
  visible,
  onClose,
  onApply,
  onReset,
  categories,
  seasons,
  occasions,
  initialFilters,
}: FilterPanelProps) {
  const [selectedCategories, setSelectedCategories] = useState<ClothingCategory[]>(
    initialFilters?.categories || []
  );
  const [selectedSeasons, setSelectedSeasons] = useState<string[]>(initialFilters?.seasons || []);
  const [selectedOccasions, setSelectedOccasions] = useState<string[]>(
    initialFilters?.occasions || []
  );
  const [isFavorite, setIsFavorite] = useState<boolean | undefined>(initialFilters?.isFavorite);

  const handleCategorySelect = (value: string) => {
    setSelectedCategories((prev) =>
      prev.includes(value as ClothingCategory)
        ? prev.filter((c) => c !== value)
        : [...prev, value as ClothingCategory]
    );
  };

  const handleSeasonSelect = (value: string) => {
    setSelectedSeasons((prev) =>
      prev.includes(value) ? prev.filter((s) => s !== value) : [...prev, value]
    );
  };

  const handleOccasionSelect = (value: string) => {
    setSelectedOccasions((prev) =>
      prev.includes(value) ? prev.filter((o) => o !== value) : [...prev, value]
    );
  };

  const handleApply = () => {
    onApply({
      categories: selectedCategories,
      seasons: selectedSeasons,
      occasions: selectedOccasions,
      isFavorite,
    });
    onClose();
  };

  const handleReset = () => {
    setSelectedCategories([]);
    setSelectedSeasons([]);
    setSelectedOccasions([]);
    setIsFavorite(undefined);
    onReset();
    onClose();
  };

  if (!visible) {
    return null;
  }

  return (
    <View style={styles.overlay}>
      <View style={styles.panel}>
        <View style={styles.header}>
          <Text style={styles.title}>绛涢€?/Text>
          <TouchableOpacity onPress={onClose}>
            <Feather name="x" size={24} color="#18181b" />
          </TouchableOpacity>
        </View>

        <ScrollView style={styles.content}>
          <FilterSection
            title="鍒嗙被"
            options={categories.map((c) => ({
              label: CATEGORY_LABELS[c.value] || c.value,
              value: c.value,
              count: c.count,
            }))}
            selected={selectedCategories}
            onSelect={handleCategorySelect}
          />

          <FilterSection
            title="瀛ｈ妭"
            options={seasons.map((s) => ({
              label: s.value,
              value: s.value,
              count: s.count,
            }))}
            selected={selectedSeasons}
            onSelect={handleSeasonSelect}
          />

          <FilterSection
            title="鍦哄悎"
            options={occasions.map((o) => ({
              label: o.value,
              value: o.value,
              count: o.count,
            }))}
            selected={selectedOccasions}
            onSelect={handleOccasionSelect}
          />

          <View style={styles.section}>
            <Text style={styles.sectionTitle}>鏀惰棌</Text>
            <View style={styles.options}>
              <TouchableOpacity
                style={[styles.option, isFavorite === true && styles.optionSelected]}
                onPress={() => setIsFavorite(isFavorite === true ? undefined : true)}
              >
                <Text style={[styles.optionText, isFavorite === true && styles.optionTextSelected]}>
                  宸叉敹钘廫n                </Text>
              </TouchableOpacity>
              <TouchableOpacity
                style={[styles.option, isFavorite === false && styles.optionSelected]}
                onPress={() => setIsFavorite(isFavorite === false ? undefined : false)}
              >
                <Text
                  style={[styles.optionText, isFavorite === false && styles.optionTextSelected]}
                >
                  鏈敹钘廫n                </Text>
              </TouchableOpacity>
            </View>
          </View>
        </ScrollView>

        <View style={styles.footer}>
          <TouchableOpacity style={styles.resetButton} onPress={handleReset}>
            <Text style={styles.resetButtonText}>閲嶇疆</Text>
          </TouchableOpacity>
          <TouchableOpacity style={styles.applyButton} onPress={handleApply}>
            <Text style={styles.applyButtonText}>搴旂敤</Text>
          </TouchableOpacity>
        </View>
      </View>
    </View>
  );
}

