  useEffect(() => {
    logoOpacity.value = withTiming(1, { duration: 500 });
    logoScale.value = withSpring(1, { damping: 10, stiffness: 100 });
    logoRotate.value = withSpring(0, { damping: 12, stiffness: 80 });

