              setProfileData((prev) => ({ ...prev, nickname }));
              goToNext();
            }}
            size="lg"
            disabled={!nickname.trim()}
          />
        </View>
      </View>
    );
  };

  const GenderOptionCard: React.FC<{
    option: {
      id: "male" | "female" | "other";
      label: string;
      icon: string;
      color: string;
    };
    index: number;
    selected: boolean;
    onPress: () => void;
  }> = ({ option, index, selected, onPress }) => {
    const scale = useSharedValue(0);

    useEffect(() => {
      scale.value = withDelay(index * 100, withSpring(1, { damping: 12, stiffness: 100 }));
    }, [index, scale]);

    useEffect(() => {
      scale.value = withSpring(selected ? 1.05 : 1, {
        damping: 12,
        stiffness: 200,
      });
    }, [scale, selected]);

    const animatedStyle = useAnimatedStyle(() => ({
      transform: [{ scale: scale.value }],
    }));

    return (
      <Pressable onPress={onPress}>
        <AnimatedView
