                : ["rgba(255,255,255,0.05)", "rgba(255,255,255,0.02)"]
            }
            style={styles.genderOptionGradient}
          >
            <FloatingElement amplitude={selected ? 5 : 0} duration={3000}>
              <Text style={styles.genderIcon}>{option.icon}</Text>
            </FloatingElement>
            <Text style={[styles.genderLabel, selected && { color: Colors.white }]}>
              {option.label}
            </Text>
          </LinearGradient>
        </AnimatedView>
      </Pressable>
    );
  };

  const GenderStep: React.FC = () => {
    const options = [
      { id: "male", label: "鐢风敓", icon: "馃懆", color: Colors.sky[500] },
      { id: "female", label: "濂崇敓", icon: "馃懇", color: Colors.rose[500] },
      { id: "other", label: "鍏朵粬", icon: "馃", color: Colors.primary[500] },
    ];

    return (
      <View style={styles.stepContent}>
        <Text style={styles.stepTitle}>浣犵殑鎬у埆鏄紵</Text>
        <Text style={styles.stepSubtitle}>甯姪鎴戜滑鎺ㄨ崘鏇村悎閫傜殑鏈嶈</Text>

        <View style={styles.genderOptions}>
          {options.map((option, index) => (
            <GenderOptionCard
              key={option.id}
              option={
                option as {
                  id: "male" | "female" | "other";
                  label: string;
                  icon: string;
                  color: string;
                }
              }
              index={index}
              selected={selectedGender === option.id}
              onPress={() => setSelectedGender(option.id as "male" | "female" | "other")}
            />
          ))}
        </View>

        <View style={styles.stepFooter}>
          <MagneticButton
            title="缁х画"
            onPress={() => {
              setProfileData((prev) => ({
                ...prev,
                gender: selectedGender ?? undefined,
              }));
              goToNext();
            }}
            size="lg"
            disabled={!selectedGender}
          />
        </View>
      </View>
    );
  };

  const BodyStep: React.FC = () => {
    const heightValue = useSharedValue(0);
    const weightValue = useSharedValue(0);

    useEffect(() => {
      heightValue.value = withSpring(1, { damping: 15, stiffness: 100 });
      weightValue.value = withDelay(200, withSpring(1, { damping: 15, stiffness: 100 }));
    }, []);

    const heightAnimatedStyle = useAnimatedStyle(() => ({
      transform: [{ scale: heightValue.value }],
      opacity: heightValue.value,
    }));

    const weightAnimatedStyle = useAnimatedStyle(() => ({
      transform: [{ scale: weightValue.value }],
      opacity: weightValue.value,
    }));

    return (
      <View style={styles.stepContent}>
        <Text style={styles.stepTitle}>浣犵殑韬潗鏁版嵁</Text>
        <Text style={styles.stepSubtitle}>鐢ㄤ簬绮惧噯鎺ㄨ崘灏虹爜鍜屾惌閰?/Text>

        <AnimatedView style={[styles.bodyInputContainer, heightAnimatedStyle]}>
          <Text style={styles.bodyInputLabel}>韬珮</Text>
          <View style={styles.bodyInputRow}>
            <TextInput
              style={styles.bodyInput}
              value={height}
              onChangeText={setHeight}
              keyboardType="numeric"
              placeholder="165"
              placeholderTextColor="rgba(255, 255, 255, 0.3)"
            />
            <Text style={styles.bodyInputUnit}>cm</Text>
          </View>
        </AnimatedView>

        <AnimatedView style={[styles.bodyInputContainer, weightAnimatedStyle]}>
          <Text style={styles.bodyInputLabel}>浣撻噸</Text>
          <View style={styles.bodyInputRow}>
            <TextInput
              style={styles.bodyInput}
              value={weight}
              onChangeText={setWeight}
              keyboardType="numeric"
              placeholder="55"
              placeholderTextColor="rgba(255, 255, 255, 0.3)"
            />
            <Text style={styles.bodyInputUnit}>kg</Text>
          </View>
        </AnimatedView>

        <View style={styles.stepFooter}>
          <MagneticButton
            title="缁х画"
            onPress={() => {
              setProfileData((prev) => ({
                ...prev,
                height: parseInt(height) || 165,
                weight: parseInt(weight) || 55,
              }));
              goToNext();
            }}
            size="lg"
          />
        </View>
      </View>
    );
  };

  const StyleOptionCard: React.FC<{
    option: (typeof STYLE_OPTIONS)[number];
    index: number;
    selected: boolean;
    onPress: () => void;
  }> = ({ option, index, selected, onPress }) => {
    const scale = useSharedValue(0);

    useEffect(() => {
      scale.value = withDelay(index * 80, withSpring(1, { damping: 12, stiffness: 100 }));
    }, [index, scale]);

    useEffect(() => {
      scale.value = withSpring(selected ? 1.05 : 1, {
        damping: 12,
        stiffness: 200,
      });
    }, [scale, selected]);

    const animatedStyle = useAnimatedStyle(() => ({
      transform: [{ scale: scale.value }],
    }));

    return (
      <Pressable onPress={onPress} style={styles.styleOptionPressable}>
        <AnimatedView
          style={[
            styles.styleOption,
            {
              borderColor: selected ? option.color : "rgba(255, 255, 255, 0.1)",
            },
            animatedStyle,
          ]}
        >
          <LinearGradient
            colors={
              selected
                ? [`${option.color}30`, `${option.color}10`]
                : ["rgba(255,255,255,0.03)", "rgba(255,255,255,0.01)"]
            }
            style={styles.styleOptionGradient}
          >
            <Text style={styles.styleIcon}>{option.icon}</Text>
            <Text style={styles.styleName}>{option.name}</Text>
            {selected && (
              <View style={[styles.styleCheck, { backgroundColor: option.color }]}>
                <Text style={styles.styleCheckIcon}>{"\u2713"}</Text>
              </View>
            )}
          </LinearGradient>
        </AnimatedView>
      </Pressable>
    );
  };

  const StyleStep: React.FC = () => {
    const toggleStyle = (styleId: string) => {
      setSelectedStyles((prev) =>
        prev.includes(styleId) ? prev.filter((id) => id !== styleId) : [...prev, styleId]
      );
    };

    return (
      <View style={styles.stepContent}>
        <Text style={styles.stepTitle}>浣犲枩娆粈涔堥鏍硷紵</Text>
        <Text style={styles.stepSubtitle}>閫夋嫨1-3涓綘鍠滄鐨勯鏍?/Text>

        <View style={styles.styleOptions}>
          {STYLE_OPTIONS.map((style, index) => {
            return (
              <StyleOptionCard
                key={style.id}
                option={style}
                index={index}
                selected={selectedStyles.includes(style.id)}
                onPress={() => toggleStyle(style.id)}
              />
            );
          })}
        </View>

        <View style={styles.stepFooter}>
          <MagneticButton
            title="缁х画"
            onPress={() => {
              setProfileData((prev) => ({
                ...prev,
                stylePreferences: selectedStyles,
              }));
              goToNext();
            }}
            size="lg"
            disabled={selectedStyles.length === 0}
          />
        </View>
      </View>
    );
  };

  const CompleteStep: React.FC = () => {
    const scale = useSharedValue(0);
    const opacity = useSharedValue(0);
    const buttonOpacity = useSharedValue(0);

    useEffect(() => {
      scale.value = withSpring(1, { damping: 12, stiffness: 100 });
      opacity.value = withTiming(1, { duration: 500 });
      buttonOpacity.value = withDelay(800, withTiming(1, { duration: 400 }));
    }, []);

    const animatedStyle = useAnimatedStyle(() => ({
      transform: [{ scale: scale.value }],
      opacity: opacity.value,
    }));

    const buttonAnimatedStyle = useAnimatedStyle(() => ({
      opacity: buttonOpacity.value,
    }));

    return (
      <View style={styles.stepContent}>
        <ParticleEffect count={50} color="rgba(168, 85, 247, 0.4)" size={4} />

        <AnimatedView style={[styles.completeContainer, animatedStyle]}>
          <LinearGradient colors={["#a855f7", "#ec4899"]} style={styles.completeIconGradient}>
            <Text style={styles.completeIcon}>馃帀</Text>
          </LinearGradient>

          <GlowText
            text="璁剧疆瀹屾垚锛乗

xl"
          />
        </AnimatedView>
      </View>
    );
  };

  const renderStep = () => {
    switch (currentStep) {
      case 0:
        return <WelcomeStep />;
      case 1:
        return <BasicStep />;
      case 2:
        return <GenderStep />;
      case 3:
        return <BodyStep />;
      case 4:
        return <StyleStep />;
      case 5:
        return <CompleteStep />;
      default:
        return null;
    }
  };

  return (
    <View style={styles.container}>
      <StatusBar barStyle="light-content" />

      <LinearGradient colors={["#0f0a1a", "#1e1b4b", "#312e81"]} style={styles.gradient}>
        {currentStep > 0 && currentStep < 5 && (
          <View style={styles.header}>
            <Pressable onPress={goToPrev} style={styles.backButton}>
              <Text style={styles.backIcon}>鈫?/Text>
            </Pressable>
            <View style={styles.progressContainer}>
              <View style={styles.progressBackground}>
                <AnimatedView style={[styles.progressFill, progressAnimatedStyle]} />
              </View>
            </View>
            <Text style={styles.stepIndicator}>
              {currentStep}/{STEP_CONFIG.length - 2}
            </Text>
          </View>
        )}

        <KeyboardAvoidingView
          style={styles.content}
          behavior={Platform.OS === "ios" ? "padding" : undefined}
        >
          <ScrollView
            contentContainerStyle={styles.scrollContent}
            showsVerticalScrollIndicator={false}
            keyboardShouldPersistTaps="handled"
          >
            {renderStep()}
          </ScrollView>
        </KeyboardAvoidingView>
      </LinearGradient>
    </View>
  );
};

const styles = StyleSheet.create({
