export interface ScreenLayoutProps {
  children: React.ReactNode;
  header?: React.ReactNode;
  footer?: React.ReactNode;
  floatingButton?: React.ReactNode;
  scrollable?: boolean;
  refreshing?: boolean;
  onRefresh?: () => void;
  backgroundColor?: string;
  gradientBackground?: string[];
  safeAreaTop?: boolean;
  safeAreaBottom?: boolean;
  headerSticky?: boolean;
  headerTransparent?: boolean;
  contentContainerStyle?: ViewStyle;
  style?: ViewStyle;
  showsVerticalScrollIndicator?: boolean;
  onScroll?: (event: NativeSyntheticEvent<ScrollEvent["nativeEvent"]>) => void;
  scrollEventThrottle?: number;
}

export const ScreenLayout: React.FC<ScreenLayoutProps> = ({
  children,
  header,
  footer,
  floatingButton,
  scrollable = false,
  refreshing = false,
  onRefresh,
  backgroundColor = Colors.neutral[50],
  gradientBackground,
  safeAreaTop = true,
  safeAreaBottom = true,
  headerSticky = true,
  headerTransparent = false,
  contentContainerStyle,
  style,
  showsVerticalScrollIndicator = false,
  onScroll,
  scrollEventThrottle = 16,
}) => {
  const insets = useSafeAreaInsets();
  const scrollY = React.useRef(new Animated.Value(0)).current;

  const renderContent = () => {
    if (scrollable) {
      return (
        <Animated.ScrollView
          style={{ flex: 1 }}
          contentContainerStyle={[
            {
              paddingTop: header && !headerSticky ? 0 : safeAreaTop ? insets.top : 0,
              paddingBottom: safeAreaBottom ? insets.bottom : 0,
            },
            contentContainerStyle,
          ]}
          showsVerticalScrollIndicator={showsVerticalScrollIndicator}
          scrollEventThrottle={scrollEventThrottle}
          onScroll={
            onScroll
              ? onScroll
              : Animated.event([{ nativeEvent: { contentOffset: { y: scrollY } } }], {
                  useNativeDriver: true,
                })
          }
          refreshControl={
            onRefresh ? (
              <RefreshControl
                refreshing={refreshing}
                onRefresh={onRefresh}
                tintColor={Colors.primary[500]}
                colors={[Colors.primary[500]]}
              />
            ) : undefined
          }
        >
          {header && !headerSticky && header}
          {children}
        </Animated.ScrollView>
      );
    }

    return (
      <View
        style={[
          styles.content,
          {
            paddingTop: safeAreaTop ? insets.top : 0,
            paddingBottom: safeAreaBottom ? insets.bottom : 0,
          },
          contentContainerStyle,
        ]}
      >
        {children}
      </View>
    );
  };

  return (
    <View style={[styles.container, { backgroundColor }, style]}>
      {gradientBackground ? (
        <LinearGradient
          colors={gradientBackground as [string, string, ...string[]]}
          start={{ x: 0, y: 0 }}
          end={{ x: 0, y: 1 }}
          style={styles.container}
        >
          {header && headerSticky && (
            <View
              style={[
                styles.headerContainer,
                {
                  paddingTop: safeAreaTop ? insets.top : 0,
                },
                headerTransparent && styles.headerTransparent,
              ]}
            >
              {header}
            </View>
          )}
          {renderContent()}
          {footer && (
            <View
              style={[
                styles.footerContainer,
                {
                  paddingBottom: safeAreaBottom ? insets.bottom : 0,
                },
              ]}
            >
              {footer}
            </View>
          )}
          {floatingButton && (
            <View style={[styles.floatingButton, { bottom: insets.bottom + Spacing[6] }]}>
              {floatingButton}
            </View>
          )}
        </LinearGradient>
      ) : (
        <View style={[styles.container, { backgroundColor }]}>
          {header && headerSticky && (
            <View
              style={[
                styles.headerContainer,
                {
                  paddingTop: safeAreaTop ? insets.top : 0,
                },
                headerTransparent && styles.headerTransparent,
              ]}
            >
              {header}
            </View>
          )}
          {renderContent()}
          {footer && (
            <View
              style={[
                styles.footerContainer,
                {
                  paddingBottom: safeAreaBottom ? insets.bottom : 0,
                },
              ]}
            >
              {footer}
            </View>
          )}
          {floatingButton && (
            <View style={[styles.floatingButton, { bottom: insets.bottom + Spacing[6] }]}>
              {floatingButton}
            </View>
          )}
        </View>
      )}
    </View>
  );
};

