      {animated && !reducedMotion && (
        <View style={styles.shimmerContainer}>
          <AnimatedView style={[styles.shimmer, shimmerAnimatedStyle]}>
            <LinearGradient
              colors={["transparent", shimmerColor, "transparent"]}
              start={{ x: 0, y: 0 }}
              end={{ x: 1, y: 0 }}
