export interface ProgressIndicatorProps {
  progress: number;
  size?: "small" | "medium" | "large";
  color?: string;
  backgroundColor?: string;
  showLabel?: boolean;
  label?: string;
  animated?: boolean;
  style?: ViewStyle;
}

export const ProgressIndicator: React.FC<ProgressIndicatorProps> = ({
  progress,
  size = "medium",
  color = Colors.primary[500],
  backgroundColor = Colors.neutral[200],
  showLabel = false,
  label,
  animated = true,
  style,
}) => {
  const animatedProgress = useSharedValue(0);
  const scale = useSharedValue(1);
  const { reducedMotion } = useReducedMotion();
  const shouldAnimate = animated && !reducedMotion;

  const sizeMap = {
    small: { width: 80, height: 4, fontSize: 10 },
    medium: { width: 120, height: 6, fontSize: 12 },
    large: { width: 180, height: 8, fontSize: 14 },
  };

  const config = sizeMap[size];

  useEffect(() => {
    if (shouldAnimate) {
      animatedProgress.value = withSpring(progress, {
        damping: 15,
        stiffness: 100,
      });
    } else {
      animatedProgress.value = progress;
    }
  }, [progress, shouldAnimate]);

  const progressAnimatedStyle = useAnimatedStyle(() => ({
    width: `${animatedProgress.value * 100}%`,
  }));

  const pulseAnimatedStyle = useAnimatedStyle(() => ({
    transform: [{ scale: scale.value }],
  }));

  useEffect(() => {
    if (progress < 1) {
      scale.value = withRepeat(
        withSequence(withTiming(1.02, { duration: 500 }), withTiming(1, { duration: 500 })),
        -1,
        true
      );
    } else {
      scale.value = withSpring(1);
    }
  }, [progress]);

  return (
    <View style={[styles.progressContainer, style]}>
      {showLabel && (
        <View style={styles.progressHeader}>
          <Text style={[styles.progressLabel, { fontSize: config.fontSize }]}>
            {label || `${Math.round(progress * 100)}%`}
          </Text>
        </View>
      )}
      <AnimatedView
        style={[
          styles.progressTrack,
          {
            width: config.width,
            height: config.height,
            backgroundColor,
          },
          pulseAnimatedStyle,
        ]}
      >
        <AnimatedView
          style={[styles.progressFill, { backgroundColor: color }, progressAnimatedStyle]}
        />
      </AnimatedView>
    </View>
  );
};

export interface CircularProgressProps {
  progress: number;
  size?: number;
  strokeWidth?: number;
  color?: string;
  backgroundColor?: string;
  showPercentage?: boolean;
  animated?: boolean;
  style?: ViewStyle;
}

export const CircularProgress: React.FC<CircularProgressProps> = ({
  progress,
  size = 60,
  strokeWidth = 4,
  color = Colors.primary[500],
  backgroundColor = Colors.neutral[200],
  showPercentage = true,
  animated = true,
  style,
}) => {
  const animatedProgress = useSharedValue(0);
  const rotation = useSharedValue(0);
  const { reducedMotion } = useReducedMotion();
  const shouldAnimate = animated && !reducedMotion;

  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;

  useEffect(() => {
    if (shouldAnimate) {
      animatedProgress.value = withSpring(progress, {
        damping: 15,
        stiffness: 80,
      });
    } else {
      animatedProgress.value = progress;
    }
  }, [progress, shouldAnimate]);

  useEffect(() => {
    if (shouldAnimate && progress < 1) {
      rotation.value = withRepeat(
        withTiming(360, { duration: 3000, easing: Easing.linear }),
        -1,
        false
      );
    }
  }, [progress, shouldAnimate]);

  const _strokeDashoffset = useDerivedValue(() => {
    return circumference * (1 - animatedProgress.value);
  });

  const rotateAnimatedStyle = useAnimatedStyle(() => ({
    transform: [{ rotateZ: `${rotation.value}deg` }],
  }));

  return (
    <View style={[styles.circularContainer, { width: size, height: size }, style]}>
      <View style={StyleSheet.absoluteFill}>
        <View style={[styles.circleBackground, { width: size, height: size }]}>
          <View
            style={{
              width: radius * 2,
              height: radius * 2,
              borderRadius: radius,
              borderWidth: strokeWidth,
              borderColor: backgroundColor,
            }}
          />
        </View>
      </View>
      <AnimatedView style={rotateAnimatedStyle}>
        <View style={{ width: size, height: size }}>
          <View
            style={{
              width: radius * 2,
              height: radius * 2,
              borderRadius: radius,
              borderWidth: strokeWidth,
              borderColor: color,
              borderTopColor: "transparent",
              borderRightColor: "transparent",
            }}
          />
        </View>
      </AnimatedView>
      {showPercentage && (
        <View style={StyleSheet.absoluteFill}>
          <Text style={[styles.percentageText, { fontSize: size * 0.25 }]}>
            {Math.round(progress * 100)}%
          </Text>
        </View>
      )}
    </View>
  );
};

export interface LoadingDotsProps {
  size?: "small" | "medium" | "large";
  color?: string;
  style?: ViewStyle;
}

interface LoadingDotProps {
  index: number;
  dotSize: number;
  gap: number;
  color: string;
}

const LoadingDot: React.FC<LoadingDotProps> = ({ index, dotSize, gap, color }) => {
  const progress = useSharedValue(0);
  const { reducedMotion } = useReducedMotion();

  useEffect(() => {
    if (reducedMotion) {
      return;
    }
    progress.value = withDelay(
      index * 150,
      withRepeat(
        withSequence(
          withTiming(1, { duration: 300, easing: Easing.out(Easing.ease) }),
          withTiming(0, { duration: 300, easing: Easing.in(Easing.ease) })
        ),
        -1,
        false
      )
    );
  }, [index, progress, reducedMotion]);

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ translateY: interpolate(progress.value, [0, 1], [0, -dotSize]) }],
    opacity: interpolate(progress.value, [0, 1], [0.5, 1]),
  }));

  return (
    <AnimatedView
      style={[
        styles.dot,
        {
          width: dotSize,
          height: dotSize,
          borderRadius: dotSize / 2,
          backgroundColor: color,
          marginHorizontal: gap / 2,
        },
        animatedStyle,
      ]}
    />
  );
};

