export interface WaveLoaderProps {
  size?: number;
  color?: string;
  style?: ViewStyle;
}

interface WaveBarProps {
  index: number;
  size: number;
  color: string;
}

const WaveBar: React.FC<WaveBarProps> = ({ index, size, color }) => {
  const scaleY = useSharedValue(0.3);
  const { reducedMotion } = useReducedMotion();

  useEffect(() => {
    if (reducedMotion) {
      scaleY.value = 0.6;
      return;
    }
    scaleY.value = withDelay(
      index * 100,
      withRepeat(
        withSequence(
          withTiming(1, { duration: 300, easing: Easing.out(Easing.ease) }),
          withTiming(0.3, { duration: 300, easing: Easing.in(Easing.ease) })
        ),
        -1,
        false
      )
    );
  }, [index, scaleY, reducedMotion]);

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ scaleY: scaleY.value }],
  }));

  const barWidth = size / 8;
  const barHeight = size * 0.8;

  return (
    <AnimatedView
      style={[
        styles.waveBar,
        {
          width: barWidth,
          height: barHeight,
          backgroundColor: color,
          borderRadius: barWidth / 2,
          marginHorizontal: barWidth / 4,
        },
        animatedStyle,
      ]}
    />
  );
};

