import React from "react";
import {
  TouchableOpacity,
  Text,
  StyleSheet,
  Animated,
  ActivityIndicator,
  ViewStyle,
  TextStyle,
  Platform,
  Pressable,
} from "react-native";
import { LinearGradient } from "@/src/polyfills/expo-linear-gradient";
import * as Haptics from "@/src/polyfills/expo-haptics";
import { Colors, BorderRadius, Shadows } from "../../../theme";
import { SpringConfigs, Duration } from "../../../theme/tokens/animations";

export type ButtonVariant = "primary" | "secondary" | "outline" | "ghost" | "gradient" | "danger";
export type ButtonSize = "sm" | "md" | "lg" | "xl";

export interface ButtonProps {
  variant?: ButtonVariant;
  size?: ButtonSize;
  loading?: boolean;
  disabled?: boolean;
  fullWidth?: boolean;
  icon?: React.ReactNode;
  iconPosition?: "left" | "right";
  children: React.ReactNode;
  onPress?: () => void;
  onPressIn?: () => void;
  onPressOut?: () => void;
  onLongPress?: () => void;
  style?: ViewStyle;
  textStyle?: TextStyle;
  hapticFeedback?: boolean;
  gradientColors?: string[];
  activeOpacity?: number;
}

const sizeConfig: Record<
  ButtonSize,
  {
    height: number;
    paddingHorizontal: number;
    fontSize: number;
    borderRadius: number;
  }
> = {
  sm: {
    height: 36,
    paddingHorizontal: 16,
    fontSize: 14,
    borderRadius: BorderRadius.lg,
  },
  md: {
    height: 44,
    paddingHorizontal: 20,
    fontSize: 16,
    borderRadius: BorderRadius.xl,
  },
  lg: {
    height: 52,
    paddingHorizontal: 24,
    fontSize: 16,
    borderRadius: BorderRadius.xl,
  },
  xl: {
    height: 60,
    paddingHorizontal: 32,
    fontSize: 18,
    borderRadius: BorderRadius["2xl"],
  },
};

const variantStyles: Record<ButtonVariant, { container: ViewStyle; text: TextStyle }> = {
  primary: {
    container: {
      backgroundColor: Colors.primary[500],
    },
    text: {
      color: Colors.white,
    },
  },
  secondary: {
    container: {
      backgroundColor: Colors.neutral[100],
    },
    text: {
      color: Colors.neutral[800],
    },
  },
  outline: {
    container: {
      backgroundColor: "transparent",
      borderWidth: 1.5,
      borderColor: Colors.primary[500],
    },
    text: {
      color: Colors.primary[500],
    },
  },
  ghost: {
    container: {
      backgroundColor: "transparent",
    },
    text: {
      color: Colors.primary[500],
    },
  },
  gradient: {
    container: {
      backgroundColor: "transparent",
    },
    text: {
      color: Colors.white,
    },
  },
  danger: {
    container: {
      backgroundColor: Colors.error[500],
    },
    text: {
      color: Colors.white,
    },
  },
};

export const Button: React.FC<ButtonProps> = ({
  variant = "primary",
  size = "md",
  loading = false,
  disabled = false,
  fullWidth = false,
  icon,
  iconPosition = "left",
  children,
  onPress,
  onPressIn,
  onPressOut,
  onLongPress,
  style,
  textStyle,
  hapticFeedback = true,
  gradientColors,
  activeOpacity = 0.8,
}) => {
  const scaleAnim = React.useRef(new Animated.Value(1)).current;
  const glowAnim = React.useRef(new Animated.Value(0)).current;
  const _rippleAnim = React.useRef(new Animated.Value(0)).current;

  const config = sizeConfig[size];
  const vStyle = variantStyles[variant];

  const triggerHaptic = React.useCallback(() => {
    if (hapticFeedback && Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
  }, [hapticFeedback]);

  const handlePressIn = React.useCallback(() => {
    triggerHaptic();
    onPressIn?.();

    Animated.parallel([
      Animated.spring(scaleAnim, {
        toValue: 0.96,
        useNativeDriver: true,
        ...SpringConfigs.snappy,
      }),
      Animated.timing(glowAnim, {
        toValue: 1,
        duration: Duration.fast,
        useNativeDriver: true,
      }),
    ]).start();
  }, [triggerHaptic, onPressIn, scaleAnim, glowAnim]);

  const handlePressOut = React.useCallback(() => {
    onPressOut?.();

    Animated.parallel([
      Animated.spring(scaleAnim, {
        toValue: 1,
        useNativeDriver: true,
        ...SpringConfigs.bouncy,
      }),
      Animated.timing(glowAnim, {
        toValue: 0,
        duration: Duration.normal,
        useNativeDriver: true,
      }),
    ]).start();
  }, [onPressOut, scaleAnim, glowAnim]);

  const handlePress = React.useCallback(() => {
    if (!disabled && !loading) {
      onPress?.();
    }
  }, [disabled, loading, onPress]);

  const handleLongPress = React.useCallback(() => {
    if (!disabled && !loading) {
      if (hapticFeedback && Platform.OS !== "web") {
        Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
      }
      onLongPress?.();
    }
  }, [disabled, loading, hapticFeedback, onLongPress]);

  const isDisabled = disabled || loading;

  const containerStyle: ViewStyle = {
    height: config.height,
    paddingHorizontal: config.paddingHorizontal,
    borderRadius: config.borderRadius,
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "center",
    opacity: isDisabled ? 0.5 : 1,
    overflow: "hidden",
    ...(fullWidth && { width: "100%" }),
    ...vStyle.container,
  };

  const textStyleMerged: TextStyle = {
    fontSize: config.fontSize,
    fontWeight: "600",
    ...vStyle.text,
    ...textStyle,
  };

  const renderContent = () => (
    <>
      {loading ? (
        <ActivityIndicator
          size="small"
          color={variant === "outline" || variant === "ghost" ? Colors.primary[500] : Colors.white}
        />
      ) : (
        <>
          {icon && iconPosition === "left" && <>{icon}</>}
          <Text style={[textStyleMerged, icon ? { marginHorizontal: 8 } : {}]}>{children}</Text>
          {icon && iconPosition === "right" && <>{icon}</>}
        </>
      )}
    </>
  );

  if (variant === "gradient") {
    const colors = gradientColors || Colors.gradient.hero;

    return (
      <Pressable
        onPress={handlePress}
        onPressIn={handlePressIn}
        onPressOut={handlePressOut}
        onLongPress={handleLongPress}
        disabled={isDisabled}
        style={({ pressed }) => [
          { opacity: pressed ? activeOpacity : 1 },
          fullWidth && { width: "100%" },
        ]}
      >
        <Animated.View style={[{ transform: [{ scale: scaleAnim }] }, style]}>
          <LinearGradient
            colors={colors as [string, string, ...string[]]}
            start={{ x: 0, y: 0 }}
            end={{ x: 1, y: 1 }}
            style={containerStyle}
          >
            {renderContent()}
          </LinearGradient>
        </Animated.View>
      </Pressable>
    );
  }

  return (
    <Pressable
      onPress={handlePress}
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
      onLongPress={handleLongPress}
      disabled={isDisabled}
      style={({ pressed }) => [
        { opacity: pressed ? activeOpacity : 1 },
        fullWidth && { width: "100%" },
      ]}
    >
      <Animated.View
        style={[
          containerStyle,
          { transform: [{ scale: scaleAnim }] },
          variant === "primary" && Shadows.md,
          style,
        ]}
      >
        {renderContent()}
      </Animated.View>
    </Pressable>
  );
};

export const IconButton: React.FC<Omit<ButtonProps, "children"> & { icon: React.ReactNode }> = ({
  icon,
