import React, { memo, useCallback } from "react";
import { View, Text, StyleSheet, Image, Pressable, type ViewStyle } from "react-native";
import { DesignTokens } from "../../theme/tokens/design-tokens";
import type { FeedItem } from "../../services/api/recommendation-feed.api";

interface RecommendationCardProps {
  item: FeedItem;
  onPress: (item: FeedItem) => void;
  onLike?: (item: FeedItem) => void;
  style?: ViewStyle;
  compact?: boolean;
}

export const RecommendationCard = memo(function RecommendationCard({
  item,
  onPress,
  onLike,
  style,
  compact = false,
}: RecommendationCardProps) {
  const handlePress = useCallback(() => onPress(item), [item, onPress]);

  const discount =
    item.originalPrice && item.originalPrice > item.price
      ? Math.round((1 - item.price / item.originalPrice) * 100)
      : 0;

  return (
    <Pressable
      style={[styles.card, compact && styles.cardCompact, style]}
      onPress={handlePress}
      accessibilityLabel={`${item.category}鎺ㄨ崘鍟嗗搧`}
      accessibilityRole="button"
    >
      <View style={styles.imageContainer}>
        <Image
          source={{ uri: item.mainImage }}
          style={styles.image as any}
          resizeMode="cover"
          accessibilityIgnoresInvertColors
        />
        {discount > 0 && (
          <View style={styles.discountBadge}>
            <Text style={styles.discountText}>-{discount}%</Text>
          </View>
        )}
        {item.colorHarmony.score >= 85 && (
          <View style={styles.harmonyBadge}>
            <Text style={styles.harmonyText}>{item.colorHarmony.score}%</Text>
          </View>
        )}
      </View>

      <View style={styles.infoContainer}>
        {item.brand && (
          <Text style={styles.brandName} numberOfLines={1}>
            {item.brand.name}
          </Text>
        )}

        {/* Match score with progress bar */}
        <View style={styles.scoreRow}>
          <Text style={styles.scoreLabel}>{item.colorHarmony.score}% 鍖归厤</Text>
          <View style={styles.scoreTrack}>
            <View style={[styles.scoreFill, { width: `${item.colorHarmony.score}%` }]} />
