import React, { useRef } from "react";
import {
  View,
  Text,
  StyleSheet,
  Image,
  Pressable,
  Animated,
  PanResponder,
  type GestureResponderEvent,
  type PanResponderGestureState,
} from "react-native";
import { DesignTokens } from "../../theme/tokens/design-tokens";
import type { FeedItem } from "../../services/api/recommendation-feed.api";

interface SwipeRecommendationCardProps {
  item: FeedItem;
  onLike: (item: FeedItem) => void;
  onDislike: (item: FeedItem) => void;
  onSkip: (item: FeedItem) => void;
}

const SWIPE_THRESHOLD = 100;

export function SwipeRecommendationCard({
  item,
  onLike,
  onDislike,
  onSkip,
}: SwipeRecommendationCardProps) {
  const pan = useRef(new Animated.ValueXY()).current;
  const _rotate = useRef(new Animated.Value(0)).current;

  const panResponder = useRef(
    PanResponder.create({
      onMoveShouldSetPanResponder: () => true,
      onPanResponderMove: Animated.event([null, { dx: pan.x, dy: pan.y }], {
        useNativeDriver: false,
      }),
      onPanResponderRelease: (
        _e: GestureResponderEvent,
        gestureState: PanResponderGestureState
      ) => {
        if (gestureState.dx > SWIPE_THRESHOLD) {
          onLike(item);
        } else if (gestureState.dx < -SWIPE_THRESHOLD) {
          onDislike(item);
        } else if (gestureState.dy < -SWIPE_THRESHOLD) {
          onSkip(item);
        }
        Animated.spring(pan, { toValue: { x: 0, y: 0 }, useNativeDriver: false }).start();
      },
    })
  ).current;

  const likeOpacity = pan.x.interpolate({
    inputRange: [0, SWIPE_THRESHOLD],
    outputRange: [0, 1],
    extrapolate: "clamp",
  });

  const dislikeOpacity = pan.x.interpolate({
    inputRange: [-SWIPE_THRESHOLD, 0],
    outputRange: [1, 0],
    extrapolate: "clamp",
  });

  const cardRotate = pan.x.interpolate({
    inputRange: [-200, 0, 200],
    outputRange: ["-15deg", "0deg", "15deg"],
    extrapolate: "clamp",
  });

  return (
    <Animated.View
      style={[
        styles.card,
        {
          transform: [{ translateX: pan.x }, { translateY: pan.y }, { rotate: cardRotate }],
        },
      ]}
      {...panResponder.panHandlers}
    >
      <Image source={{ uri: item.mainImage }} style={styles.image as any} resizeMode="cover" />

      <Animated.View style={[styles.overlay, styles.likeOverlay, { opacity: likeOpacity }]}>
        <Text style={styles.likeText}>鈾?鍠滄</Text>
      </Animated.View>

      <Animated.View style={[styles.overlay, styles.dislikeOverlay, { opacity: dislikeOpacity }]}>
        <Text style={styles.dislikeText}>鉁?涓嶅枩娆?/Text>
      </Animated.View>

      <View style={styles.infoBar}>
        {item.brand && <Text style={styles.brandName}>{item.brand.name}</Text>}
        <Text style={styles.price}>楼{item.price}</Text>
        <Text style={styles.matchReason}>{item.matchReason}</Text>
      </View>

      <View style={styles.actionHints}>
        <Text style={styles.hintText}>鈫?涓嶅枩娆?/Text>
        <Text style={styles.hintText}>鈫?璺宠繃</Text>
        <Text style={styles.hintText}>鍠滄 鈫?/Text>
      </View>
    </Animated.View>
  );
}

