export interface ThemeSettingsSheetProps {
  visible: boolean;
  onClose: () => void;
}

export const ThemeSettingsSheet: React.FC<ThemeSettingsSheetProps> = ({ visible, onClose }) => {
  const { theme, themeMode, setThemeMode, isDark } = useTheme();
  const translateY = useSharedValue(SCREEN_WIDTH);
  const backdropOpacity = useSharedValue(0);

  useEffect(() => {
    if (visible) {
      translateY.value = withSpring(0, { damping: 20, stiffness: 200 });
      backdropOpacity.value = withTiming(0.5, { duration: 300 });
    } else {
      translateY.value = withTiming(SCREEN_WIDTH, { duration: 250 });
      backdropOpacity.value = withTiming(0, { duration: 200 });
    }
  }, [visible]);

  const sheetAnimatedStyle = useAnimatedStyle(() => ({
    transform: [{ translateY: translateY.value }],
  }));

  const backdropAnimatedStyle = useAnimatedStyle(() => ({
    opacity: backdropOpacity.value,
  }));

  const themeOptions: { mode: ThemeMode; label: string; icon: string }[] = [
    { mode: "light", label: "娴呰壊", icon: "sunny" },
    { mode: "dark", label: "娣辫壊", icon: "moon" },
    { mode: "system", label: "璺熼殢绯荤粺", icon: "phone-portrait" },
  ];

  if (!visible) {
    return null;
  }

  return (
    <View style={StyleSheet.absoluteFill}>
      <AnimatedPressable style={[styles.backdrop, backdropAnimatedStyle]} onPress={onClose} />
      <AnimatedView
        style={[styles.sheet, { backgroundColor: theme.colors.surface }, sheetAnimatedStyle]}
      >
        <View style={styles.sheetHandle} />
        <Text style={[styles.sheetTitle, { color: theme.colors.text }]}>澶栬璁剧疆</Text>

        <View style={styles.themeOptions}>
          {themeOptions.map((option) => {
            const isSelected = themeMode === option.mode;
            const effectiveDark = option.mode === "system" ? isDark : option.mode === "dark";

            return (
              <TouchableOpacity
                key={option.mode}
                style={[
                  styles.themeOption,
                  { backgroundColor: theme.colors.surfaceSecondary },
                  isSelected && {
                    borderColor: theme.colors.primary,
                    borderWidth: 2,
                  },
                ]}
                onPress={() => setThemeMode(option.mode)}
              >
                <View
                  style={[
                    styles.themeOptionIcon,
                    {
                      backgroundColor: effectiveDark ? theme.colors.primary : theme.colors.border,
                    },
                  ]}
                >
                  <Ionicons
                    name={option.icon as ThemeIoniconsIconName}
                    size={20}
                    color={effectiveDark ? "#fff" : theme.colors.textSecondary}
                  />
                </View>
                <Text style={[styles.themeOptionLabel, { color: theme.colors.text }]}>
                  {option.label}
                </Text>
                {isSelected && (
                  <View style={[styles.checkMark, { backgroundColor: theme.colors.primary }]}>
                    <Ionicons name="checkmark" size={12} color="#fff" />
                  </View>
                )}
              </TouchableOpacity>
            );
          })}
        </View>

        <AccentColorPicker style={styles.accentSection} />
      </AnimatedView>
    </View>
  );
};

