      snapPoints={snapPoints}
      backdropComponent={renderBackdrop}
      onAnimate={handleAnimate}
      enablePanDownToClose
      handleIndicatorStyle={styles.handleIndicator}
      backgroundStyle={styles.background}
    >
      <BottomSheetView style={styles.shareContent}>
        <Text style={styles.shareTitle}>鍒嗕韩鍒?/Text>
        <View style={styles.shareGrid}>
          {platforms.map((platform) => (
            <TouchableOpacity
              key={platform.id}
              style={styles.shareItem}
              onPress={() => onShare?.(platform.id)}
              activeOpacity={0.7}
            >
              <View style={styles.shareIconContainer}>
                <Text style={styles.shareIcon}>{platform.icon}</Text>
              </View>
              <Text style={styles.shareName}>{platform.name}</Text>
            </TouchableOpacity>
          ))}
        </View>
        <TouchableOpacity style={styles.cancelButton} onPress={onClose}>
          <Text style={styles.cancelText}>鍙栨秷</Text>
        </TouchableOpacity>
      </BottomSheetView>
    </BottomSheetModal>
  );
}

