import React from "react";
import {
  TouchableOpacity,
  Text,
  StyleSheet,
  ViewStyle,
  TextStyle,
  ActivityIndicator,
} from "react-native";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import { LinearGradient } from "@/src/polyfills/expo-linear-gradient";
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  withSequence,
  withTiming,
} from "react-native-reanimated";

// 寮曞叆涓婚浠ょ墝
import { colors } from "../../theme/tokens/colors";
import { typography } from "../../theme/tokens/typography";
import { spacing } from "../../theme/tokens/spacing";
import { shadows } from "../../theme/tokens/shadows";

interface GradientButtonProps {
  title: string;
  onPress: () => void;
  variant?: "primary" | "secondary" | "success" | "ocean";
  size?: "small" | "medium" | "large";
  disabled?: boolean;
  loading?: boolean;
  icon?: string; // Ionicons name
  fullWidth?: boolean;
  style?: ViewStyle;
}

/**
 * GradientButton - 鍥借禌涓€绛夊姘村噯娓愬彉鎸夐挳
 *
 * 璁捐鐗圭偣锛歕n * - 澶氱娓愬彉閰嶈壊鏂规锛堢強鐟氱矇/钖勮嵎缁?娣辨捣钃濓級
 * - 鎸夊帇鍔ㄧ敾鍙嶉 (scale 0.95)
 * - 鍔犺浇鐘舵€佹寚绀哄櫒
 * - 鍥炬爣鏀寔
 * - 3绉嶅昂瀵歌鏍糪n */
export const GradientButton: React.FC<GradientButtonProps> = ({
  title,
  onPress,
  variant = "primary",
  size = "medium",
  disabled = false,
  loading = false,
  icon,
  fullWidth = true,
  style,
}) => {
  // 鍔ㄧ敾鍊糪n  const scaleValue = useSharedValue(1);

  // 娓愬彉閰嶈壊鏄犲皠
  const gradientColors = {
    primary: [colors.warmPrimary.coral[500], colors.warmPrimary.coral[600]],
    secondary: [colors.warmPrimary.mint[500], colors.warmPrimary.mint[600]],
    success: ["#51CF66", "#40C057"],
    ocean: [colors.warmPrimary.ocean[500], colors.warmPrimary.ocean[600]],
  };

  // 灏哄閰嶇疆
  const sizeConfig = {
    small: {
      paddingVertical: 10,
      paddingHorizontal: 16,
      fontSize: typography.fontSize.sm,
      borderRadius: spacing.borderRadius.lg,
    },
    medium: {
      paddingVertical: 14,
      paddingHorizontal: 20,
      fontSize: typography.fontSize.base,
      borderRadius: spacing.borderRadius.xl,
    },
    large: {
      paddingVertical: 16,
      paddingHorizontal: 24,
      fontSize: typography.fontSize.lg,
      borderRadius: spacing.borderRadius.xl,
    },
  };

  // 鎸夊帇鍔ㄧ敾鏍峰紡
  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ scale: scaleValue.value }],
  }));

  // 澶勭悊鎸夊帇浜嬩欢
  const handlePressIn = () => {
    if (!disabled && !loading) {
      scaleValue.value = withSpring(0.95, { damping: 15, stiffness: 400 });
    }
  };

  const handlePressOut = () => {
    if (!disabled && !loading) {
      scaleValue.value = withSpring(1, { damping: 15, stiffness: 400 });
    }
  };

  return (
    <Animated.View style={[animatedStyle, fullWidth && styles.fullWidth, style]}>
      <TouchableOpacity
        onPress={onPress}
        onPressIn={handlePressIn}
        onPressOut={handlePressOut}
        activeOpacity={0.9}
        disabled={disabled || loading}
        style={[styles.button, sizeConfig[size], disabled && styles.disabled]}
      >
        <LinearGradient
          colors={gradientColors[variant] as [string, string]}
          start={{ x: 0, y: 0 }}
          end={{ x: 1, y: 1 }}
          style={styles.gradient}
        >
          {loading ? (
            <ActivityIndicator size="small" color="#FFFFFF" />
          ) : (
            <>
              {icon && <Ionicons name={icon} size={size === "small" ? 18 : 20} color="#FFFFFF" />}
              <Text style={[styles.title, { fontSize: sizeConfig[size].fontSize }]}>{title}</Text>
            </>
          )}
        </LinearGradient>
      </TouchableOpacity>
    </Animated.View>
  );
};

const styles = StyleSheet.create({
  button: {
    overflow: "hidden",
    ...shadows.presets.md,
  },
  gradient: {
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "center",
    gap: 8,
  },
  title: {
    fontWeight: typography.fontWeight.bold,
    color: "#FFFFFF",
  },
  fullWidth: {
    width: "100%",
  },
  disabled: {
    opacity: 0.5,
  },
});

export default GradientButton;

import React from "react";
import {
  View,
  TextInput,
  Text,
  StyleSheet,
  Animated,
  ViewStyle,
  TextStyle,
  TextInputProps,
  Pressable,
  Platform,
} from "react-native";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import * as Haptics from "@/src/polyfills/expo-haptics";
import { Colors, Spacing, BorderRadius, Typography } from "../../theme";

export type InputVariant = "outlined" | "filled" | "underline";
export type InputSize = "sm" | "md" | "lg";

export interface InputProps extends Omit<TextInputProps, "style"> {
  variant?: InputVariant;
  size?: InputSize;
  label?: string;
  error?: string;
  hint?: string;
  leftIcon?: React.ReactNode;
  rightIcon?: React.ReactNode;
  leftIconName?: keyof typeof Ionicons.glyphMap;
  rightIconName?: keyof typeof Ionicons.glyphMap;
  onRightIconPress?: () => void;
  containerStyle?: ViewStyle;
  inputStyle?: TextStyle;
  disabled?: boolean;
  required?: boolean;
  hapticFeedback?: boolean;
}

const sizeConfig: Record<
  InputSize,
  { height: number; fontSize: number; paddingHorizontal: number }
> = {
  sm: { height: 40, fontSize: Typography.sizes.sm, paddingHorizontal: Spacing.md },
  md: { height: 48, fontSize: Typography.sizes.base, paddingHorizontal: Spacing.lg },
  lg: { height: 56, fontSize: Typography.sizes.base, paddingHorizontal: Spacing.xl },
};

export const Input: React.FC<InputProps> = ({
  variant = "outlined",
  size = "md",
  label,
  error,
  hint,
  leftIcon,
  rightIcon,
  leftIconName,
  rightIconName,
  onRightIconPress,
  containerStyle,
  inputStyle,
  disabled = false,
  required = false,
  hapticFeedback = true,
  onFocus,
  onBlur,
  ...textInputProps
}) => {
  const [isFocused, setIsFocused] = React.useState(false);
  const [hasValue, setHasValue] = React.useState(
    !!textInputProps.value || !!textInputProps.defaultValue
  );

  const labelAnim = React.useRef(new Animated.Value(hasValue || isFocused ? 1 : 0)).current;
  const borderAnim = React.useRef(new Animated.Value(0)).current;
  const shakeAnim = React.useRef(new Animated.Value(0)).current;

  React.useEffect(() => {
    Animated.timing(labelAnim, {
      toValue: isFocused || hasValue ? 1 : 0,
      duration: 200,
      useNativeDriver: false,
    }).start();
  }, [isFocused, hasValue, labelAnim]);

  React.useEffect(() => {
    Animated.timing(borderAnim, {
      toValue: isFocused ? 1 : 0,
      duration: 200,
      useNativeDriver: false,
    }).start();
  }, [isFocused, borderAnim]);

  React.useEffect(() => {
    if (error) {
      Animated.sequence([
        Animated.timing(shakeAnim, { toValue: 10, duration: 50, useNativeDriver: true }),
        Animated.timing(shakeAnim, { toValue: -10, duration: 50, useNativeDriver: true }),
        Animated.timing(shakeAnim, { toValue: 10, duration: 50, useNativeDriver: true }),
        Animated.timing(shakeAnim, { toValue: 0, duration: 50, useNativeDriver: true }),
      ]).start();
      if (hapticFeedback && Platform.OS !== "web") {
        Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
      }
    }
  }, [error, shakeAnim, hapticFeedback]);

  const handleFocus = (e: any) => {
    setIsFocused(true);
    if (hapticFeedback && Platform.OS !== "web") {
      Haptics.selectionAsync();
    }
    onFocus?.(e);
  };

  const handleBlur = (e: any) => {
    setIsFocused(false);
    onBlur?.(e);
  };

  const handleChangeText = (text: string) => {
    setHasValue(!!text);
    textInputProps.onChangeText?.(text);
  };

  const config = sizeConfig[size];
  const borderColor = error
    ? Colors.semantic.error
    : isFocused
    ? Colors.primary[500]
    : Colors.neutral[200];

  const getVariantStyle = (): ViewStyle => {
    switch (variant) {
      case "outlined":
        return {
          borderWidth: 1.5,
          borderColor,
          backgroundColor: Colors.neutral.white,
          borderRadius: BorderRadius.xl,
        };
      case "filled":
        return {
          borderWidth: 0,
          backgroundColor: isFocused ? Colors.neutral[100] : Colors.neutral[50],
          borderRadius: BorderRadius.xl,
        };
      case "underline":
        return {
          borderWidth: 0,
          borderBottomWidth: 1.5,
          borderColor,
          backgroundColor: "transparent",
          borderRadius: 0,
        };
      default:
        return {};
    }
  };

  const labelStyle: any = {
    position: "absolute",
    left: config.paddingHorizontal + (leftIcon || leftIconName ? 32 : 0),
    top: labelAnim.interpolate({ inputRange: [0, 1], outputRange: [config.height / 2 - 8, 6] }),
    fontSize: labelAnim.interpolate({ inputRange: [0, 1], outputRange: [config.fontSize, 12] }),
    color: labelAnim.interpolate({
      inputRange: [0, 1],
      outputRange: [Colors.neutral[400], error ? Colors.semantic.error : Colors.primary[500]],
    }),
    backgroundColor: variant === "outlined" ? Colors.neutral.white : "transparent",
    paddingHorizontal: labelAnim.interpolate({ inputRange: [0, 1], outputRange: [0, 4] }),
    fontWeight: "500",
    zIndex: 1,
  };

  return (
    <Animated.View
      style={[styles.container, { transform: [{ translateX: shakeAnim }] }, containerStyle]}
    >
      {label && (
        <Animated.Text style={labelStyle}>
          {label}
          {required && <Text style={styles.required}> *</Text>}
        </Animated.Text>
      )}
      <View style={[styles.inputContainer, { height: config.height }, getVariantStyle()]}>
        {(leftIcon || leftIconName) && (
          <View style={styles.leftIconContainer}>
            {leftIcon || (
              <Ionicons
                name={leftIconName!}
                size={20}
                color={isFocused ? Colors.primary[500] : Colors.neutral[400]}
              />
            )}
          </View>
        )}
        <TextInput
          {...textInputProps}
          style={StyleSheet.flatten([
            styles.input,
            {
              fontSize: config.fontSize,
              paddingHorizontal: config.paddingHorizontal,
              paddingTop: label ? Spacing.md : 0,
            },
            leftIcon || leftIconName ? { paddingLeft: 0 } : null,
            rightIcon || rightIconName ? { paddingRight: 0 } : null,
            disabled && styles.disabled,
            inputStyle,
          ])}
          placeholderTextColor={Colors.neutral[400]}
          editable={!disabled}
          onFocus={handleFocus}
          onBlur={handleBlur}
          onChangeText={handleChangeText}
        />
        {(rightIcon || rightIconName) && (
          <Pressable
            onPress={onRightIconPress}
            style={styles.rightIconContainer}
            disabled={!onRightIconPress}
          >
            {rightIcon || (
              <Ionicons
                name={rightIconName!}
                size={20}
                color={onRightIconPress ? Colors.neutral[600] : Colors.neutral[400]}
              />
            )}
          </Pressable>
        )}
      </View>
      {(error || hint) && (
        <View style={styles.hintContainer}>
          <Text style={[styles.hintText, error && styles.errorText]}>{error || hint}</Text>
        </View>
      )}
    </Animated.View>
  );
};

