export interface ModernButtonProps {
  title: string;
  onPress: () => void;
  variant?: "primary" | "secondary" | "outline" | "ghost" | "gradient";
  size?: "sm" | "md" | "lg" | "xl";
  disabled?: boolean;
  loading?: boolean;
  icon?: React.ReactNode;
  iconPosition?: "left" | "right";
  fullWidth?: boolean;
  style?: ViewStyle;
}

export const ModernButton: React.FC<ModernButtonProps> = ({
  title,
  onPress,
  variant = "primary",
  size = "lg",
  disabled = false,
  loading = false,
  icon,
  iconPosition = "left",
  fullWidth = false,
  style,
}) => {
  const scaleAnim = React.useRef(new Animated.Value(1)).current;

  const handlePressIn = () => {
    Animated.spring(scaleAnim, {
      toValue: 0.96,
      useNativeDriver: true,
      ...{ damping: 15, stiffness: 300 },
    }).start();
  };

  const handlePressOut = () => {
    Animated.spring(scaleAnim, {
      toValue: 1,
      useNativeDriver: true,
      ...{ damping: 15, stiffness: 300 },
    }).start();
  };

  const sizeStyles = {
    sm: { height: 36, paddingHorizontal: Spacing[4] },
    md: { height: 44, paddingHorizontal: Spacing[5] },
    lg: { height: 52, paddingHorizontal: Spacing[6] },
    xl: { height: 60, paddingHorizontal: Spacing[8] },
  };

  const variantStyles: Record<string, ViewStyle> = {
    primary: {
      backgroundColor: Colors.primary[600],
    },
    secondary: {
      backgroundColor: Colors.neutral[100],
    },
    outline: {
      backgroundColor: "transparent",
      borderWidth: 2,
      borderColor: Colors.primary[500],
    },
    ghost: {
      backgroundColor: "transparent",
    },
    gradient: {
      backgroundColor: "transparent",
    },
  };

  const textStyles: Record<string, TextStyle> = {
    primary: { color: Colors.white },
    secondary: { color: Colors.neutral[800] },
    outline: { color: Colors.primary[600] },
    ghost: { color: Colors.primary[600] },
    gradient: { color: Colors.white },
  };

  const buttonContent = (
    <View style={styles.buttonContent}>
      {icon && iconPosition === "left" && <View style={styles.buttonIcon}>{icon}</View>}
      <Text style={[Typography.styles.button, textStyles[variant]]}>
        {loading ? "鍔犺浇涓?.." : title}
      </Text>
      {icon && iconPosition === "right" && <View style={styles.buttonIcon}>{icon}</View>}
    </View>
  );

  if (variant === "gradient") {
    return (
      <TouchableOpacity
        onPress={onPress}
        onPressIn={handlePressIn}
        onPressOut={handlePressOut}
        disabled={disabled || loading}
        activeOpacity={0.9}
        style={[fullWidth && styles.fullWidth, style]}
      >
        <Animated.View style={{ transform: [{ scale: scaleAnim }] }}>
          <LinearGradient
            colors={[...Colors.gradient.primary]}
            start={{ x: 0, y: 0 }}
            end={{ x: 1, y: 0 }}
            style={[styles.button, sizeStyles[size], { borderRadius: BorderRadius.xl }]}
          >
            {buttonContent}
          </LinearGradient>
        </Animated.View>
      </TouchableOpacity>
    );
  }

  return (
    <TouchableOpacity
      onPress={onPress}
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
      disabled={disabled || loading}
      activeOpacity={0.8}
      style={[
        styles.button,
        sizeStyles[size],
        variantStyles[variant],
        { borderRadius: BorderRadius.xl },
        fullWidth && styles.fullWidth,
        style,
      ]}
    >
      <Animated.View style={{ transform: [{ scale: scaleAnim }] }}>{buttonContent}</Animated.View>
    </TouchableOpacity>
  );
};

export interface ProductCardProps {
  id: string;
  name: string;
  price: number;
  originalPrice?: number;
  image: string;
  brand?: string;
  rating?: number;
  reviewCount?: number;
  tags?: string[];
  onPress: () => void;
  onFavorite?: () => void;
  isFavorite?: boolean;
}

export const ProductCard: React.FC<ProductCardProps> = ({
  name,
  price,
  originalPrice,
  image,
  brand,
  rating,
  reviewCount,
  tags,
  onPress,
  onFavorite,
  isFavorite = false,
}) => {
  const scaleAnim = React.useRef(new Animated.Value(1)).current;
  const favoriteAnim = React.useRef(new Animated.Value(1)).current;

  const handlePressIn = () => {
    Animated.spring(scaleAnim, {
      toValue: 0.97,
      useNativeDriver: true,
      ...{ damping: 15, stiffness: 300 },
    }).start();
  };

  const handlePressOut = () => {
    Animated.spring(scaleAnim, {
      toValue: 1,
      useNativeDriver: true,
      ...{ damping: 15, stiffness: 300 },
    }).start();
  };

  const handleFavorite = () => {
    Animated.sequence([
      Animated.spring(favoriteAnim, {
        toValue: 1.3,
        useNativeDriver: true,
        ...{ damping: 10, stiffness: 400 },
      }),
      Animated.spring(favoriteAnim, {
        toValue: 1,
        useNativeDriver: true,
        ...{ damping: 10, stiffness: 400 },
      }),
    ]).start();
    onFavorite?.();
  };

  const discount = originalPrice ? Math.round((1 - price / originalPrice) * 100) : 0;

  return (
    <TouchableOpacity
      onPress={onPress}
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
      activeOpacity={0.95}
      style={styles.productCardContainer}
    >
      <Animated.View style={[styles.productCard, { transform: [{ scale: scaleAnim }] }]}>
        <View style={styles.productImageContainer}>
          <View style={styles.productImagePlaceholder}>
            <Text style={styles.productImageEmoji}>馃憲</Text>
          </View>
          {discount > 0 && (
            <View style={styles.discountBadge}>
              <Text style={styles.discountText}>-{discount}%</Text>
            </View>
          )}
          {onFavorite && (
            <TouchableOpacity
              onPress={handleFavorite}
              style={styles.favoriteButton}
              activeOpacity={0.7}
            >
              <Animated.View style={{ transform: [{ scale: favoriteAnim }] }}>
                <Text style={styles.favoriteIcon}>{isFavorite ? "鉂わ笍" : "馃"}</Text>
              </Animated.View>
            </TouchableOpacity>
          )}
        </View>

        <View style={styles.productInfo}>
          {brand && (
            <Text style={styles.productBrand} numberOfLines={1}>
              {brand}
            </Text>
          )}
          <Text style={styles.productName} numberOfLines={2}>
            {name}
          </Text>

          {rating !== undefined && (
            <View style={styles.ratingContainer}>
              <Text style={styles.ratingStar}>猸?/Text>
              <Text style={styles.ratingText}>{rating.toFixed(1)}</Text>
              {reviewCount !== undefined && <Text style={styles.reviewCount}>({reviewCount})</Text>}
            </View>
          )}

          <View style={styles.priceContainer}>
            <Text style={styles.productPrice}>楼{price}</Text>
            {originalPrice && <Text style={styles.originalPrice}>楼{originalPrice}</Text>}
          </View>

          {tags && tags.length > 0 && (
            <View style={styles.tagsContainer}>
              {tags.slice(0, 2).map((tag, index) => (
                <View key={index} style={styles.tag}>
                  <Text style={styles.tagText}>{tag}</Text>
                </View>
              ))}
            </View>
          )}
        </View>
      </Animated.View>
    </TouchableOpacity>
  );
};

