interface ProductCardProps {
  item: Product;
  onPress?: () => void;
  onFavorite?: () => void;
  isFavorite?: boolean;
}

const ProductCard = memo(function ProductCard({
  item,
  onPress,
  onFavorite,
  isFavorite = false,
}: ProductCardProps) {
  const discount = item.originalPrice
    ? Math.round((1 - item.price / item.originalPrice) * 100)
    : item.discount || 0;

  return (
    <TouchableOpacity
      style={styles.card}
      onPress={() => onPress?.() || router.push(`/clothing/${item.id}`)}
      activeOpacity={0.9}
    >
      <View style={styles.imageContainer}>
        {item.image ? (
          <Image source={{ uri: item.image }} style={styles.image} resizeMode="cover" />
        ) : (
          <LinearGradient colors={["#f3e8ff", "#fae8ff", "#fce7f3"]} style={styles.image}>
            <Text style={styles.imageEmoji}>馃憲</Text>
          </LinearGradient>
        )}
        {onFavorite && (
          <TouchableOpacity style={styles.favoriteButton} onPress={onFavorite} activeOpacity={0.7}>
            <Text style={styles.favoriteIcon}>{isFavorite ? "鉂わ笍" : "馃"}</Text>
          </TouchableOpacity>
        )}
        {discount > 0 && (
          <View style={styles.discountTag}>
            <Text style={styles.discountText}>-{discount}%</Text>
          </View>
        )}
      </View>

      <View style={styles.content}>
        {item.category && <Text style={styles.category}>{item.category}</Text>}
        <Text style={styles.name} numberOfLines={2}>
          {item.name}
        </Text>
        <View style={styles.ratingRow}>
