}

export function ProductGrid({
  products,
  onItemPress,
  onFavorite,
  favorites,
  loading = false,
  onEndReached,
}: ProductGridProps) {
  const renderItem = useCallback(
    ({ item }: { item: Product }) => (
      <ProductCard
        item={item}
        onPress={() => onItemPress?.(item)}
        onFavorite={() => onFavorite?.(item)}
        isFavorite={favorites?.has(item.id)}
