import React, { useState, useCallback, useRef } from "react";
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Animated,
  PanResponder,
  GestureResponderEvent,
  PanResponderGestureState,
} from "react-native";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import { theme } from "../../theme";

interface DragSortItem {
  id: string;
  [key: string]: unknown;
}

interface DragSortListProps<T extends DragSortItem> {
  data: T[];
  renderItem: (item: T, index: number) => React.ReactNode;
  onReorder: (newData: T[]) => void;
  keyExtractor: (item: T) => string;
  itemHeight?: number;
}

function DragSortList<T extends DragSortItem>({
  data,
  renderItem,
  onReorder,
  keyExtractor,
  itemHeight = 72,
}: DragSortListProps<T>) {
  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  const [localData, setLocalData] = useState<T[]>(data);
  const panY = useRef(new Animated.Value(0)).current;
  const itemAnimations = useRef<Animated.Value[]>(data.map(() => new Animated.Value(0))).current;

  // Sync local data when prop changes
  React.useEffect(() => {
    setLocalData(data);
    // Ensure animations array matches data length
    while (itemAnimations.length < data.length) {
      itemAnimations.push(new Animated.Value(0));
    }
  }, [data]);

  const moveItem = useCallback(
    (fromIndex: number, toIndex: number) => {
      const newData = [...localData];
      const [movedItem] = newData.splice(fromIndex, 1);
      newData.splice(toIndex, 0, movedItem);
      setLocalData(newData);
      onReorder(newData);
    },
    [localData, onReorder]
  );

  const createPanResponder = useCallback(
    (index: number) =>
      PanResponder.create({
        onStartShouldSetPanResponder: () => false,
        onMoveShouldSetPanResponder: (
          _: GestureResponderEvent,
          gestureState: PanResponderGestureState
        ) => {
          return Math.abs(gestureState.dy) > 10;
        },
        onPanResponderGrant: () => {
          setActiveIndex(index);
          panY.setValue(0);
          Animated.spring(itemAnimations[index], {
            toValue: 1,
            useNativeDriver: true,
            tension: 150,
            friction: 10,
          }).start();
        },
        onPanResponderMove: (_: GestureResponderEvent, gestureState: PanResponderGestureState) => {
          panY.setValue(gestureState.dy);

          // Calculate potential new position
          const currentY = index * itemHeight + gestureState.dy;
          const newIndex = Math.max(
            0,
            Math.min(localData.length - 1, Math.round(currentY / itemHeight))
          );

          if (newIndex !== index) {
            // Animate other items to make room
            localData.forEach((_, i) => {
              if (i === index) {
                return;
              }
              const targetOffset =
                i >= Math.min(index, newIndex) && i <= Math.max(index, newIndex)
                  ? i < newIndex
                    ? -itemHeight
                    : itemHeight
                  : 0;
              Animated.spring(itemAnimations[i], {
                toValue: targetOffset !== 0 ? 0.5 : 0,
                useNativeDriver: true,
                tension: 200,
                friction: 15,
              }).start();
            });
          }
        },
        onPanResponderRelease: (
          _: GestureResponderEvent,
          gestureState: PanResponderGestureState
        ) => {
          const currentY = index * itemHeight + gestureState.dy;
          const newIndex = Math.max(
            0,
            Math.min(localData.length - 1, Math.round(currentY / itemHeight))
          );

          // Reset all animations
          itemAnimations.forEach((anim) => {
            Animated.spring(anim, {
              toValue: 0,
              useNativeDriver: true,
              tension: 200,
              friction: 15,
            }).start();
          });

          if (newIndex !== index) {
            moveItem(index, newIndex);
          }

          setActiveIndex(null);
          panY.setValue(0);
        },
      }),
    [localData, itemHeight, moveItem, panY, itemAnimations]
  );

  // Pan responders need to be recreated when data changes
  const panResponders = useRef<Map<number, ReturnType<typeof PanResponder.create>>>(
    new Map()
  ).current;

  localData.forEach((_, index) => {
    if (!panResponders.has(index)) {
      panResponders.set(index, createPanResponder(index));
    }
  });

  return (
    <View style={styles.container}>
      {localData.map((item, index) => {
        const responder = panResponders.get(index);
        const isActive = activeIndex === index;

        const animatedStyle = {
          transform: [
            {
              scale: itemAnimations[index].interpolate({
                inputRange: [0, 1],
                outputRange: [1, 1.05],
              }),
            },
            {
              translateY: isActive
                ? panY
                : itemAnimations[index].interpolate({
                    inputRange: [0, 0.5, 1],
                    outputRange: [0, itemHeight * 0.3, itemHeight],
                  }),
            },
          ],
          opacity: itemAnimations[index].interpolate({
            inputRange: [0, 1],
            outputRange: [1, 0.9],
          }),
          zIndex: isActive ? 10 : 1,
          elevation: isActive ? 8 : 2,
        };

        return (
          <Animated.View
            key={keyExtractor(item)}
            style={[styles.itemWrapper, animatedStyle, { height: itemHeight }]}
            {...(responder?.panHandlers ?? {})}
          >
            {renderItem(item, index)}
          </Animated.View>
        );
      })}
    </View>
  );
}

export interface CollectionItem {
  id: string;
  name: string;
  icon: string;
  itemCount: number;
}

interface CollectionDragListProps {
  collections: CollectionItem[];
  onReorder: (collections: CollectionItem[]) => void;
  onEdit?: (id: string) => void;
  onDelete?: (id: string) => void;
  onPress?: (id: string) => void;
}

export const CollectionDragList: React.FC<CollectionDragListProps> = ({
  collections,
  onReorder,
  onEdit,
  onDelete,
  onPress,
}) => {
  const renderCollectionItem = useCallback(
    (item: CollectionItem) => (
      <TouchableOpacity
        style={collectionStyles.card}
        onPress={() => onPress?.(item.id)}
        activeOpacity={0.7}
      >
        <View style={collectionStyles.dragHandle}>
          <Ionicons name="reorder-three-outline" size={20} color={theme.colors.textTertiary} />
        </View>
        <View style={collectionStyles.iconContainer}>
          <Ionicons name={item.icon as "folder"} size={22} color="#6C5CE7" />
        </View>
        <View style={collectionStyles.info}>
          <Text style={collectionStyles.name}>{item.name}</Text>
          <Text style={collectionStyles.count}>{item.itemCount} 涓唴瀹?/Text>
        </View>
        <View style={collectionStyles.actions}>
          {onEdit && (
            <TouchableOpacity style={collectionStyles.actionBtn} onPress={() => onEdit(item.id)}>
              <Ionicons name="create-outline" size={18} color={theme.colors.textSecondary} />
            </TouchableOpacity>
          )}
          {onDelete && (
            <TouchableOpacity style={collectionStyles.actionBtn} onPress={() => onDelete(item.id)}>
              <Ionicons name="trash-outline" size={18} color={theme.colors.error} />
            </TouchableOpacity>
          )}
        </View>
      </TouchableOpacity>
    ),
    [onEdit, onDelete, onPress]
  );

  return (
    <DragSortList<CollectionItem & { [key: string]: unknown }>
      data={collections as (CollectionItem & { [key: string]: unknown })[]}
      renderItem={renderCollectionItem}
      onReorder={onReorder}
      keyExtractor={(item) => item.id}
      itemHeight={72}
    />
  );
};

const styles = StyleSheet.create({
  container: {
    position: "relative",
  },
  itemWrapper: {
    position: "relative",
    backgroundColor: theme.colors.surface,
    borderRadius: 12,
    marginVertical: 4,
    shadowColor: "#000",
    shadowOffset: { width: 0, height: 1 },
    shadowOpacity: 0.05,
    shadowRadius: 3,
  },
});

const collectionStyles = StyleSheet.create({
  card: {
    flex: 1,
    flexDirection: "row",
    alignItems: "center",
    paddingHorizontal: 12,
    gap: 10,
  },
  dragHandle: {
    padding: 4,
  },
  iconContainer: {
    width: 40,
    height: 40,
    borderRadius: 10,
    backgroundColor: "#F0EDFF",
    alignItems: "center",
    justifyContent: "center",
  },
  info: { flex: 1 },
  name: { fontSize: 14, fontWeight: "600", color: theme.colors.text },
  count: { fontSize: 12, color: theme.colors.textTertiary, marginTop: 2 },
  actions: { flexDirection: "row", gap: 4 },
  actionBtn: { padding: 8 },
});

export default DragSortList;

import React, { useState, useEffect, useCallback } from "react";
import {
  View,
  Text,
  StyleSheet,
  ScrollView,
  TouchableOpacity,
  Image,
  ActivityIndicator,
  Alert,
  Modal,
  FlatList,
} from "react-native";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import { theme } from "../../theme";
import { communityApi } from "../../services/api/community.api";

type ImportSource = "community" | "ai_stylist" | "tryon";

interface ImportItem {
  id: string;
  name: string;
  image: string;
  selected: boolean;
}

interface Collection {
  id: string;
  name: string;
  itemCount: number;
}

interface ImportSheetProps {
  visible: boolean;
  source?: ImportSource;
  sourceData?: {
    postId?: string;
    sessionId?: string;
    tryOnId?: string;
    images?: string[];
    items?: { id: string; name: string; image: string }[];
  };
  onClose: () => void;
  onImported?: () => void;
}

const SOURCE_LABELS: Record<ImportSource, string> = {
  community: "绀惧尯甯栧瓙",
  ai_stylist: "AI閫犲瀷甯堟柟妗圽

people-outline",
  ai_stylist: "sparkles-outline",
  tryon: "shirt-outline",
};

export const ImportSheet: React.FC<ImportSheetProps> = ({
  visible,
  source,
  sourceData,
  onClose,
  onImported,
}) => {
  const [activeSource, setActiveSource] = useState<ImportSource>(source ?? "community");
  const [items, setItems] = useState<ImportItem[]>([]);
  const [collections, setCollections] = useState<Collection[]>([]);
  const [selectedCollectionId, setSelectedCollectionId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [importing, setImporting] = useState(false);

  useEffect(() => {
    if (visible) {
      if (source) {
        setActiveSource(source);
      }
      void fetchItems();
      void fetchCollections();
    }
  }, [visible, source]);

  const fetchItems = useCallback(async () => {
    if (sourceData?.items) {
      setItems(
        sourceData.items.map((item) => ({
          id: item.id,
          name: item.name,
          image: item.image,
          selected: true,
        }))
      );
      return;
    }

    // Default items for source types
    setLoading(true);
    try {
      if (activeSource === "community" && sourceData?.postId) {
        const response = await communityApi.getPostById(sourceData.postId);
        if (response.success && response.data) {
          const relatedItems = response.data.outfit?.items ?? [];
          setItems(
            relatedItems.map((item) => ({
              id: item.id,
              name: item.name,
              image: item.image,
              selected: true,
            }))
          );
        }
      } else {
        // For AI stylist and tryon, use placeholder items
        setItems([]);
      }
    } catch {
      setItems([]);
    } finally {
      setLoading(false);
    }
  }, [activeSource, sourceData]);

  const fetchCollections = useCallback(async () => {
    try {
      const response = await communityApi.getCollections?.();
      if (response && response.success && response.data) {
        const cols = Array.isArray(response.data) ? response.data : [];
        setCollections(
          cols.map((c: { id?: string; name?: string; _count?: { items?: number } }) => ({
            id: c.id ?? "",
            name: c.name ?? "",
            itemCount: c._count?.items ?? 0,
          }))
        );
        if (cols.length > 0) {
          setSelectedCollectionId(cols[0].id ?? null);
        }
      }
    } catch {
      // Collections loading failure is non-critical
    }
  }, []);

  const toggleItem = useCallback((id: string) => {
    setItems((prev) =>
      prev.map((item) => (item.id === id ? { ...item, selected: !item.selected } : item))
    );
  }, []);

  const handleImport = useCallback(async () => {
    const selectedItems = items.filter((item) => item.selected);
    if (selectedItems.length === 0) {
      Alert.alert("鎻愮ず", "璇疯嚦灏戦€夋嫨涓€涓崟鍝乗

鎴愬姛", `宸插鍏?${selectedItems.length} 涓崟鍝佸埌鐏垫劅琛ｆ┍`);
      onImported?.();
      onClose();
    } catch {
      Alert.alert("鎻愮ず", "瀵煎叆澶辫触锛岃閲嶈瘯");
    } finally {
      setImporting(false);
    }
  }, [items, selectedCollectionId, onImported, onClose]);

  if (!visible) {
    return null;
  }

  return (
    <Modal visible={visible} transparent animationType="slide" onRequestClose={onClose}>
      <View style={styles.overlay}>
        <TouchableOpacity style={styles.backdrop} onPress={onClose} />
        <View style={styles.sheet}>
          <View style={styles.handle} />
          <Text style={styles.title}>瀵煎叆鍒扮伒鎰熻。姗?/Text>

          {/* Source selector */}
          {!source && (
            <View style={styles.sourceRow}>
              {(Object.keys(SOURCE_LABELS) as ImportSource[]).map((key) => (
                <TouchableOpacity
                  key={key}
                  style={[styles.sourceChip, activeSource === key && styles.sourceChipActive]}
                  onPress={() => setActiveSource(key)}
                >
                  <Ionicons
                    name={SOURCE_ICONS[key] as "people-outline"}
                    size={14}
                    color={activeSource === key ? "#FFFFFF" : "#6C5CE7"}
                  />
                  <Text
                    style={[
                      styles.sourceChipText,
                      activeSource === key && styles.sourceChipTextActive,
                    ]}
                  >
                    {SOURCE_LABELS[key]}
                  </Text>
                </TouchableOpacity>
              ))}
            </View>
          )}

          {/* Collection selector */}
          {collections.length > 0 && (
            <View style={styles.collectionRow}>
              <Text style={styles.collectionLabel}>淇濆瓨鍒?</Text>
              <ScrollView horizontal showsHorizontalScrollIndicator={false}>
                {collections.map((col) => (
                  <TouchableOpacity
                    key={col.id}
                    style={[
                      styles.collectionChip,
                      selectedCollectionId === col.id && styles.collectionChipActive,
                    ]}
                    onPress={() => setSelectedCollectionId(col.id)}
                  >
                    <Text
                      style={[
                        styles.collectionChipText,
                        selectedCollectionId === col.id && styles.collectionChipTextActive,
                      ]}
                    >
                      {col.name}
                    </Text>
                  </TouchableOpacity>
                ))}
              </ScrollView>
            </View>
          )}

          {/* Item list with checkboxes */}
          {loading ? (
            <ActivityIndicator size="small" color={theme.colors.primary} style={styles.loader} />
          ) : items.length > 0 ? (
            <ScrollView style={styles.itemList} showsVerticalScrollIndicator={false}>
              {items.map((item) => (
                <TouchableOpacity
                  key={item.id}
                  style={[styles.itemRow, item.selected && styles.itemRowSelected]}
                  onPress={() => toggleItem(item.id)}
                >
                  {item.image ? (
                    <Image source={{ uri: item.image }} style={styles.itemImage} />
                  ) : (
                    <View style={styles.itemImagePlaceholder}>
                      <Ionicons name="shirt-outline" size={18} color={theme.colors.textTertiary} />
                    </View>
                  )}
                  <Text style={styles.itemName} numberOfLines={1}>
                    {item.name}
                  </Text>
                  <View style={[styles.checkbox, item.selected && styles.checkboxChecked]}>
                    {item.selected && <Ionicons name="checkmark" size={12} color="#FFFFFF" />}
                  </View>
                </TouchableOpacity>
              ))}
            </ScrollView>
          ) : (
            <View style={styles.emptyItems}>
              <Text style={styles.emptyItemsText}>鏃犲彲瀵煎叆鐨勫崟鍝?/Text>
            </View>
          )}

          {/* Import button */}
          <TouchableOpacity
            style={[styles.importBtn, importing && styles.importBtnDisabled]}
            onPress={handleImport}
            disabled={importing}
          >
            {importing ? (
              <ActivityIndicator size="small" color="#FFFFFF" />
            ) : (
              <Text style={styles.importBtnText}>
                瀵煎叆閫変腑椤?({items.filter((i) => i.selected).length})
              </Text>
            )}
          </TouchableOpacity>
        </View>
      </View>
    </Modal>
  );
};

const styles = StyleSheet.create({
  overlay: { flex: 1, justifyContent: "flex-end" },
  backdrop: { ...StyleSheet.absoluteFillObject, backgroundColor: "rgba(0,0,0,0.4)" },
  sheet: {
