  }, []);

  return { start, displayValue };
};

import { useRef, useEffect, useCallback } from "react";
import { Animated, Easing, EasingFunction } from "react-native";
import { SpringConfigs, Duration } from "../theme/tokens/animations";

export function useAnimation(initialValue = 0) {
  const anim = useRef(new Animated.Value(initialValue)).current;

  const animate = useCallback(
    (
      toValue: number,
      config?: { duration?: number; useNativeDriver?: boolean; easing?: EasingFunction }
    ) => {
      return Animated.timing(anim, {
        toValue,
        duration: config?.duration ?? Duration.normal,
        useNativeDriver: config?.useNativeDriver ?? true,
        easing: config?.easing ?? Easing.out(Easing.cubic),
      });
    },
    [anim]
  );

  const spring = useCallback(
    (toValue: number, config?: Partial<typeof SpringConfigs.default>) => {
      return Animated.spring(anim, {
        toValue,
        useNativeDriver: true,
        ...SpringConfigs.default,
        ...config,
      });
    },
    [anim]
  );

  return { anim, animate, spring };
}

export function useFadeAnimation(initialVisible = false) {
  const opacity = useRef(new Animated.Value(initialVisible ? 1 : 0)).current;
  const scale = useRef(new Animated.Value(initialVisible ? 1 : 0.95)).current;
  const isVisibleRef = useRef(initialVisible);

  const show = useCallback(() => {
    isVisibleRef.current = true;
    Animated.parallel([
      Animated.timing(opacity, {
        toValue: 1,
        duration: Duration.normal,
        useNativeDriver: true,
      }),
      Animated.spring(scale, {
        toValue: 1,
        ...SpringConfigs.gentle,
        useNativeDriver: true,
      }),
    ]).start();
  }, [opacity, scale]);

  const hide = useCallback(() => {
    isVisibleRef.current = false;
    Animated.parallel([
      Animated.timing(opacity, {
        toValue: 0,
        duration: Duration.fast,
        useNativeDriver: true,
      }),
      Animated.timing(scale, {
        toValue: 0.95,
        duration: Duration.fast,
        useNativeDriver: true,
      }),
    ]).start();
  }, [opacity, scale]);

  const toggle = useCallback(() => {
    if (isVisibleRef.current) {
      hide();
    } else {
      show();
    }
  }, [show, hide]);

  return { opacity, scale, show, hide, toggle };
}

export function useScaleAnimation(triggerOnMount = false) {
  const scale = useRef(new Animated.Value(triggerOnMount ? 0 : 1)).current;

  const scaleIn = useCallback(() => {
    Animated.spring(scale, {
      toValue: 1,
      ...SpringConfigs.bouncy,
      useNativeDriver: true,
    }).start();
  }, [scale]);

  const scaleOut = useCallback(() => {
    Animated.timing(scale, {
      toValue: 0,
      duration: Duration.fast,
      useNativeDriver: true,
    }).start();
  }, [scale]);

  const pulse = useCallback(() => {
    Animated.sequence([
      Animated.spring(scale, {
        toValue: 1.1,
        ...SpringConfigs.bouncy,
        useNativeDriver: true,
      }),
      Animated.spring(scale, {
        toValue: 1,
        ...SpringConfigs.gentle,
        useNativeDriver: true,
      }),
    ]).start();
  }, [scale]);

  useEffect(() => {
    if (triggerOnMount) {
      scaleIn();
    }
  }, [triggerOnMount, scaleIn]);

  return { scale, scaleIn, scaleOut, pulse };
}

export function useSlideAnimation(
  direction: "up" | "down" | "left" | "right" = "up",
  distance = 100
) {
  const translateValue = direction === "up" || direction === "down" ? "translateY" : "translateX";
  const offset = direction === "down" || direction === "right" ? distance : -distance;

  const translate = useRef(new Animated.Value(offset)).current;
  const opacity = useRef(new Animated.Value(0)).current;

  const slideIn = useCallback(() => {
    Animated.parallel([
      Animated.spring(translate, {
        toValue: 0,
        ...SpringConfigs.gentle,
        useNativeDriver: true,
      }),
      Animated.timing(opacity, {
        toValue: 1,
        duration: Duration.normal,
        useNativeDriver: true,
      }),
    ]).start();
  }, [translate, opacity]);

  const slideOut = useCallback(() => {
    Animated.parallel([
      Animated.timing(translate, {
        toValue: offset,
        duration: Duration.fast,
        useNativeDriver: true,
      }),
      Animated.timing(opacity, {
        toValue: 0,
        duration: Duration.fast,
        useNativeDriver: true,
      }),
    ]).start();
  }, [translate, opacity, offset]);

  return {
    translate,
    opacity,
    slideIn,
    slideOut,
    transform: [{ [translateValue]: translate }],
  };
}

export function useStaggerAnimation(itemCount: number, staggerDelay = 50) {
  const animations = useRef(
    Array.from({ length: itemCount }, () => ({
      opacity: new Animated.Value(0),
      translateY: new Animated.Value(20),
    }))
  ).current;

  const start = useCallback(() => {
    const animatedItems = animations.map((anim, index) =>
      Animated.parallel([
        Animated.timing(anim.opacity, {
          toValue: 1,
          duration: Duration.normal,
          delay: index * staggerDelay,
          useNativeDriver: true,
        }),
        Animated.spring(anim.translateY, {
          toValue: 0,
          delay: index * staggerDelay,
          ...SpringConfigs.gentle,
          useNativeDriver: true,
        }),
      ])
    );

    Animated.stagger(staggerDelay, animatedItems).start();
  }, [animations, staggerDelay]);

  const reset = useCallback(() => {
    animations.forEach((anim) => {
      anim.opacity.setValue(0);
      anim.translateY.setValue(20);
    });
  }, [animations]);

  return { animations, start, reset };
}

export function useMountAnimation() {
  const opacity = useRef(new Animated.Value(0)).current;
  const scale = useRef(new Animated.Value(0.9)).current;
  const translateY = useRef(new Animated.Value(20)).current;

  useEffect(() => {
    Animated.parallel([
      Animated.timing(opacity, {
        toValue: 1,
        duration: Duration.normal,
        useNativeDriver: true,
      }),
      Animated.spring(scale, {
        toValue: 1,
        ...SpringConfigs.snappy,
        useNativeDriver: true,
      }),
      Animated.spring(translateY, {
        toValue: 0,
        ...SpringConfigs.gentle,
        useNativeDriver: true,
      }),
    ]).start();
  }, []);

  return { opacity, scale, translateY };
}

export function useShakeAnimation() {
  const shake = useRef(new Animated.Value(0)).current;

  const trigger = useCallback(() => {
    Animated.sequence([
      Animated.timing(shake, {
        toValue: 10,
        duration: 50,
        useNativeDriver: true,
      }),
      Animated.timing(shake, {
        toValue: -10,
        duration: 50,
        useNativeDriver: true,
      }),
      Animated.timing(shake, {
        toValue: 10,
        duration: 50,
        useNativeDriver: true,
      }),
      Animated.timing(shake, {
        toValue: -10,
        duration: 50,
        useNativeDriver: true,
      }),
      Animated.timing(shake, {
        toValue: 0,
        duration: 50,
        useNativeDriver: true,
      }),
    ]).start();
  }, [shake]);

  return { shake, trigger, transform: [{ translateX: shake }] };
}

export function usePulseAnimation(active = true, interval = 2000) {
  const scale = useRef(new Animated.Value(1)).current;
  const opacity = useRef(new Animated.Value(1)).current;

  useEffect(() => {
    if (!active) {
      return;
    }

    const animation = Animated.loop(
      Animated.sequence([
        Animated.parallel([
          Animated.timing(scale, {
            toValue: 1.05,
            duration: interval / 2,
            useNativeDriver: true,
          }),
          Animated.timing(opacity, {
            toValue: 0.8,
            duration: interval / 2,
            useNativeDriver: true,
          }),
        ]),
        Animated.parallel([
          Animated.timing(scale, {
            toValue: 1,
            duration: interval / 2,
            useNativeDriver: true,
          }),
          Animated.timing(opacity, {
            toValue: 1,
            duration: interval / 2,
            useNativeDriver: true,
          }),
        ]),
      ])
    );

    animation.start();

    return () => animation.stop();
  }, [active, interval, scale, opacity]);

  return { scale, opacity };
}

export function usePressAnimation() {
  const scale = useRef(new Animated.Value(1)).current;

  const onPressIn = useCallback(() => {
    Animated.spring(scale, {
      toValue: 0.95,
      ...SpringConfigs.snappy,
      useNativeDriver: true,
    }).start();
  }, [scale]);

  const onPressOut = useCallback(() => {
    Animated.spring(scale, {
      toValue: 1,
      ...SpringConfigs.bouncy,
      useNativeDriver: true,
    }).start();
  }, [scale]);

  return { scale, onPressIn, onPressOut };
}

import {
  useInfiniteQuery as useTanStackInfiniteQuery,
  type UseInfiniteQueryOptions,
} from "@tanstack/react-query";
import { useCallback } from "react";
import apiClient from "../services/api/client";
import type { ApiResponse, PaginatedResponse } from "../types";

interface CursorPage<T> {
  items: T[];
  nextCursor: string | null;
  hasMore: boolean;
}

interface UseInfiniteQueryOptions_<_T> {
  queryKey: (string | number)[];
  url: string;
  pageSize?: number;
  enabled?: boolean;
  staleTime?: number;
}

export function useInfiniteQuery<T>(options: UseInfiniteQueryOptions_<T>) {
  const { queryKey, url, pageSize = 20, enabled = true, staleTime = 60000 } = options;

  const query = useTanStackInfiniteQuery<CursorPage<T>, Error>({
    queryKey,
    queryFn: async ({ pageParam }) => {
      const cursor = pageParam as string | undefined;
      const params: Record<string, unknown> = { pageSize };
      if (cursor) {
        params.cursor = cursor;
      }

      const response = await apiClient.get<PaginatedResponse<T>>(url, params);
      if (!response.success || !response.data) {
        throw new Error(response.error?.message || "Failed to fetch data");
      }

      const lastItem = response.data.items[response.data.items.length - 1];
      const nextCursor = lastItem
        ? String((lastItem as Record<string, unknown>)["id"] ?? null)
        : null;
      return {
        items: response.data.items,
        nextCursor: nextCursor === "null" ? null : nextCursor,
        hasMore: response.data.hasMore ?? response.data.items.length >= pageSize,
      };
    },
    initialPageParam: undefined as string | undefined,
    getNextPageParam: (lastPage) => (lastPage.hasMore ? lastPage.nextCursor : undefined),
    enabled,
    staleTime,
  });

  const items = query.data?.pages.flatMap((page) => page.items) ?? [];
  const hasMore = query.hasNextPage;
  const loadMore = useCallback(() => {
    if (query.hasNextPage && !query.isFetchingNextPage) {
      void query.fetchNextPage();
    }
  }, [query.hasNextPage, query.isFetchingNextPage, query.fetchNextPage]);

  return {
    items,
    hasMore,
    loadMore,
    isLoading: query.isLoading,
    isLoadingMore: query.isFetchingNextPage,
    isRefreshing: query.isRefetching,
    refresh: query.refetch,
    error: query.error,
  };
}

export default useInfiniteQuery;

import { useCallback, useRef, useState } from "react";
import type { NativeScrollEvent, NativeSyntheticEvent } from "react-native";

interface UseLazyLoadOptions {
  /** How many items ahead of the viewport to preload */
  preloadThreshold?: number;
}

interface UseLazyLoadReturn {
  /** Track visibility via onViewableItemsChanged (for FlatList) */
  onViewableItemsChanged: (info: {
    viewableItems: { index: number | null; item: unknown }[];
    changed: { index: number | null; item: unknown; isViewable: boolean }[];
  }) => void;
  /** Current set of visible item indices */
  visibleIndices: Set<number>;
  /** Check if a specific index is considered visible (within threshold) */
  isVisible: (index: number) => boolean;
  /** Stable ref for FlatList viewability config */
  viewabilityConfig: {
    minimumViewTime: number;
    viewAreaCoveragePercentThreshold: number;
  };
}

/**
 * Custom hook for intersection-based lazy loading with FlatList integration.
 *
 * Tracks which items are visible in the viewport and preloads items
 * slightly ahead of the visible area for smoother scrolling.
 *
 * @param options.preloadThreshold - Number of positions before visible to preload (default: 3)
 */
export function useLazyLoad(options: UseLazyLoadOptions = {}): UseLazyLoadReturn {
  const { preloadThreshold = 3 } = options;

  const [visibleIndices, setVisibleIndices] = useState<Set<number>>(new Set());
  const preloadThresholdRef = useRef(preloadThreshold);

  /**
   * Called by FlatList onViewableItemsChanged.
   * Updates the visible indices set including preloaded positions.
   */
  const onViewableItemsChanged = useCallback(
    (info: {
      viewableItems: { index: number | null; item: unknown }[];
      changed: { index: number | null; item: unknown; isViewable: boolean }[];
    }) => {
      const newVisible = new Set<number>();

      for (const item of info.viewableItems) {
        if (item.index !== null) {
          // Add the visible index itself
          newVisible.add(item.index);

          // Preload ahead by the threshold amount
          for (let i = 1; i <= preloadThresholdRef.current; i++) {
            newVisible.add(item.index + i);
            if (item.index - i >= 0) {
              newVisible.add(item.index - i);
            }
          }
        }
      }

      setVisibleIndices(newVisible);
    },
    []
  );

  /**
   * Check if a specific index is within the visible + preload zone.
   */
  const isVisible = useCallback(
    (index: number): boolean => {
      return visibleIndices.has(index);
    },
    [visibleIndices]
  );

  // Stable viewabilityConfig ref for FlatList
  const viewabilityConfig = useRef({
    minimumViewTime: 300,
    viewAreaCoveragePercentThreshold: 50,
  }).current;

  return {
    onViewableItemsChanged,
    visibleIndices,
    isVisible,
    viewabilityConfig,
  };
}

import { useState, useEffect, useCallback, useRef } from "react";
import { offlineStorage, OfflineRequest } from "../utils/secureStorage";
import apiClient from "../services/api/client";

export type NetInfoStateType =
  | "unknown"
  | "none"
  | "cellular"
  | "wifi"
  | "bluetooth"
  | "ethernet"
  | "wimax"
  | "vpn"
  | "other";

export interface NetworkState {
  isConnected: boolean | null;
  isInternetReachable: boolean | null;
  type: NetInfoStateType;
  isConnectionExpensive: boolean;
}

export interface UseNetworkResult {
  networkState: NetworkState;
  isOffline: boolean;
  pendingRequests: number;
  syncOfflineRequests: () => Promise<void>;
  queueOfflineRequest: (
    request: Omit<OfflineRequest, "id" | "timestamp" | "retries">
  ) => Promise<string>;
}

const MAX_RETRIES = 3;
const _RETRY_DELAY_MS = 1000;

async function checkNetworkConnection(): Promise<NetworkState> {
  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 5000);

    const _response = await fetch("https://connectivitycheck.gstatic.com/generate_204", {
      method: "HEAD",
      mode: "no-cors",
      signal: controller.signal,
    });

    clearTimeout(timeoutId);

    return {
      isConnected: true,
      isInternetReachable: true,
      type: "wifi",
      isConnectionExpensive: false,
    };
  } catch {
    return {
      isConnected: false,
      isInternetReachable: false,
      type: "none",
      isConnectionExpensive: false,
    };
  }
}

export function useNetwork(): UseNetworkResult {
  const [networkState, setNetworkState] = useState<NetworkState>({
    isConnected: null,
    isInternetReachable: null,
    type: "unknown",
    isConnectionExpensive: false,
  });
  const [pendingRequests, setPendingRequests] = useState(0);
  const isSyncingRef = useRef(false);

  useEffect(() => {
    const checkConnection = async () => {
      const state = await checkNetworkConnection();
      setNetworkState(state);

      if (state.isConnected && state.isInternetReachable) {
        void syncOfflineRequests();
      }
    };

    void checkConnection();
    void loadPendingCount();

    const interval = setInterval(checkConnection, 30000);

    return () => clearInterval(interval);
  }, []);

  const loadPendingCount = async () => {
    const queue = await offlineStorage.getQueue();
    setPendingRequests(queue.length);
  };

  const syncOfflineRequests = useCallback(async () => {
    if (isSyncingRef.current) {
      return;
    }
    isSyncingRef.current = true;

    try {
      const queue = await offlineStorage.getQueue();

      for (const request of queue) {
        if (request.retries >= MAX_RETRIES) {
          await offlineStorage.removeRequest(request.id);
          continue;
        }

        try {
          let result;
          switch (request.method) {
            case "POST":
              result = await apiClient.post(request.url, request.data);
              break;
            case "PUT":
              result = await apiClient.put(request.url, request.data);
              break;
            case "PATCH":
              result = await apiClient.patch(request.url, request.data);
              break;
            case "DELETE":
              result = await apiClient.delete(request.url);
              break;
          }

          if (result?.success) {
            await offlineStorage.removeRequest(request.id);
          } else {
            await offlineStorage.incrementRetries(request.id);
          }
        } catch (error) {
          console.error(`Failed to sync request ${request.id}:`, error);
          await offlineStorage.incrementRetries(request.id);
        }
      }

      await loadPendingCount();
    } finally {
      isSyncingRef.current = false;
    }
  }, []);

  const queueOfflineRequest = useCallback(
    async (request: Omit<OfflineRequest, "id" | "timestamp" | "retries">): Promise<string> => {
      const id = await offlineStorage.queueRequest(request);
      await loadPendingCount();
      return id;
    },
    []
  );

  return {
    networkState,
    isOffline: networkState.isConnected === false || networkState.isInternetReachable === false,
    pendingRequests,
    syncOfflineRequests,
    queueOfflineRequest,
  };
}

export function useOfflineQueue() {
  const { isOffline, pendingRequests, syncOfflineRequests, queueOfflineRequest } = useNetwork();

  const executeWithOfflineSupport = useCallback(
    async <T>(
      operation: () => Promise<T>,
      offlineAction: Omit<OfflineRequest, "id" | "timestamp" | "retries">
    ): Promise<T | null> => {
      if (!isOffline) {
        try {
          return await operation();
        } catch (error) {
          console.error("Operation failed, queuing for offline:", error);
          await queueOfflineRequest(offlineAction);
          return null;
        }
      } else {
        await queueOfflineRequest(offlineAction);
        return null;
      }
    },
    [isOffline, queueOfflineRequest]
  );

  return {
    isOffline,
    pendingRequests,
    syncOfflineRequests,
    executeWithOfflineSupport,
  };
}

import { useState, useEffect } from "react";
import { AccessibilityInfo, Platform } from "react-native";
import { useSharedValue } from "react-native-reanimated";

export function useReducedMotion() {
  const [reducedMotion, setReducedMotion] = useState(false);
  const reducedMotionSV = useSharedValue(false);

  useEffect(() => {
    const osVersion = Platform.Version;
    if (Platform.OS === "ios" && typeof osVersion === "number" && osVersion < 16) {
      void AccessibilityInfo.isReduceMotionEnabled().then((enabled) => {
        setReducedMotion(enabled);
        reducedMotionSV.value = enabled;
      });
      return;
    }
    if (Platform.OS === "android" && typeof osVersion === "number" && osVersion < 24) {
      return;
    }

    let mounted = true;

    void AccessibilityInfo.isReduceMotionEnabled().then((enabled) => {
      if (mounted) {
        setReducedMotion(enabled);
        reducedMotionSV.value = enabled;
      }
    });

    const subscription = AccessibilityInfo.addEventListener(
      "reduceMotionChanged",
      (enabled: boolean) => {
        if (mounted) {
          setReducedMotion(enabled);
          reducedMotionSV.value = enabled;
        }
      }
    );

    return () => {
      mounted = false;
      subscription?.remove();
    };
  }, []);

  return { reducedMotion, reducedMotionSV };
}

export function useMotionHelpers() {
  const { reducedMotion, reducedMotionSV } = useReducedMotion();

  return { reducedMotion, reducedMotionSV };
}

import { useState, useCallback, useRef } from "react";
import apiClient from "../services/api/client";
import type { ApiResponse } from "../types";

interface UseUploadProgressOptions {
  onProgress?: (progress: number) => void;
  onSuccess?: <T>(response: ApiResponse<T>) => void;
  onError?: (error: Error) => void;
}

interface UseUploadProgressReturn {
  progress: number;
  isUploading: boolean;
  error: Error | null;
  upload: <T>(url: string, formData: FormData) => Promise<ApiResponse<T> | null>;
  cancel: () => void;
  retry: () => void;
  reset: () => void;
}

export function useUploadProgress(options: UseUploadProgressOptions = {}): UseUploadProgressReturn {
  const { onProgress, onSuccess, onError } = options;
  const [progress, setProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState<Error | null>(null);
  const isMountedRef = useRef(true);
  const lastUploadRef = useRef<{ url: string; formData: FormData } | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const upload = useCallback(
    async <T>(url: string, formData: FormData): Promise<ApiResponse<T> | null> => {
      lastUploadRef.current = { url, formData };
      setIsUploading(true);
      setProgress(0);
      setError(null);

      abortControllerRef.current = new AbortController();

      try {
        setProgress(10);
        const response = await apiClient.upload<T>(url, formData);
        if (abortControllerRef.current.signal.aborted) {
          return null;
        }
        setProgress(100);
        if (isMountedRef.current) {
          setIsUploading(false);
          if (response.success) {
            onSuccess?.(response);
          }
        }
        return response;
      } catch (err) {
        if (abortControllerRef.current.signal.aborted) {
          return null;
        }
        if (isMountedRef.current) {
          setError(err as Error);
          setIsUploading(false);
          onError?.(err as Error);
        }
        return null;
      }
    },
    [onProgress, onSuccess, onError]
  );

  const cancel = useCallback(() => {
    abortControllerRef.current?.abort();
    if (isMountedRef.current) {
      setIsUploading(false);
      setProgress(0);
    }
  }, []);

  const retry = useCallback(() => {
    if (lastUploadRef.current) {
      void upload(lastUploadRef.current.url, lastUploadRef.current.formData);
    }
  }, [upload]);

  const reset = useCallback(() => {
    abortControllerRef.current?.abort();
    setProgress(0);
    setIsUploading(false);
    setError(null);
    lastUploadRef.current = null;
  }, []);

  return { progress, isUploading, error, upload, cancel, retry, reset };
}

export default useUploadProgress;

