import React, { useCallback, useEffect, useRef, useState } from "react";
import {
  View,
  Text,
  StyleSheet,
  TextInput,
  TouchableOpacity,
  ActivityIndicator,
  ScrollView,
  KeyboardAvoidingView,
  Platform,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { useNavigation, useRoute } from "@react-navigation/native";
import type { RouteProp } from "@react-navigation/native";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import { theme } from "../theme";
import { DesignTokens } from "../theme/tokens/design-tokens";
import { AIThinkingAnimation } from "../components/aistylist/AIThinkingAnimation";
import { useAiStylistStore } from "../stores/aiStylistStore";
import { useAiStylistChatStore } from "../stores/aiStylistChatStore";
import type { ChatMessage } from "../stores/aiStylistChatStore";
import type { StylistStackParamList } from "../navigation/types";

type AiStylistChatRoute = RouteProp<StylistStackParamList, "AiStylistChat">;

const SCENE_BUTTONS = [
  { key: "date", label: "绾︿細涔嬪", icon: "heart-outline" as const, message: "鎴戦渶瑕佷竴濂楃害浼氱┛鎼璡

");

  const { messages, addMessage } = useAiStylistChatStore();

  const {
    currentSessionId,
    isGenerating,
    error,
    createSession,
    sendMessage,
    fetchOutfitPlan,
    clearError,
  } = useAiStylistStore();

  const activeSessionId = sessionId ?? currentSessionId;

  useEffect(() => {
    if (sessionId) {
      useAiStylistStore.getState().setCurrentSessionId(sessionId);
    }
  }, [sessionId]);

  const handleSend = useCallback(async () => {
    const text = inputText.trim();
    if (!text || isGenerating) {
      return;
    }

    setInputText("");

    const userMsg: ChatMessage = {
      id: `user_${Date.now()}`,
      role: "user",
      content: text,
      timestamp: new Date().toISOString(),
    };
    addMessage(userMsg);

    let sid = activeSessionId;
    if (!sid) {
      sid = await createSession(text);
    }

    if (sid) {
      const result = await sendMessage(text);
      if (result?.assistantMessage) {
        const assistantMsg: ChatMessage = {
          id: `assistant_${Date.now()}`,
          role: "assistant",
          content: result.assistantMessage,
          timestamp: new Date().toISOString(),
        };
        addMessage(assistantMsg);
      }
      if (result?.result) {
        await fetchOutfitPlan(sid);
      }
    }
  }, [inputText, isGenerating, activeSessionId, createSession, sendMessage, fetchOutfitPlan]);

  const handleScenePress = useCallback(
    async (scene: (typeof SCENE_BUTTONS)[number]) => {
      if (isGenerating) {
        return;
      }

      const userMsg: ChatMessage = {
        id: `user_${Date.now()}`,
        role: "user",
        content: scene.message,
        timestamp: new Date().toISOString(),
      };
      addMessage(userMsg);

      let sid = activeSessionId;
      if (!sid) {
        sid = await createSession(scene.message);
      }
      if (sid) {
        const result = await sendMessage(scene.message);
        if (result?.assistantMessage) {
          const assistantMsg: ChatMessage = {
            id: `assistant_${Date.now()}`,
            role: "assistant",
            content: result.assistantMessage,
            timestamp: new Date().toISOString(),
          };
          addMessage(assistantMsg);
        }
      }
    },
    [isGenerating, activeSessionId, createSession, sendMessage]
  );

  const renderMessage = useCallback(
    (msg: ChatMessage) => (
      <View
        key={msg.id}
        style={[s.messageBubble, msg.role === "user" ? s.userBubble : s.assistantBubble]}
      >
        {msg.role === "assistant" && (
          <View style={s.aiAvatar}>
            <Ionicons name="sparkles" size={12} color={theme.colors.surface} />
          </View>
        )}
        <View
          style={[
            s.bubbleContent,
            msg.role === "user" ? s.userBubbleContent : s.assistantBubbleContent,
          ]}
        >
          <Text
            style={[s.bubbleText, msg.role === "user" ? s.userBubbleText : s.assistantBubbleText]}
          >
            {msg.content}
          </Text>
        </View>
      </View>
    ),
    []
  );

  return (
    <SafeAreaView style={s.container}>
      <View style={s.header}>
        <TouchableOpacity onPress={() => navigation.goBack()} style={s.backBtn}>
          <Ionicons name="chevron-back" size={24} color={theme.colors.text} />
        </TouchableOpacity>
        <View style={s.headerCenter}>
          <View style={s.onlineDot} />
          <Text style={s.headerTitle}>AI 閫犲瀷甯?/Text>
        </View>
        <TouchableOpacity
          style={s.backBtn}
          onPress={() => (navigation as any).navigate("ChatHistory")}
        >
          <Ionicons name="time-outline" size={22} color={theme.colors.text} />
        </TouchableOpacity>
      </View>

      <KeyboardAvoidingView style={s.flex} behavior={Platform.OS === "ios" ? "padding" : undefined}>
        <ScrollView
          ref={scrollViewRef}
          style={s.flex}
          contentContainerStyle={s.messagesContainer}
          onContentSizeChange={() => scrollViewRef.current?.scrollToEnd({ animated: true })}
        >
          {error && (
            <View style={s.errorBanner}>
              <Text style={s.errorText}>{error}</Text>
              <TouchableOpacity onPress={clearError}>
                <Text style={s.errorDismiss}>鍏抽棴</Text>
              </TouchableOpacity>
            </View>
          )}

          {messages.length === 0 && (
            <View style={s.welcomeSection}>
              <View style={s.welcomeIcon}>
                <Ionicons name="sparkles" size={32} color={theme.colors.primary} />
              </View>
              <Text style={s.welcomeTitle}>浠婂ぉ鎯崇┛浠€涔堬紵</Text>
              <Text style={s.welcomeSubtitle}>鍛婅瘔鎴戝満鍚堛€佸績鎯咃紝鎴栬€呰鎴戠粰浣犳儕鍠?/Text>
            </View>
          )}

          {messages.map(renderMessage)}

          {isGenerating && (
            <View style={[s.messageBubble, s.assistantBubble]}>
              <View style={s.aiAvatar}>
                <Ionicons name="sparkles" size={12} color={theme.colors.surface} />
              </View>
              <AIThinkingAnimation />
            </View>
          )}
        </ScrollView>

        {/* Scene quick buttons */}
        <View style={s.sceneRow}>
          <ScrollView
            horizontal
            showsHorizontalScrollIndicator={false}
            contentContainerStyle={s.sceneScrollContent}
          >
            {SCENE_BUTTONS.map((scene) => (
              <TouchableOpacity
                key={scene.key}
                style={s.sceneButton}
                onPress={() => handleScenePress(scene)}
                disabled={isGenerating}
              >
                <Ionicons name={scene.icon} size={16} color={theme.colors.primary} />
                <Text style={s.sceneLabel}>{scene.label}</Text>
              </TouchableOpacity>
            ))}
          </ScrollView>
        </View>

        {/* Input area */}
        <View style={s.inputRow}>
          <View style={s.inputWrapper}>
            <TextInput
              style={s.input}
              placeholder="鎻忚堪浣犵殑绌挎惌闇€姹?.."
              placeholderTextColor={theme.colors.textTertiary}
              value={inputText}
              onChangeText={setInputText}
              onSubmitEditing={handleSend}
              editable={!isGenerating}
              multiline
              maxLength={500}
            />
          </View>
          <TouchableOpacity
            style={[s.sendButton, (!inputText.trim() || isGenerating) && s.sendButtonDisabled]}
            onPress={handleSend}
            disabled={!inputText.trim() || isGenerating}
          >
            {isGenerating ? (
              <ActivityIndicator size="small" color="#fff" />
            ) : (
              <Ionicons
                name="send"
                size={18}
                color={inputText.trim() ? "#fff" : theme.colors.textTertiary}
              />
            )}
          </TouchableOpacity>
        </View>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
};

const s = StyleSheet.create({
  container: { flex: 1, backgroundColor: theme.colors.background },
  flex: { flex: 1 },
  header: {
