const CHART_CENTER = CHART_SIZE / 2;
const CHART_RADIUS = 90;
const AXES = ["鑲╁", "鑳稿洿", "鑵板洿", "鑷€鍥碶

 ");
  const idealPath = idealPoints.map((p) => `${p.x},${p.y}`).join(" ");

  const gridLevels = [0.25, 0.5, 0.75, 1.0];

  return (
    <Svg width={CHART_SIZE} height={CHART_SIZE}>
      {/* Grid lines */}
      {gridLevels.map((level) => {
        const points = AXES.map((_, i) => {
          const p = getPointOnAxis(
            startAngle + i * angleStep,
            level * CHART_RADIUS,
            CHART_CENTER,
            CHART_CENTER
          );
          return `${p.x},${p.y}`;
        }).join(" ");
        return (
          <Polygon
            key={level}
            points={points}
            fill="none"
            stroke={Colors.neutral[200]}
            strokeWidth={1}
          />
        );
      })}

      {/* Axis lines */}
      {axisPoints.map((point, i) => (
        <Line
          key={i}
          x1={CHART_CENTER}
          y1={CHART_CENTER}
          x2={point.x}
          y2={point.y}
          stroke={Colors.neutral[200]}
          strokeWidth={1}
        />
      ))}

      {/* Ideal shape (dashed) */}
      <Polygon
        points={idealPath}
        fill="rgba(198, 123, 92, 0.1)"
        stroke="rgba(198, 123, 92, 0.4)"
        strokeWidth={1.5}
        strokeDasharray="4 3"
      />

      {/* Actual shape */}
      <Polygon
        points={actualPath}
        fill="rgba(198, 123, 92, 0.2)"
        stroke="#C67B5C"
        strokeWidth={2}
      />

      {/* Actual points */}
      {actualPoints.map((point, i) => (
        <Circle key={`actual-${i}`} cx={point.x} cy={point.y} r={4} fill="#C67B5C" />
      ))}

      {/* Axis labels */}
      {axisPoints.map((point, i) => {
        const labelOffset = 20;
        const dx = point.x - CHART_CENTER;
        const dy = point.y - CHART_CENTER;
        const len = Math.sqrt(dx * dx + dy * dy);
        const labelX = CHART_CENTER + (dx / len) * (CHART_RADIUS + labelOffset);
        const labelY = CHART_CENTER + (dy / len) * (CHART_RADIUS + labelOffset);
        return (
          <SvgText
            key={`label-${i}`}
            x={labelX}
            y={labelY}
            textAnchor="middle"
            alignmentBaseline="middle"
            fontSize={12}
            fill={theme.colors.textSecondary}
          >
            {AXES[i]}
          </SvgText>
        );
      })}
    </Svg>
  );
};

