import React, { useCallback, useEffect, useState } from "react";
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ActivityIndicator,
  FlatList,
  Image,
  RefreshControl,
  Alert,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { useNavigation, useRoute } from "@react-navigation/native";
import type { RouteProp } from "@react-navigation/native";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import { theme } from "../theme";
import { clothingApi } from "../services/api/clothing.api";
import type { ClothingItem } from "../types/clothing";

import type { ProfileStackParamList } from "../navigation/types";

type BrandRoute = RouteProp<ProfileStackParamList, "Brand">;

export const BrandScreen: React.FC = () => {
  const navigation = useNavigation();
  const route = useRoute<BrandRoute>();
  const brandId = route.params?.brandId;

  const [items, setItems] = useState<ClothingItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);

  const fetchItems = useCallback(
    async (pageNum: number = 1, append: boolean = false) => {
      try {
        if (pageNum === 1) {
          setLoading(true);
        }
        setError(null);

        const response = await clothingApi.getAll({
          brandId,
          page: pageNum,
          limit: 20,
        });

        if (response.success && response.data) {
          const newItems = response.data.items;
          setItems((prev) => (append ? [...prev, ...newItems] : newItems));
          setPage(pageNum);
          setHasMore(response.data.hasMore ?? newItems.length >= 20);
        } else {
          setError("Failed to load brand products");
        }
      } catch {
        setError("Network error, please retry");
      } finally {
        setLoading(false);
        setRefreshing(false);
      }
    },
    [brandId]
  );

  useEffect(() => {
    if (brandId) {
      void fetchItems(1, false);
    }
  }, [brandId, fetchItems]);

  const handleRefresh = useCallback(() => {
    setRefreshing(true);
    void fetchItems(1, false);
  }, [fetchItems]);

  const handleLoadMore = useCallback(() => {
    if (hasMore && !loading) {
      void fetchItems(page + 1, true);
    }
  }, [hasMore, loading, page, fetchItems]);

  const handleQRScan = useCallback(async () => {
    Alert.alert("QR Scanner", "Camera would open to scan brand QR codes");
  }, []);

  const handleItemPress = useCallback(
    (item: ClothingItem) => {
      (navigation as any).navigate("Product", { clothingId: item.id });
    },
    [navigation]
  );

  const renderItem = useCallback(
    ({ item }: { item: ClothingItem }) => (
      <TouchableOpacity
        style={s.productCard}
        onPress={() => handleItemPress(item)}
        activeOpacity={0.85}
      >
        {item.imageUri ? (
          <Image source={{ uri: item.imageUri }} style={s.productImage} resizeMode="cover" />
        ) : (
          <View style={s.productImagePlaceholder}>
            <Ionicons name="image-outline" size={28} color={theme.colors.textTertiary} />
          </View>
        )}
        <View style={s.productInfo}>
          <Text style={s.productName} numberOfLines={2}>
            {item.name ?? "Product"}
          </Text>
          {item.brand && <Text style={s.productBrand}>{item.brand}</Text>}
          {item.price !== null && (
            <View style={s.priceRow}>
              <Text style={s.productPrice}>楼{item.price!.toFixed(2)}</Text>
              {item.colors && item.colors.length > 0 && (
                <Text style={s.productColors}>{item.colors.length} colors</Text>
              )}
            </View>
          )}
        </View>
      </TouchableOpacity>
    ),
    [handleItemPress]
  );

  return (
    <SafeAreaView style={s.container}>
      <View style={s.header}>
        <TouchableOpacity onPress={() => navigation.goBack()} style={s.iconBtn}>
          <Ionicons name="chevron-back" size={24} color={theme.colors.text} />
        </TouchableOpacity>
        <Text style={s.headerTitle}>Brand</Text>
        <TouchableOpacity style={s.iconBtn} onPress={handleQRScan}>
          <Ionicons name="qr-code-outline" size={22} color={theme.colors.text} />
        </TouchableOpacity>
      </View>

      {/* QR import banner */}
      <TouchableOpacity style={s.qrBanner} onPress={handleQRScan} activeOpacity={0.8}>
        <View style={s.qrBannerIcon}>
          <Ionicons name="scan-outline" size={20} color={theme.colors.primary} />
        </View>
        <View style={s.qrBannerText}>
          <Text style={s.qrBannerTitle}>Scan Brand QR Code</Text>
          <Text style={s.qrBannerDesc}>Quickly import products by scanning</Text>
        </View>
        <Ionicons name="chevron-forward" size={18} color={theme.colors.textTertiary} />
      </TouchableOpacity>

      {loading && items.length === 0 ? (
        <View style={s.centerContent}>
          <ActivityIndicator size="large" color={theme.colors.primary} />
          <Text style={s.loadingText}>Loading products...</Text>
        </View>
      ) : error && items.length === 0 ? (
        <View style={s.centerContent}>
          <Ionicons name="alert-circle-outline" size={48} color={theme.colors.textTertiary} />
          <Text style={s.errorText}>{error}</Text>
          <TouchableOpacity style={s.retryBtn} onPress={() => fetchItems(1, false)}>
            <Text style={s.retryBtnText}>Retry</Text>
          </TouchableOpacity>
        </View>
      ) : (
        <FlatList
          data={items}
          keyExtractor={(item) => item.id}
          renderItem={renderItem}
          refreshControl={
            <RefreshControl
              refreshing={refreshing}
              onRefresh={handleRefresh}
              tintColor={theme.colors.primary}
            />
          }
          onEndReached={handleLoadMore}
          onEndReachedThreshold={0.5}
          contentContainerStyle={{ paddingBottom: 24 }}
          ListEmptyComponent={
            <View style={s.centerContent}>
              <Ionicons name="shirt-outline" size={48} color={theme.colors.textTertiary} />
              <Text style={s.emptyTitle}>No products found</Text>
              <Text style={s.emptySubtitle}>This brand has not listed any products yet</Text>
            </View>
          }
          ListFooterComponent={
            loading && items.length > 0 ? (
              <View style={s.loadingMore}>
                <ActivityIndicator size="small" color={theme.colors.primary} />
                <Text style={s.loadingMoreText}>Loading more...</Text>
              </View>
            ) : null
          }
        />
      )}
    </SafeAreaView>
  );
};

const s = StyleSheet.create({
  container: { flex: 1, backgroundColor: theme.colors.background },
  header: {
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "space-between",
    paddingHorizontal: 16,
    paddingVertical: 12,
    backgroundColor: theme.colors.surface,
    borderBottomWidth: 1,
    borderBottomColor: theme.colors.border,
  },
  headerTitle: { fontSize: 18, fontWeight: "700", color: theme.colors.text },
  iconBtn: { width: 36, height: 36, alignItems: "center", justifyContent: "center" },
  qrBanner: {
    flexDirection: "row",
    alignItems: "center",
    marginHorizontal: 16,
    marginVertical: 12,
    backgroundColor: theme.colors.surface,
    borderRadius: 14,
    padding: 14,
    shadowColor: "#000",
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.06,
    shadowRadius: 8,
    elevation: 3,
  },
  qrBannerIcon: {
    width: 40,
    height: 40,
    borderRadius: 10,
    backgroundColor: theme.colors.subtleBg,
    alignItems: "center",
    justifyContent: "center",
  },
  qrBannerText: { flex: 1, marginLeft: 12 },
  qrBannerTitle: { fontSize: 14, fontWeight: "600", color: theme.colors.text },
  qrBannerDesc: { fontSize: 12, color: theme.colors.textTertiary, marginTop: 2 },
  centerContent: { flex: 1, alignItems: "center", justifyContent: "center", paddingHorizontal: 32 },
  loadingText: { fontSize: 14, color: theme.colors.textSecondary, marginTop: 12 },
  errorText: { fontSize: 14, color: theme.colors.error, marginTop: 12 },
  retryBtn: {
    marginTop: 16,
    backgroundColor: theme.colors.primary,
    paddingHorizontal: 24,
    paddingVertical: 10,
    borderRadius: 20,
  },
  retryBtnText: { color: theme.colors.surface, fontSize: 14, fontWeight: "600" },
  emptyTitle: { fontSize: 18, fontWeight: "600", color: theme.colors.text, marginTop: 16 },
  emptySubtitle: {
    fontSize: 14,
    color: theme.colors.textTertiary,
    marginTop: 8,
    textAlign: "center",
  },
  productCard: {
    flexDirection: "row",
    alignItems: "center",
    backgroundColor: theme.colors.surface,
    paddingHorizontal: 16,
    paddingVertical: 14,
    borderBottomWidth: 1,
    borderBottomColor: theme.colors.divider,
  },
  productImage: {
    width: 72,
    height: 72,
    borderRadius: 10,
    backgroundColor: theme.colors.placeholderBg,
  },
  productImagePlaceholder: {
    width: 72,
    height: 72,
    borderRadius: 10,
    backgroundColor: theme.colors.subtleBg,
    alignItems: "center",
    justifyContent: "center",
  },
  productInfo: { flex: 1, marginLeft: 14 },
  productName: { fontSize: 15, fontWeight: "500", color: theme.colors.text, lineHeight: 20 },
  productBrand: { fontSize: 12, color: theme.colors.textTertiary, marginTop: 3 },
  priceRow: { flexDirection: "row", alignItems: "center", gap: 8, marginTop: 6 },
  productPrice: { fontSize: 16, fontWeight: "700", color: theme.colors.primary },
  productColors: { fontSize: 12, color: theme.colors.textTertiary },
  loadingMore: {
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "center",
    gap: 8,
    paddingVertical: 16,
  },
  loadingMoreText: { fontSize: 13, color: theme.colors.textTertiary },
});

export default BrandScreen;

import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Image,
  ActivityIndicator,
  RefreshControl,
  FlatList,
  Animated,
  Alert,
  PanResponder,
  Dimensions,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { useNavigation } from "@react-navigation/native";
import type { NativeStackNavigationProp } from "@react-navigation/native-stack";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import { cartApi, cartEnhancementApi } from "../services/api/commerce.api";
import { useCartStore } from "../stores/index";
import { useCouponStore } from "../stores/couponStore";
import type { CartItem } from "../types";
import { theme } from "../theme";
import { withErrorBoundary } from "../components/ErrorBoundary";
import { EmptyCartView } from "../components/EmptyCartView";
import { FreeShippingProgress } from "../components/FreeShippingProgress";
import { CouponSelector } from "../components/CouponSelector";
import type { RootStackParamList } from "../types/navigation";

type Navigation = NativeStackNavigationProp<RootStackParamList>;

const _SCREEN_WIDTH = Dimensions.get("window").width;
const SWIPE_THRESHOLD = -80;

export const CartScreenComponent: React.FC = () => {
  const navigation = useNavigation<Navigation>();
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [updatingIds, setUpdatingIds] = useState<Set<string>>(new Set());
  const [editMode, setEditMode] = useState(false);
  const [showCouponSelector, setShowCouponSelector] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const couponStore = useCouponStore();

  const { items, setItems, removeItem, updateItem, totalItems, totalPrice } = useCartStore();

  const fetchCart = useCallback(async () => {
    try {
      setError(null);
      const response = await cartApi.get();
      if (response.success && response.data) {
        const selected = new Set(
          response.data.filter((item) => item.selected).map((item) => item.id)
        );

        setItems(
          response.data.map((item) => ({
            id: item.id,
            item: item as any,
            color: item.color,
            size: item.size,
            quantity: item.quantity,
            selected: item.selected ?? false,
          }))
        );
        setSelectedIds(selected);
      }
    } catch {
      setError("Failed to load cart");
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, [setItems]);

  useEffect(() => {
    void fetchCart();
  }, [fetchCart]);

  const handleRefresh = useCallback(() => {
    setRefreshing(true);
    void fetchCart();
  }, [fetchCart]);

  const allSelected = items.length > 0 && selectedIds.size === items.length;
  const someSelected = selectedIds.size > 0 && !allSelected;

  const selectedTotal = useMemo(() => {
    return items
      .filter((item) => selectedIds.has(item.id))
      .reduce((sum, item) => sum + (item.item?.price || 0) * item.quantity, 0);
  }, [items, selectedIds]);

  const selectedCount = useMemo(() => {
    return items
      .filter((item) => selectedIds.has(item.id))
      .reduce((sum, item) => sum + item.quantity, 0);
  }, [items, selectedIds]);

  const toggleSelect = useCallback(
    async (id: string) => {
      const currentlySelected = selectedIds.has(id);
      const nextSelected = !currentlySelected;

      setSelectedIds((prev) => {
        const next = new Set(prev);
        if (nextSelected) {
          next.add(id);
        } else {
          next.delete(id);
        }
        return next;
      });
      updateItem(id, { selected: nextSelected });

      try {
        await cartApi.update(id, { selected: nextSelected });
      } catch {
        setSelectedIds((prev) => {
          const next = new Set(prev);
          if (currentlySelected) {
            next.add(id);
          } else {
            next.delete(id);
          }
          return next;
        });
        updateItem(id, { selected: currentlySelected });
        Alert.alert("鎻愮ず", "鏇存柊鍕鹃€夌姸鎬佸け璐ワ紝璇烽噸璇昞

鎻愮ず", "鏇存柊鏁伴噺澶辫触锛岃閲嶈瘯");
      } finally {
        setUpdatingIds((prev) => {
          const next = new Set(prev);
          next.delete(id);
          return next;
        });
      }
    },
    [items, updateItem]
  );

  const handleDelete = useCallback(
    async (id: string) => {
      Alert.alert("纭鍒犻櫎", "纭畾瑕佷粠璐墿杞︿腑绉婚櫎璇ュ晢鍝佸悧锛焅

checkmark" size={14} color={theme.colors.surface} />
                )}
                {someSelected && !allSelected && (
                  <Ionicons name="remove" size={14} color={theme.colors.surface} />
                )}
              </View>
              <Text style={styles.selectAllText}>鍏ㄩ€?/Text>
            </TouchableOpacity>
          </View>
        }
        ListEmptyComponent={
          error ? (
            <View style={styles.errorContainer}>
              <Ionicons name="cloud-offline-outline" size={40} color={theme.colors.textTertiary} />
              <Text style={styles.errorText}>{error}</Text>
              <TouchableOpacity style={styles.retryButton} onPress={handleRefresh}>
                <Text style={styles.retryButtonText}>Retry</Text>
              </TouchableOpacity>
            </View>
          ) : (
            <EmptyCartView
              onGoShopping={() => navigation.navigate("MainTabs", { screen: "Home" } as never)}
            />
          )
        }
        refreshControl={
          <RefreshControl
            refreshing={refreshing}
            onRefresh={handleRefresh}
            colors={[theme.colors.primary]}
            tintColor={theme.colors.primary}
          />
        }
        contentContainerStyle={[styles.scrollContent, items.length === 0 && { flex: 1 }]}
        showsVerticalScrollIndicator={false}
        removeClippedSubviews={true}
        maxToRenderPerBatch={8}
        windowSize={5}
      />

      <View style={styles.footer}>
        <TouchableOpacity
          style={styles.couponEntry}
          onPress={() => {
            void couponStore.fetchUserCoupons();
            setShowCouponSelector(true);
          }}
        >
          <Text style={styles.couponEntryText}>
            {couponStore.availableCoupons.length > 0
              ? `${couponStore.availableCoupons.length}寮犱紭鎯犲埜鍙敤`
              : "浣跨敤浼樻儬鍒竆

checkmark" size={14} color={theme.colors.surface} />
                )}
                {someSelected && !allSelected && (
                  <Ionicons name="remove" size={14} color={theme.colors.surface} />
                )}
              </View>
              <Text style={styles.selectAllText}>鍏ㄩ€?/Text>
            </TouchableOpacity>

            <View style={styles.totalSection}>
              <Text style={styles.totalLabel}>鍚堣锛?/Text>
              <Text style={styles.totalPrice}>楼{selectedTotal.toFixed(2)}</Text>
            </View>

            <TouchableOpacity
              style={[
                styles.checkoutButton,
                selectedIds.size === 0 && styles.checkoutButtonDisabled,
              ]}
              onPress={handleCheckout}
              disabled={selectedIds.size === 0}
              activeOpacity={0.8}
            >
              <Text style={styles.checkoutButtonText}>
                缁撶畻{selectedCount > 0 ? `(${selectedCount})` : ""}
              </Text>
            </TouchableOpacity>
          </View>
        )}
      </View>

      <CouponSelector
        visible={showCouponSelector}
        coupons={couponStore.availableCoupons}
        selectedCouponId={couponStore.selectedCoupon?.id ?? null}
        onSelect={(coupon) => couponStore.selectCoupon(coupon)}
        onClose={() => setShowCouponSelector(false)}
      />
    </SafeAreaView>
  );
};

interface CartItemCardProps {
  item: {
    id: string;
    item: {
      name?: string;
      price?: number;
      imageUri?: string;
      originalPrice?: number;
    };
    color: string;
    size: string;
    quantity: number;
  };
  isSelected: boolean;
  isUpdating: boolean;
  onToggleSelect: () => void;
  onQuantityChange: (quantity: number) => void;
  onDelete: () => void;
}

const CartItemCard: React.FC<CartItemCardProps> = ({
  item,
  isSelected,
  isUpdating,
  onToggleSelect,
  onQuantityChange,
  onDelete,
}) => {
  const translateX = useRef(new Animated.Value(0)).current;
  const itemPrice = item.item?.price ?? 0;
  const lineTotal = itemPrice * item.quantity;

  const panResponder = useRef(
    PanResponder.create({
      onStartShouldSetPanResponder: () => false,
      onMoveShouldSetPanResponder: (_, gestureState) =>
        Math.abs(gestureState.dx) > 10 && Math.abs(gestureState.dx) > Math.abs(gestureState.dy),
      onPanResponderMove: (_, gestureState) => {
        if (gestureState.dx < 0) {
          translateX.setValue(Math.max(gestureState.dx, -160));
        }
      },
      onPanResponderRelease: (_, gestureState) => {
        if (gestureState.dx < SWIPE_THRESHOLD) {
          Animated.spring(translateX, {
            toValue: -120,
            useNativeDriver: true,
            overshootClamping: true,
          }).start();
        } else {
          Animated.spring(translateX, {
            toValue: 0,
            useNativeDriver: true,
          }).start();
        }
      },
    })
  ).current;

  const resetSwipe = useCallback(() => {
    Animated.spring(translateX, {
      toValue: 0,
      useNativeDriver: true,
    }).start();
  }, [translateX]);

  return (
    <View style={styles.cardOuter}>
      <Animated.View
        style={[styles.cardSwipeable, { transform: [{ translateX }] }]}
        {...panResponder.panHandlers}
      >
        <TouchableOpacity
          style={styles.checkboxTouchable}
          onPress={onToggleSelect}
          activeOpacity={0.7}
          accessibilityLabel={isSelected ? "鍙栨秷閫夋嫨" : "閫夋嫨鍟嗗搧"}
        >
          <View style={[styles.checkbox, isSelected && styles.checkboxChecked]}>
            {isSelected && <Ionicons name="checkmark" size={14} color={theme.colors.surface} />}
          </View>
        </TouchableOpacity>

        <View style={styles.cardImageWrap}>
          {item.item?.imageUri ? (
            <Image
              source={{ uri: item.item.imageUri }}
              style={styles.cardImage}
              resizeMode="cover"
            />
          ) : (
            <View style={styles.cardImagePlaceholder}>
              <Ionicons name="image-outline" size={24} color={theme.colors.textTertiary} />
            </View>
          )}
        </View>

        <View style={styles.cardInfo}>
          <Text style={styles.cardName} numberOfLines={2}>
            {item.item?.name || "鍟嗗搧"}
          </Text>
          <View style={styles.cardSpecs}>
            {item.color ? (
              <View style={styles.specChip}>
                <Text style={styles.specText}>{item.color}</Text>
              </View>
            ) : null}
            {item.size ? (
              <View style={styles.specChip}>
                <Text style={styles.specText}>{item.size}</Text>
              </View>
            ) : null}
          </View>
          <View style={styles.cardBottom}>
            <Text style={styles.cardPrice}>楼{lineTotal.toFixed(2)}</Text>
            <View style={styles.quantityControls}>
              <TouchableOpacity
                style={styles.quantityButton}
                onPress={() => onQuantityChange(item.quantity - 1)}
                disabled={item.quantity <= 1 || isUpdating}
                activeOpacity={0.7}
                accessibilityLabel="鍑忓皯鏁伴噺"
              >
                <Ionicons
                  name="remove"
                  size={16}
                  color={item.quantity <= 1 ? theme.colors.border : theme.colors.primary}
                />
              </TouchableOpacity>
              <View style={styles.quantityDisplay}>
                {isUpdating ? (
                  <ActivityIndicator size="small" color={theme.colors.primary} />
                ) : (
                  <Text style={styles.quantityText}>{item.quantity}</Text>
                )}
              </View>
              <TouchableOpacity
                style={styles.quantityButton}
                onPress={() => onQuantityChange(item.quantity + 1)}
                disabled={isUpdating}
                activeOpacity={0.7}
                accessibilityLabel="澧炲姞鏁伴噺"
              >
                <Ionicons name="add" size={16} color={theme.colors.primary} />
              </TouchableOpacity>
            </View>
          </View>
        </View>
      </Animated.View>

      <View style={styles.deleteAction}>
        <TouchableOpacity
          style={styles.deleteButton}
          onPress={() => {
            resetSwipe();
            onDelete();
          }}
          activeOpacity={0.7}
          accessibilityLabel="鍒犻櫎鍟嗗搧"
        >
          <Ionicons name="trash-outline" size={22} color={theme.colors.surface} />
          <Text style={styles.deleteText}>鍒犻櫎</Text>
        </TouchableOpacity>
      </View>
    </View>
  );
};

