                  navigation.goBack();
                } else if (step === "address") {
                  setStep("summary");
                } else {
                  setStep("address");
                }
              }}
              accessibilityLabel="杩斿洖"
            >
              <Ionicons name="arrow-back" size={22} color={theme.colors.text} />
            </TouchableOpacity>
            <Text style={styles.headerTitle}>缁撶畻</Text>
            <View style={styles.headerPlaceholder} />
          </View>

          <View style={styles.progressRow}>
            {steps.map((label, index) => {
              const activeIndex = step === "summary" ? 0 : step === "address" ? 1 : 2;
              return (
                <View key={label} style={styles.progressItem}>
                  <View
                    style={[styles.progressDot, index <= activeIndex && styles.progressDotActive]}
                  />
                  <Text
                    style={[styles.progressText, index <= activeIndex && styles.progressTextActive]}
                  >
                    {label}
                  </Text>
                </View>
              );
            })}
          </View>
        </>
      ) : null}

      <KeyboardAvoidingView
        style={styles.flex}
        behavior={Platform.OS === "ios" ? "padding" : undefined}
      >
        {loading ? (
          <View style={styles.center}>
