                    onPress={async () => {
                      await handlePlaceOrder();
                      if (orderId) {
                        const res = await paymentApi.createPayment(orderId, "wechat");
                        if (res.success) {
                          setPaymentOrderId(orderId);
                          setShowPaymentWaiting(true);
                        }
                      }
                    }}
                    disabled={submitting}
                  >
                    {submitting ? (
                      <ActivityIndicator size="small" color="#FFFFFF" />
                    ) : (
                      <Text style={styles.paymentButtonText}>寰俊鏀粯</Text>
                    )}
                  </TouchableOpacity>
                </View>
              </>
            ) : null}

            {step === "success" ? (
              <View style={styles.successCard}>
                <Ionicons name="checkmark-circle" size={72} color={theme.colors.success} />
                <Text style={styles.successTitle}>璁㈠崟宸叉彁浜?/Text>
