                >
                  <Text style={styles.primaryText}>鏌ョ湅璁㈠崟</Text>
                </TouchableOpacity>
                <TouchableOpacity
                  style={styles.secondaryButtonWide}
                  onPress={() => (navigation as any).navigate("MainTabs", { screen: "Home" })}
                  accessibilityLabel="杩斿洖棣栭〉"
                >
                  <Text style={styles.secondaryText}>杩斿洖棣栭〉</Text>
