        onSelect={(coupon) => couponStore.selectCoupon(coupon)}
        onClose={() => setShowCouponSelector(false)}
      />

      {showPaymentWaiting && paymentOrderId ? (
        <PaymentWaitingScreen
          orderId={paymentOrderId}
          onSuccess={() => {
            setShowPaymentWaiting(false);
            setStep("success");
          }}
          onTimeout={() => {
            setShowPaymentWaiting(false);
          }}
        />
      ) : null}
    </SafeAreaView>
  );
