import React, { useState, useCallback, useEffect } from "react";
import {
  View,
  Text,
  StyleSheet,
  ScrollView,
  TouchableOpacity,
  ActivityIndicator,
  Alert,
} from "react-native";
import { useNavigation, useRoute, RouteProp } from "@react-navigation/native";
import type { NativeStackNavigationProp } from "@react-navigation/native-stack";
import { SafeAreaView } from "react-native-safe-area-context";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import type { RootStackParamList } from "../types/navigation";
import type { ClothingItem } from "../types/clothing";
import { clothingApi } from "../services/api/clothing.api";
import { theme } from "../theme";
import {
  cartApi,
  favoriteApi,
  clothingEnhancementApi,
  type SizeRecommendation,
} from "../services/api/commerce.api";
import { useSizeRecommendationStore } from "../stores/sizeRecommendationStore";
import { ProductImageCarousel } from "../components/ProductImageCarousel";
import { SKUSelector } from "../components/SKUSelector";
import { OutfitRecommendationCards } from "../components/OutfitRecommendationCards";

type ClothingDetailRouteProp = RouteProp<RootStackParamList, "ClothingDetail">;
type NavigationProp = NativeStackNavigationProp<RootStackParamList>;

export const ClothingDetailScreen: React.FC = () => {
  const navigation = useNavigation<NavigationProp>();
  const route = useRoute<ClothingDetailRouteProp>();
  const { clothingId } = route.params;

  const [item, setItem] = useState<ClothingItem | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isFavorite, setIsFavorite] = useState(false);
  const [showSKU, setShowSKU] = useState(false);
  const [selectedColor, setSelectedColor] = useState("");
  const [selectedSize, setSelectedSize] = useState("");
  const [quantity, setQuantity] = useState(1);
  const [relatedItems, setRelatedItems] = useState<
    { id: string; items: ClothingItem[]; title?: string }[]
  >([]);

  const sizeRecStore = useSizeRecommendationStore();
  const aiRecommendation = sizeRecStore.getRecommendation(clothingId);

  const loadItem = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await clothingApi.getById(clothingId);
      if (response.success && response.data) {
        setItem(response.data);
        setSelectedColor(response.data.colors?.[0] ?? "");
        setSelectedSize(response.data.size ?? "");

        const favResponse = await favoriteApi.check(clothingId);
        if (favResponse.success && favResponse.data) {
          setIsFavorite(favResponse.data.isFavorite);
        }
      } else {
        setError(response.error?.message ?? "鍔犺浇澶辫触");
      }
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "缃戠粶閿欒锛岃閲嶈瘯");
    } finally {
      setIsLoading(false);
    }
  }, [clothingId]);

  useEffect(() => {
    void loadItem();
    void sizeRecStore.fetchRecommendation(clothingId);

    void clothingEnhancementApi.getRelatedItems(clothingId).then((res) => {
      if (res.success && res.data) {
        const outfits = res.data.slice(0, 5).map((ri, idx) => ({
          id: `outfit-${idx}`,
          items: [ri],
          title: ri.name ?? `鎼厤 ${idx + 1}`,
        }));
        setRelatedItems(outfits);
      }
    });
  }, [clothingId, loadItem]);

  const handleToggleFavorite = useCallback(async () => {
    try {
      if (isFavorite) {
        await favoriteApi.remove(clothingId);
      } else {
        await favoriteApi.add(clothingId);
      }
      setIsFavorite(!isFavorite);
    } catch {
      Alert.alert("鎿嶄綔澶辫触", "璇风◢鍚庨噸璇昞

宸插姞鍏ヨ喘鐗╄溅", `${item.name ?? "鍟嗗搧"} x${quantity}`);
      } else {
        Alert.alert("娣诲姞澶辫触", response.error?.message ?? "璇风◢鍚庨噸璇昞

娣诲姞澶辫触", "缃戠粶閿欒");
    }
  }, [item, selectedColor, selectedSize, quantity]);

  const handleBuyNow = useCallback(async () => {
    if (!item) {
      return;
    }
    setShowSKU(false);
    Alert.alert("鎻愮ず", "璇峰厛娣诲姞鍒拌喘鐗╄溅鎴栦粠璐墿杞︾粨绠梊

large" color={theme.colors.primary} />
          <Text style={styles.loadingText}>鍔犺浇涓?..</Text>
        </View>
      </SafeAreaView>
    );
  }

  if (error || !item) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.errorContainer}>
          <Ionicons name="alert-circle-outline" size={48} color={theme.colors.error} />
          <Text style={styles.errorText}>{error ?? "鏈壘鍒板晢鍝乗

heart" : "heart-outline"}
              size={22}
              color={isFavorite ? theme.colors.like : theme.colors.textSecondary}
            />
            <Text style={styles.bottomIconLabel}>鏀惰棌</Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={styles.bottomIconButton}
            onPress={() => navigation.navigate("VirtualTryOn", { clothingId })}
          >
            <Ionicons name="sparkles-outline" size={22} color={theme.colors.textSecondary} />
            <Text style={styles.bottomIconLabel}>璇曡。</Text>
          </TouchableOpacity>
        </View>
        <View style={styles.bottomRight}>
          <TouchableOpacity style={styles.addToCartButton} onPress={() => setShowSKU(true)}>
            <Text style={styles.addToCartText}>鍔犲叆璐墿杞?/Text>
          </TouchableOpacity>
          <TouchableOpacity style={styles.buyNowButton} onPress={handleBuyNow}>
            <Text style={styles.buyNowText}>绔嬪嵆璐拱</Text>
          </TouchableOpacity>
        </View>
      </View>

      <SKUSelector
        visible={showSKU}
        colors={item.colors ?? []}
        sizes={item.size ? [item.size] : []}
        stock={999}
        selectedColor={selectedColor}
        selectedSize={selectedSize}
        quantity={quantity}
        onChange={handleSKUChange}
        onClose={() => setShowSKU(false)}
        itemId={clothingId}
        aiRecommendation={aiRecommendation ?? null}
      />
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: theme.colors.surface },
  header: {
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "space-between",
    paddingHorizontal: 16,
    paddingVertical: 12,
    borderBottomWidth: 1,
    borderBottomColor: theme.colors.border,
  },
  backButton: {
    width: 36,
    height: 36,
    alignItems: "center",
    justifyContent: "center",
  },
  headerTitle: { fontSize: 17, fontWeight: "600", color: theme.colors.text },
  loadingContainer: {
    flex: 1,
    alignItems: "center",
    justifyContent: "center",
  },
  loadingText: { fontSize: 14, color: theme.colors.textTertiary, marginTop: 8 },
  errorContainer: {
    flex: 1,
    alignItems: "center",
    justifyContent: "center",
    padding: 20,
  },
  errorText: { fontSize: 14, color: theme.colors.textTertiary, marginTop: 12, textAlign: "center" },
  retryButton: {
    backgroundColor: theme.colors.error,
    paddingHorizontal: 24,
    paddingVertical: 10,
    borderRadius: 8,
    marginTop: 16,
  },
  retryButtonText: { fontSize: 14, fontWeight: "500", color: theme.colors.surface },
  content: { flex: 1 },
  priceSection: { paddingHorizontal: 16, paddingTop: 16 },
  priceRow: { flexDirection: "row", alignItems: "baseline", gap: 8 },
  currentPrice: { fontSize: 20, fontWeight: "700", color: theme.colors.primary },
  originalPrice: {
    fontSize: 14,
    color: theme.colors.textTertiary,
    textDecorationLine: "line-through",
  },
  discountBadge: {
    backgroundColor: theme.colors.primary,
    paddingHorizontal: 6,
    paddingVertical: 2,
    borderRadius: 4,
  },
  discountText: { fontSize: 11, fontWeight: "600", color: theme.colors.surface },
  skuTrigger: {
    flexDirection: "row",
    justifyContent: "space-between",
    alignItems: "center",
    paddingHorizontal: 16,
    paddingVertical: 12,
    borderBottomWidth: 1,
    borderBottomColor: theme.colors.border,
  },
  skuTriggerLabel: { fontSize: 14, color: theme.colors.textSecondary },
  infoSection: { paddingHorizontal: 16, paddingTop: 16 },
  itemName: { fontSize: 18, fontWeight: "600", color: theme.colors.text, marginBottom: 4 },
  itemBrand: { fontSize: 14, color: theme.colors.textTertiary, marginBottom: 8 },
  relatedSection: { paddingHorizontal: 16, paddingTop: 8 },
  bottomBar: {
    flexDirection: "row",
    alignItems: "center",
    paddingHorizontal: 16,
    paddingVertical: 10,
    borderTopWidth: 1,
    borderTopColor: theme.colors.border,
    backgroundColor: theme.colors.surface,
  },
  bottomLeft: { flexDirection: "row", gap: 16 },
  bottomIconButton: { alignItems: "center", gap: 2 },
  bottomIconLabel: { fontSize: 10, color: theme.colors.textSecondary },
  bottomRight: { flex: 1, flexDirection: "row", justifyContent: "flex-end", gap: 8 },
  addToCartButton: {
    paddingHorizontal: 16,
    paddingVertical: 10,
    borderRadius: 20,
    borderWidth: 1,
    borderColor: theme.colors.primary,
  },
  addToCartText: { fontSize: 14, fontWeight: "500", color: theme.colors.primary },
  buyNowButton: {
