    ...Typography.caption.sm,
    color: theme.colors.textSecondary,
  },
  neutralRow: {
    flexDirection: "row",
    flexWrap: "wrap",
    gap: Spacing[3],
  },
  neutralItem: {
    alignItems: "center",
  },
  neutralCircle: {
    width: 32,
    height: 32,
    borderRadius: 16,
    marginBottom: Spacing[1],
  },
  avoidRow: {
    flexDirection: "row",
    flexWrap: "wrap",
    gap: Spacing[3],
  },
  avoidItem: {
    alignItems: "center",
  },
  avoidCircle: {
    width: 32,
    height: 32,
    borderRadius: 16,
    justifyContent: "center",
