      <Text style={styles.headerTitle}>瀹氬埗鏈嶅姟</Text>
      <View style={styles.headerSpacer} />
    </View>
  );

  const renderTabs = () => (
    <View style={styles.tabs}>
      <TouchableOpacity
        style={[styles.tab, activeTab === "new" && styles.tabActive]}
        onPress={() => setActiveTab("new")}
        activeOpacity={0.7}
      >
        <Text style={[styles.tabText, activeTab === "new" && styles.tabTextActive]}>鍙戣捣瀹氬埗</Text>
      </TouchableOpacity>
      <TouchableOpacity
        style={[styles.tab, activeTab === "list" && styles.tabActive]}
        onPress={() => setActiveTab("list")}
        activeOpacity={0.7}
      >
        <Text style={[styles.tabText, activeTab === "list" && styles.tabTextActive]}>鎴戠殑瀹氬埗</Text>
      </TouchableOpacity>
    </View>
  );

  const renderNewRequest = () => (
    <ScrollView
      showsVerticalScrollIndicator={false}
      contentContainerStyle={styles.formContainer}
      keyboardShouldPersistTaps="handled"
    >
      {/* Quick Action Cards */}
      <View style={styles.quickActions}>
        <TouchableOpacity
          style={styles.quickActionCard}
          onPress={() => navigation.navigate("CustomizationEditor" as any)}
          activeOpacity={0.7}
        >
          <View style={styles.quickActionIcon}>
            <Ionicons name="color-palette-outline" size={28} color={theme.colors.primary} />
          </View>
          <Text style={styles.quickActionTitle}>璁捐瀹氬埗</Text>
          <Text style={styles.quickActionDesc}>閫夋嫨妯℃澘锛屼笂浼犲浘妗堬紝鍒涘缓涓撳睘瀹氬埗</Text>
        </TouchableOpacity>
        <TouchableOpacity
          style={styles.quickActionCard}
          onPress={() => navigation.navigate("BrandQRScan")}
          activeOpacity={0.7}
        >
          <View style={styles.quickActionIcon}>
            <Ionicons name="qr-code-outline" size={28} color={theme.colors.primary} />
          </View>
          <Text style={styles.quickActionTitle}>鍝佺墝鎵爜</Text>
          <Text style={styles.quickActionDesc}>鎵弿鍝佺墝浜岀淮鐮侊紝涓€閿鍏ヨ。姗?/Text>
        </TouchableOpacity>
      </View>

      <Text style={styles.sectionTitle}>閫夋嫨鏈嶅姟绫诲瀷</Text>
      <View style={styles.serviceGrid}>
        {SERVICE_TYPES.map((service) => {
          const isSelected = selectedType === service.id;
          return (
            <TouchableOpacity
              key={service.id}
              style={[styles.serviceCard, isSelected && styles.serviceCardSelected]}
              onPress={() => setSelectedType(isSelected ? null : service.id)}
              activeOpacity={0.7}
            >
              <View
                style={[
                  styles.serviceIconContainer,
                  isSelected && styles.serviceIconContainerSelected,
                ]}
              >
                <Ionicons
                  name={service.icon}
                  size={24}
                  color={isSelected ? theme.colors.surface : theme.colors.primary}
                />
              </View>
              <Text style={[styles.serviceLabel, isSelected && styles.serviceLabelSelected]}>
                {service.label}
              </Text>
              <Text style={styles.serviceDescription} numberOfLines={2}>
                {service.description}
              </Text>
            </TouchableOpacity>
          );
        })}
      </View>

      <Text style={styles.sectionTitle}>瀹氬埗闇€姹傛弿杩?/Text>
      <View style={styles.textAreaContainer}>
        <TextInput
          style={styles.textArea}
          placeholder="璇疯缁嗘弿杩版偍鐨勫畾鍒堕渶姹傦紝鍖呮嫭娆惧紡銆佺敤閫斻€佺壒娈婅姹傜瓑..."
          placeholderTextColor={theme.colors.textTertiary}
          value={description}
          onChangeText={setDescription}
          multiline
          numberOfLines={5}
          textAlignVertical="top"
          maxLength={500}
        />
        <Text style={styles.charCount}>{description.length}/500</Text>
      </View>

      <Text style={styles.sectionTitle}>鍋忓ソ涓庨绠?(閫夊～)</Text>
      <View style={styles.optionalFields}>
        <View style={styles.inputField}>
          <Ionicons name="shirt-outline" size={18} color={theme.colors.textTertiary} />
          <TextInput
            style={styles.textInput}
            placeholder="闈㈡枡鍋忓ソ (濡傦細鐪熶笣銆佺緤姣涖€佷簹楹?"
            placeholderTextColor={theme.colors.textTertiary}
            value={fabricPreference}
            onChangeText={setFabricPreference}
            maxLength={50}
          />
        </View>
        <View style={styles.inputField}>
          <Ionicons name="wallet-outline" size={18} color={theme.colors.textTertiary} />
          <TextInput
            style={styles.textInput}
            placeholder="棰勭畻鑼冨洿 (濡傦細2000-5000)"
            placeholderTextColor={theme.colors.textTertiary}
            value={budgetRange}
            onChangeText={setBudgetRange}
            maxLength={30}
          />
        </View>
        <View style={styles.inputField}>
          <Ionicons name="document-text-outline" size={18} color={theme.colors.textTertiary} />
          <TextInput
            style={styles.textInput}
            placeholder="鍏朵粬琛ュ厖璇存槑"
            placeholderTextColor={theme.colors.textTertiary}
            value={additionalNotes}
            onChangeText={setAdditionalNotes}
            maxLength={200}
          />
        </View>
      </View>

      <TouchableOpacity
        style={[styles.submitButton, isSubmitting && styles.submitButtonDisabled]}
        onPress={handleSubmit}
        disabled={isSubmitting}
        activeOpacity={0.7}
      >
        {isSubmitting ? (
          <ActivityIndicator size="small" color={theme.colors.surface} />
        ) : (
          <Text style={styles.submitButtonText}>鎻愪氦瀹氬埗闇€姹?/Text>
        )}
      </TouchableOpacity>

      <View style={styles.bottomSpacer} />
    </ScrollView>
  );

  const renderRequestList = () => {
    if (isLoadingRequests) {
      return (
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="large" color={theme.colors.primary} />
          <Text style={styles.loadingText}>鍔犺浇涓?..</Text>
        </View>
      );
    }

    if (requests.length === 0) {
      return (
        <View style={styles.emptyContainer}>
          <Ionicons name="document-text-outline" size={48} color={Colors.neutral[300]} />
          <Text style={styles.emptyTitle}>鏆傛棤瀹氬埗闇€姹?/Text>
          <Text style={styles.emptySubtitle}>鐐瑰嚮"鍙戣捣瀹氬埗"寮€濮嬫偍鐨勭涓€涓畾鍒舵湇鍔?/Text>
          <TouchableOpacity
            style={styles.emptyButton}
            onPress={() => setActiveTab("new")}
            activeOpacity={0.7}
          >
            <Text style={styles.emptyButtonText}>鍙戣捣瀹氬埗</Text>
          </TouchableOpacity>
        </View>
      );
    }

    return (
      <ScrollView
        showsVerticalScrollIndicator={false}
        refreshControl={
          <RefreshControl
            refreshing={isRefreshing}
            onRefresh={handleRefresh}
            tintColor={theme.colors.primary}
          />
        }
        contentContainerStyle={styles.listContainer}
      >
        {requests.map((request) => {
          const statusConfig = STATUS_CONFIG[request.status] || {
            label: request.status,
            color: Colors.neutral[500],
          };
          return (
            <View key={request.id} style={styles.requestCard}>
              <View style={styles.requestCardHeader}>
                <View style={styles.requestTypeTag}>
                  <Ionicons
                    name={SERVICE_TYPES.find((s) => s.id === request.type)?.icon ?? "help-outline"}
                    size={14}
                    color={theme.colors.primary}
                  />
                  <Text style={styles.requestTypeText}>
                    {SERVICE_TYPES.find((s) => s.id === request.type)?.label || request.type}
                  </Text>
                </View>
                <View style={[styles.statusBadge, { backgroundColor: `${statusConfig.color}18` }]}>
                  <Text style={[styles.statusText, { color: statusConfig.color }]}>
                    {statusConfig.label}
                  </Text>
                </View>
              </View>
              <Text style={styles.requestDescription} numberOfLines={2}>
                {request.description}
              </Text>
              <View style={styles.requestFooter}>
                <Text style={styles.requestDate}>
                  {new Date(request.createdAt).toLocaleDateString("zh-CN")}
                </Text>
                {request.quotes && request.quotes.length > 0 && (
                  <View style={styles.quoteInfo}>
                    <Ionicons name="pricetag-outline" size={14} color={theme.colors.textTertiary} />
                    <Text style={styles.quoteText}>{request.quotes.length} 涓姤浠?/Text>
                  </View>
                )}
              </View>
            </View>
          );
        })}
      </ScrollView>
    );
  };

  return (
    <SafeAreaView style={styles.container}>
      {renderHeader()}
      {renderTabs()}
      <View style={styles.content}>
        {activeTab === "new" ? renderNewRequest() : renderRequestList()}
      </View>
    </SafeAreaView>
  );
};

