import React, { useCallback, useState, memo } from "react";
import {
  View,
  Text,
  StyleSheet,
  FlatList,
  ActivityIndicator,
  RefreshControl,
  TouchableOpacity,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { useFocusEffect, useNavigation } from "@react-navigation/native";
import type { NativeStackNavigationProp } from "@react-navigation/native-stack";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import { theme } from "../theme";
import { favoriteApi } from "../services/api/commerce.api";
import { useAuthStore } from "../stores/index";
import type { ClothingItem } from "../types/clothing";
import type { RootStackParamList } from "../types/navigation";
import { ImageWithPlaceholder } from "../components/common/ImageWithPlaceholder";

type NavProp = NativeStackNavigationProp<RootStackParamList>;

// 鍒楄〃椤归珮搴﹀父閲廫nconst LIST_ITEM_HEIGHT = 100;

/**
 * 鏀惰棌椤圭粍浠?- 浣跨敤 React.memo 浼樺寲
 * 閬垮厤涓嶅繀瑕佺殑閲嶆覆鏌揬n */
interface FavoriteItemProps {
  item: ClothingItem;
  onPress: (id: string) => void;
  onRemove: (id: string) => void;
}

const FavoriteItem = memo(function FavoriteItem({ item, onPress, onRemove }: FavoriteItemProps) {
  return (
    <TouchableOpacity style={styles.card} onPress={() => onPress(item.id)} activeOpacity={0.7}>
      {item.imageUri ? (
        <ImageWithPlaceholder source={{ uri: item.imageUri }} style={styles.image} />
      ) : (
        <View style={styles.placeholder}>
          <Ionicons name="shirt-outline" size={40} color={theme.colors.textTertiary} />
        </View>
      )}
      <View style={styles.info}>
        <Text style={styles.name} numberOfLines={1}>
          {item.name || item.category}
        </Text>
        {item.brand ? <Text style={styles.brand}>{item.brand}</Text> : null}
        {item.price != null ? <Text style={styles.price}>楼{item.price.toFixed(0)}</Text> : null}
      </View>
      <View style={styles.actions}>
        <TouchableOpacity
          style={styles.removeBtn}
          onPress={() => onRemove(item.id)}
          accessibilityLabel="鍙栨秷鏀惰棌"
          accessibilityRole="button"
        >
          <Ionicons name="heart" size={20} color={theme.colors.error} />
        </TouchableOpacity>
      </View>
    </TouchableOpacity>
  );
});

export const FavoritesScreen: React.FC = () => {
  const navigation = useNavigation<NavProp>();
  const isAuthenticated = useAuthStore((state) => state.isAuthenticated);
  const authLoading = useAuthStore((state) => state.isLoading);
  const [items, setItems] = useState<ClothingItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  const fetchFavorites = useCallback(async () => {
    try {
      const response = await favoriteApi.getAll();
      if (response.success && response.data) {
        setItems(response.data);
      } else {
        setItems([]);
      }
    } catch {
      setItems([]);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useFocusEffect(
    useCallback(() => {
      if (!isAuthenticated) {
        if (!authLoading) {
          setItems([]);
          setLoading(false);
        }
        return;
      }

      setLoading(true);
      void fetchFavorites();
    }, [authLoading, fetchFavorites, isAuthenticated])
  );

  const handleRemove = useCallback(async (id: string) => {
    try {
      await favoriteApi.remove(id);
      setItems((prev) => prev.filter((item) => item.id !== id));
    } catch {
      // ignore
    }
  }, []);

  const handleNavigate = useCallback(
    (id: string) => {
      navigation.navigate("Product", { clothingId: id });
    },
    [navigation]
  );

  const renderItem = useCallback(
    ({ item }: { item: ClothingItem }) => (
      <FavoriteItem item={item} onPress={handleNavigate} onRemove={handleRemove} />
    ),
    [handleNavigate, handleRemove]
  );

  const keyExtractor = useCallback((item: ClothingItem) => item.id, []);

  // 浣跨敤 getItemLayout 浼樺寲 FlatList 鎬ц兘
  const getItemLayout = useCallback(
    (_data: any, index: number) => ({
      length: LIST_ITEM_HEIGHT,
      offset: LIST_ITEM_HEIGHT * index + 12 * index, // 12 鏄?marginBottom
      index,
    }),
    []
  );

  if (loading) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.centerContainer}>
          <ActivityIndicator size="large" color={theme.colors.primary} />
          <Text style={styles.loadingText}>鍔犺浇涓?..</Text>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.header}>
        <TouchableOpacity onPress={() => navigation.goBack()} style={styles.backBtn}>
          <Ionicons name="arrow-back" size={24} color={theme.colors.text} />
        </TouchableOpacity>
        <Text style={styles.headerTitle}>鎴戠殑鏀惰棌</Text>
        <View style={styles.backBtn} />
      </View>
      <FlatList
        data={items}
        renderItem={renderItem}
        keyExtractor={keyExtractor}
        contentContainerStyle={items.length === 0 ? styles.emptyList : styles.list}
        refreshControl={
          <RefreshControl
            refreshing={refreshing}
            onRefresh={() => {
              setRefreshing(true);
              void fetchFavorites();
            }}
            tintColor={theme.colors.primary}
          />
        }
        ListEmptyComponent={
          <View style={styles.emptyContainer}>
            <Ionicons name="heart-outline" size={48} color={theme.colors.textTertiary} />
            <Text style={styles.emptyText}>杩樻病鏈夋敹钘忓摝</Text>
            <TouchableOpacity onPress={() => navigation.goBack()}>
              <Text style={styles.emptyAction}>鍘婚€涢€?/Text>
            </TouchableOpacity>
          </View>
        }
        // FlatList 鎬ц兘浼樺寲鍙傛暟
        getItemLayout={getItemLayout}
        removeClippedSubviews={true}
        maxToRenderPerBatch={10}
        windowSize={5}
        initialNumToRender={10}
      />
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: theme.colors.background },
  header: {
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "space-between",
    padding: 16,
    backgroundColor: theme.colors.surface,
    borderBottomWidth: 1,
    borderBottomColor: theme.colors.border,
  },
  headerTitle: { fontSize: 18, fontWeight: "700", color: theme.colors.text },
  backBtn: { width: 32, height: 32, alignItems: "center", justifyContent: "center" },
  list: { padding: 16 },
