import React, { useState, useEffect, useCallback } from "react";
import {
  View,
  Text,
  StyleSheet,
  TextInput,
  TouchableOpacity,
  ActivityIndicator,
  ScrollView,
  Alert,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import { merchantApi } from "../services/api/commerce.api";

type ScreenState = "form" | "pending" | "approved" | "rejected";

const BUSINESS_LICENSE_REGEX = /^[0-9A-HJ-NP-RTUW-Y]{2}\d{6}[0-9A-HJ-NP-RTUW-Y]{10}$/;
const PHONE_REGEX = /^1[3-9]\d{9}$/;

export const MerchantApplyScreen: React.FC = () => {
  const [screenState, setScreenState] = useState<ScreenState>("form");
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [rejectReason, setRejectReason] = useState("");

  const [brandName, setBrandName] = useState("");
  const [businessLicense, setBusinessLicense] = useState("");
  const [contactName, setContactName] = useState("");
  const [phone, setPhone] = useState("");
  const [description, setDescription] = useState("");
  const [brandNameError, setBrandNameError] = useState("");

  const checkExistingApplication = useCallback(async () => {
    try {
      const response = await merchantApi.getMerchantApplicationStatus();
      if (response.success && response.data) {
        const status = response.data.status;
        if (status === "pending" || status === "PENDING") {
          setScreenState("pending");
        } else if (status === "approved" || status === "APPROVED") {
          setScreenState("approved");
        } else if (status === "rejected" || status === "REJECTED") {
          setScreenState("rejected");
          setRejectReason((response.data as any).reason ?? "鏈€氳繃瀹℃牳");
        }
      }
    } catch {
      // No existing application, show form
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    void checkExistingApplication();
  }, [checkExistingApplication]);

  const isLicenseValid = BUSINESS_LICENSE_REGEX.test(businessLicense);
  const isPhoneValid = PHONE_REGEX.test(phone);
  const isFormValid =
    brandName.trim().length > 0 &&
    isLicenseValid &&
    contactName.trim().length > 0 &&
    isPhoneValid &&
    description.length <= 500;

  const handleSubmit = async () => {
    setSubmitting(true);
    try {
      const response = await merchantApi.applyForMerchant({
        brandName: brandName.trim(),
        businessLicense,
        contactName: contactName.trim(),
        phone,
        description: description.trim() || undefined,
      });
      if (response.success) {
        setScreenState("pending");
      } else {
        Alert.alert("鎻愪氦澶辫触", response.error?.message ?? "璇风◢鍚庨噸璇昞

鎻愪氦澶辫触", "缃戠粶閿欒锛岃绋嶅悗閲嶈瘯");
    } finally {
      setSubmitting(false);
    }
  };

  const handleRetry = () => {
    setScreenState("form");
    setBrandName("");
    setBusinessLicense("");
    setContactName("");
    setPhone("");
    setDescription("");
    setRejectReason("");
  };

  if (loading) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.center}>
          <ActivityIndicator size="large" color="#FF4D4F" />
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.headerTitle}>鍟嗗鍏ラ┗</Text>
      </View>

      {screenState === "form" ? (
        <ScrollView style={styles.content} keyboardShouldPersistTaps="handled">
          <Text style={styles.fieldLabel}>鍝佺墝鍚嶇О</Text>
          <TextInput
            style={styles.input}
            value={brandName}
            onChangeText={(text) => {
              setBrandName(text);
              setBrandNameError("");
            }}
            placeholder="璇疯緭鍏ュ搧鐗屽悕绉癨

#CCCCCC"
          />
          {brandNameError ? <Text style={styles.errorText}>{brandNameError}</Text> : null}

          <Text style={styles.fieldLabel}>钀ヤ笟鎵х収鍙?/Text>
          <View style={styles.inputRow}>
            <TextInput
              style={[styles.input, styles.inputWithIcon]}
              value={businessLicense}
              onChangeText={setBusinessLicense}
              placeholder="18浣嶇粺涓€绀句細淇＄敤浠ｇ爜"
              placeholderTextColor="#CCCCCC"
              maxLength={18}
            />
            {businessLicense.length > 0 && (
              <Ionicons
                name={isLicenseValid ? "checkmark-circle" : "close-circle"}
                size={20}
                color={isLicenseValid ? "#52C41A" : "#FF4D4F"}
                style={styles.validationIcon}
              />
            )}
          </View>

          <Text style={styles.fieldLabel}>鑱旂郴浜?/Text>
          <TextInput
            style={styles.input}
            value={contactName}
            onChangeText={setContactName}
            placeholder="璇疯緭鍏ヨ仈绯讳汉濮撳悕"
            placeholderTextColor="#CCCCCC"
          />

          <Text style={styles.fieldLabel}>鎵嬫満鍙?/Text>
          <View style={styles.inputRow}>
            <TextInput
              style={[styles.input, styles.inputWithIcon]}
              value={phone}
              onChangeText={setPhone}
              placeholder="璇疯緭鍏ユ墜鏈哄彿"
              placeholderTextColor="#CCCCCC"
              keyboardType="phone-pad"
              maxLength={11}
            />
            {phone.length > 0 && (
              <Ionicons
                name={isPhoneValid ? "checkmark-circle" : "close-circle"}
                size={20}
                color={isPhoneValid ? "#52C41A" : "#FF4D4F"}
                style={styles.validationIcon}
              />
            )}
          </View>

          <Text style={styles.fieldLabel}>鍝佺墝绠€浠?/Text>
          <TextInput
            style={[styles.input, styles.textArea]}
            value={description}
            onChangeText={setDescription}
            placeholder="璇风畝瑕佷粙缁嶅搧鐗岋紙閫夊～锛塡

#CCCCCC"
            multiline
            maxLength={500}
          />
          <Text style={styles.charCount}>{description.length}/500</Text>

          <TouchableOpacity
            style={[styles.submitButton, !isFormValid && styles.submitButtonDisabled]}
            onPress={handleSubmit}
            disabled={!isFormValid || submitting}
          >
            {submitting ? (
              <ActivityIndicator size="small" color="#FFFFFF" />
            ) : (
              <Text style={styles.submitButtonText}>鎻愪氦鐢宠</Text>
            )}
          </TouchableOpacity>
        </ScrollView>
      ) : null}

      {screenState === "pending" ? (
        <View style={styles.statusContainer}>
          <ActivityIndicator size="large" color="#FF4D4F" />
          <Text style={styles.statusTitle}>鐢宠瀹℃牳涓?/Text>
          <Text style={styles.statusMessage}>鐢宠宸叉彁浜わ紝鎴戜滑灏嗗湪1-3涓伐浣滄棩鍐呭畬鎴愬鏍?/Text>
        </View>
      ) : null}

      {screenState === "approved" ? (
        <View style={styles.statusContainer}>
          <Ionicons name="checkmark-circle" size={64} color="#52C41A" />
          <Text style={styles.statusTitle}>鎭枩锛佹偍鐨勫晢瀹剁敵璇峰凡閫氳繃</Text>
          <TouchableOpacity style={styles.submitButton}>
            <Text style={styles.submitButtonText}>杩涘叆鍟嗗鍚庡彴</Text>
          </TouchableOpacity>
        </View>
      ) : null}

      {screenState === "rejected" ? (
        <View style={styles.statusContainer}>
          <Ionicons name="close-circle" size={64} color="#FF4D4F" />
          <Text style={styles.statusTitle}>寰堟姳姝夛紝鎮ㄧ殑鐢宠鏈€氳繃</Text>
          <Text style={styles.statusMessage}>鍘熷洜锛歿rejectReason}</Text>
          <TouchableOpacity style={styles.submitButton} onPress={handleRetry}>
            <Text style={styles.submitButtonText}>閲嶆柊鐢宠</Text>
          </TouchableOpacity>
        </View>
      ) : null}
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: "#FFFFFF" },
  header: {
    paddingHorizontal: 16,
    paddingVertical: 14,
    borderBottomWidth: 1,
    borderBottomColor: "#F0F0F0",
    alignItems: "center",
  },
  headerTitle: { fontSize: 17, fontWeight: "600", color: "#333333" },
  center: { flex: 1, alignItems: "center", justifyContent: "center" },
  content: { flex: 1, padding: 16 },
  fieldLabel: {
    fontSize: 14,
    fontWeight: "500",
    color: "#333333",
    marginBottom: 6,
    marginTop: 12,
  },
  input: {
    borderWidth: 1,
