    borderRadius: 8,
    paddingHorizontal: 12,
    paddingVertical: 10,
    fontSize: 15,
    color: "#333333",
  },
  inputRow: { position: "relative" },
  inputWithIcon: { paddingRight: 40 },
  validationIcon: { position: "absolute", right: 12, top: 12 },
  errorText: { fontSize: 12, color: "#FF4D4F", marginTop: 4 },
  textArea: { height: 80, textAlignVertical: "top" },
  charCount: {
    fontSize: 12,
    color: "#999999",
    textAlign: "right",
    marginTop: 4,
  },
  submitButton: {
    backgroundColor: "#FF4D4F",
    paddingVertical: 14,
    borderRadius: 10,
    alignItems: "center",
    marginTop: 24,
  },
  submitButtonDisabled: { backgroundColor: "#FFB0B0" },
  submitButtonText: {
    fontSize: 16,
    fontWeight: "600",
    color: "#FFFFFF",
  },
  statusContainer: {
    flex: 1,
    alignItems: "center",
    justifyContent: "center",
    padding: 32,
  },
  statusTitle: {
    fontSize: 20,
    fontWeight: "700",
    color: "#333333",
    marginTop: 16,
    textAlign: "center",
  },
  statusMessage: {
    fontSize: 14,
    color: "#999999",
    marginTop: 8,
    textAlign: "center",
    lineHeight: 22,
  },
});

export default MerchantApplyScreen;

