import React, { useState, useCallback } from "react";
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
  TextInput,
  Dimensions,
  Alert,
  ActivityIndicator,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { Ionicons } from "../polyfills/expo-vector-icons";
import Animated, {
  FadeIn,
  useAnimatedStyle,
  withSpring,
  useSharedValue,
} from "react-native-reanimated";
import AsyncStorage from "@react-native-async-storage/async-storage";
import { useNavigation } from "@react-navigation/native";
import type { NavigationProp as NavProp } from "@react-navigation/native";
import { theme, Colors, Spacing, BorderRadius, Shadows } from "../theme";
import { profileApi } from "../services/api/profile.api";
import { PhotoGuideOverlay } from "../components/photo/PhotoGuideOverlay";
import { PrivacyConsentModal } from "../components/privacy/PrivacyConsentModal";
import type { RootStackParamList } from "../types/navigation";

const { width: _SCREEN_WIDTH } = Dimensions.get("window");
const ONBOARDING_COMPLETE_KEY = "@aineed:onboarding_complete";

type NavigationProp = NavProp<RootStackParamList>;
type OnboardingStep = "BASIC_INFO" | "PHOTO" | "QUIZ" | "COMPLETE";

const STEPS: OnboardingStep[] = ["BASIC_INFO", "PHOTO", "QUIZ", "COMPLETE"];
const TOTAL_STEPS = 3; // BASIC_INFO, PHOTO, QUIZ (COMPLETE is terminal)

const GENDER_OPTIONS = [
  { id: "female", label: "濂砛

man-outline" as const },
  { id: "other", label: "鍏朵粬", icon: "person-outline" as const },
];

const AGE_RANGES = ["18-24", "25-30", "31-40", "40+"];

export const OnboardingScreen: React.FC = () => {
  const navigation = useNavigation<NavigationProp>();
  const [currentStep, setCurrentStep] = useState<OnboardingStep>("BASIC_INFO");
  const [isSaving, setIsSaving] = useState(false);

  // Step 0: BASIC_INFO state
  const [gender, setGender] = useState<string | null>(null);
  const [ageRange, setAgeRange] = useState<string | null>(null);

  // Step 1: PHOTO state
  const [photoUri, setPhotoUri] = useState<string | null>(null);
  const [showCameraGuide, setShowCameraGuide] = useState(false);
  const [showPrivacyModal, setShowPrivacyModal] = useState(false);

  const progressValue = useSharedValue(1 / TOTAL_STEPS);

  const currentStepIndex = STEPS.indexOf(currentStep);

  const updateProgress = useCallback(
    (step: OnboardingStep) => {
      const idx = STEPS.indexOf(step);
      progressValue.value = withSpring(Math.min(idx + 1, TOTAL_STEPS) / TOTAL_STEPS, {
        damping: 15,
        stiffness: 120,
      });
    },
    [progressValue]
  );

  const progressStyle = useAnimatedStyle(() => ({
    width: `${progressValue.value * 100}%`,
  }));

  const canProceed = useCallback((): boolean => {
    switch (currentStep) {
      case "BASIC_INFO":
        return gender !== null && ageRange !== null;
      case "PHOTO":
        return true; // photo is optional, skip is allowed
      case "QUIZ":
        return true; // quiz is optional, skip is allowed
      default:
        return false;
    }
  }, [currentStep, gender, ageRange]);

  const handleNext = useCallback(() => {
    if (currentStep === "BASIC_INFO") {
      const nextStep: OnboardingStep = "PHOTO";
      setCurrentStep(nextStep);
      updateProgress(nextStep);
    } else if (currentStep === "PHOTO") {
      const nextStep: OnboardingStep = "QUIZ";
      setCurrentStep(nextStep);
      updateProgress(nextStep);
    } else if (currentStep === "QUIZ") {
      void handleComplete();
    }
  }, [currentStep, updateProgress]);

  const handleBack = useCallback(() => {
    if (currentStep === "PHOTO") {
      setCurrentStep("BASIC_INFO");
      updateProgress("BASIC_INFO");
    } else if (currentStep === "QUIZ") {
      setCurrentStep("PHOTO");
      updateProgress("PHOTO");
    }
  }, [currentStep, updateProgress]);

  const handleSkip = useCallback(() => {
    if (currentStep === "PHOTO") {
      handleNext();
    } else if (currentStep === "QUIZ") {
      void handleComplete();
    }
  }, [currentStep, handleNext]);

  const handleComplete = useCallback(async () => {
    setIsSaving(true);
    try {
      const updateData: Record<string, unknown> = {
        gender: gender ?? undefined,
        ageRange: ageRange ?? undefined,
      };

      await profileApi.updateProfile(updateData as any);
      await AsyncStorage.setItem(ONBOARDING_COMPLETE_KEY, "true");

      navigation.reset({
        index: 0,
        routes: [{ name: "MainTabs" }],
      });
    } catch {
      await AsyncStorage.setItem(ONBOARDING_COMPLETE_KEY, "true");
      navigation.reset({
        index: 0,
        routes: [{ name: "MainTabs" }],
      });
    } finally {
      setIsSaving(false);
    }
  }, [gender, ageRange, navigation]);

  const handlePhotoUpload = useCallback(() => {
    setShowPrivacyModal(true);
  }, []);

  const handlePrivacyConfirm = useCallback(() => {
    setShowPrivacyModal(false);
    setShowCameraGuide(true);
  }, []);

  const handlePrivacyCancel = useCallback(() => {
    setShowPrivacyModal(false);
  }, []);

  const handleTakePhoto = useCallback(() => {
    // Placeholder: in production this would open camera via expo-image-picker
    setShowCameraGuide(false);
    setPhotoUri("placeholder://photo-taken");
  }, []);

  const renderProgressBar = () => (
    <View style={styles.progressContainer}>
      <View style={styles.progressTrack}>
        <Animated.View style={[styles.progressFill, progressStyle]} />
      </View>
      <Text style={styles.progressText}>
        {Math.min(currentStepIndex + 1, TOTAL_STEPS)} / {TOTAL_STEPS}
      </Text>
    </View>
  );

  const renderBasicInfoStep = () => (
    <Animated.View entering={FadeIn.duration(350)} style={styles.stepContent}>
      <View style={styles.stepHeader}>
        <Text style={styles.stepTitle}>鍩烘湰淇℃伅</Text>
        <Text style={styles.stepSubtitle}>甯姪鎴戜滑鏇村ソ鍦颁簡瑙ｄ綘</Text>
      </View>
      <ScrollView showsVerticalScrollIndicator={false} contentContainerStyle={styles.formContent}>
        {/* Gender selector */}
        <View style={styles.sectionBlock}>
          <Text style={styles.sectionLabel}>
            鎬у埆 <Text style={styles.requiredAsterisk}>*</Text>
          </Text>
          <View style={styles.genderRow}>
            {GENDER_OPTIONS.map((option) => {
              const isSelected = gender === option.id;
              return (
                <TouchableOpacity
                  key={option.id}
                  style={[styles.genderPill, isSelected && styles.genderPillSelected]}
                  onPress={() => setGender(option.id)}
                  activeOpacity={0.7}
                  accessibilityLabel={option.label}
                  accessibilityRole="button"
                >
                  <Ionicons
                    name={option.icon}
                    size={20}
                    color={isSelected ? "#FFFFFF" : theme.colors.textSecondary}
                  />
                  <Text
                    style={[styles.genderPillText, isSelected && styles.genderPillTextSelected]}
                  >
                    {option.label}
                  </Text>
                </TouchableOpacity>
              );
            })}
          </View>
        </View>

        {/* Age range selector */}
        <View style={styles.sectionBlock}>
          <Text style={styles.sectionLabel}>
            骞撮緞娈?<Text style={styles.requiredAsterisk}>*</Text>
          </Text>
          <ScrollView
            horizontal
            showsHorizontalScrollIndicator={false}
            contentContainerStyle={styles.ageRow}
          >
            {AGE_RANGES.map((range) => {
              const isSelected = ageRange === range;
              return (
                <TouchableOpacity
                  key={range}
                  style={[styles.agePill, isSelected && styles.agePillSelected]}
                  onPress={() => setAgeRange(range)}
                  activeOpacity={0.7}
                  accessibilityLabel={range}
                  accessibilityRole="button"
                >
                  <Text style={[styles.agePillText, isSelected && styles.agePillTextSelected]}>
                    {range}
                  </Text>
                </TouchableOpacity>
              );
            })}
          </ScrollView>
        </View>
      </ScrollView>
    </Animated.View>
  );

  const renderPhotoStep = () => (
    <Animated.View entering={FadeIn.duration(350)} style={styles.stepContent}>
      <View style={styles.stepHeader}>
        <Text style={styles.stepTitle}>涓婁紶浣犵殑鐓х墖</Text>
        <Text style={styles.stepSubtitle}>璁╅鏍煎垎鏋愭洿绮惧噯</Text>
      </View>
      <ScrollView showsVerticalScrollIndicator={false} contentContainerStyle={styles.formContent}>
        <TouchableOpacity
          style={styles.uploadArea}
          onPress={handlePhotoUpload}
          activeOpacity={0.7}
          accessibilityLabel="鐐瑰嚮涓婁紶鐓х墖"
          accessibilityRole="button"
        >
          <Ionicons name="camera-outline" size={40} color={theme.colors.textTertiary} />
          <Text style={styles.uploadLabel}>鐐瑰嚮涓婁紶</Text>
          <Text style={styles.uploadHint}>浠呯敤浜庝綋鍨嬪垎鏋愬拰璇曡。鏁堟灉鐢熸垚</Text>
        </TouchableOpacity>

        {photoUri && (
          <View style={styles.photoUploadedContainer}>
            <Ionicons name="checkmark-circle" size={20} color={Colors.semantic.success} />
            <Text style={styles.photoUploadedText}>鐓х墖宸查€夋嫨</Text>
          </View>
        )}

        {/* Camera guide overlay */}
        {showCameraGuide && (
          <View style={styles.cameraGuideContainer}>
            <PhotoGuideOverlay visible={showCameraGuide} />
            <TouchableOpacity
              style={styles.captureButton}
              onPress={handleTakePhoto}
              activeOpacity={0.7}
              accessibilityLabel="鎷嶇収"
              accessibilityRole="button"
            >
              <Ionicons name="camera" size={24} color="#FFFFFF" />
              <Text style={styles.captureButtonText}>鎷嶇収</Text>
            </TouchableOpacity>
          </View>
        )}
      </ScrollView>

      {/* Skip option */}
      <TouchableOpacity
        style={styles.skipButton}
        onPress={handleSkip}
        activeOpacity={0.7}
        accessibilityLabel="璺宠繃杩欎竴姝

button"
      >
        <Text style={styles.skipText}>璺宠繃杩欎竴姝?/Text>
      </TouchableOpacity>

      <PrivacyConsentModal
        visible={showPrivacyModal}
        onConfirm={handlePrivacyConfirm}
        onCancel={handlePrivacyCancel}
      />
    </Animated.View>
  );

  const renderQuizStep = () => (
    <Animated.View entering={FadeIn.duration(350)} style={styles.stepContent}>
      <View style={styles.stepHeader}>
        <Text style={styles.stepTitle}>椋庢牸娴嬭瘯</Text>
        <Text style={styles.stepSubtitle}>鍙戠幇浣犵殑涓撳睘椋庢牸</Text>
      </View>
      <View style={styles.quizPlaceholder}>
        <Ionicons name="sparkles-outline" size={48} color={theme.colors.primary} />
        <Text style={styles.quizPlaceholderTitle}>椋庢牸娴嬭瘯</Text>
        <Text style={styles.quizPlaceholderSubtitle}>
          閫氳繃鍑犻亾鍥剧墖閫夋嫨棰橈紝甯綘鎵惧埌鏈€閫傚悎鐨勯鏍兼柟鍚慭n        </Text>
        <TouchableOpacity
          style={styles.quizStartButton}
          onPress={() => {
            navigation.navigate("StyleQuiz");
          }}
          activeOpacity={0.7}
          accessibilityLabel="寮€濮嬫祴璇昞

button"
        >
          <Text style={styles.quizStartButtonText}>寮€濮嬫祴璇?/Text>
        </TouchableOpacity>
      </View>

      {/* Skip option */}
      <TouchableOpacity
        style={styles.skipButton}
        onPress={handleSkip}
        activeOpacity={0.7}
        accessibilityLabel="璺宠繃"
        accessibilityRole="button"
      >
        <Text style={styles.skipText}>璺宠繃</Text>
      </TouchableOpacity>
    </Animated.View>
  );

  const renderCurrentStep = () => {
    switch (currentStep) {
      case "BASIC_INFO":
        return renderBasicInfoStep();
      case "PHOTO":
        return renderPhotoStep();
      case "QUIZ":
        return renderQuizStep();
      case "COMPLETE":
        return null;
      default:
        return null;
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      {renderProgressBar()}
      <View style={styles.content}>{renderCurrentStep()}</View>
      <View style={styles.footer}>
        {currentStep !== "BASIC_INFO" && (
          <TouchableOpacity
            style={styles.backButton}
            onPress={handleBack}
            activeOpacity={0.7}
            accessibilityLabel="涓婁竴姝

button"
          >
            <Ionicons name="arrow-back" size={20} color={theme.colors.textSecondary} />
            <Text style={styles.backButtonText}>涓婁竴姝?/Text>
          </TouchableOpacity>
        )}
        <View style={styles.footerSpacer} />
        <TouchableOpacity
          style={[styles.nextButton, !canProceed() && styles.nextButtonDisabled]}
          onPress={handleNext}
          disabled={!canProceed() || isSaving}
          activeOpacity={0.7}
          accessibilityLabel={currentStep === "QUIZ" ? "瀹屾垚" : "涓嬩竴姝

QUIZ" && (
                <Ionicons name="arrow-forward" size={18} color={theme.colors.surface} />
              )}
            </>
          )}
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
};

