import React, { useCallback, useEffect, useMemo, useState } from "react";
import {
  ActivityIndicator,
  Alert,
  FlatList,
  Image,
  RefreshControl,
  StyleSheet,
  Text,
  TouchableOpacity,
  View,
} from "react-native";
import { useNavigation } from "@react-navigation/native";
import type { NativeStackNavigationProp } from "@react-navigation/native-stack";
import { SafeAreaView } from "react-native-safe-area-context";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import { orderApi, orderEnhancementApi } from "../services/api/commerce.api";
import type { Order, OrderStatus } from "../types";
import type { RootStackParamList } from "../types/navigation";
import { theme } from "../theme";

type OrdersNavigation = NativeStackNavigationProp<RootStackParamList>;
type TabKey = "all" | "pending" | "paid" | "shipped" | "delivered" | "refund";

interface TabConfig {
  key: TabKey;
  label: string;
  status?: OrderStatus;
  isRefundTab?: boolean;
}

const TABS: TabConfig[] = [
  { key: "all", label: "鍏ㄩ儴" },
  { key: "pending", label: "寰呮敮浠榎

0");
  const day = String(date.getDate()).padStart(2, "0");
  const hours = String(date.getHours()).padStart(2, "0");
  const minutes = String(date.getMinutes()).padStart(2, "0");
  return `${month}/${day} ${hours}:${minutes}`;
}

export const OrdersScreen: React.FC = () => {
  const navigation = useNavigation<OrdersNavigation>();
  const [activeTab, setActiveTab] = useState<TabKey>("all");
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [loadingMore, setLoadingMore] = useState(false);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);

  const activeStatus = useMemo(
    () => TABS.find((tab) => tab.key === activeTab)?.status,
    [activeTab]
  );

  const loadOrders = useCallback(
    async (pageNumber = 1, mode: "initial" | "refresh" | "append" = "initial") => {
      if (mode === "append") {
        setLoadingMore(true);
      } else if (mode === "refresh") {
        setRefreshing(true);
      } else {
        setLoading(true);
      }

      try {
        const activeTabConfig = TABS.find((tab) => tab.key === activeTab);
        const isRefund = activeTabConfig?.isRefundTab ?? false;

        const response = isRefund
          ? await orderEnhancementApi.getOrdersByTab("refund", pageNumber, 10)
          : await orderApi.getAll({
              status: activeStatus,
              page: pageNumber,
              limit: 10,
            });
        const payload = response.data;

        if (response.success && payload) {
          setOrders((prev) => (mode === "append" ? [...prev, ...payload.items] : payload.items));
          setHasMore(payload.hasMore ?? false);
          setPage(pageNumber);
        } else if (mode !== "append") {
          setOrders([]);
          setHasMore(false);
        }
      } catch {
        if (mode !== "append") {
          setOrders([]);
          setHasMore(false);
        }
      } finally {
        setLoading(false);
        setRefreshing(false);
        setLoadingMore(false);
      }
    },
    [activeStatus]
  );

  useEffect(() => {
    void loadOrders(1, "initial");
  }, [loadOrders]);

  const handleCancelOrder = useCallback(
    async (orderId: string) => {
      const response = await orderApi.cancel(orderId);
      if (response.success) {
        await loadOrders(1, "refresh");
      }
    },
    [loadOrders]
  );

  const renderOrderCard = useCallback(
    ({ item }: { item: Order }) => {
      const status = STATUS_META[item.status] ?? {
        label: item.status,
        color: theme.colors.textSecondary,
      };

      return (
        <View style={styles.orderCard}>
          <View style={styles.orderHeader}>
            <View>
              <Text style={styles.orderIdLabel}>璁㈠崟鍙?/Text>
              <Text style={styles.orderIdValue}>{item.id.slice(0, 12).toUpperCase()}</Text>
            </View>
            <View style={[styles.statusBadge, { backgroundColor: `${status.color}16` }]}>
              <Text style={[styles.statusText, { color: status.color }]}>{status.label}</Text>
            </View>
          </View>

          <View style={styles.itemsRow}>
            {item.items.slice(0, 4).map((orderItem) =>
              orderItem.imageUri ? (
                <Image
                  key={orderItem.id}
                  source={{ uri: orderItem.imageUri }}
                  style={styles.itemThumbnail}
                />
              ) : (
                <View key={orderItem.id} style={styles.itemThumbnailFallback}>
                  <Ionicons name="shirt-outline" size={18} color={theme.colors.textTertiary} />
                </View>
              )
            )}
            {item.items.length > 4 ? (
              <View style={styles.moreItemsBadge}>
                <Text style={styles.moreItemsText}>+{item.items.length - 4}</Text>
              </View>
            ) : null}
          </View>

          <View style={styles.orderFooter}>
            <Text style={styles.orderDate}>{formatDate(item.createdAt)}</Text>
            <View style={styles.orderSummary}>
              <Text style={styles.orderSummaryText}>{item.items.length} 浠?路 鍚堣</Text>
              <Text style={styles.orderTotal}>
                {"\u00A5"}
                {item.totalAmount.toFixed(2)}
              </Text>
            </View>
          </View>

          <View style={styles.actionRow}>
            {item.status === "pending" ? (
              <TouchableOpacity
                style={styles.secondaryButton}
                onPress={() => void handleCancelOrder(item.id)}
                accessibilityLabel="鍙栨秷璁㈠崟"
              >
                <Text style={styles.secondaryButtonText}>鍙栨秷璁㈠崟</Text>
              </TouchableOpacity>
            ) : null}

            {item.status === "pending" ? (
              <TouchableOpacity
                style={styles.primaryButton}
                onPress={() => navigation.navigate("OrderDetail", { orderId: item.id })}
              >
                <Text style={styles.primaryButtonText}>鍘绘敮浠?/Text>
              </TouchableOpacity>
            ) : null}

            {item.status === "paid" ? (
              <TouchableOpacity
                style={styles.secondaryButton}
                onPress={() => {
                  Alert.alert("鎻愰啋鍙戣揣", "宸叉彁閱掑晢瀹跺敖蹇彂璐

shipped" ? (
              <TouchableOpacity
                style={styles.secondaryButton}
                onPress={() => {
                  Alert.alert("鏌ョ湅鐗╂祦", "鐗╂祦淇℃伅鍙湪璁㈠崟璇︽儏涓煡鐪媆

shipped" ? (
              <TouchableOpacity
                style={styles.primaryButton}
                onPress={async () => {
                  await orderEnhancementApi.confirmReceipt(item.id);
                  await loadOrders(1, "refresh");
                }}
              >
                <Text style={styles.primaryButtonText}>纭鏀惰揣</Text>
              </TouchableOpacity>
            ) : null}

            {item.status === "delivered" ? (
              <TouchableOpacity
                style={styles.secondaryButton}
                onPress={() => navigation.navigate("MainTabs", { screen: "Home" } as never)}
              >
                <Text style={styles.secondaryButtonText}>鍐嶆璐拱</Text>
              </TouchableOpacity>
            ) : null}

            {item.status === "delivered" || item.status === "cancelled" ? (
              <TouchableOpacity
                style={styles.dangerTextButton}
                onPress={async () => {
                  Alert.alert("鍒犻櫎璁㈠崟", "纭畾鍒犻櫎姝よ鍗曪紵", [
                    { text: "鍙栨秷", style: "cancel" },
                    {
                      text: "鍒犻櫎",
                      style: "destructive",
                      onPress: async () => {
                        await orderEnhancementApi.softDeleteOrder(item.id);
                        await loadOrders(1, "refresh");
                      },
                    },
                  ]);
                }}
              >
                <Text style={styles.dangerText}>鍒犻櫎</Text>
              </TouchableOpacity>
            ) : null}

            <TouchableOpacity
              style={styles.primaryButton}
              onPress={() => navigation.navigate("OrderDetail", { orderId: item.id })}
              accessibilityLabel="鏌ョ湅璁㈠崟璇︽儏"
            >
              <Text style={styles.primaryButtonText}>鏌ョ湅璇︽儏</Text>
            </TouchableOpacity>
          </View>
        </View>
      );
    },
    [handleCancelOrder, navigation]
  );

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.header}>
        <TouchableOpacity
          style={styles.iconButton}
          onPress={() => navigation.goBack()}
          accessibilityLabel="杩斿洖"
        >
          <Ionicons name="arrow-back" size={22} color={theme.colors.text} />
        </TouchableOpacity>
        <Text style={styles.headerTitle}>鎴戠殑璁㈠崟</Text>
        <View style={styles.headerPlaceholder} />
      </View>

      <View style={styles.tabBar}>
        {TABS.map((tab) => (
          <TouchableOpacity
            key={tab.key}
            style={[styles.tabItem, activeTab === tab.key && styles.tabItemActive]}
            onPress={() => setActiveTab(tab.key)}
            accessibilityLabel={`${tab.label}璁㈠崟`}
          >
            <Text style={[styles.tabText, activeTab === tab.key && styles.tabTextActive]}>
              {tab.label}
            </Text>
          </TouchableOpacity>
        ))}
      </View>

      {loading ? (
        <View style={styles.center}>
          <ActivityIndicator size="large" color={theme.colors.primary} />
        </View>
      ) : orders.length === 0 ? (
        <FlatList
          data={[]}
          renderItem={null}
          ListEmptyComponent={
            <View style={styles.emptyState}>
              <Ionicons name="bag-handle-outline" size={64} color={theme.colors.textTertiary} />
              <Text style={styles.emptyTitle}>杩樻病鏈夎鍗?/Text>
              <Text style={styles.emptySubtitle}>鍏堝幓鐪嬬湅鎺ㄨ崘鐨勭┛鎼拰鍗曞搧鍚с€?/Text>
            </View>
          }
          refreshControl={
            <RefreshControl
              refreshing={refreshing}
              onRefresh={() => void loadOrders(1, "refresh")}
              colors={[theme.colors.primary]}
            />
          }
        />
      ) : (
        <FlatList
          data={orders}
          keyExtractor={(item) => item.id}
          renderItem={renderOrderCard}
          contentContainerStyle={styles.listContent}
          onEndReachedThreshold={0.2}
          onEndReached={() => {
            if (!loadingMore && hasMore) {
              void loadOrders(page + 1, "append");
            }
          }}
          refreshControl={
            <RefreshControl
              refreshing={refreshing}
              onRefresh={() => void loadOrders(1, "refresh")}
              colors={[theme.colors.primary]}
            />
          }
          ListFooterComponent={
            loadingMore ? (
              <View style={styles.footerLoading}>
                <ActivityIndicator size="small" color={theme.colors.primary} />
              </View>
            ) : !hasMore ? (
              <Text style={styles.footerText}>娌℃湁鏇村璁㈠崟浜?/Text>
            ) : null
          }
        />
      )}
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
