import React, { useState, useEffect, useCallback, useRef } from "react";
import {
  View,
  Text,
  StyleSheet,
  ScrollView,
  Image,
  TouchableOpacity,
  TextInput,
  ActivityIndicator,
  Alert,
  FlatList,
  Dimensions,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { useNavigation, useRoute } from "@react-navigation/native";
import type { NativeStackNavigationProp } from "@react-navigation/native-stack";
import type { RouteProp } from "@react-navigation/native";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import { SharedElement } from "react-navigation-shared-element";
import { theme } from "../theme";
import { communityApi, PostComment } from "../services/api/community.api";
import { BookmarkSheet } from "../components/community/BookmarkSheet";
import type { RootStackParamList } from "../types/navigation";

type Navigation = NativeStackNavigationProp<RootStackParamList>;
type _PostDetailRoute = RouteProp<RootStackParamList, "Community">;

const SCREEN_WIDTH = Dimensions.get("window").width;

const DEFAULT_COMMENTS: PostComment[] = [];

export const PostDetailScreen: React.FC = () => {
  const navigation = useNavigation<Navigation>();
  const route = useRoute<any>();
  const postId = (route.params as any)?.postId ?? "";

  const [post, setPost] = useState<{
    id: string;
    title: string;
    content: string;
    images: string[];
    tags: string[];
    likesCount: number;
    commentsCount: number;
    isLiked: boolean;
    isBookmarked: boolean;
    author: { id: string; nickname: string; avatar: string | null };
    bloggerLevel?: "blogger" | "big_v" | null;
    createdAt: string;
  } | null>(null);
  const [comments, setComments] = useState<PostComment[]>(DEFAULT_COMMENTS);
  const [loading, setLoading] = useState(true);
  const [commentText, setCommentText] = useState("");
  const [submittingComment, setSubmittingComment] = useState(false);
  const [showBookmarkSheet, setShowBookmarkSheet] = useState(false);
  const [expandedReplies, setExpandedReplies] = useState<Set<string>>(new Set());
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const scrollViewRef = useRef<ScrollView>(null);

  const fetchPost = useCallback(async () => {
    if (!postId) {
      return;
    }
    try {
      setLoading(true);
      const response = await communityApi.getPostById(postId);
      if (response.success && response.data) {
        setPost({
          id: response.data.id,
          title: response.data.title,
          content: response.data.content,
          images: response.data.images,
          tags: response.data.tags,
          likesCount: response.data.likesCount,
          commentsCount: response.data.commentsCount,
          isLiked: response.data.isLiked,
          isBookmarked: response.data.isBookmarked,
          author: response.data.author,
          createdAt: response.data.createdAt,
        });
      }
    } catch {
      Alert.alert("鎻愮ず", "鍔犺浇甯栧瓙澶辫触");
    } finally {
      setLoading(false);
    }
  }, [postId]);

  const fetchComments = useCallback(async () => {
    if (!postId) {
      return;
    }
    try {
      const response = await communityApi.getComments(postId, { limit: 50 });
      if (response.success && response.data) {
        setComments(response.data.items);
      }
    } catch {
      // Comments loading failure is non-critical
    }
  }, [postId]);

  useEffect(() => {
    void fetchPost();
    void fetchComments();
  }, [fetchPost, fetchComments]);

  const handleLike = useCallback(async () => {
    if (!postId) {
      return;
    }
    try {
      const response = await communityApi.toggleLike(postId);
      if (response.success && response.data) {
        setPost((prev) =>
          prev
            ? {
                ...prev,
                isLiked: response.data!.liked,
                likesCount: prev.likesCount + (response.data!.liked ? 1 : -1),
              }
            : prev
        );
      }
    } catch {
      // Like toggle failure is non-critical
    }
  }, [postId]);

  const handleShare = useCallback(async () => {
    if (!postId) {
      return;
    }
    try {
      await communityApi.sharePost(postId);
      Alert.alert("鎻愮ず", "鍒嗕韩閾炬帴宸插鍒禱

source:
鎻愮ず", "鍒嗕韩澶辫触");
    }
  }, [postId]);

  const handleReport = useCallback(() => {
    const reasons = ["鍨冨溇鍐呭", "铏氬亣淇℃伅", "涓嶅綋鍐呭", "渚垫潈", "鍏朵粬"];
    Alert.alert("涓炬姤", "璇烽€夋嫨涓炬姤鍘熷洜", [
      { text: "鍙栨秷", style: "cancel" },
      ...reasons.map((reason) => ({
        text: reason,
        onPress: async () => {
          try {
            await communityApi.reportContent({
              targetType: "post",
              targetId: postId,
              reason,
            });
            Alert.alert("鎻愮ず", "涓炬姤宸叉彁浜

鎻愮ず", "涓炬姤澶辫触");
          }
        },
      })),
    ]);
  }, [postId]);

  const handleSubmitComment = useCallback(async () => {
    if (!commentText.trim() || !postId) {
      return;
    }
    try {
      setSubmittingComment(true);
      const response = await communityApi.addComment(postId, {
        content: commentText.trim(),
      });
      if (response.success) {
        setCommentText("");
        void fetchComments();
      }
    } catch {
      Alert.alert("鎻愮ず", "璇勮澶辫触");
    } finally {
      setSubmittingComment(false);
    }
  }, [commentText, postId, fetchComments]);

  const toggleReplies = useCallback((commentId: string) => {
    setExpandedReplies((prev) => {
      const next = new Set(prev);
      if (next.has(commentId)) {
        next.delete(commentId);
      } else {
        next.add(commentId);
      }
      return next;
    });
  }, []);

  if (loading) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.centerContainer}>
          <ActivityIndicator size="large" color={theme.colors.primary} />
        </View>
      </SafeAreaView>
    );
  }

  if (!post) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.centerContainer}>
          <Text style={styles.errorText}>甯栧瓙涓嶅瓨鍦?/Text>
          <TouchableOpacity onPress={() => navigation.goBack()}>
            <Text style={styles.goBackText}>杩斿洖</Text>
          </TouchableOpacity>
        </View>
      </SafeAreaView>
    );
  }

  const renderComment = (comment: PostComment) => {
    const isExpanded = expandedReplies.has(comment.id);
    const hasReplies = comment.repliesCount > 0;

    return (
      <View key={comment.id} style={styles.commentItem}>
        <View style={styles.commentHeader}>
          {comment.author.avatar ? (
            <Image source={{ uri: comment.author.avatar }} style={styles.commentAvatar} />
          ) : (
            <View style={styles.commentAvatarPlaceholder}>
              <Text style={styles.commentAvatarText}>
                {comment.author.nickname?.charAt(0) ?? "U"}
              </Text>
            </View>
          )}
          <View style={styles.commentBody}>
            <Text style={styles.commentAuthor}>{comment.author.nickname}</Text>
            <Text style={styles.commentContent}>{comment.content}</Text>
            <View style={styles.commentMeta}>
              <Text style={styles.commentTime}>
                {new Date(comment.createdAt).toLocaleDateString("zh-CN", {
                  month: "short",
                  day: "numeric",
                  hour: "2-digit",
                  minute: "2-digit",
                })}
              </Text>
              <TouchableOpacity
                onPress={() => {
                  setCommentText(`@${comment.author.nickname} `);
                }}
              >
                <Text style={styles.replyLink}>鍥炲</Text>
              </TouchableOpacity>
            </View>

            {/* Replies section - collapsed by default, show first 2 */}
            {hasReplies && (
              <View style={styles.repliesSection}>
                {isExpanded ? (
                  <Text style={styles.repliesExpanded}>鎵€鏈夊洖澶嶅凡灞曞紑</Text>
                ) : (
                  <TouchableOpacity onPress={() => toggleReplies(comment.id)}>
                    <Text style={styles.showRepliesText}>鏌ョ湅鏇村鍥炲({comment.repliesCount})</Text>
                  </TouchableOpacity>
                )}
              </View>
            )}
          </View>
        </View>
      </View>
    );
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.header}>
        <TouchableOpacity onPress={() => navigation.goBack()} style={styles.backBtn}>
          <Ionicons name="arrow-back" size={24} color={theme.colors.text} />
        </TouchableOpacity>
        <Text style={styles.headerTitle}>甯栧瓙璇︽儏</Text>
        <TouchableOpacity onPress={handleReport} style={styles.moreBtn}>
          <Ionicons name="ellipsis-horizontal" size={22} color={theme.colors.text} />
        </TouchableOpacity>
      </View>

      <ScrollView style={styles.content} showsVerticalScrollIndicator={false}>
        {/* Author section */}
        <View style={styles.authorSection}>
          {post.author.avatar ? (
            <View style={styles.authorAvatarWrapper}>
              <Image source={{ uri: post.author.avatar }} style={styles.authorAvatar} />
              {post.bloggerLevel === "blogger" && (
                <View style={styles.authorBadge}>
                  <Ionicons name="checkmark" size={8} color="#FFFFFF" />
                </View>
              )}
              {post.bloggerLevel === "big_v" && (
                <View style={styles.authorBigVBadge}>
                  <Ionicons name="shield-checkmark" size={10} color="#FFFFFF" />
                </View>
              )}
            </View>
          ) : (
            <View style={styles.authorAvatarPlaceholder}>
              <Text style={styles.authorAvatarText}>{post.author.nickname.charAt(0)}</Text>
            </View>
          )}
          <View style={styles.authorInfo}>
            <Text style={styles.authorName}>{post.author.nickname}</Text>
            <Text style={styles.postTime}>
              {new Date(post.createdAt).toLocaleDateString("zh-CN", {
                month: "long",
                day: "numeric",
              })}
            </Text>
          </View>
        </View>

        {/* Title and content */}
        <Text style={styles.postTitle}>{post.title}</Text>
        <Text style={styles.postContent}>{post.content}</Text>

        {/* Image carousel */}
        {post.images.length > 0 && (
          <View style={styles.imageCarousel}>
            <ScrollView
              ref={scrollViewRef}
              horizontal
              pagingEnabled
              showsHorizontalScrollIndicator={false}
              onScroll={(e) => {
                const offsetX = e.nativeEvent.contentOffset.x;
                const index = Math.round(offsetX / SCREEN_WIDTH);
                setCurrentImageIndex(index);
              }}
              scrollEventThrottle={16}
            >
              {post.images.map((uri, index) =>
                index === 0 ? (
                  <SharedElement key={uri} id={`post.${postId}.image`}>
                    <Image source={{ uri }} style={styles.carouselImage} resizeMode="cover" />
                  </SharedElement>
                ) : (
                  <Image
                    key={uri}
                    source={{ uri }}
                    style={styles.carouselImage}
                    resizeMode="cover"
                  />
                )
              )}
            </ScrollView>
            {post.images.length > 1 && (
              <View style={styles.paginationDots}>
                {post.images.map((_, index) => (
                  <View
                    key={`dot-${index}`}
                    style={[styles.dot, index === currentImageIndex && styles.dotActive]}
                  />
                ))}
              </View>
            )}
          </View>
        )}

        {/* Tags */}
        {post.tags.length > 0 && (
          <View style={styles.tagsRow}>
            {post.tags.map((tag, index) => (
              <View key={tag} style={styles.tagChip}>
                <Text style={styles.tagText}>#{tag}</Text>
              </View>
            ))}
          </View>
        )}

        {/* Purchase button for blogger posts */}
        {post.bloggerLevel && (
          <TouchableOpacity style={styles.purchaseBtn}>
            <Ionicons name="bag-outline" size={18} color="#FFFFFF" />
            <Text style={styles.purchaseBtnText}>璐拱姝ゆ柟妗?/Text>
          </TouchableOpacity>
        )}

        {/* Comments */}
        <View style={styles.commentsSection}>
          <Text style={styles.commentsTitle}>璇勮 ({comments.length})</Text>
          {comments.length === 0 ? (
            <Text style={styles.noComments}>鏆傛棤璇勮锛屾潵璇寸偣浠€涔堝惂</Text>
          ) : (
            comments.map(renderComment)
          )}
        </View>

        <View style={{ height: 80 }} />
      </ScrollView>

      {/* Bottom action bar */}
      <View style={styles.bottomBar}>
        <View style={styles.commentInputContainer}>
          <TextInput
            style={styles.commentInput}
            placeholder="鍐欒瘎璁?.."
            placeholderTextColor={theme.colors.textTertiary}
            value={commentText}
            onChangeText={setCommentText}
            maxLength={500}
          />
          <TouchableOpacity
            style={[styles.sendBtn, !commentText.trim() && styles.sendBtnDisabled]}
            onPress={handleSubmitComment}
            disabled={!commentText.trim() || submittingComment}
          >
            {submittingComment ? (
              <ActivityIndicator size="small" color="#FFFFFF" />
            ) : (
              <Ionicons
                name="send"
                size={18}
                color={commentText.trim() ? "#FFFFFF" : theme.colors.textTertiary}
              />
            )}
          </TouchableOpacity>
