          keyboardType="numeric"
          maxLength={5}
          accessibilityLabel={label}
        />
        <Text style={styles.unitText}>{unit}</Text>
      </View>
    </View>
  );

  return (
    <ScreenLayout
      header={
        <Header
          title="缂栬緫鐢诲儚"
          leftAction={
            <TouchableOpacity
              onPress={() => navigation.goBack()}
              accessibilityLabel="杩斿洖"
              accessibilityRole="button"
            >
              <Ionicons name="chevron-back" size={24} color={theme.colors.text} />
            </TouchableOpacity>
          }
          rightAction={
            <TouchableOpacity
              onPress={handleSave}
              disabled={isLoading}
              accessibilityLabel="淇濆瓨"
              accessibilityRole="button"
            >
              {isLoading ? (
                <ActivityIndicator size="small" color={theme.colors.primary} />
              ) : (
                <Text style={styles.saveButtonText}>淇濆瓨</Text>
              )}
            </TouchableOpacity>
          }
        />
      }
      scrollable
      backgroundColor={Colors.neutral[50]}
    >
      <View style={styles.content}>
        {/* Basic Info Section */}
        <View style={styles.sectionCard}>
          <Text style={styles.sectionTitle}>鍩烘湰淇℃伅</Text>

          <View style={styles.formGroup}>
            <Text style={styles.inputLabel}>鏄电О</Text>
            <View style={styles.inputContainer}>
              <TextInput
                style={styles.textInput}
                placeholder="杈撳叆鏄电О"
                placeholderTextColor={theme.colors.textTertiary}
                value={nickname}
                onChangeText={setNickname}
                accessibilityLabel="鏄电О"
              />
            </View>
          </View>

          <View style={styles.formGroup}>
            <Text style={styles.inputLabel}>鎬у埆</Text>
            <View style={styles.pillRow}>
              {GENDER_OPTIONS.map((opt) => {
                const isSelected = gender === opt.id;
                return (
                  <TouchableOpacity
                    key={opt.id}
                    style={[styles.pill, isSelected && styles.pillSelected]}
                    onPress={() => setGender(opt.id)}
                    activeOpacity={0.7}
                    accessibilityLabel={opt.label}
                    accessibilityRole="button"
                  >
                    <Text style={[styles.pillText, isSelected && styles.pillTextSelected]}>
                      {opt.label}
                    </Text>
                  </TouchableOpacity>
                );
              })}
            </View>
          </View>

          <View style={styles.formGroup}>
            <Text style={styles.inputLabel}>骞撮緞娈?/Text>
            <ScrollView
              horizontal
              showsHorizontalScrollIndicator={false}
              contentContainerStyle={styles.pillRow}
            >
              {AGE_RANGES.map((range) => {
                const isSelected = ageRange === range;
                return (
                  <TouchableOpacity
                    key={range}
                    style={[styles.pill, isSelected && styles.pillSelected]}
                    onPress={() => setAgeRange(range)}
                    activeOpacity={0.7}
                    accessibilityLabel={range}
                    accessibilityRole="button"
                  >
                    <Text style={[styles.pillText, isSelected && styles.pillTextSelected]}>
                      {range}
                    </Text>
                  </TouchableOpacity>
                );
              })}
            </ScrollView>
          </View>
        </View>

        {/* Body Data Section */}
        <View style={styles.sectionCard}>
          <Text style={styles.sectionTitle}>韬潗鏁版嵁</Text>
          <View style={styles.bodyGrid}>
            {renderBodyField("height", "韬珮", "cm")}
            {renderBodyField("weight", "浣撻噸", "kg")}
            {renderBodyField("shoulder", "鑲╁", "cm")}
            {renderBodyField("bust", "鑳稿洿", "cm")}
            {renderBodyField("waist", "鑵板洿", "cm")}
            {renderBodyField("hip", "鑷€鍥碶

cm")}
            {renderBodyField("inseam", "鍐呯紳", "cm")}
          </View>
        </View>

        {/* Style Preferences Section */}
        <View style={styles.sectionCard}>
          <Text style={styles.sectionTitle}>椋庢牸鍋忓ソ</Text>
          <View style={styles.tagGrid}>
            {STYLE_KEYWORDS.map((keyword) => {
              const isSelected = selectedStyles.has(keyword);
              return (
                <TouchableOpacity
                  key={keyword}
                  style={[styles.tag, isSelected && styles.tagSelected]}
                  onPress={() => toggleStyle(keyword)}
                  activeOpacity={0.7}
                  accessibilityLabel={keyword}
                  accessibilityRole="button"
                >
                  <Text style={[styles.tagText, isSelected && styles.tagTextSelected]}>
                    {keyword}
                  </Text>
                </TouchableOpacity>
              );
            })}
          </View>
        </View>
      </View>
    </ScreenLayout>
  );
};

const styles = StyleSheet.create({
  content: {
    paddingHorizontal: Spacing[5],
    paddingTop: Spacing[4],
    paddingBottom: Spacing[8],
  },
  sectionCard: {
    backgroundColor: "#FFFFFF",
    borderRadius: BorderRadius.xl,
    padding: Spacing[4],
    marginBottom: Spacing[4],
    ...Shadows.sm,
  },
  sectionTitle: {
    fontSize: 20,
    fontWeight: "600",
    color: theme.colors.text,
    marginBottom: Spacing[4],
  },
  formGroup: {
    marginBottom: Spacing[4],
  },
  inputLabel: {
    fontSize: 16,
    fontWeight: "400",
    color: theme.colors.textSecondary,
    marginBottom: Spacing[2],
  },
  inputContainer: {
    flexDirection: "row",
