interface RecommendationDetail {
  id: string;
  name: string;
  brand?: string;
  description?: string;
  imageUri?: string;
  price?: number;
  category?: string;
  colors: string[];
  sizes: string[];
  styles: string[];
  seasons: string[];
  occasions: string[];
  score?: number;
  matchReasons: string[];
  externalUrl?: string;
}

const { width: SCREEN_WIDTH } = Dimensions.get("window");

type RecommendationDetailRouteProp = RouteProp<RootStackParamList, "RecommendationDetail">;

interface RecommendationPreview {
  id: string;
  name?: string;
  brand?: string;
  mainImage?: string;
  price?: number;
  category?: string;
  score?: number;
  matchReasons?: string[];
  externalUrl?: string;
}

function _mapRouteRecommendation(preview?: RecommendationPreview): RecommendationDetail | null {
  if (!preview) {
    return null;
  }

  return {
    id: preview.id,
    name: preview.name ?? "AI 鎺ㄨ崘鍗曞搧",
    brand: preview.brand,
    description: undefined,
    imageUri: preview.mainImage,
    price: preview.price,
    category: preview.category,
    colors: [],
    sizes: [],
    styles: [],
    seasons: [],
    occasions: [],
    score: preview.score,
    matchReasons: preview.matchReasons ?? [],
    externalUrl: preview.externalUrl,
  };
}

function buildFallbackReasons(item: ClothingItem, preview: RecommendationDetail | null): string[] {
  const reasons = preview?.matchReasons?.filter(Boolean) ?? [];

  if (reasons.length > 0) {
    return reasons.slice(0, 3);
  }

  if (item.brand) {
    reasons.push(`${item.brand} 鐨勯鏍间笌褰撳墠鍋忓ソ鏇存帴杩慲);
  }

  if (item.style.length > 0) {
    const style = STYLE_LABELS[item.style[0]] ?? item.style[0];
    reasons.push(`杩欎欢鍗曞搧閫傚悎 ${style} 鏂瑰悜鐨勬棩甯告惌閰峘);
  }

  if (item.seasons.length > 0) {
    const season = SEASON_LABELS[item.seasons[0]] ?? item.seasons[0];
    reasons.push(`${season} 鍦烘櫙涓嬫洿瀹规槗绌垮嚭瀹屾暣閫犲瀷`);
  }

  if (item.occasions.length > 0) {
    const occasion = OCCASION_LABELS[item.occasions[0]] ?? item.occasions[0];
    reasons.push(`鍦?${occasion} 鍦烘櫙閲屾洿璐村悎浣犵殑褰撲笅闇€姹俙);
  }

  if (reasons.length === 0) {
    reasons.push("杩欎欢鍗曞搧宸茶繘鍏ヤ綘鐨勪釜鎬у寲鎺ㄨ崘姹燶

usedDeprecatedRules:
