  const [isLoading, setIsLoading] = useState(!previewDetail);
  const [isAddingToCart, setIsAddingToCart] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadData = useCallback(async () => {
    if (!previewDetail) {
