      const response = await clothingApi.getById(recommendationId);
      if (response.success && response.data) {
        setRecommendation(mergeRecommendationDetail(response.data, previewDetail));
      } else {
        setError(
          typeof response.error === "string"
            ? response.error
            : response.error?.message || "鍔犺浇鎺ㄨ崘璇︽儏澶辫触"
        );
      }
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "缃戠粶寮傚父锛岃绋嶅悗閲嶈瘯");
    } finally {
      setIsLoading(false);
    }
  }, [recommendationId, previewDetail]);

