export const AdvisorProfileScreen: React.FC = () => {
  const insets = useSafeAreaInsets();
  const route = useRoute<any>();
  const navigation = useNavigation<any>();
  const { currentConsultant, fetchConsultantById, isLoading } = useConsultantStore();
  const [cases, setCases] = useState<any[]>([]);

  const consultantId = route.params?.id;

  useFocusEffect(
    useCallback(() => {
      if (consultantId) {
        void fetchConsultantById(consultantId);
      }
    }, [consultantId, fetchConsultantById])
  );

  useEffect(() => {
    if (consultantId) {
      consultantApi
        .getCases(consultantId)
        .then((res) => {
          setCases((res.data || []) as any[]);
        })
        .catch(() => {});
    }
  }, [consultantId]);

  if (isLoading || !currentConsultant) {
    return (
      <View style={styles.loadingContainer}>
        <ActivityIndicator size="large" color="#C67B5C" />
      </View>
    );
  }

  const profile = "data" in currentConsultant ? (currentConsultant as any).data : currentConsultant;
  const specialties = Array.isArray(profile.specialties) ? profile.specialties : [];
  const bookingCount = profile._count?.bookings || 0;

  return (
    <View style={styles.container}>
      <ScrollView showsVerticalScrollIndicator={false}>
        {/* Header */}
        <View style={[styles.header, { paddingTop: insets.top }]}>
          <TouchableOpacity onPress={() => navigation.goBack()} style={styles.backBtn}>
            <Text style={styles.backBtnText}>{"<"}</Text>
          </TouchableOpacity>
          <Text style={styles.headerTitle}>椤鹃棶璇︽儏</Text>
          <TouchableOpacity style={styles.shareBtn}>
            <Text style={styles.shareBtnText}>鍒嗕韩</Text>
          </TouchableOpacity>
        </View>

        {/* Profile Hero */}
        <View style={styles.profileHero}>
          {profile.avatar ? (
            <Image source={{ uri: profile.avatar }} style={styles.avatar} />
          ) : (
            <View style={styles.avatarPlaceholder}>
              <Text style={styles.avatarPlaceholderText}>
                {(profile.studioName || "椤鹃棶").charAt(0)}
              </Text>
            </View>
          )}
          <Text style={styles.studioName}>{profile.studioName}</Text>
          <View style={styles.specialtyRow}>
            {specialties.slice(0, 4).map((s: string) => (
              <View key={s} style={styles.specialtyBadge}>
                <Text style={styles.specialtyText}>{s}</Text>
              </View>
            ))}
          </View>
          <View style={styles.ratingRow}>
            <Text style={styles.ratingValue}>{profile.rating || 0}</Text>
            <Text style={styles.ratingLabel}>璇勫垎</Text>
            <Text style={styles.reviewCount}>{profile.reviewCount || 0} 鏉¤瘎浠?/Text>
          </View>
        </View>

        {/* Info Row */}
        <View style={styles.infoRow}>
          <View style={styles.infoItem}>
            <Text style={styles.infoValue}>{profile.yearsOfExperience || 0} 骞?/Text>
            <Text style={styles.infoLabel}>浠庝笟缁忛獙</Text>
          </View>
          <View style={styles.infoDivider} />
          <View style={styles.infoItem}>
            <Text style={styles.infoValue}>{profile.responseTimeAvg ?? "--"} 鍒?/Text>
            <Text style={styles.infoLabel}>骞冲潎鍥炲</Text>
          </View>
          <View style={styles.infoDivider} />
          <View style={styles.infoItem}>
            <Text style={styles.infoValue}>{bookingCount} 鍗?/Text>
            <Text style={styles.infoLabel}>宸叉湇鍔?/Text>
          </View>
        </View>

        {/* Bio */}
        {profile.bio && (
          <View style={styles.section}>
            <Text style={styles.sectionTitle}>涓汉绠€浠?/Text>
            <Text style={styles.bioText} numberOfLines={3}>
              {profile.bio}
            </Text>
          </View>
        )}

        {/* Portfolio / Cases */}
        {cases.length > 0 && (
          <View style={styles.section}>
            <Text style={styles.sectionTitle}>鏈嶅姟妗堜緥</Text>
            <FlatList
              horizontal
              data={cases}
              keyExtractor={(item: any) => item.bookingId}
              renderItem={({ item }: any) => <CaseCard {...item} />}
              showsHorizontalScrollIndicator={false}
              contentContainerStyle={styles.casesList}
            />
          </View>
        )}
      </ScrollView>

      {/* Fixed bottom CTA */}
      <View style={styles.bottomCta}>
        <TouchableOpacity
          style={styles.bookButton}
          onPress={() => navigation.navigate("Booking", { consultantId, consultant: profile })}
        >
          <Text style={styles.bookButtonText}>棰勭害椤鹃棶</Text>
        </TouchableOpacity>
      </View>
    </View>
  );
};

