import React, { useCallback, useEffect, useRef, useState } from "react";
import {
  View,
  Text,
  StyleSheet,
  FlatList,
  TextInput,
  TouchableOpacity,
  Image,
  KeyboardAvoidingView,
  Platform,
  Alert,
} from "react-native";
import { useRoute, useNavigation } from "@react-navigation/native";
import { useChatStore } from "../../stores/chatStore";
import { useConsultantStore } from "../../stores/consultantStore";
import { ChatBubble } from "../../components/ui/ChatBubble";
import { TypingIndicator } from "../../components/consultant/TypingIndicator";
import { ProposalCard } from "../../components/consultant/ProposalCard";
import wsService from "../../services/websocket";
import { useSafeAreaInsets } from "react-native-safe-area-context";

export const ChatScreen: React.FC = () => {
  const insets = useSafeAreaInsets();
  const route = useRoute<any>();
  const navigation = useNavigation<any>();
  const { roomId, _consultantId, consultantName } = route.params || {};

  const { messages, currentRoom, fetchMessages, sendMessage, markAsRead, addMessage } =
    useChatStore();

  const { currentConsultant } = useConsultantStore();

  const [inputText, setInputText] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [isConnected, setIsConnected] = useState(false);
  const flatListRef = useRef<FlatList>(null);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    const initChat = async () => {
      if (roomId) {
        await fetchMessages(roomId);
        await wsService.connectChat();
        wsService.joinChatRoom(roomId);
        setIsConnected(wsService.isChatConnected());
      }
    };
    void initChat();

    // Listen for new messages
    const unsubscribe = wsService.onChatMessage(roomId || "*", (payload: any) => {
      addMessage(payload);
    });

    const unsubscribeTyping = wsService.onChatTyping(roomId || "", (payload: any) => {
      setIsTyping(payload.isTyping);
    });

    return () => {
      unsubscribe();
      unsubscribeTyping();
      if (roomId) {
        wsService.leaveChatRoom(roomId);
      }
    };
  }, [roomId, fetchMessages, addMessage]);

  const handleSend = useCallback(async () => {
    const text = inputText.trim();
    if (!text || !roomId) {
      return;
    }

    setInputText("");

    // Send via WebSocket for real-time
    wsService.sendChatMessage({
      roomId,
      content: text,
      messageType: "text",
    });

    // Also send via REST API for persistence
    try {
      await sendMessage({
        roomId,
        senderType: "user",
        content: text,
        messageType: "text",
      });
    } catch {
      // REST failure is acceptable if WS delivered it
    }

    // Mark as read
    void markAsRead(roomId);
  }, [inputText, roomId, sendMessage, markAsRead]);

  const handleInputChange = (text: string) => {
    setInputText(text);
    if (roomId) {
      wsService.sendTyping(roomId, text.length > 0);
      if (typingTimeoutRef.current) {
        clearTimeout(typingTimeoutRef.current);
      }
      typingTimeoutRef.current = setTimeout(() => {
        wsService.sendTyping(roomId, false);
      }, 2000);
    }
  };

  const renderMessage = ({ item }: { item: any }) => {
    const isUser = item.senderType === "user";

    if (item.messageType === "proposal") {
      return (
        <View style={styles.proposalWrapper}>
          <ProposalCard
            title={item.proposalData?.title || "閫犲瀷鏂规"}
            summary={item.proposalData?.summary || item.content}
            onViewProposal={() => Alert.alert("鏌ョ湅鏂规", "鏂规璇︽儏鍔熻兘鍗冲皢涓婄嚎")}
            onSaveToWardrobe={() => Alert.alert("淇濆瓨", "宸蹭繚瀛樺埌鐏垫劅琛ｆ┍")}
          />
        </View>
      );
    }

    if (item.messageType === "system") {
      return (
        <View style={styles.systemMessage}>
          <Text style={styles.systemMessageText}>{item.content}</Text>
        </View>
      );
    }

    return (
      <ChatBubble
        message={item.content}
        isUser={isUser}
        timestamp={item.createdAt}
        avatar={isUser ? undefined : "馃帹"}
      />
    );
  };

  const displayName = consultantName || currentConsultant?.studioName || "閫犲瀷椤鹃棶";

  return (
    <KeyboardAvoidingView
      style={styles.container}
      behavior={Platform.OS === "ios" ? "padding" : undefined}
    >
      {/* Header */}
      <View style={[styles.header, { paddingTop: insets.top }]}>
        <TouchableOpacity onPress={() => navigation.goBack()} style={styles.backBtn}>
          <Text style={styles.backBtnText}>{"<"}</Text>
        </TouchableOpacity>
        <View style={styles.headerCenter}>
          <Text style={styles.headerName}>{displayName}</Text>
          <View style={styles.onlineIndicator}>
            <View style={[styles.onlineDot, isConnected ? styles.dotOnline : styles.dotOffline]} />
            <Text style={styles.onlineText}>{isConnected ? "鍦ㄧ嚎" : "绂荤嚎"}</Text>
          </View>
        </View>
        {currentConsultant?.avatar ? (
          <Image source={{ uri: currentConsultant.avatar }} style={styles.headerAvatar} />
        ) : (
          <View style={styles.headerAvatarPlaceholder}>
            <Text style={styles.headerAvatarText}>{displayName.charAt(0)}</Text>
          </View>
        )}
      </View>

      {/* Messages */}
      <FlatList
        ref={flatListRef}
        data={messages}
        keyExtractor={(item: any) => item.id || Math.random().toString()}
        renderItem={renderMessage}
        contentContainerStyle={styles.messagesList}
        onContentSizeChange={() => flatListRef.current?.scrollToEnd()}
        ListFooterComponent={isTyping ? <TypingIndicator /> : null}
      />

      {/* Input Bar */}
      <View style={styles.inputBar}>
        <TextInput
          style={styles.textInput}
          placeholder="杈撳叆娑堟伅..."
          value={inputText}
          onChangeText={handleInputChange}
          multiline
        />
        <TouchableOpacity style={styles.sendButton} onPress={handleSend}>
          <Text style={styles.sendButtonText}>鍙戦€?/Text>
        </TouchableOpacity>
      </View>
    </KeyboardAvoidingView>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: "#FAFAF8" },
  header: {
    flexDirection: "row",
    alignItems: "center",
    paddingHorizontal: 12,
    paddingBottom: 12,
    backgroundColor: "#FFFFFF",
    borderBottomWidth: 1,
    borderBottomColor: "#F0F0F0",
  },
  backBtn: { padding: 8 },
  backBtnText: { fontSize: 20, color: "#333" },
  headerCenter: { flex: 1, alignItems: "center" },
  headerName: { fontSize: 16, fontWeight: "600", color: "#1A1A1A" },
  onlineIndicator: { flexDirection: "row", alignItems: "center", gap: 4, marginTop: 2 },
  onlineDot: { width: 8, height: 8, borderRadius: 4 },
  dotOnline: { backgroundColor: "#4CAF50" },
  dotOffline: { backgroundColor: "#CCC" },
  onlineText: { fontSize: 11, color: "#888" },
  headerAvatar: { width: 32, height: 32, borderRadius: 16 },
  headerAvatarPlaceholder: {
    width: 32,
    height: 32,
    borderRadius: 16,
    backgroundColor: "#C67B5C",
    alignItems: "center",
    justifyContent: "center",
  },
  headerAvatarText: { color: "#FFF", fontSize: 14, fontWeight: "600" },
  messagesList: { paddingHorizontal: 16, paddingTop: 12, paddingBottom: 12 },
  proposalWrapper: { marginVertical: 8, maxWidth: "85%", alignSelf: "center" },
  systemMessage: { alignItems: "center", marginVertical: 8 },
  systemMessageText: { fontSize: 12, color: "#999" },
  inputBar: {
    flexDirection: "row",
    alignItems: "flex-end",
    paddingHorizontal: 12,
    paddingVertical: 10,
    paddingBottom: 28,
    backgroundColor: "#FFFFFF",
    borderTopWidth: 1,
    borderTopColor: "#F0F0F0",
    gap: 8,
  },
  textInput: {
    flex: 1,
    borderWidth: 1,
    borderColor: "#E0E0E0",
    borderRadius: 20,
    paddingHorizontal: 16,
    paddingVertical: 10,
    fontSize: 14,
    maxHeight: 100,
  },
  sendButton: {
    backgroundColor: "#C67B5C",
    paddingHorizontal: 16,
    paddingVertical: 10,
    borderRadius: 20,
  },
  sendButtonText: { color: "#FFFFFF", fontSize: 14, fontWeight: "500" },
});

export default ChatScreen;

import { useCallback, useEffect, useRef, useState } from "react";
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  RefreshControl,
  type TextStyle,
} from "react-native";
import Geolocation, { type GeolocationResponse } from "@react-native-community/geolocation";
import { useNavigation, NavigationProp } from "@react-navigation/native";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { Ionicons } from "@/src/polyfills/expo-vector-icons";
import { FlashList } from "@/src/polyfills/flash-list";
import { useHomeStore } from "../../stores/homeStore";
import { useAuthStore } from "../../stores/index";
import { useRecommendationFeedStore } from "../../stores/recommendationFeedStore";
import { DesignTokens } from "../../theme/tokens/design-tokens";
import { withErrorBoundary } from "../../components/ErrorBoundary";
import { WeatherGreeting } from "./components/WeatherGreeting";
import { ProfileCompletionBanner } from "./components/ProfileCompletionBanner";
import QuickActions from "./components/QuickActions";
import { RecommendationCard } from "../../components/recommendations/RecommendationFeedCard";
import type { RootStackParamList } from "../../types/navigation";
import type { FeedItem } from "../../services/api/recommendation-feed.api";

const HORIZONTAL_PADDING = 20;

type HomeSection =
  | { type: "greeting" }
  | { type: "banner" }
  | { type: "quickActions" }
  | { type: "search" }
  | { type: "recommendationHeader" }
  | { type: "recommendationItem"; item: FeedItem };

const BASE_SECTIONS: HomeSection[] = [
  { type: "greeting" },
  { type: "banner" },
  { type: "quickActions" },
  { type: "search" },
];

const FALLBACK_LATITUDE = 35.8617;
const FALLBACK_LONGITUDE = 104.1954;

const HomeScreen: React.FC = () => {
  const navigation = useNavigation<NavigationProp<RootStackParamList>>();
  const insets = useSafeAreaInsets();
  const user = useAuthStore((s) => s.user);
  const {
    profileCompletionPercent,
    isProfileComplete,
    isBannerDismissed,
    weatherData,
    isLoadingWeather,
    dismissBanner,
    fetchWeather,
    fetchProfileCompletion,
  } = useHomeStore();

  const {
    items: feedItems,
    isLoading: isFeedLoading,
    fetchFeed,
    loadMore,
    hasMore,
  } = useRecommendationFeedStore();

  const [refreshing, setRefreshing] = useState(false);
  const [coords, setCoords] = useState<{ latitude: number; longitude: number } | null>(null);
  const locationFetched = useRef(false);
  const isMountedRef = useRef(true);

  useEffect(() => {
    return () => {
      isMountedRef.current = false;
    };
  }, []);

  const displayName = user?.nickname || user?.email?.split("@")[0] || "鐢ㄦ埛";

  useEffect(() => {
    if (locationFetched.current) {
      return;
    }
    locationFetched.current = true;
    Geolocation.getCurrentPosition(
      (position: GeolocationResponse) => {
        if (isMountedRef.current) {
          setCoords({
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
          });
        }
      },
      () => {
        if (isMountedRef.current) {
          setCoords({ latitude: FALLBACK_LATITUDE, longitude: FALLBACK_LONGITUDE });
        }
      },
      { enableHighAccuracy: false, timeout: 10000, maximumAge: 300000 }
    );
  }, []);

  useEffect(() => {
    void fetchProfileCompletion();
    if (coords) {
      void fetchWeather(coords.latitude, coords.longitude);
    }
    void fetchFeed(true);
  }, [fetchProfileCompletion, fetchWeather, fetchFeed, coords]);

  const sections: HomeSection[] = [
    ...BASE_SECTIONS,
    { type: "recommendationHeader" as const },
    ...feedItems.map((item): HomeSection => ({ type: "recommendationItem", item })),
  ];

  const handleRefresh = useCallback(async () => {
    setRefreshing(true);
    await Promise.all([
      fetchProfileCompletion(),
      coords ? fetchWeather(coords.latitude, coords.longitude) : Promise.resolve(),
      fetchFeed(true),
    ]);
    setRefreshing(false);
  }, [fetchProfileCompletion, fetchWeather, fetchFeed, coords]);

  const handleSearchPress = useCallback(() => {
    navigation.navigate("Search");
  }, [navigation]);

  const handleProfilePress = useCallback(() => {
    navigation.navigate("Profile");
  }, [navigation]);

  const handleAiStylistPress = useCallback(() => {
    navigation.navigate("MainTabs", { screen: "Stylist", params: { screen: "AIStylist" } });
  }, [navigation]);

  const handleVirtualTryOnPress = useCallback(() => {
    navigation.navigate("VirtualTryOn", {});
  }, [navigation]);

  const handleWardrobePress = useCallback(() => {
    navigation.navigate("MainTabs", { screen: "Profile", params: { screen: "Wardrobe" } });
  }, [navigation]);

  const handleStyleReportPress = useCallback(() => {
    navigation.navigate("Profile");
  }, [navigation]);

  const handleBannerDismiss = useCallback(() => {
    dismissBanner();
  }, [dismissBanner]);

  const renderItem = useCallback(
    ({ item }: { item: HomeSection }) => {
      switch (item.type) {
        case "greeting":
          return (
            <WeatherGreeting
              userName={displayName}
              weatherData={weatherData}
              isLoading={isLoadingWeather}
            />
          );

        case "banner":
          if (isProfileComplete || isBannerDismissed) {
            return null;
          }
          return (
            <ProfileCompletionBanner
              completionPercent={profileCompletionPercent}
              isComplete={isProfileComplete}
              onDismiss={handleBannerDismiss}
              onContinue={handleProfilePress}
            />
          );

        case "quickActions":
          return (
            <QuickActions
              onAiStylist={handleAiStylistPress}
              onVirtualTryOn={handleVirtualTryOnPress}
              onWardrobe={handleWardrobePress}
              onStyleReport={handleStyleReportPress}
              isStyleReportUnlocked={isProfileComplete}
            />
          );

        case "search":
          return (
            <TouchableOpacity
              style={styles.searchBar}
              onPress={handleSearchPress}
              activeOpacity={0.7}
            >
              <Ionicons name="search-outline" size={20} color={DesignTokens.colors.text.tertiary} />
              <Text style={styles.searchText}>鎼滅储绌挎惌銆佸崟鍝併€侀鏍?..</Text>
              <Ionicons name="mic-outline" size={20} color={DesignTokens.colors.text.tertiary} />
            </TouchableOpacity>
          );

        case "recommendationHeader":
          return (
            <View style={styles.sectionHeader}>
              <Text style={styles.sectionTitle}>涓轰綘鎺ㄨ崘</Text>
              <TouchableOpacity
                onPress={() => {
                  // Already on Home tab; no-op or scroll to top
                }}
              >
                <Text style={styles.sectionMore}>鏌ョ湅鍏ㄩ儴</Text>
              </TouchableOpacity>
            </View>
          );

        case "recommendationItem":
          return (
            <RecommendationCard
              item={(item as { type: "recommendationItem"; item: FeedItem }).item}
              onPress={(feedItem) => navigation.navigate("Product", { clothingId: feedItem.id })}
            />
          );

        default:
          return null;
      }
    },
    [
      displayName,
      weatherData,
      isLoadingWeather,
      isProfileComplete,
      isBannerDismissed,
      profileCompletionPercent,
      handleBannerDismiss,
      handleProfilePress,
      handleSearchPress,
      handleAiStylistPress,
      handleVirtualTryOnPress,
      handleWardrobePress,
      handleStyleReportPress,
    ]
  );

  return (
    <View style={styles.container}>
      <FlashList<HomeSection>
        data={sections}
        renderItem={renderItem}
        estimatedItemSize={120}
        contentContainerStyle={[styles.listContent, { paddingTop: insets.top + 16 }]}
        showsVerticalScrollIndicator={false}
        onEndReached={() => {
          if (hasMore && !isFeedLoading) {
            void loadMore();
          }
        }}
        onEndReachedThreshold={0.3}
        refreshControl={
          <RefreshControl
            refreshing={refreshing}
            onRefresh={handleRefresh}
            tintColor={DesignTokens.colors.brand.terracotta}
          />
        }
      />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: DesignTokens.colors.backgrounds.secondary,
  },
  listContent: {
    paddingBottom: 120,
    paddingHorizontal: HORIZONTAL_PADDING,
  },
  searchBar: {
    flexDirection: "row",
    alignItems: "center",
    backgroundColor: DesignTokens.colors.backgrounds.primary,
    borderRadius: 20,
    paddingHorizontal: 18,
    paddingVertical: 14,
    marginVertical: 16,
    ...DesignTokens.shadows.sm,
  },
  searchText: {
    flex: 1,
    fontSize: DesignTokens.typography.sizes.md,
    color: DesignTokens.colors.text.tertiary,
    marginHorizontal: 10,
    fontWeight: DesignTokens.typography.fontWeights.regular as TextStyle["fontWeight"],
  },
  sectionHeader: {
    flexDirection: "row",
    justifyContent: "space-between",
    alignItems: "center",
    marginTop: 20,
    marginBottom: 12,
  },
  sectionTitle: {
    fontSize: DesignTokens.typography.sizes.lg,
    fontWeight: DesignTokens.typography.fontWeights.semibold as TextStyle["fontWeight"],
    color: DesignTokens.colors.text.primary,
  },
  sectionMore: {
    fontSize: DesignTokens.typography.sizes.sm,
    color: DesignTokens.colors.brand.terracotta,
    fontWeight: DesignTokens.typography.fontWeights.medium as TextStyle["fontWeight"],
  },
});

export default withErrorBoundary(HomeScreen, {
  screenName: "HomeScreen",
  maxRetries: 3,
});

import React, { useCallback, useMemo } from "react";
import { View, Text, StyleSheet, TouchableOpacity, ActivityIndicator } from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { useNavigation } from "@react-navigation/native";
import type { NavigationProp } from "@react-navigation/native";
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  SlideInRight,
  SlideOutLeft,
} from "react-native-reanimated";
import { Ionicons } from "../../polyfills/expo-vector-icons";
import { theme, Colors, Spacing, BorderRadius, Shadows } from "../../theme";
import { useOnboardingStore } from "../../stores/onboardingStore";
import type { OnboardingStep, OnboardingFormData } from "../../stores/onboardingStore";
import { onboardingService } from "../../services/onboardingService";
import { BasicInfoStep } from "./steps/BasicInfoStep";
import { PhotoStep } from "./steps/PhotoStep";
import { StyleTestStep } from "./steps/StyleTestStep";
import { CompleteStep } from "./steps/CompleteStep";
import type { RootStackParamList } from "../../types/navigation";

type NavigationPropType = NavigationProp<RootStackParamList>;

const STEP_ORDER: OnboardingStep[] = ["basicInfo", "photo", "styleTest", "complete"];

const STEP_TITLES: Record<OnboardingStep, string> = {
  basicInfo: "鍩烘湰淇℃伅",
  photo: "涓婁紶鐓х墖",
  styleTest: "椋庢牸娴嬭瘯",
  complete: "瀹屾垚璁剧疆",
};

const SKIPPABLE_STEPS: OnboardingStep[] = ["photo", "styleTest"];

export const OnboardingWizard: React.FC = () => {
  const navigation = useNavigation<NavigationPropType>();
  const {
    currentStep,
    formData,
    isLoading,
    completeStep,
    updateFormData,
    goToNextStep,
    goToPrevStep,
    setLoading,
  } = useOnboardingStore();

  const stepIndex = STEP_ORDER.indexOf(currentStep);
  const totalSteps = STEP_ORDER.length;

  const progressValue = useSharedValue((stepIndex + 1) / totalSteps);

  const updateProgress = useCallback(
    (step: number) => {
      progressValue.value = withSpring((step + 1) / totalSteps, {
        damping: 15,
        stiffness: 120,
      });
    },
    [progressValue, totalSteps]
  );

  const progressStyle = useAnimatedStyle(() => ({
    width: `${progressValue.value * 100}%`,
  }));

  const canProceed = useCallback((): boolean => {
    if (currentStep === "basicInfo") {
      return formData.gender !== null && formData.ageRange !== null;
    }
    return true;
  }, [currentStep, formData.gender, formData.ageRange]);

  const handleNext = useCallback(() => {
    if (!canProceed()) {
      return;
    }

    completeStep(currentStep);

    if (currentStep === "complete") {
      void handleComplete();
      return;
    }

    goToNextStep();
    updateProgress(stepIndex + 1);
  }, [canProceed, currentStep, completeStep, goToNextStep, stepIndex, updateProgress]);

  const handleBack = useCallback(() => {
    if (stepIndex > 0) {
      goToPrevStep();
      updateProgress(stepIndex - 1);
    }
  }, [stepIndex, goToPrevStep, updateProgress]);

  const handleSkip = useCallback(() => {
    completeStep(currentStep);
    goToNextStep();
    updateProgress(stepIndex + 1);
  }, [currentStep, completeStep, goToNextStep, stepIndex, updateProgress]);

  const handleComplete = useCallback(async () => {
    setLoading(true);
    try {
      await onboardingService.saveOnboardingData(formData);
      await onboardingService.markOnboardingComplete();
      navigation.reset({
        index: 0,
        routes: [{ name: "MainTabs" }],
      });
    } catch {
      await onboardingService.markOnboardingComplete();
      navigation.reset({
        index: 0,
        routes: [{ name: "MainTabs" }],
      });
    } finally {
      setLoading(false);
    }
  }, [formData, navigation, setLoading]);

  const isLastStep = currentStep === "complete";
  const isFirstStep = currentStep === "basicInfo";
  const isSkippable = SKIPPABLE_STEPS.includes(currentStep);

  const renderStep = useMemo(() => {
    switch (currentStep) {
      case "basicInfo":
        return (
          <Animated.View
            key={currentStep}
            entering={SlideInRight}
            exiting={SlideOutLeft}
            style={styles.stepContainer}
          >
            <BasicInfoStep
              formData={formData}
              updateFormData={updateFormData}
              onNext={handleNext}
            />
          </Animated.View>
        );
      case "photo":
        return (
          <Animated.View
            key={currentStep}
            entering={SlideInRight}
            exiting={SlideOutLeft}
            style={styles.stepContainer}
          >
            <PhotoStep onNext={handleNext} onSkip={handleSkip} />
          </Animated.View>
        );
      case "styleTest":
        return (
          <Animated.View
            key={currentStep}
            entering={SlideInRight}
            exiting={SlideOutLeft}
            style={styles.stepContainer}
          >
            <StyleTestStep onNext={handleNext} onSkip={handleSkip} />
          </Animated.View>
        );
      case "complete":
        return (
          <Animated.View
            key={currentStep}
            entering={SlideInRight}
            exiting={SlideOutLeft}
            style={styles.stepContainer}
          >
            <CompleteStep onComplete={handleComplete} />
          </Animated.View>
        );
      default:
        return null;
    }
  }, [currentStep, formData, handleNext, handleSkip, handleComplete, updateFormData]);

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.progressContainer}>
        <View style={styles.progressTrack}>
          <Animated.View style={[styles.progressFill, progressStyle]} />
        </View>
        <Text style={styles.stepCounter}>
          {stepIndex + 1}/{totalSteps}
        </Text>
      </View>

      <View style={styles.stepHeader}>
