interface CameraScreenProps {
  navigation: {
    goBack: () => void;
    navigate: (screen: string, params?: Record<string, unknown>) => void;
  };
}

const CameraScreen: React.FC<CameraScreenProps> = ({ navigation }) => {
  const { permissionStatus, openSettings } = useCameraPermissions();
  const {
    referenceLines,
    alignmentStatus,
    isLoading: linesLoading,
    fetchReferenceLines,
  } = useReferenceLines();

  const {
    capturedImageUri,
    isCapturing,
    qualityResult,
    showQualityFeedback,
    setCapturedImage,
    setCapturing,
    setQualityResult,
    setShowQualityFeedback,
    toggleCameraType,
    reset,
  } = usePhotoStore();

  const [previewLayout, setPreviewLayout] = useState({ width: 0, height: 0 });

  const handleTakePhoto = useCallback(async () => {
    if (isCapturing) {
      return;
    }

    Haptics.impactAsync("medium");
    setCapturing(true);

    try {
      if (permissionStatus !== "granted") {
        const result = await requestCameraPermissionsAsync();
        if (!result.granted) {
          setCapturing(false);
          return;
        }
      }

      const response = await launchCameraAsync({
        mediaTypes: "Images",
        quality: 0.85,
      });

      if (response.canceled || !response.assets?.[0]) {
        setCapturing(false);
        return;
      }

      const asset = response.assets[0];
      const maxDimension = 2048;
      const needsResize =
        (asset.width && asset.width > maxDimension) ||
        (asset.height && asset.height > maxDimension);

      const uri = asset.uri;
      setCapturedImage(uri);

      const qualityScore = Math.min(100, Math.round((needsResize ? 70 : 90) + Math.random() * 15));

      setQualityResult({
        score: qualityScore,
        isAcceptable: qualityScore >= 60,
        issues:
          qualityScore < 60
            ? [
                {
                  type: "blur",
                  severity: "medium",
                  message: "鐓х墖鍙兘妯＄硦锛屽缓璁噸鏂版媿鎽刓

usedDeprecatedRules:
blur",
            severity: "high",
            message: "鎷嶇収澶辫触锛岃閲嶈瘯",
          },
        ],
      });
      setShowQualityFeedback(true);
    } finally {
      setCapturing(false);
    }
  }, [
    isCapturing,
    permissionStatus,
    setCapturing,
    setCapturedImage,
    setQualityResult,
    setShowQualityFeedback,
  ]);

  const handlePickImage = useCallback(async () => {
    try {
      const permResult = await requestMediaLibraryPermissionsAsync();
      if (!permResult.granted) {
        return;
      }

      const result = await pickImageSecurely();
      if (!result) {
        return;
      }

      setCapturedImage(result.uri);

      const qualityScore = Math.min(100, Math.round(75 + Math.random() * 20));
      setQualityResult({
        score: qualityScore,
        isAcceptable: qualityScore >= 60,
        issues: [],
      });
      setShowQualityFeedback(true);
    } catch {}
  }, [setCapturedImage, setQualityResult, setShowQualityFeedback]);

  const handleRetake = useCallback(() => {
    reset();
  }, [reset]);

  const handleContinue = useCallback(() => {
    if (capturedImageUri) {
      // PhotoPreview route and screen are not yet implemented. Navigate to the
      // photo preview once the route is added to the navigator.
      // navigation.navigate('PhotoPreview', { imageUri: capturedImageUri });
    }
  }, [capturedImageUri, navigation]);

  const handleLayout = useCallback(
    (event: { nativeEvent: { layout: { width: number; height: number } } }) => {
      const { width, height } = event.nativeEvent.layout;
      setPreviewLayout({ width, height });
      if (!referenceLines) {
        void fetchReferenceLines();
      }
    },
    [referenceLines, fetchReferenceLines]
  );

  if (permissionStatus === "denied") {
    return (
      <SafeAreaView style={styles.container} edges={["top", "bottom"]}>
        <View style={styles.header}>
          <TouchableOpacity onPress={navigation.goBack} style={styles.backButton}>
            <Ionicons name="arrow-back" size={24} color={theme.colors.text} />
          </TouchableOpacity>
          <Text style={styles.title}>鎷嶇収</Text>
          <View style={styles.headerSpacer} />
        </View>
        <View style={styles.permissionContainer}>
          <Ionicons name="camera-outline" size={64} color={theme.colors.textSecondary} />
          <Text style={styles.permissionTitle}>闇€瑕佺浉鏈烘潈闄?/Text>
          <Text style={styles.permissionMessage}>璇峰湪绯荤粺璁剧疆涓紑鍚浉鏈烘潈闄愶紝浠ヤ究浣跨敤鎷嶇収鍔熻兘</Text>
          <TouchableOpacity style={styles.settingsButton} onPress={openSettings}>
            <LinearGradient
              colors={[theme.colors.primary, theme.colors.primaryDark]}
