          </TouchableOpacity>
          <TouchableOpacity style={styles.laterButton} onPress={navigation.goBack}>
            <Text style={styles.laterButtonText}>绋嶅悗鍐嶈</Text>
          </TouchableOpacity>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container} edges={["top", "bottom"]}>
      <View style={styles.header}>
        <TouchableOpacity onPress={navigation.goBack} style={styles.backButton}>
          <Ionicons name="close" size={28} color="#FFFFFF" />
        </TouchableOpacity>
        <Text style={[styles.title, { color: "#FFFFFF" }]}>鎷嶇収</Text>
        <View style={styles.headerSpacer} />
      </View>

      <View style={styles.previewContainer} onLayout={handleLayout}>
        <View style={styles.previewPlaceholder}>
          {linesLoading && <ActivityIndicator color="#FFFFFF" size="small" />}
        </View>
        <ReferenceLineOverlay
          referenceLines={referenceLines}
          alignmentStatus={alignmentStatus}
          width={previewLayout.width}
          height={previewLayout.height}
        />
        <AlignmentGuide alignmentStatus={alignmentStatus} />
      </View>

      <View style={styles.controls}>
        <View style={styles.controlsRow}>
          <TouchableOpacity style={styles.galleryButton} onPress={handlePickImage}>
            <Ionicons name="images-outline" size={28} color="#FFFFFF" />
          </TouchableOpacity>

          <TouchableOpacity
            style={styles.captureButton}
            onPress={handleTakePhoto}
            disabled={isCapturing}
            activeOpacity={0.8}
          >
            <View style={styles.captureButtonOuter}>
              {isCapturing ? (
                <ActivityIndicator color={theme.colors.primary} size="small" />
              ) : (
                <View style={styles.captureButtonInner} />
              )}
            </View>
          </TouchableOpacity>

          <TouchableOpacity
            style={styles.flipButton}
            onPress={() => {
              Haptics.selectionAsync();
              toggleCameraType();
            }}
          >
            <Ionicons name="camera-reverse-outline" size={28} color="#FFFFFF" />
          </TouchableOpacity>
        </View>
      </View>

      {showQualityFeedback && (
        <PhotoQualityFeedback
          qualityResult={qualityResult}
          onRetake={handleRetake}
          onContinue={handleContinue}
        />
      )}
    </SafeAreaView>
  );
};

