          </View>
        </View>
        <Ionicons
          name={collapsed ? "chevron-down" : "chevron-up"}
          size={20}
          color={colors.neutral[400]}
        />
      </TouchableOpacity>

      {!collapsed && (
        <View style={styles.cardContent}>
          <View style={styles.seasonHeader}>
            <Text style={styles.seasonName}>{seasonName}</Text>
            {seasonTags && (
              <View style={styles.seasonTagsRow}>
                <View style={[styles.seasonTag, styles.warmTag]}>
                  <Text style={styles.seasonTagText}>{seasonTags.warm}鑹茶皟</Text>
                </View>
                <View style={[styles.seasonTag, styles.depthTag]}>
                  <Text style={styles.seasonTagText}>{seasonTags.depth}鏄庡害</Text>
