interface QuizImageCardProps {
  image: QuizImage;
  isSelected: boolean;
  onPress: () => void;
  index: number;
}

export const QuizImageCard: React.FC<QuizImageCardProps> = ({
  image,
  isSelected,
  onPress,
  index,
}) => {
  const scaleAnim = useRef(new Animated.Value(1)).current;

  const handlePressIn = useCallback(() => {
    Animated.spring(scaleAnim, {
      toValue: 0.95,
      useNativeDriver: true,
      speed: 50,
      bounciness: 4,
    }).start();
  }, [scaleAnim]);

  const handlePressOut = useCallback(() => {
    Animated.spring(scaleAnim, {
      toValue: 1,
      useNativeDriver: true,
      speed: 50,
      bounciness: 4,
    }).start();
  }, [scaleAnim]);

  return (
    <Pressable
      onPress={onPress}
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
      accessibilityLabel={`${image.label} 鍥剧墖${isSelected ? " 宸查€夋嫨" : ""}`}
      accessibilityRole="button"
      accessibilityState={{ selected: isSelected }}
    >
      <Animated.View
        style={[
          styles.card,
          isSelected && styles.cardSelected,
          { transform: [{ scale: scaleAnim }] },
        ]}
      >
        <ProgressiveImage
          source={{ uri: image.uri }}
          thumbnailSource={image.thumbnailUri ? { uri: image.thumbnailUri } : undefined}
          style={styles.image}
          borderRadius={BorderRadius.lg}
          accessibilityLabel={image.label}
        />
        {isSelected && (
          <View style={styles.checkBadge}>
            <Text style={styles.checkMark}>鉁?/Text>
          </View>
        )}
        <View style={styles.labelContainer}>
          <Text style={styles.label} numberOfLines={1}>
            {image.label}
          </Text>
        </View>
      </Animated.View>
    </Pressable>
  );
};

