import apiClient from "./client";
import { ApiResponse } from "../../types";
import { buildPhotoAssetUrl } from "./asset-url";
import type { FormDataValue } from "../../types";

export type PhotoType = "front" | "side" | "full_body" | "half_body" | "face";

/**
 * React Native FormData 鏂囦欢鏉＄洰绫诲瀷
 */
interface RNFileBody {
  uri: string;
  name: string;
  type: string;
}

interface PhotoUploadPayload {
  id: string;
  url: string;
  thumbnailUrl?: string;
  thumbnailDataUri?: string;
  type: PhotoType;
  status?: "pending" | "processing" | "completed" | "failed";
}

export interface UserPhoto {
  id: string;
  type: PhotoType;
  url: string;
  thumbnailUrl?: string;
  thumbnailDataUri?: string;
  analysisStatus: "pending" | "processing" | "completed" | "failed";
  analysisResult?: {
    bodyType?: string;
    skinTone?: string;
    faceShape?: string;
    colorSeason?: string;
    confidence?: number;
    measurements?: {
      shoulderWidth?: number;
      chestWidth?: number;
      waistWidth?: number;
      hipWidth?: number;
    };
  };
  analyzedAt?: string;
  createdAt: string;
}

function normalizeUploadedPhoto(payload: PhotoUploadPayload): UserPhoto {
  const now = new Date().toISOString();

  return {
    id: payload.id,
    type: payload.type,
    url: buildPhotoAssetUrl(payload.id, "original", payload.url),
    thumbnailUrl: buildPhotoAssetUrl(payload.id, "thumbnail", payload.thumbnailUrl),
    thumbnailDataUri: payload.thumbnailDataUri,
    analysisStatus: payload.status ?? "pending",
    createdAt: now,
  };
}

function normalizeUserPhoto(payload: UserPhoto): UserPhoto {
  return {
    ...payload,
    url: buildPhotoAssetUrl(payload.id, "original", payload.url),
    thumbnailUrl: buildPhotoAssetUrl(payload.id, "thumbnail", payload.thumbnailUrl),
    thumbnailDataUri: payload.thumbnailDataUri,
  };
}

export const photosApi = {
  async upload(imageUri: string, type: PhotoType = "full_body"): Promise<ApiResponse<UserPhoto>> {
    const formData = new FormData();
    const filename = imageUri.split("/").pop() || "image.jpg";
    const match = /\.(\w+)$/.exec(filename);
    const fileType = match ? `image/${match[1]}` : "image/jpeg";

    formData.append("file", {
      uri: imageUri,
      name: filename,
      type: fileType,
    } as RNFileBody);
    formData.append("type", type);

    const response = await apiClient.upload<PhotoUploadPayload>("/photos/upload", formData);

    if (!response.success || !response.data) {
      return response as ApiResponse<UserPhoto>;
    }

    return {
      success: true,
      data: normalizeUploadedPhoto(response.data),
    };
  },

  async getAll(type?: PhotoType): Promise<ApiResponse<UserPhoto[]>> {
    const response = await apiClient.get<UserPhoto[]>("/photos", { type });

    if (!response.success || !response.data) {
      return response;
    }

    return {
      success: true,
      data: response.data.map(normalizeUserPhoto),
    };
  },

  async getById(photoId: string): Promise<ApiResponse<UserPhoto>> {
    const response = await apiClient.get<UserPhoto>(`/photos/${photoId}`);

    if (!response.success || !response.data) {
      return response;
    }

    return {
      success: true,
      data: normalizeUserPhoto(response.data),
    };
  },

  async delete(photoId: string): Promise<ApiResponse<{ success: boolean }>> {
    return apiClient.delete<{ success: boolean }>(`/photos/${photoId}`);
  },
};

export default photosApi;

import { Platform, Linking, Alert } from "react-native";
import apiClient from "../api/client";
import { ApiResponse } from "../../types";
import { User } from "../../types/user";

interface WechatAuthResponse {
  user: User;
  accessToken: string;
  refreshToken: string;
}

interface WechatAuthResult {
  code: string;
  state?: string;
}

const WECHAT_APP_ID = process.env.EXPO_PUBLIC_WECHAT_APP_ID || "";
const WECHAT_UNIVERSAL_LINK = process.env.EXPO_PUBLIC_WECHAT_UNIVERSAL_LINK || "";

let isWechatInstalled = false;

async function checkWechatInstalled(): Promise<boolean> {
  if (Platform.OS === "android") {
    try {
      const result = await Linking.canOpenURL("weixin://");
      isWechatInstalled = result;
      return result;
    } catch {
      isWechatInstalled = false;
      return false;
    }
  } else if (Platform.OS === "ios") {
    try {
      const result = await Linking.canOpenURL("weixin://");
      isWechatInstalled = result;
      return result;
    } catch {
      isWechatInstalled = false;
      return false;
    }
  }
  return false;
}

async function authorize(): Promise<WechatAuthResult | null> {
  const installed = await checkWechatInstalled();

  if (!installed) {
    Alert.alert("寰俊鏈畨瑁匼

usedDeprecatedRules:
WeChat App ID not configured. Using mock auth for development.");
    return mockAuthorize();
  }

  return new Promise((resolve) => {
    try {
      const redirectUri = encodeURIComponent(WECHAT_UNIVERSAL_LINK || "xuno://wechat-callback");
      const state = Math.random().toString(36).substring(7);
      const authUrl = `https://open.weixin.qq.com/connect/oauth2/authorize?appid=${WECHAT_APP_ID}&redirect_uri=${redirectUri}&response_type=code&scope=snsapi_userinfo&state=${state}#wechat_redirect`;

      Linking.openURL(authUrl).catch(() => {
        resolve(null);
      });

      const handleOpenURL = (event: { url: string }) => {
        const url = event.url;
        if (url.includes("wechat-callback") || url.includes("code=")) {
          const codeMatch = url.match(/code=([^&]+)/);
          const stateMatch = url.match(/state=([^&]+)/);

          if (codeMatch) {
            resolve({
              code: codeMatch[1],
              state: stateMatch?.[1],
            });
          } else {
            resolve(null);
          }
        }
      };

      Linking.addEventListener("url", handleOpenURL);
    } catch {
      resolve(null);
    }
  });
}

function mockAuthorize(): WechatAuthResult {
  return {
    code: `mock_code_${Date.now()}`,
    state: "mock_state",
  };
}

