    console.log(`[OfflineCache] Demo 鏁版嵁宸蹭繚瀛?(${JSON.stringify(data).length / 1024} KB)`);
  }

  /**
   * 鑾峰彇瀹屾暣鐨?Demo 鏁版嵁
   */
  async getFullDemoData(): Promise<DemoDataPackage | null> {
    // 鍏堜粠鍐呭瓨鑾峰彇
    let entry = this.memoryCache.get(CACHE_KEYS.FULL_DEMO_DATA);

    // 鍐呭瓨娌℃湁鍒欎粠纾佺洏璇诲彇
    if (!entry) {
      entry = (await this.loadKeyToMemory(CACHE_KEYS.FULL_DEMO_DATA)) ?? undefined;
    }

    if (!entry) {
      return null;
    }

    // 妫€鏌ユ槸鍚﹁繃鏈焅n    if (Date.now() - entry.timestamp > CACHE_EXPIRY_MS) {
