  ): Promise<T[] | null> {
    const keyMap = {
      clothing: CACHE_KEYS.CLOTHING,
      users: CACHE_KEYS.USERS,
      recommendations: CACHE_KEYS.RECOMMENDATIONS,
      conversations: CACHE_KEYS.CONVERSATIONS,
    };

