import { Platform } from "react-native";
import { notificationApi } from "./api/notification.api";
import { secureStorage } from "../utils/secureStorage";

const PUSH_TOKEN_KEY = "@xuno_push_token";

/**
 * Mobile push notification service.
 * Handles permission request, token registration, and notification handling.
 * Gracefully degrades when Firebase is not configured (dev environment).
 */
class PushNotificationService {
  private token: string | null = null;
  private initialized = false;

  /**
   * Initialize push notification service.
   * Call this once on app startup.
   */
  async initialize(): Promise<void> {
    if (this.initialized) {
      return;
    }

    try {
      // Try to load existing token
      const storedToken = await secureStorage.getItem(PUSH_TOKEN_KEY);
      if (storedToken) {
        this.token = storedToken;
      }

      this.initialized = true;
    } catch (error) {
      console.warn("[PushNotification] Initialize failed:", error);
    }
  }

  /**
   * Request notification permission from the OS.
   * Returns true if permission granted.
   */
  async requestPermission(): Promise<boolean> {
    try {
      // Try to use Firebase messaging if available
      const messaging = this.getFirebaseMessaging();
      if (messaging) {
        const authStatus = await messaging.requestPermission();
        const enabled =
          authStatus === messaging.AuthorizationStatus.AUTHORIZED ||
          authStatus === messaging.AuthorizationStatus.PROVISIONAL;
        return enabled;
      }

      // Fallback: on iOS, use PushNotificationIOS
      if (Platform.OS === "ios") {
        const PushNotificationIOS =
          require("@react-native-community/push-notification-ios").default;
        return new Promise((resolve) => {
          PushNotificationIOS.requestPermissions({ alert: true, badge: true, sound: true })
            .then((permissions: { alert?: boolean }) => {
              resolve(!!permissions.alert);
            })
            .catch(() => resolve(false));
        });
      }

      // Android: permissions are granted by default for push notifications
      return true;
    } catch (error) {
      console.warn("[PushNotification] Permission request failed:", error);
      return false;
    }
  }

  /**
   * Get the current push token and register with backend.
   */
  async getAndRegisterToken(): Promise<string | null> {
    try {
      const messaging = this.getFirebaseMessaging();
      if (messaging) {
        const token = await messaging.getToken();
        if (token) {
          this.token = token;
          await secureStorage.setItem(PUSH_TOKEN_KEY, token);
          await this.registerTokenWithBackend(token);
          return token;
        }
      }

      // If no Firebase, return null (push not available in dev)
      return null;
    } catch (error) {
      console.warn("[PushNotification] Get token failed:", error);
      return null;
    }
  }

  /**
   * Register the token with the backend API.
   */
  private async registerTokenWithBackend(token: string): Promise<void> {
    try {
      const platform = Platform.OS === "ios" ? "ios" : "android";
      await notificationApi.registerDeviceToken(token, platform);
    } catch (error) {
      console.warn("[PushNotification] Backend registration failed:", error);
    }
  }

  /**
   * Deregister the current token from the backend (e.g., on logout).
   */
  async deregisterToken(): Promise<void> {
    if (!this.token) {
      return;
    }

    try {
      await notificationApi.deregisterDeviceToken(this.token);
    } catch (error) {
      console.warn("[PushNotification] Backend deregistration failed:", error);
    } finally {
      this.token = null;
      await secureStorage.deleteItem(PUSH_TOKEN_KEY);
    }
  }

  /**
   * Listen for foreground push notifications.
   * Returns an unsubscribe function.
   */
  onNotificationReceived(
    callback: (notification: {
      title?: string;
      body?: string;
      data?: Record<string, unknown>;
    }) => void
  ): () => void {
    try {
      const messaging = this.getFirebaseMessaging();
      if (messaging) {
        return messaging.onMessage(async (remoteMessage: Record<string, unknown>) => {
          const notification = remoteMessage.notification as
            | { title?: string; body?: string }
            | undefined;
          callback({
            title: notification?.title,
            body: notification?.body,
            data: (remoteMessage.data as Record<string, unknown>) || {},
          });
        });
      }
    } catch (error) {
      console.warn("[PushNotification] onMessage setup failed:", error);
    }
    return () => {};
  }

  /**
   * Listen for notification opened (app opened from notification tap).
   * Returns an unsubscribe function.
   */
  onNotificationOpened(
    callback: (notification: {
      title?: string;
      body?: string;
      data?: Record<string, unknown>;
    }) => void
  ): () => void {
    try {
      const messaging = this.getFirebaseMessaging();
      if (messaging) {
        // App in foreground when notification tapped
        const unsub1 = messaging.onNotificationOpenedApp(
          (remoteMessage: Record<string, unknown>) => {
            const notification = remoteMessage.notification as
              | { title?: string; body?: string }
              | undefined;
            callback({
              title: notification?.title,
              body: notification?.body,
              data: (remoteMessage.data as Record<string, unknown>) || {},
            });
          }
        );

        // App opened from quit state by notification tap
        void messaging
          .getInitialNotification()
          .then((remoteMessage: Record<string, unknown> | null) => {
            if (remoteMessage) {
              const notification = remoteMessage.notification as
                | { title?: string; body?: string }
                | undefined;
              callback({
                title: notification?.title,
                body: notification?.body,
                data: (remoteMessage.data as Record<string, unknown>) || {},
              });
            }
          });

        return unsub1;
      }
    } catch (error) {
      console.warn("[PushNotification] onNotificationOpened setup failed:", error);
    }
    return () => {};
  }

  /**
   * Try to get Firebase messaging module.
   * Returns null if not available (e.g., not configured in dev).
   */
  private getFirebaseMessaging(): {
    getToken: () => Promise<string>;
    requestPermission: () => Promise<number>;
    AuthorizationStatus: { AUTHORIZED: number; PROVISIONAL: number };
    onMessage: (cb: (msg: Record<string, unknown>) => void) => () => void;
    onNotificationOpenedApp: (cb: (msg: Record<string, unknown>) => void) => () => void;
    getInitialNotification: () => Promise<Record<string, unknown> | null>;
  } | null {
    try {
      // eslint-disable-next-line @typescript-eslint/no-var-requires, @typescript-eslint/no-require-imports
      const messaging = require("@react-native-firebase/messaging").default;
      return messaging();
    } catch {
      return null;
    }
  }
}

export const pushNotificationService = new PushNotificationService();
export default pushNotificationService;

import { useState, useCallback, useRef, useEffect } from "react";
import { Platform, PermissionsAndroid } from "react-native";
import * as FileSystem from "@/src/polyfills/expo-file-system";
import { Audio, Recording } from "@/src/polyfills/expo-av";

declare const process: { env: Record<string, string | undefined> };

export type SpeechRecognitionStatus = "idle" | "listening" | "processing" | "error" | "success";

export interface SpeechRecognitionResult {
  text: string;
  confidence: number;
  duration: number;
}

export interface SpeechRecognitionError {
  code: string;
  message: string;
}

export interface SpeechRecognitionConfig {
  language?: string;
  continuous?: boolean;
  timeout?: number;
  onResult?: (result: SpeechRecognitionResult) => void;
  onError?: (error: SpeechRecognitionError) => void;
  onStatusChange?: (status: SpeechRecognitionStatus) => void;
}

const SPEECH_SERVICE_CONFIG = {
  apiUrl:
    (typeof process !== "undefined" ? process.env?.EXPO_PUBLIC_SPEECH_API_URL : undefined) ||
    "https://api.example.com/speech",
  apiKey:
    (typeof process !== "undefined" ? process.env?.EXPO_PUBLIC_SPEECH_API_KEY : undefined) || "",
  defaultLanguage: "zh-CN",
  defaultTimeout: 30000,
};

export function useSpeechRecognition(config: SpeechRecognitionConfig = {}) {
  const [status, setStatus] = useState<SpeechRecognitionStatus>("idle");
  const [result, setResult] = useState<SpeechRecognitionResult | null>(null);
  const [error, setError] = useState<SpeechRecognitionError | null>(null);
  const [isAvailable, setIsAvailable] = useState(false);

  const recordingRef = useRef<Recording | null>(null);
  const startTimeRef = useRef<number>(0);
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    void checkAvailability();
    return () => {
      void stopListening();
    };
  }, []);

  const checkAvailability = async (): Promise<boolean> => {
    try {
      const { status: audioStatus } = await Audio.requestPermissionsAsync();
      const available = audioStatus === "granted";
      setIsAvailable(available);
      return available;
    } catch (err) {
      console.error("Failed to check speech recognition availability:", err);
      setIsAvailable(false);
      return false;
    }
  };

  const requestPermissions = async (): Promise<boolean> => {
    try {
      if (Platform.OS === "android") {
        const granted = await PermissionsAndroid.request(
          PermissionsAndroid.PERMISSIONS.RECORD_AUDIO
        );
        return granted === PermissionsAndroid.RESULTS.GRANTED;
      } else {
        const { status } = await Audio.requestPermissionsAsync();
        return status === "granted";
      }
    } catch (err) {
      console.error("Failed to request permissions:", err);
      return false;
    }
  };

  const startListening = useCallback(async () => {
    try {
      setError(null);
      setResult(null);

      const hasPermission = await requestPermissions();
      if (!hasPermission) {
        const permissionError: SpeechRecognitionError = {
          code: "PERMISSION_DENIED",
          message: "楹﹀厠椋庢潈闄愯鎷掔粷",
        };
        setError(permissionError);
        config.onError?.(permissionError);
        return;
      }

      setStatus("listening");
      config.onStatusChange?.("listening");
      startTimeRef.current = Date.now();

      await Audio.setAudioModeAsync({
        allowsRecordingIOS: true,
        playsInSilentModeIOS: true,
      });

      const { recording } = await Recording.createAsync(Audio.RecordingOptionsPresets.HIGH_QUALITY);

      recordingRef.current = recording;

      const timeout = config.timeout || SPEECH_SERVICE_CONFIG.defaultTimeout;
      setTimeout(() => {
        if (status === "listening") {
          void stopListening();
        }
      }, timeout);
    } catch (err) {
      const speechError: SpeechRecognitionError = {
        code: "START_FAILED",
        message: err instanceof Error ? err.message : "鍚姩璇煶璇嗗埆澶辫触",
      };
      setError(speechError);
      setStatus("error");
      config.onError?.(speechError);
      config.onStatusChange?.("error");
    }
  }, [config, status]);

  const stopListening = useCallback(async () => {
    try {
      if (!recordingRef.current) {
        return;
      }

      setStatus("processing");
      config.onStatusChange?.("processing");

      const recording = recordingRef.current;
      recordingRef.current = null;

      await recording.stopAndUnloadAsync();

      const uri = recording.getURI();
      if (!uri) {
        throw new Error("Failed to get recording URI");
      }

      const duration = Date.now() - startTimeRef.current;

      await processAudioFile(uri, duration);
    } catch (err) {
      const speechError: SpeechRecognitionError = {
        code: "STOP_FAILED",
        message: err instanceof Error ? err.message : "鍋滄璇煶璇嗗埆澶辫触",
      };
      setError(speechError);
      setStatus("error");
      config.onError?.(speechError);
      config.onStatusChange?.("error");
    }
  }, [config]);

  const processAudioFile = async (uri: string, duration: number) => {
    try {
      abortControllerRef.current = new AbortController();

      const base64Audio = await FileSystem.readAsStringAsync(uri, {
        encoding: FileSystem.EncodingType.Base64,
      });

      const response = await fetch(`${SPEECH_SERVICE_CONFIG.apiUrl}/recognize`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${SPEECH_SERVICE_CONFIG.apiKey}`,
        },
        body: JSON.stringify({
          audio: base64Audio,
          language: config.language || SPEECH_SERVICE_CONFIG.defaultLanguage,
          format: "wav",
        }),
        signal: abortControllerRef.current.signal,
      });

      if (!response.ok) {
        throw new Error(`Speech API error: ${response.status}`);
      }

      const data = await response.json();

      const recognitionResult: SpeechRecognitionResult = {
        text: data.text || data.result || "",
        confidence: data.confidence || 0.9,
        duration,
      };

      setResult(recognitionResult);
      setStatus("success");
      config.onResult?.(recognitionResult);
      config.onStatusChange?.("success");
    } catch (err) {
      if (err instanceof Error && err.name === "AbortError") {
        return;
      }

      const speechError: SpeechRecognitionError = {
        code: "RECOGNITION_FAILED",
        message: err instanceof Error ? err.message : "璇煶璇嗗埆澶辫触",
      };
      setError(speechError);
      setStatus("error");
      config.onError?.(speechError);
      config.onStatusChange?.("error");
    }
  };

  const cancel = useCallback(() => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    if (recordingRef.current) {
      void recordingRef.current.stopAndUnloadAsync();
      recordingRef.current = null;
    }

    setStatus("idle");
    setError(null);
    setResult(null);
    config.onStatusChange?.("idle");
  }, [config]);

  const reset = useCallback(() => {
    setStatus("idle");
    setError(null);
    setResult(null);
    config.onStatusChange?.("idle");
  }, [config]);

  return {
    status,
    result,
    error,
    isAvailable,
    startListening,
    stopListening,
    cancel,
    reset,
    requestPermissions,
  };
}

export interface SpeechRecognitionServiceConfig {
  apiUrl: string;
  apiKey: string;
  defaultLanguage?: string;
}

export class SpeechRecognitionService {
  private config: SpeechRecognitionServiceConfig;

  constructor(config: SpeechRecognitionServiceConfig) {
    this.config = {
      defaultLanguage: "zh-CN",
      ...config,
    };
  }

  async recognize(audioBase64: string, language?: string): Promise<SpeechRecognitionResult> {
    const response = await fetch(`${this.config.apiUrl}/recognize`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${this.config.apiKey}`,
      },
      body: JSON.stringify({
        audio: audioBase64,
        language: language || this.config.defaultLanguage,
        format: "wav",
      }),
    });

    if (!response.ok) {
      throw new Error(`Speech recognition failed: ${response.status}`);
    }

    const data = await response.json();

    return {
      text: data.text || data.result || "",
      confidence: data.confidence || 0.9,
      duration: data.duration || 0,
    };
  }
}

export const createSpeechRecognitionService = (): SpeechRecognitionService => {
  return new SpeechRecognitionService({
    apiUrl: SPEECH_SERVICE_CONFIG.apiUrl,
    apiKey: SPEECH_SERVICE_CONFIG.apiKey,
  });
};

import { io, Socket } from "socket.io-client";
import { mobileRuntimeConfig } from "../config/runtime";
import EncryptedStorage from "react-native-encrypted-storage";
import type { ChatMessage, ChatTypingPayload, ChatReadPayload } from "../types/chat";

const WS_URL = mobileRuntimeConfig.apiUrl.replace(/\/api\/v1$/, "");

type TryOnEventPayload = {
  tryOnId: string;
  status: "completed" | "failed";
  resultImageUrl?: string;
  errorMessage?: string;
};

type TryOnProgressPayload = {
  tryOnId: string;
  progress: number;
  stage: "uploading" | "processing" | "generating" | "completed" | "failed";
  timestamp: string;
};

type TryOnEventListener = (payload: TryOnEventPayload) => void;
type TryOnProgressListener = (payload: TryOnProgressPayload) => void;

class WebSocketService {
  private socket: Socket | null = null;
  private chatSocket: Socket | null = null;
  private tryOnListeners: Map<string, Set<TryOnEventListener>> = new Map();
  private progressListeners: Map<string, Set<TryOnProgressListener>> = new Map();
  private chatMessageListeners: Map<string, Set<(payload: ChatMessage) => void>> = new Map();
  private chatTypingListeners: Map<string, Set<(payload: ChatTypingPayload) => void>> = new Map();
  private chatReadListeners: Map<string, Set<(payload: ChatReadPayload) => void>> = new Map();
  private reconnectAttempts = 0;
  private maxReconnectAttempts = 5;

  async connect(): Promise<void> {
    if (this.socket?.connected) {
      return;
    }

    let token: string | null = null;
    try {
      token = await EncryptedStorage.getItem("accessToken");
    } catch {
      return;
    }

    if (!token) {
      return;
    }

    this.socket = io(`${WS_URL}/ws`, {
      auth: { token },
      transports: ["websocket"],
      reconnection: true,
      reconnectionAttempts: this.maxReconnectAttempts,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 5000,
      timeout: 10000,
    });

    this.socket.on("connect", () => {
      this.reconnectAttempts = 0;
    });

    this.socket.on("disconnect", (reason: Socket.DisconnectReason) => {
      if (reason === "io server disconnect") {
        void this.reconnect();
      }
    });

    // Backend NotificationGateway emits "notification" events with type field
    this.socket.on(
      "notification",
      (payload: {
        type: string;
        tryOnId?: string;
        tryOnResult?: TryOnEventPayload;
        progress?: TryOnProgressPayload;
      }) => {
        if (payload.type === "try_on_complete" && payload.tryOnResult) {
          const data = payload.tryOnResult;
          const listeners = this.tryOnListeners.get(data.tryOnId);
          if (listeners) {
            listeners.forEach((listener) => listener(data));
          }
          const wildcardListeners = this.tryOnListeners.get("*");
          if (wildcardListeners) {
            wildcardListeners.forEach((listener) => listener(data));
          }
        } else if (payload.type === "try_on_progress" && payload.progress) {
          const data = payload.progress;
          const listeners = this.progressListeners.get(data.tryOnId);
          if (listeners) {
            listeners.forEach((listener) => listener(data));
          }
          const wildcardListeners = this.progressListeners.get("*");
          if (wildcardListeners) {
            wildcardListeners.forEach((listener) => listener(data));
          }
        }
      }
    );

    this.socket.on("connect_error", () => {
      this.reconnectAttempts++;
    });
  }

  async reconnect(): Promise<void> {
    this.disconnect();
    await this.connect();
  }

  disconnect(): void {
    if (this.socket) {
      this.socket.disconnect();
      this.socket = null;
    }
    this.tryOnListeners.clear();
    this.progressListeners.clear();
  }

  // ==================== Chat namespace (/ws/chat) ====================

  async connectChat(): Promise<void> {
    if (this.chatSocket?.connected) {
      return;
    }

    let token: string | null = null;
    try {
      token = await EncryptedStorage.getItem("accessToken");
    } catch {
      return;
    }
    if (!token) {
      return;
    }

    this.chatSocket = io(`${WS_URL}/ws/chat`, {
      auth: { token },
      transports: ["websocket"],
      reconnection: true,
      reconnectionAttempts: this.maxReconnectAttempts,
      reconnectionDelay: 1000,
    });

    this.chatSocket.on("chat:message", (payload: ChatMessage) => {
      const roomId = payload.roomId;
      const listeners = this.chatMessageListeners.get(roomId);
      if (listeners) {
        listeners.forEach((l) => l(payload));
      }
      const wildcard = this.chatMessageListeners.get("*");
      if (wildcard) {
        wildcard.forEach((l) => l(payload));
      }
    });

    this.chatSocket.on("chat:typing", (payload: ChatTypingPayload) => {
      const roomId = payload.roomId;
      const listeners = this.chatTypingListeners.get(roomId);
      if (listeners) {
        listeners.forEach((l) => l(payload));
      }
    });

    this.chatSocket.on("chat:read", (payload: ChatReadPayload) => {
      const roomId = payload.roomId;
      const listeners = this.chatReadListeners.get(roomId);
      if (listeners) {
        listeners.forEach((l) => l(payload));
      }
    });
  }

  disconnectChat(): void {
    if (this.chatSocket) {
      this.chatSocket.disconnect();
      this.chatSocket = null;
    }
    this.chatMessageListeners.clear();
    this.chatTypingListeners.clear();
    this.chatReadListeners.clear();
  }

  joinChatRoom(roomId: string): void {
    this.chatSocket?.emit("chat:join", { roomId });
  }

  leaveChatRoom(roomId: string): void {
    this.chatSocket?.emit("chat:leave", { roomId });
  }

  sendChatMessage(data: { roomId: string; content: string; messageType?: string }): void {
    this.chatSocket?.emit("chat:message", data);
  }

  sendTyping(roomId: string, isTyping: boolean): void {
    this.chatSocket?.emit("chat:typing", { roomId, isTyping });
  }

  sendReadReceipt(roomId: string, lastMessageId?: string): void {
    this.chatSocket?.emit("chat:read", { roomId, lastMessageId });
  }

  onChatMessage(roomId: string, listener: (payload: ChatMessage) => void): () => void {
    if (!this.chatMessageListeners.has(roomId)) {
      this.chatMessageListeners.set(roomId, new Set());
    }
    this.chatMessageListeners.get(roomId)!.add(listener);
    return () => {
      const listeners = this.chatMessageListeners.get(roomId);
      if (listeners) {
        listeners.delete(listener);
        if (listeners.size === 0) {
          this.chatMessageListeners.delete(roomId);
        }
      }
    };
  }

  onChatTyping(roomId: string, listener: (payload: ChatTypingPayload) => void): () => void {
    if (!this.chatTypingListeners.has(roomId)) {
      this.chatTypingListeners.set(roomId, new Set());
    }
    this.chatTypingListeners.get(roomId)!.add(listener);
    return () => {
      const listeners = this.chatTypingListeners.get(roomId);
      if (listeners) {
        listeners.delete(listener);
        if (listeners.size === 0) {
          this.chatTypingListeners.delete(roomId);
        }
      }
    };
  }

  onChatRead(roomId: string, listener: (payload: ChatReadPayload) => void): () => void {
    if (!this.chatReadListeners.has(roomId)) {
      this.chatReadListeners.set(roomId, new Set());
    }
    this.chatReadListeners.get(roomId)!.add(listener);
    return () => {
      const listeners = this.chatReadListeners.get(roomId);
      if (listeners) {
        listeners.delete(listener);
        if (listeners.size === 0) {
          this.chatReadListeners.delete(roomId);
        }
      }
    };
  }

  isChatConnected(): boolean {
    return this.chatSocket?.connected ?? false;
  }

  onTryOnComplete(tryOnId: string, listener: TryOnEventListener): () => void {
    if (!this.tryOnListeners.has(tryOnId)) {
      this.tryOnListeners.set(tryOnId, new Set());
    }
    this.tryOnListeners.get(tryOnId)!.add(listener);

    return () => {
      const listeners = this.tryOnListeners.get(tryOnId);
      if (listeners) {
        listeners.delete(listener);
        if (listeners.size === 0) {
          this.tryOnListeners.delete(tryOnId);
        }
      }
    };
  }

  onTryOnProgress(tryOnId: string, listener: TryOnProgressListener): () => void {
    if (!this.progressListeners.has(tryOnId)) {
      this.progressListeners.set(tryOnId, new Set());
    }
    this.progressListeners.get(tryOnId)!.add(listener);

    return () => {
      const listeners = this.progressListeners.get(tryOnId);
      if (listeners) {
        listeners.delete(listener);
        if (listeners.size === 0) {
          this.progressListeners.delete(tryOnId);
        }
      }
    };
  }

  isConnected(): boolean {
    return this.socket?.connected ?? false;
  }

  on(event: string, listener: (...args: unknown[]) => void): void {
    if (this.socket) {
      this.socket.on(event, listener as (...args: unknown[]) => void);
    }
  }

  off(event: string, listener: (...args: unknown[]) => void): void {
    if (this.socket) {
      this.socket.off(event, listener as (...args: unknown[]) => void);
    }
  }
}

export const wsService = new WebSocketService();
export type { TryOnEventPayload, TryOnEventListener, TryOnProgressPayload, TryOnProgressListener };
export default wsService;

