      // q3 is the last question (index=2), should not advance
      expect(state.currentIndex).toBe(2);
    });

    it("should handle answering questions out of order", () => {
      useQuizStore.setState({ questions: mockQuestions });

      useQuizStore.getState().selectAnswer("q3", "o4");

      const state = useQuizStore.getState();
      expect(state.answers).toEqual({ q3: "o4" });
      // q3 is last question, currentIndex stays
      expect(state.currentIndex).toBe(0);
    });
  });

  // ==================== selectAnswerWithDuration ====================

  describe("selectAnswerWithDuration", () => {
    it("should add answer to answerList and update answers", () => {
      useQuizStore.setState({ questions: mockQuestions });

      useQuizStore.getState().selectAnswerWithDuration("q1", 2, 1500);

      const state = useQuizStore.getState();
      expect(state.answerList).toEqual([
        { questionId: "q1", selectedImageIndex: 2, duration: 1500 },
      ]);
      expect(state.answers).toEqual({ q1: "2" });
      // q1 is at index 1, next = 2
      expect(state.currentQuestionIndex).toBe(2);
    });

    it("should update existing answer in answerList", () => {
      useQuizStore.setState({
        questions: mockQuestions,
        answerList: [{ questionId: "q1", selectedImageIndex: 0, duration: 500 }],
      });

      useQuizStore.getState().selectAnswerWithDuration("q1", 3, 2000);

      const state = useQuizStore.getState();
      expect(state.answerList).toHaveLength(1);
      expect(state.answerList[0]).toEqual({
        questionId: "q1",
        selectedImageIndex: 3,
        duration: 2000,
      });
    });

    it("should not advance currentQuestionIndex on last question", () => {
      useQuizStore.setState({
        questions: mockQuestions,
        currentQuestionIndex: 2,
      });

      useQuizStore.getState().selectAnswerWithDuration("q3", 1, 800);

      const state = useQuizStore.getState();
      expect(state.currentQuestionIndex).toBe(2);
    });
  });

  // ==================== submitQuiz ====================

  describe("submitQuiz", () => {
    it("should set result on successful submission", async () => {
      useQuizStore.setState({ answers: { q1: "o1", q2: "o3" } });

      mockedApiClient.post.mockResolvedValueOnce({
        success: true,
        data: mockResult,
      });

      await useQuizStore.getState().submitQuiz();

      const state = useQuizStore.getState();
      expect(mockedApiClient.post).toHaveBeenCalledWith("/quiz/submit", {
        answers: { q1: "o1", q2: "o3" },
      });
      expect(state.result).toEqual(mockResult);
      expect(state.isLoading).toBe(false);
    });

    it("should set error when submission fails", async () => {
      useQuizStore.setState({ answers: { q1: "o1" } });

      mockedApiClient.post.mockResolvedValueOnce({
        success: false,
        error: { code: "ERR", message: "Failed to submit quiz" },
      });

      await useQuizStore.getState().submitQuiz();

      const state = useQuizStore.getState();
      expect(state.error).toBe("Failed to submit quiz");
      expect(state.result).toBeNull();
      expect(state.isLoading).toBe(false);
    });

    it("should set error on exception during submission", async () => {
      useQuizStore.setState({ answers: { q1: "o1" } });

      mockedApiClient.post.mockRejectedValueOnce(new Error("Server error"));

      await useQuizStore.getState().submitQuiz();

      const state = useQuizStore.getState();
      expect(state.error).toBe("Server error");
      expect(state.isLoading).toBe(false);
    });
  });

  // ==================== resetQuiz ====================

  describe("resetQuiz", () => {
    it("should reset all state to initial values", () => {
      useQuizStore.setState({
        questions: mockQuestions,
        currentIndex: 2,
        currentQuestionIndex: 2,
        answers: { q1: "o1" },
        answerList: [{ questionId: "q1", selectedImageIndex: 0, duration: 500 }],
        result: mockResult,
        isLoading: true,
        error: "some error",
      });

      useQuizStore.getState().resetQuiz();

      const state = useQuizStore.getState();
      expect(state.questions).toEqual([]);
      expect(state.currentIndex).toBe(0);
      expect(state.currentQuestionIndex).toBe(0);
      expect(state.answers).toEqual({});
      expect(state.answerList).toEqual([]);
      expect(state.result).toBeNull();
      expect(state.isLoading).toBe(false);
      expect(state.error).toBeNull();
    });
  });

  // ==================== setQuestions ====================

  describe("setQuestions", () => {
    it("should set questions directly", () => {
      useQuizStore.getState().setQuestions(mockQuestions);

      expect(useQuizStore.getState().questions).toEqual(mockQuestions);
    });
  });

  // ==================== nextQuestion ====================

  describe("nextQuestion", () => {
    it("should increment currentQuestionIndex", () => {
      useQuizStore.setState({
        questions: mockQuestions,
        currentQuestionIndex: 0,
      });

      useQuizStore.getState().nextQuestion();

      expect(useQuizStore.getState().currentQuestionIndex).toBe(1);
    });

    it("should not exceed questions length - 1", () => {
      useQuizStore.setState({
        questions: mockQuestions,
        currentQuestionIndex: 2,
      });

      useQuizStore.getState().nextQuestion();

      expect(useQuizStore.getState().currentQuestionIndex).toBe(2);
    });
  });

  // ==================== previousQuestion ====================

  describe("previousQuestion", () => {
    it("should decrement currentQuestionIndex", () => {
      useQuizStore.setState({
        questions: mockQuestions,
        currentQuestionIndex: 2,
      });

      useQuizStore.getState().previousQuestion();

      expect(useQuizStore.getState().currentQuestionIndex).toBe(1);
    });

    it("should not go below 0", () => {
      useQuizStore.setState({
        questions: mockQuestions,
        currentQuestionIndex: 0,
      });

      useQuizStore.getState().previousQuestion();

      expect(useQuizStore.getState().currentQuestionIndex).toBe(0);
    });
  });

  // ==================== setLoading ====================

  describe("setLoading", () => {
    it("should set isLoading", () => {
      useQuizStore.getState().setLoading(true);
      expect(useQuizStore.getState().isLoading).toBe(true);

      useQuizStore.getState().setLoading(false);
      expect(useQuizStore.getState().isLoading).toBe(false);
    });
  });

  // ==================== setError ====================

  describe("setError", () => {
    it("should set error message", () => {
      useQuizStore.getState().setError("Test error");
      expect(useQuizStore.getState().error).toBe("Test error");
    });

    it("should clear error with null", () => {
      useQuizStore.getState().setError("Test error");
      useQuizStore.getState().setError(null);
      expect(useQuizStore.getState().error).toBeNull();
    });
  });
});

import { create } from "zustand";

import { couponApi, type Coupon, type UserCoupon } from "../services/api/commerce.api";

interface CouponStore {
  availableCoupons: UserCoupon[];
  isLoading: boolean;
  selectedCoupon: UserCoupon | null;
  validationResult: { valid: boolean; discount: number } | null;

  fetchUserCoupons: () => Promise<void>;
  validateCoupon: (code: string, orderAmount: number) => Promise<void>;
  selectCoupon: (coupon: UserCoupon | null) => void;
  applyCoupon: (code: string) => Promise<void>;
  clearValidation: () => void;
}

export const useCouponStore = create<CouponStore>((set) => ({
  availableCoupons: [],
  isLoading: false,
  selectedCoupon: null,
  validationResult: null,

  fetchUserCoupons: async () => {
    set({ isLoading: true });
    try {
      const response = await couponApi.getUserCoupons("AVAILABLE");
      if (response.success && response.data) {
        set({ availableCoupons: response.data });
      }
    } catch (error) {
      console.error("Failed to fetch user coupons:", error);
    } finally {
      set({ isLoading: false });
    }
  },

  validateCoupon: async (code: string, orderAmount: number) => {
    set({ isLoading: true });
    try {
      const response = await couponApi.validateCoupon(code, orderAmount);
      if (response.success && response.data) {
        set({
          validationResult: {
            valid: response.data.valid,
            discount: response.data.discount,
          },
        });
      } else {
        set({ validationResult: { valid: false, discount: 0 } });
      }
    } catch (error) {
      console.error("Failed to validate coupon:", error);
      set({ validationResult: { valid: false, discount: 0 } });
    } finally {
      set({ isLoading: false });
    }
  },

  selectCoupon: (coupon: UserCoupon | null) => {
    set({ selectedCoupon: coupon });
  },

  applyCoupon: async (code: string) => {
    set({ isLoading: true });
    try {
      const response = await couponApi.applyCoupon(code);
      if (response.success && response.data) {
        set((state) => ({
          availableCoupons: state.availableCoupons.map((uc) =>
            uc.id === response.data!.id ? response.data! : uc
          ),
        }));
      }
    } catch (error) {
      console.error("Failed to apply coupon:", error);
    } finally {
      set({ isLoading: false });
    }
  },

  clearValidation: () => {
    set({ validationResult: null });
  },
}));

import { create } from "zustand";

import { orderEnhancementApi } from "../services/api/commerce.api";
import type { Order, PaginatedResponse } from "../types";

interface OrderStore {
  ordersByTab: Record<string, Order[]>;
  currentTab: string;
  isLoading: boolean;
  totalByTab: Record<string, number>;
  hasMoreByTab: Record<string, boolean>;

  fetchOrdersByTab: (tab: string, page?: number) => Promise<void>;
  setCurrentTab: (tab: string) => void;
  confirmReceipt: (orderId: string) => Promise<void>;
  softDeleteOrder: (orderId: string) => Promise<void>;
}

const PAGE_SIZE = 10;

export const useOrderStore = create<OrderStore>((set, _get) => ({
  ordersByTab: {},
  currentTab: "all",
  isLoading: false,
  totalByTab: {},
  hasMoreByTab: {},

  fetchOrdersByTab: async (tab: string, page?: number) => {
    set({ isLoading: true });
    try {
      const response = await orderEnhancementApi.getOrdersByTab(tab, page ?? 1, PAGE_SIZE);
      if (response.success && response.data) {
        const { items, total, hasMore } = response.data;
        set((state) => ({
          ordersByTab: {
            ...state.ordersByTab,
            [tab]: page && page > 1 ? [...(state.ordersByTab[tab] ?? []), ...items] : items,
          },
          totalByTab: { ...state.totalByTab, [tab]: total },
          hasMoreByTab: { ...state.hasMoreByTab, [tab]: hasMore ?? false },
        }));
      }
    } catch (error) {
      console.error("Failed to fetch orders by tab:", error);
    } finally {
      set({ isLoading: false });
    }
  },

  setCurrentTab: (tab: string) => {
    set({ currentTab: tab });
  },

  confirmReceipt: async (orderId: string) => {
    try {
      const response = await orderEnhancementApi.confirmReceipt(orderId);
      if (response.success) {
        set((state) => {
          const updated = { ...state.ordersByTab };
          for (const tabKey of Object.keys(updated)) {
            updated[tabKey] = updated[tabKey].map((order) =>
              order.id === orderId ? { ...order, status: "delivered" as const } : order
            );
          }
          return { ordersByTab: updated };
        });
      }
    } catch (error) {
      console.error("Failed to confirm receipt:", error);
    }
  },

  softDeleteOrder: async (orderId: string) => {
    try {
      const response = await orderEnhancementApi.softDeleteOrder(orderId);
      if (response.success) {
        set((state) => {
          const updated = { ...state.ordersByTab };
          for (const tabKey of Object.keys(updated)) {
            updated[tabKey] = updated[tabKey].filter((order) => order.id !== orderId);
          }
          return { ordersByTab: updated };
        });
      }
    } catch (error) {
      console.error("Failed to soft delete order:", error);
    }
  },
}));

