/**
 * 鍦ㄤ氦浜掑畬鎴愬悗鎵ц浠诲姟
 * 鐢ㄤ簬寤惰繜闈炲叧閿搷浣滐紝閬垮厤闃诲鐢ㄦ埛浜や簰
 *
 * @param task 瑕佹墽琛岀殑浠诲姟
 * @param delay 寤惰繜鏃堕棿锛堟绉掞級
 */
export function runAfterInteractions<T>(task: () => T, delay: number = 0): Promise<T | null> {
  return new Promise((resolve) => {
    void InteractionManager.runAfterInteractions(() => {
      if (delay > 0) {
        setTimeout(() => {
          resolve(task());
        }, delay);
      } else {
        resolve(task());
      }
    });
  });
}

/**
 * 寤惰繜鍔犺浇缁勪欢
 * 杩斿洖涓€涓?Promise锛屽湪鎸囧畾寤惰繜鍚?resolve
 *
 * @param delay 寤惰繜鏃堕棿锛堟绉掞級
 */
export function delayLoad(delay: number): Promise<void> {
  return new Promise((resolve) => {
    setTimeout(resolve, delay);
  });
}

/**
 * 鎵归噺鎵ц浠诲姟
 * 灏嗕换鍔″垎鎵规墽琛岋紝閬垮厤涓€娆℃€ф墽琛岃繃澶氫换鍔″鑷村崱椤縗n *
 * @param tasks 浠诲姟鍒楄〃
 * @param batchSize 姣忔壒鎵ц鐨勪换鍔℃暟閲廫n * @param batchDelay 鎵规涔嬮棿鐨勫欢杩燂紙姣锛塡n */
export async function batchExecute<T>(
  tasks: (() => T)[],
  batchSize: number = 5,
  batchDelay: number = 100
): Promise<T[]> {
  const results: T[] = [];

  for (let i = 0; i < tasks.length; i += batchSize) {
    const batch = tasks.slice(i, i + batchSize);
    const batchResults = await Promise.all(batch.map((task) => task()));
    results.push(...batchResults);

    if (i + batchSize < tasks.length) {
      await delayLoad(batchDelay);
    }
  }

  return results;
}

/**
 * 鎬ц兘璁℃椂鍣╘n * 鐢ㄤ簬娴嬮噺浠ｇ爜鎵ц鏃堕棿
